%MACRO _gral_linescatterplot(
    layout                   = BOTH
  , linetype                 = SERIES
  , data                     =
  , xvar                     =
  , yvar                     =
  , filename                 =
  , by                       =
  , equal_axis_by            = <DEFAULT>
  , quadratic                = NO
  , class                    =
  , inclass                  =
  , class_data               =
  , class_order              =
  , class_scale              = 0.5
  , completeclass            = <DEFAULT>
  , datalabel                =
  , ellipse_type             =
  , ellipse_alpha            =
  , ellipse_fill             =
  , show_scatter             =
  , lloq                     =
  , lloq_scale               =
  , lloq_footlabel           =
  , lloq_footfmt             =
  , lloq_footunit            =
  , lloq_footnote            =
  , lloq_refline             =
  , lloq_reflinetext         =
  , identity_ny              =
  , regression               =
  , regression_stat          =
  , annodata                 =
  , title_ny                 = YES
  , titfoot_scale            = 1
  , figtit_file_ny           =
  , legend                   = <DEFAULT>
  , legendtitle              = <DEFAULT>
  , special_pk_profile       =
  , special_pk_legend_ignore =
  , data_n                   =
  , data_n_ignore            =
  , subject                  = SUBJIDN
  , xvar_table_ny            = NO
  , xvar_table_label         =
  , xvar_enumerate_class     = YES
  , bands                    =
  , style                    = REPORT
  , style_options            =
  , outdat                   =
  , combo_tag                = YES
  , template2log             = NO
  , lower_error              =
  , upper_error              =
  , ticksplitchar            =
  , xlabel                   =
  , xtype                    = LIN
  , xbase                    =
  , xstart                   = MIN
  , xend                     = MAX
  , xticklist                = AUTO
  , xticklist_label          =
  , xincrement               = AUTO
  , xrefline                 =
  , xreflinetext             =
  , xshift                   =
  , xoffset                  = <DEFAULT>
  , ylabel                   =
  , ytype                    = LIN
  , ystart                   = MIN
  , yend                     = MAX
  , yticklist                = AUTO
  , yincrement               = AUTO
  , yrefline                 =
  , yreflinetext             =
  , xaxisbreakranges         =
  , yaxisbreakranges         =
  , axisbreaktype            =
  , axisbreaksymbol          =
  , module                   =
) / minoperator DES='GraL system macro to generate line, scatter and line-scatter plots';
/*******************************************************************************
 * Bayer Pharma AG
 * Macro rely on: SAS 9.2 Graphic Template Language
 *******************************************************************************
 * Purpose          : Create standard Plots for individual and mean data with or without standard deviation
 *                    e.g. for Vital Signs, Laboratory, ElectroCardiogram, Pharmacokinetic data
 *
 * Parameters       : See wrapper macros LINEPLOT, SCATTERPLOT and MEANDEVIATIONPLOT, plus:
 *           layout : Plot types to be created: SERIES, SCATTER, BOTH or SPECIAL_PK_PROFILE
 * Validation Level : 1 as used here at study level
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions  :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used: GraL system macros
 *
 * Postconditions :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         : For change history prior to v4.0 see _gral_linescatterplot.sas here:
 *                    /var/swan/root/bhc/general/tools/gral/gral3/prod/macros
 *******************************************************************************
 * Author(s)        : phkib (Lutz Kieselbach)
 *                    evmqf (Rowland Hale),
 *                    gcwer (Ren� Wentzeck),
 *                    sgqyq (Katja Gla�)      / date: 27SEP2012
 ******************************************************************************/
/* Changed by       : evmqf (Rowland Hale) / date: 02NOV2017        Version 4.0
 * Reason           : - Added handling for parameter ANNODATA
 *                    - Added parameter FIGTIT_FILE_NY
 *                    - Added parameter TICKSPLITCHAR
 *                    - Removed writing of image size to metadata for quadratic
 *                      plots as now handled via %gral_ods_options
 *                    - Changed SPro calls to _gral_ equivalents
 *                    - Added parameters XAXISBREAKRANGES YAXISBREAKRANGES
 *                      AXISBREAKTYPE AXISBREAKSYMBOL
 *                    - Changed %upcase to %qupcase in xticklist condition
 *                    - Optimised handling for combinations of SPECIAL_PK_PROFILE,
 *                      SHOW_SCATTER, DATALABEL and SHOW_SCATTER
 *                    - Added sort to _gral_graphdata_eqa for proc reg
 *                    - Added missing parameter SPECIAL_PK_PROFILE
 ******************************************************************************/
/* Changed by       : evmqf (Rowland Hale) / date: 28OCT2019        Version 4.1
 * Reason           : - Corrected copy/paste typo with mode=keep
 *                    - Fixed incorrect setting of semi-logarithmic scale title
 *                      when blank footnote present
 *                    - Fixed incorrect handling of multiple user-defined footnotes
 *                      when regression_stat=footnote.
 *                    - Added new legend handling (support for curve option)
 *                    - Added $$ text replacement for LEGENDTITLE
 *                    - Added forcing of TITLE_NY=YES behaviour for panel handling
 *                    - Swapped single/double quotes for setting of footnote via call execute
 *                    - Fixed issue with $var$ text replacement in file names where graphic
 *                      is empty
 *                    - Removed macro var mversion
 ******************************************************************************/
/* Changed by       : evmqf (Rowland Hale) / date: 13MAY2020        Version 4.2
 * Reason           : - Corrected filename on empty graphic
 *                    - Optimised quoting for legend title
 *                    - Added check for length of file name
 *                    - Change metadata type to yaxis for yoffsetmax
 ******************************************************************************/
/* Changed by       : evmqf (Rowland Hale) / date: 15DEC2020   Version 4.2 HF-5
 * Reason           : - Corrected dummy _classid applied when SPECIAL_PK_LEGEND_IGNORE
 *                      is used for when COMPLETECLASS is set to NO
 ******************************************************************************/
/* Changed by       : evmqf (Rowland Hale) / date: 21JUN2021   Version 4.3
 * Reason           : - Added support for LLOQ scatter markers
 *                    - Changes to big number dummy value
 *                    - Fixed bug where default value applied to XOFFSET for
 *                      multiple BY groups
 ******************************************************************************/
/* Changed by       : evmqf (Rowland Hale) / date: 14JUN2022   Version 4.4
 * Reason           : - Added support for ellipse plots
 *                    - Added support for band plots on line plots
 *                    - Fix for bug #1515
 *                    - Increased length of current_by_group variable
 *                    - Removed SAS option handling as handled by the calling
 *                      macro
 *                    - Added removal of cl<n>fmt formats as tidy-up
 ******************************************************************************/
/* Changed by       : evmqf (Rowland Hale) / date: 30NOV2023   Version 4.4.1
 * Reason           : - Fix at study level: moved reset of regression stat
 *                      footnotes from end of macro to end of BY group loop
 ******************************************************************************/

    %LOCAL macro;
    %let macro = &sysmacroname;
    %if %length(&module) = 0 %then %let module = &macro;

    %if &v_gral ne 4.4 %then %do;
        %put %str(WAR)NING: A study-level version of GraL macro &sysmacroname is in use in a version of GraL which does not support it!;
    %end;

    %local l_hasfootdesc l_set_x_tmp_fmt _filename;

    %let layout = %upcase(&layout);
    %if %upcase(&xvar) = %upcase(&class) %then %let xshift = NO;

    %let linetype = %upcase(&linetype);
    %let module   = %upcase(&module);

    %* Set big number dummy value ;
    %local L_BIGNUMBER;
    %if %symglobl(gral_bignumber) %then %do;
        %let L_BIGNUMBER = &gral_bignumber;
    %end;
    %else %do;
        %let L_BIGNUMBER = 9999999999;
    %end;

%*;
%* Determine CLASS_DATA;
%*;

    %if %length(&class) > 0 %then %do;
        %let class_data = %_gral_class_data(data=&data, class=&class, class_data=&class_data, ignore=&special_pk_legend_ignore, module=&module);
    %end;
    %if %qupcase(&completeclass) = %bquote(<DEFAULT>) %then %do;
        %if %length(&class) > 0 and %length(&class_data) > 0 and %length(&ellipse_type) = 0 %then %let completeclass = YES;
        %else %let completeclass = NO;
    %end;
    %if %length(&ellipse_type) > 0 and %sysfunc(findc(&completeclass, y, i)) = 1 %then %do;
        %put %str(WAR)NING: &module - Class completion is not currently supported for scatter-ellipse plots.;
        %let completeclass = NO;
    %end;

%*;
%* Set scatter_only flag ;
%*;

    %local l_scatter_only;
    %if %_gral_getvarlist(&data,scatter_only,mode=keep) = SCATTER_ONLY %then %let l_scatter_only = Y;

%*;
%* Arrange data for SPECIAL_PK_LEGEND_IGNORE ;
%*;

    %if %length(&special_pk_legend_ignore) > 0 %then %do;
        proc sort data=&data out=_gral_data;
            by &by &class &inclass &xvar;
        run;

        data _gral_data (drop=newclass);
            set _gral_data;
            %if %length(&class) > 0 %then %do;
                if missing(&class) then delete;
            %end;
            y4axis = &yvar;
            %if %length(&datalabel) > 0 %then %do;
                var4datalabel = &datalabel;
                format var4datalabel %_gral_varattrib(_gral_data,&datalabel,varfmt);
                %let datalabel = var4datalabel;
            %end;
            format y4axis %_gral_varattrib(&data,&yvar,varfmt);
            if _n_ = 1 then newclass = &L_BIGNUMBER;
            if &class in (&special_pk_legend_ignore) then do;
                _nolegend = &yvar;
                _nolegendid + 1;
                &class = newclass;
                newclass + 1;
                call missing (&yvar);
                %if %_gral_getvarlist(&data,series_only,mode=keep) = SERIES_ONLY %then %do;
                    call missing (series_only);
                %end;
            end;
        run;

        proc sort data=&class_data out=_gral__class_data (keep=&class &inclass) nodupkey;
            by &class &inclass;
        run;

        data _gral__class_data (drop=newclass);
            set _gral__class_data;
            if _n_ = 1 then newclass = &L_BIGNUMBER;
            if &class in (&special_pk_legend_ignore) then do;
                &class = newclass;
                newclass + 1;
            END;
        run;

        %let class_data = _gral__class_data;

        %* Remove SPECIAL_PK_LEGEND_IGNORE values from CLASS_ORDER;
        %if %length(&class_order) > 0 %then %do;
            %local l_c l_spli;
            %do l_c = 1 %to %sysfunc(countw(&special_pk_legend_ignore,%str( )));
                %let l_spli = %scan(&special_pk_legend_ignore,&l_c,%str( ));
                %let class_order = %sysfunc(prxchange(s/((?<![-\d])&l_spli(?!\d))//i,1,&class_order));

documents.summary:
%end;
        %end;
    %end;
    %else %do;
        data _gral_data;
            set &data;
            %if %length(&class) > 0 %then %do;
                if missing(&class) then delete;
            %end;
            %if %upcase(&class) = %upcase(&xvar) %then %do;
                %local l_gral_classxvar_lab;
                %let l_gral_classxvar_lab = %_gral_varlabel(&data,&xvar,return_varname=y);
                _gral_classxvar = &xvar;
                %let xvar = _gral_classxvar;
            %end;
            %if %_gral_getvarlist(&data,scatter_only,mode=keep) = SCATTER_ONLY %then %do;
                y4axis = coalesce(&yvar,scatter_only);
            %end;
            %else %if %length(&lloq) > 0 %then %do;
                y4axis      = ifn(&yvar > &lloq, &yvar, .);
                y4axis_lloq = ifn(&yvar > &lloq, &yvar, &lloq);
            %end;
            %else %do;
                y4axis = &yvar;
            %end;
            format y4axis %_gral_varattrib(&data,&yvar,varfmt);
            %if %length(&datalabel) > 0 %then %do;
                var4datalabel = &datalabel;
                format var4datalabel %_gral_varattrib(&data,&datalabel,varfmt);
                %let datalabel = var4datalabel;
            %end;
        run;
    %end;

    %let data = _gral_data;

%*;
%* Prepare data for special_pk_profile ;
%*;

    %if &layout = SPECIAL_PK_PROFILE %then %do;
        %local l_i l_profilen;

        data _gral_data;
            set _gral_data;
            %do l_i = 1

documents.sourceText:
%end;
        %end;
    %end;
    %else %do;
        data _gral_data;
            set &data;
            %if %length(&class) > 0 %then %do;
                if missing(&class) then delete;
            %end;
            %if %upcase(&class) = %upcase(&xvar) %then %do;
                %local l_gral_classxvar_lab;
                %let l_gral_classxvar_lab = %_gral_varlabel(&data,&xvar,return_varname=y);
                _gral_classxvar = &xvar;
                %let xvar = _gral_classxvar;
            %end;
            %if %_gral_getvarlist(&data,scatter_only,mode=keep) = SCATTER_ONLY %then %do;
                y4axis = coalesce(&yvar,scatter_only);
            %end;
            %else %if %length(&lloq) > 0 %then %do;
                y4axis      = ifn(&yvar > &lloq, &yvar, .);
                y4axis_lloq = ifn(&yvar > &lloq, &yvar, &lloq);
            %end;
            %else %do;
                y4axis = &yvar;
            %end;
            format y4axis %_gral_varattrib(&data,&yvar,varfmt);
            %if %length(&datalabel) > 0 %then %do;
                var4datalabel = &datalabel;
                format var4datalabel %_gral_varattrib(&data,&datalabel,varfmt);
                %let datalabel = var4datalabel;
            %end;
        run;
    %end;

    %let data = _gral_data;

%*;
%* Prepare data for special_pk_profile ;
%*;

    %if &layout = SPECIAL_PK_PROFILE %then %do;
        %local l_i l_profilen;

        data _gral_data;
            set _gral_data;
            %do l_i = 1 %to %sysfunc(countw(%str(&special_pk_profile),#));
                if %scan(%str(&special_pk_profile),&l_i,#) then do;
                    ___profile = &xvar;
                    __profile&l_i = &xvar;
                    %if %_gral_getvarlist(&data,series_only,mode=keep) = SERIES_ONLY %then %do;
                        if missing(series_only) then call missing(__profile&l_i, ___profile);
                    %end;
                end;
            %end;
            %if &l_scatter_only = Y %then %do;
                if not missing(scatter_only) then ___profile = &xvar;
            %end;
            %else %if %sysfunc(findc(&show_scatter,y,i)) = 1 or %length(&datalabel) > 0 %then %do;
                ___profile = &xvar;
            %end;
            format __profile: ___profile %_gral_varfmt(_gral_data, &xvar);
            label ___profile="%_gral_varlabel(_gral_data, &xvar, return_varname=y)";

            %* <check>;
            %* @TYPE: LINEPLOT;
            %* @PARAMETER: SPECIAL_PK_PROFILE;
            %* @CHECK: Ranges defined in SPECIAL_PK_PROFILE do not overlap;
            %* @ACTIONONFAILURE: Issue error and abort program;
            %* @SOLUTION: Specify SPECIAL_PK_PROFILE with conditions which define distinct ranges of XVAR values.;
            if n(of __profile:) > 1 then do;
                PUT 'ERR' "OR: &module - Ranges defined in SPECIAL_PK_PROFILE (&special_pk_profile) overlap!";
                call symputx('macro_parameter_error',1,'g');
                stop;
            end;
            %* </check>;
        run;
        %if &macro_parameter_error = 1 %then %GOTO ABORT_MACRO;

        %let l_profilen = %sysfunc(countw(&special_pk_profile,#));
        %if %sysfunc(findc(&show_scatter,n,i)) = 1 %then %let xvar = ___profile;

        %* <check>;
        %* @TYPE: LINEPLOT;
        %* @PARAMETER: SPECIAL_PK_PROFILE;
        %* @CHECK: SPECIAL_PK_PROFILE is correctly defined;
        %* @ACTIONONFAILURE: Issue error and abort program;
        %* @SOLUTION: Specify SPECIAL_PK_PROFILE with conditions which define distinct ranges of XVAR values.;
        proc means data=_gral_data noprint;
            var __profile:;
            output out=_gral_spkpcheck (where=(_stat_ = 'N'));
        run;
        data _null_;
            set _gral_spkpcheck;
            if findw(catx('#', of __profile:),'0','#') then do;
                %* Using compress to avoid strange splitting of ERR OR in log;
                put "%sysfunc(compress(ERR OR)): &module - SPECIAL_PK_PROFILE (&special_pk_profile) contains a definition error! Please review this parameter!";
                put 'ERR' "OR: &module - Please specify SPECIAL_PK_PROFILE with conditions which define distinct ranges of XVAR values!";
                %if %length(&scatter_only_cond) > 0 %then %do;
                    put 'ERR' "OR: &module - Please ensure entire profiles are not excluded by SCATTER_ONLY_COND conditions.";
                %end;
                call symputx('macro_parameter_error',1,'g');
            end;
        run;
        %if &macro_parameter_error = 1 %then %GOTO ABORT_MACRO;
        %* </check>;

    %end;

%*;
%* Read input dataset;
%*      keep only required variables;
%*      create global macro variables g_nEqAxis  (number of equal-axis-by groups);
%*                                    g_nGraphs  (number of graphics);
%*                                    g_nClasses (number of classes);
%*      create dataset variables _eqaxbyid (id for nEqAxis):
%*                               _byid    (id for nGraphs);
%*                               _inbyid  (id for nGraphs within nEqAxis);
%*                               _classid (id for nClasses);
%* Delete _gral_graphopts dataset as there all options will be defined;
%*;
    %if %qupcase(&equal_axis_by) = %bquote(<DEFAULT>) %then %let equal_axis_by = &by;

    %local vars4repl;
    %let vars4repl = %_gral_replace_text_vars(labels=&xlabel &ylabel &xreflinetext &yreflinetext &legendtitle, filename=&filename, module=&module);
    %if &macro_parameter_error = 1 %then %goto ABORT_MACRO;

    %_gral_read_data(
        data          = &data
      , out           = _gral_indat
      , class         = &class
      , inclass       = &inclass
      , class_data    = &class_data
      , class_order   = &class_order
      , completeclass = &completeclass
      , by            = &by
      , equal_axis_by = &equal_axis_by
      , var           = &xvar &yvar y4axis &lower_error &upper_error &datalabel &vars4repl &bands
                        %if %length(&lloq) > 0 %then y4axis_lloq;
                        %if %length(&special_pk_legend_ignore) > 0 %then _nolegend _nolegendid y4axis;
                        %if &layout = SPECIAL_PK_PROFILE %then __profile: ___profile;
                        %_gral_getvarlist(&data,scatter_only series_only,mode=keep)
      , var_or_value  = &xstart &xend &xticklist &xticklist_label &xincrement &xrefline &ystart &yend &yticklist &yincrement &yrefline &lloq &lloq_scale &lloq_footunit
      , xvar          = &xvar
      , module        = &module
    );

    %if %length(&special_pk_legend_ignore) > 0 %then %do;
        %* Get maximum non-ignore _classids per _byid for use as dummies;
        proc sql;
            create table _gral_indat_tmp as
            select _byid, max(_classid) as _classid_bymax
            from _gral_indat
            where &class < &L_BIGNUMBER
            group by _byid
            ;
        quit;

        %* Put dummy _classids into macro variables;
        data _null_;
            set _gral_indat_tmp;
            call symputx(cats('_classid_bymax', _byid), _classid_bymax);
        run;

        data _gral_indat;
            set _gral_indat;
            by &by _classid _inclassid;
            if &class >= &L_BIGNUMBER then do;
                %* Apply dummy _classids;
                _classid = symgetn(cats('_classid_bymax', _byid));
                _nocompleteclassid = .;
                if _noDataforClass = 'Y' then delete;
            end;
            if _noDataforClass = 'Y' then _nolegendid = 99;
        run;
    %end;

    %* <check>;
    %* @TYPE: LINEPLOT SCATTERPLOT MEANDEVIATIONPLOT;
    %* @PARAMETER: XTYPE;
    %* @CONDITION: XVAR is character;
    %* @CHECK: XTYPE is DISCRETE;
    %* @ACTIONONFAILURE: Issue warning;
    %* @MESSAGEONFAILURE: X axis variable is <xvar> - character variables are not supported for non-discrete axes! XTYPE has been reset to DISCRETE!;
    %* @SOLUTION: Specify XTYPE as DISCRETE;
    %* </check>;
    %if %_gral_vartype(_gral_indat, &xvar) = C and %UPCASE(&xtype) NE DISCRETE %then %do;
        %put %str(WAR)NING: &module - X axis variable is &xvar - character variables are not supported for non-discrete axes!;
        %let xtype = DISCRETE;
        %put %str(WAR)NING: &module - XTYPE has been reset to DISCRETE!;
    %end;

    %* <check>;
    %* @TYPE: LINEPLOT SCATTERPLOT MEANDEVIATIONPLOT;
    %* @PARAMETER: XTICKLIST;
    %* @CHECK: XTYPE is not DISCRETE;
    %* @ACTIONONFAILURE: Issue warning;
    %* @MESSAGEONFAILURE:  XTICKLIST is not supported for discrete axes!;
    %* @SOLUTION: Set XTICKLIST to blank;
    %* </check>;
    %if %qupcase(&xticklist) ne AUTO and %upcase(&xtype) = DISCRETE %then %do;
        %put %str(WAR)NING: &module - XTICKLIST is not supported for discrete axes!;
        %let xticklist = AUTO;
        %let xticklist_label = ;
        %put %str(WAR)NING: &module - XTICKLIST has been reset to AUTO!;
    %end;

%*;
%* Derive current_by_group for log reporting ;
%*;

    %if %length(&by) > 0 %then %do;
        %local l_g;
        data _gral_indat;
            set _gral_indat;
            length current_by_group $2000;
            %do l_g = 1 %to %sysfunc(countw(&by,%str( )));
                %if &l_g = 1 %then current_by_group = "%upcase(%scan(&by,&l_g,%str( )))=" || left(vvalue(%scan(&by,&l_g,%str( ))));
                %else current_by_group = trim(current_by_group) || ", %upcase(%scan(&by,&l_g,%str( )))=" || left(vvalue(%scan(&by,&l_g,%str( ))));
                ;
            %end;
            current_by_group = quote(trim(current_by_group));
        run;
    %end;

%*;
%* Calculate Big N ;
%*;

    %local big_n_class;
    %if %length(&data_n) > 0 %then %do;

        %_gral_big_n(
            indat         = _gral_indat
          , outdat        = _gral_indat
          , data_n        = &data_n
          , data_n_ignore = &data_n_ignore
          , xvar          = %if %sysfunc(findc(&xvar_table_ny,y,i)) = 1 %then &xvar;
          , class         = &class
          , by            = &by
          , subject       = &subject
          , module        = &module
        );

        /* For use in $$ text replacement add BIG_N_BY to *end* of list of BY variables regardless of which BY-group
         * level the Big N counts relate to. This is possible as it is _BYID which is used for BY-group processing */
        %let vars4repl = &vars4repl big_n_by;
        %if %length(&class) > 0 %then %let big_n_class = big_n_class;
    %end;

%*;
%* Create style ;
%*;

    %if %symexist(gral_panel) %then %do;
        %_gral_panel_style_check(style=&style, options=&style_options, module=&module)
        %let style = DEFAULT;
        %let style_options = ;
    %end;
    %else %do;
        %_gral_style(
            style           = &style
          , options         = &style_options
        %if %length(&ellipse_fill) > 0 or (%length(&bands) > 0 and &layout = BOTH) %then %do;
          , alt_symbols_ny  = Y;
        %end;
        %if %length(&ellipse_fill) > 0 or (%length(&bands) > 0 and &layout = BOTH) %then %do;
          , color_repeat_ny = N;
        %end;
          , module          = &module
        );

        %if &macro_parameter_error = 1 %then %do;
            %let style = REPORT;
            %put %str(WAR)NING: &module - STYLE has been reset to REPORT!;
            %let macro_parameter_error = 0;
        %end;
    %end;

%*;
%* Check number of CLASS groups for BAND and filled ELLIPSE plots ;
%*;

    %local l_nClasses2;
    %if %length(&class) > 0 %then %do;
        proc sql noprint;
            select count(*) into :l_nClasses2 from _gral_class_data
            %if %sysfunc(findc(&completeclass, n, i)) = 1/* or (%length(&ellipse_type) > 0 and %length(&ellipse_fill) = 0)*/ %then %do;
                where classInData = 'Y'
            %end;
            ;
