proc sort data=_gral_graphdata_eqa (keep=&xvar &class &inclass _classid) out=_gral_shift_tmp (drop=&class) nodupkey;
                    by _classid &inclass &xvar;
                    %if %length(&special_pk_legend_ignore) > 0 %then
                        where &class < &L_BIGNUMBER and not missing(&inclass);
                    ;
                run;

                proc sql noprint;
                    select count(distinct &inclass) into :l_nclasses from _gral_shift_tmp;
                quit;

                data _gral_shift_tmp;
                    set _gral_shift_tmp;
                    by _classid &inclass;
                    _shiftid + first.&inclass;
                run;

                %_gral_shift(
                    indat       = _gral_shift_tmp
                  , outdat      = _gral_shift_tmp
                  , class_scale = &class_scale
                  , nclasses    = &l_nclasses
                  , invalue     = &xvar
                  , classid     = _shiftid
                  , module      = &module
                );

                proc sort data=_gral_graphdata_eqa;
                    by _classid &inclass &xvar;
                run;

                proc sort data=_gral_shift_tmp;
                    by _classid &inclass &xvar;
                run;

                data _gral_graphdata_eqa;
                    merge _gral_graphdata_eqa _gral_shift_tmp;
                    by _classid &inclass &xvar;
                run;
            %end;
            %else %do;
                %if %length(&special_pk_legend_ignore) > 0 %then %do;
                    proc sql noprint;
                        select count(distinct &class) into :l_nclasses
                        from _gral_graphdata_eqa
                        where missing(_nolegend)
                        ;
                    quit;
                %end;
                %else %let l_nclasses = &g_nclasses;

                %_gral_shift(
                    indat       = _gral_graphdata_eqa
                  , outdat      = _gral_graphdata_eqa
                  , class_scale = &class_scale
                  , nclasses    = &l_nclasses
                  , invalue     = &xvar
                  , classid     = _nocompleteclassid
                  , module      = &module
                );
            %end;
        %end;

        %if %length(&special_pk_legend_ignore) > 0 %then %do;
            data _gral_graphdata_eqa;
                set _gral_graphdata_eqa;
                if not missing(_nolegend) then do;
                    %* Remove shifting for special_pk_legend_ignore values;
                    %if %sysfunc(findc(&xshift,y,i)) = 1 %then %do;
                        _shftval = 0;
                    %end;
                    _x4nolegend = &xvar;
                end;
            run;
        %end;

        %*;
        %* Perform axis calculation and settings;
        %*;

        %put ;
        %put - &module: Creating axis settings.;
        %_gral_axis_settings(
            axis                = X
          , axis_data           = _gral_graphdata_eqa
          , axis_xvar           = &xvar
          , axis_yvar           = %if %length(&lloq) > 0 %then y4axis_lloq; %else y4axis;
          , axis_type           = &xtype
          , axis_base           = &xbase
          , axis_start          = &xstart
          , axis_end            = &xend
          , axis_ticklist       = &xticklist
          , axis_ticklist_label = &xticklist_label
          , axis_increment      = &xincrement
          , axis_refline        = &xrefline
          , module              = &module
        )
        %if &macro_parameter_error = 1 %then %goto ABORT_MACRO;


        %* Get top and bottom Y values of regression line for axis calculation ;
        %local l_yaxis_data;
        %if %sysfunc(findc(&regression,y,i)) = 1 and (%sysevalf(%upcase(&ystart) = MIN, boolean) or %sysevalf(%upcase(&yend) = MAX, boolean)) %then %do;
            proc sort data=_gral_graphdata_eqa;
                by _classid;
            run;

            proc reg data=_gral_graphdata_eqa (where=(missing(_noDataForClass))) outest=_gral_reg noprint;
                model y4axis=&xvar;
                by _classid;
            quit;

            %local l_intercept l_xmin l_xmax;
            proc sql noprint;
                select min(&xvar), max(&xvar) into :l_xmin, :l_xmax from _gral_graphdata_eqa;
            quit;

            data _null_;
                set _gral_reg end=_eof;
                retain min4axis max4axis;
                min4axis = min(min4axis, intercept + (&xvar * &l_xmin));
                max4axis = min(max4axis, intercept + (&xvar * &l_xmax));
                if _eof then do;
                    call symputx('min4axis',min4axis);
                    call symputx('max4axis',max4axis);
                end;
            run;

            data _gral_graphdata_eqa_4yaxis;
                set _gral_graphdata_eqa end=_eof;
                output;
                if _eof then do;
                    %if %sysevalf(%upcase(&ystart) = MIN, boolean) %then %do;
                        y4axis = symget('min4axis');
                        output;
                    %end;
                    %if %sysevalf(%upcase(&yend) = MAX, boolean) %then %do;
                        y4axis = symget('max4axis');
                        output;
                    %end;
                END;
            run;

            %let l_yaxis_data = _gral_graphdata_eqa_4yaxis;
        %end;
        %else %do;
            %let l_yaxis_data = _gral_graphdata_eqa;
        %end;

        %LOCAL l_ytype_num;
        %DO l_ytype_num = 1 %TO %SYSFUNC(COUNTW(&ytype%str( )));

            %_gral_axis_settings(
                axis           = Y
              , axis_data      = &l_yaxis_data
              , axis_xvar      = &xvar
              , axis_yvar      = %if %length(&lloq) > 0 and %upcase(%scan(&ytype,&l_ytype_num)) = LOG %then y4axis_lloq; %else y4axis;
              , axis_type      = %scan(&ytype,&l_ytype_num)
              , call_type      = &ytype
              , axis_base      = 10
              , axis_start     = &ystart
              , axis_end       = &yend
              , axis_ticklist  = &yticklist
              , axis_increment = &yincrement
              , axis_refline   = &yrefline %if %upcase(%scan(&ytype,&l_ytype_num)) = LOG %then &lloq;
              , axis_error     = &lower_error &upper_error &bands
              , module         = &module
            )

            %if &macro_parameter_error = 1 %then %goto ABORT_MACRO;

        %end;

        %*;
        %* Perform axis re-calculations for a quadratic scatter plot ;
        %* QUADRATIC=YES means both axes will have the same start tick mark values ;
        %* QUADRATIC=BOTH means both axes will have the same start and end tick mark values ;
        %*;

        %if %sysfunc(findc(&quadratic,y,i)) = 1 or %upcase(&quadratic) = BOTH %then %do;
            %local l_xmin l_ymin l_axis l_axis2;
            %let l_xmin = %_gral_get_vlookup(dataset=_gral_xaxistemp_lin, searchval=xmin);
            %let l_ymin = %_gral_get_vlookup(dataset=_gral_yaxistemp_lin, searchval=ymin);
            %if &l_xmin < &l_ymin %then %do;
                %let l_axis  = y;
                %let l_axis2 = x;
            %end;
            %else %if &l_ymin < &l_xmin %then %do;
                %let l_axis  = x;
                %let l_axis2 = y;
            %end;
            %if %length(&l_axis) > 0 %then %do;
                %if %upcase(&&&l_axis.ticklist) = AUTO %then %do;
                    %local l_max;
                    %let l_max = %_gral_get_vlookup(dataset=_gral_&l_axis.axistemp_lin, searchval=&l_axis.max);

                    %_gral_axis_settings(
                        axis           = %upcase(&l_axis)
                      , axis_data      = _gral_graphdata_eqa
                      , axis_xvar      = &xvar
                      , axis_yvar      = y4axis
                      , call_type      = lin
                      , axis_base      = %sysfunc(ifn(&l_axis = x, &xbase, 10))
                      , axis_start     = &&&l_&l_axis2.min
                      , axis_end       = &l_max
                      , axis_increment = &&&l_axis.increment
                      , axis_refline   = &&&l_axis.refline
                      , module         = &module
                    )
                %end;
            %end;


            %if %upcase(&quadratic) = BOTH %then %do;
                %local l_xmax l_ymax;
                %let l_xmax = %_gral_get_vlookup(dataset=_gral_xaxistemp_lin, searchval=xmax);
                %let l_ymax = %_gral_get_vlookup(dataset=_gral_yaxistemp_lin, searchval=ymax);
                %if &l_xmax > &l_ymax %then %do;
                    %let l_axis  = y;
                    %let l_axis2 = x;
                %end;
                %else %if &l_ymax > &l_xmax %then %do;
                    %let l_axis  = x;
                    %let l_axis2 = y;
                %end;
                %if %length(&l_axis) > 0 %then %do;
                    %if %upcase(&&&l_axis.ticklist) = AUTO %then %do;
                        %local l_min;
                        %let l_min = %_gral_get_vlookup(dataset=_gral_&l_axis.axistemp_lin, searchval=&l_axis.min);

                        %_gral_axis_settings(
                            axis           = %upcase(&l_axis)
                          , axis_data      = _gral_graphdata_eqa
                          , axis_xvar      = &xvar
                          , axis_yvar      = y4axis
                          , call_type      = LIN
                          , axis_base      = %sysfunc(ifn(&l_axis = x, &xbase, 10))
                          , axis_start     = &l_min
