                                    %end;
                                %end;
                            %end;
                            %else %do;
                                %local l_line1;
                                %let l_rn = 1;
                                %let l_line1 = Linear regression line: intercept=&l_intercept%str(,) slope=&l_slope;
                            %end;

                            %if %sysfunc(find(&regression_stat,graph,i)) > 0 %then %do;
