                                    %_gral_set_graphoption(plot=&l_idx, cell=1, object=series&l_i, type=seriesplot, attribute=group, value=_classid);
                                %end;
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series&l_i, type=seriesplot, attribute=index, value=_classid);
                            %end;

/*                            %if &l_i = &l_profilen and %sysfunc(prxmatch(/curve/i,&legend)) %then %do;*/
/*                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series&l_i, type=seriesplot, attribute=curvelabel, value=_classid);*/
/*                            %end;*/
                        %end;
                        %if %length(&inclass) > 0 %then %do;
