documents.sourceText:
%if %_gral_getvarlist(_gral_graphdata,series_only,mode=keep) = SERIES_ONLY %then %do;
                            %_gral_set_graphoption(plot=&l_idx, cell=1, object=series1, type=seriesplot, attribute=yvar, value=series_only);
                        %end;
                        %else %do;
                            %if %length(&lloq) > 1 %then %do;
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series1, type=seriesplot, attribute=yvar, value=_y4lloq);
                            %end;
                            %else %do;
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series1, type=seriesplot, attribute=yvar, value=&yvar);
                            %end;
                        %end;

                        %if %length(&class) > 0 %then %do;
                            %if %sysfunc(findc(&xshift,y,i)) = 1 %then %do;
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series1, type=seriesplot, attribute=xvar, value=%str(eval(&xvar + _shftval)));
                            %end;
                            %if %length(&inclass) > 0 %then %do;
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series1, type=seriesplot, attribute=group, value=_inclassid);
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series1, type=seriesplot, attribute=index, value=_classid);
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series2, type=seriesplot, attribute=xvar,  value=dummyx);
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series2, type=seriesplot, attribute=yvar,  value=dummyy);
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series2, type=seriesplot, attribute=group, value=_classid);
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series2, type=seriesplot, attribute=index, value=_classid);
                            %end;
                            %else %do;
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series1, type=seriesplot, attribute=group, value=_classid);
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=series1, type=seriesplot, attribute=index, value=_classid);
                            %end;
                        %end;

                        %if %length(&bands) > 0 %then %do;
                            %_gral_set_graphoption(plot=&l_idx, cell=1, object=band1, type=BandPlot, attribute=xvar, value=&xvar);
                            %if %length(&class) > 0 and %sysfunc(findc(&xshift,y,i)) = 1 %then %do;
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=band1, type=BandPlot, attribute=xvar, value=%str(eval(&xvar + _shftval)));
                            %end;
                            %else %do;
                                %_gral_set_graphoption(plot=&l_idx, cell=1, object=band1, type=BandPlot, attribute=xvar, value=&xvar);
                            %end;

                            %_gral_set_graphoption(plot=&l_idx, cell=1, object=band1, type=BandPlot, attribute=group, value=_classid);
                            %_gral_set_graphoption(plot=&l_idx, cell=1, object=band1, type=BandPlot, attribute=index, value=_classid);
                            %_gral_set_graphoption(plot=&l_idx, cell=1, object=band1, type=BandPlot, attribute=datatransparency, value=0.75);
                            %_gral_set_graphoption(plot=&l_idx, cell=1, object=band1, type=BandPlot, attribute=limitlower, value=%scan(&bands, 1));
                            %_gral_set_graphoption(plot=&l_idx, cell=1, object=band1, type=BandPlot, attribute=limitupper, value=%scan(&bands, 2));
                        %end;
                    %end;

                    %if &layout in SCATTER BOTH SPECIAL_PK_PROFILE or (&layout = SERIES and (%length(&datalabel) > 0)) or &l_scatter_only = Y %then %do;

                        %if %length(&lloq) > 0 and &layout in BOTH SPECIAL_PK_PROFILE and %sysfunc(prxmatch(/log/i, &ytype)) > 0 %then %do;

                            %local l_ylogmin l_ylogmax l_yrange l_fact l_fact2;
                            %let l_ylogmin = %_gral_get_vlookup(dataset=_gral_yaxistemp_log, searchval=ymin);
                            %let l_ylogmax = %_gral_get_vlookup(dataset=_gral_yaxistemp_log, searchval=ymax);
                            %let l_yrange  = %eval(%sysfunc(log10(&l_ylogmax)) - %sysfunc(log10(&l_ylogmin)));
                            %if &l_yrange = 0 %then %let l_yrange = 1;

                            %* Get number of titles and footnotes and convert to lloq marker positioning adjustment factor;
                            proc sql noprint;
                                select sum(coalesce(int(max(a.number)), 0), coalesce(int(max(b.number) * 0.75), 0)) into :l_fact
                                from (select number from dictionary.titles where type = 'T') a
                                   , (select number from dictionary.titles where type = 'F') b
                                ;
                            quit;
                            %let l_fact = &l_fact;

                            %local l_has_lloq_val;
                            %let l_has_lloq_val = ;
                            %symdel g_has_non_lloq_val / nowarn;

                            %if %upcase(%scan(&ytype,&l_ytype_num,%str( ))) = LIN %then %do;
                                %put INFO: &module - Values < LLOQ are not displayed on the linear-linear plot when YTYPE is LIN_LOG or LOG_LIN.;
                            %end;

                            data _gral_graphdata;
                                set _gral_graphdata;
                                length __scale $40 __scale1 __scale2 8;

                                %if %sysfunc(nvalid(&lloq_scale)) %then %do;
                                    __scale = cats(&lloq_scale);
                                %end;
                                %else %do;
                                    __scale = "&lloq_scale";
                                %end;

                                if findc(__scale, '#') = 0 then do;
                                    __scale1 = input(__scale, best.);
                                    __scale2 = __scale1;
                                end;
                                else do;
                                    __scale = prxchange('s/#$/#1/', 1, trim(__scale));
                                    __scale = prxchange('s/^#/1#/', 1, trim(__scale));
                                    __scale1 = input(scan(__scale, 1, '#', 's'), best.);
                                    __scale2 = input(scan(__scale, 2, '#', 's'), best.);
                                end;

                                %if %sysfunc(nvalid(&lloq_scale)) %then %do;
                                    retain _msg_flag ' ';
                                    if __scale1 = 0 or __scale2 = 0 then do;
                                        if missing(_msg_flag) then do;
                                            put 'WARN'"ING: &module - The scale definition in the defined scale variable (&lloq_scale) is not valid.";
                                            %if %length(&by) > 1 %then %do;
                                                put 'WARN'"ING: &module - Using SCALE=1 for the current BY group.";
                                            %end;
                                            %else %do;
                                                put 'WARN'"ING: &module - Using SCALE=1.";
                                            %end;
                                            _msg_flag = 'Y';
                                        end;
                                        __scale1 = 1;
                                        __scale2 = 1;
                                    end;
                                %end;

                                      %if &l_yrange in 1   %then %let l_fact2 = 9;
                                %else %if &l_yrange in 2   %then %let l_fact2 = 75;
                                %else %if &l_yrange in 3 4 %then %let l_fact2 = 6;
                                %else %if &l_yrange in 5 6 %then %let l_fact2 = 5;
                                %else %if &l_yrange in 7 8 %then %let l_fact2 = 4;
                                                           %else %let l_fact2 = 3;

                                if .Z < _y4lloqhandling < &lloq then do;
                                    scatter_lloq1 = (&lloq - ((&lloq / 10) * 0.2&l_fact * &l_yrange))              * __scale1;  %* for main marker ;
                                    scatter_lloq2 = (&lloq - ((&lloq / 10) * 0.2&l_fact * &l_yrange * 2.&l_fact2)) * __scale2;  %* for down arrow marker ;
                                    call symputx('l_has_lloq_val', 'Y', 'L');
                                end;
                                else do;
                                    _y4lloq = _y4lloqhandling;
                                    if missing(_noDataForClass) then do;
                                        call symputx('g_has_non_lloq_val', 'Y', 'G');
                                    end;
                                end;
                            run;

                            %local l_lloq_val;
                            %if %sysfunc(nvalid(&lloq)) %then %do;
                                %let l_lloq_val = %sysfunc(putn(%_gral_getdatavaluelist(_gral_graphdata, &lloq, distinct=Y, getmissings=N), &lloq_footfmt));
                            %end;
                            %else %do;
                                %let l_lloq_val = %sysfunc(putn(&lloq, &lloq_footfmt));
                            %end;

                            %if &l_has_lloq_val = Y %then %do;

                                %if %_gral_getvarlist(_gral_graphdata,series_only,mode=keep) = SERIES_ONLY %then %do;
                                    data _gral_graphdata;
                                        set _gral_graphdata;
                                        if .Z < series_only < &lloq then do;
                                            call missing(series_only);
                                            %if &layout = SPECIAL_PK_PROFILE %then %do;
                                                call missing(of __profile:);
                                            %end;
                                        end;
                                    run;
                                %end;

                                %if %upcase(%scan(&ytype,&l_ytype_num,%str( ))) = LOG %then %do;

                                    %* Ensure there is a suitable offset to display the LLOQ markers if LLOQ as at or very near to the bottom of the plot ;
                                    %if %sysevalf(&l_lloq_val <= (&l_ylogmin * 1.5), boolean) %then %do;
                                        %_gral_set_graphoption(plot=&l_idx, cell=1, object=graph, type=yaxis, attribute=yoffsetmin, value=0.05);
