                        %_gral_set_graphoption(plot=&l_idx, cell=2, object=block,      type=BlockPlot, attribute=block,                      value=_big_n_xvar);
                        %_gral_set_graphoption(plot=&l_idx, cell=2, object=block,      type=BlockPlot, attribute=xaxisblockdisplay,          value=(line));
                        %_gral_set_graphoption(plot=&l_idx, cell=2, object=block,      type=BlockPlot, attribute=xaxisblockdisplaysecondary, value=(line));
                        %_gral_set_graphoption(plot=&l_idx, cell=2, object=block,      type=BlockPlot, attribute=display,                    value=(label values));
                        %_gral_set_graphoption(plot=&l_idx, cell=2, object=block,      type=BlockPlot, attribute=repeatedvalues,             value=true);
                        %_gral_set_graphoption(plot=&l_idx, cell=2, object=block,      type=BlockPlot, attribute=labelposition,              value=left);
                        %_gral_set_graphoption(plot=&l_idx, cell=2, object=block,      type=BlockPlot, attribute=class,                      value=blockclass);
                        %_gral_set_graphoption(plot=&l_idx, cell=2, object=block,      type=BlockPlot, attribute=valuehalign,                value=start);

                        %if %lowcase(%scan(&legend,1)) = outside %then %do;
                            %_gral_set_graphoption(plot=&l_idx, cell=2, object=block, type=BlockPlot, attribute=blocklabelskip, value=YES);
                        %end;
                    %end;

                    %* end of cell 2;

        %*;
        %* Handle split characters ;
        %*;

                    %if &l_ticksplit_handle = ANNO %then %do;
                        %_gral_set_annoticks(
                            axis       = X
                          , axis_type  = &xtype
                          , by         = &_g
                          , cell       = 1
                          , graphidx   = &l_idx
                          , splitchars = &ticksplitchar
                          , legend_ny  = %if %sysfunc(findc(&legend,n,i)) ne 1 and %length(&class) > 0 %then Y;
                          , module     = &module
                        )
                    %end;

        %*;
        %* create OFFSET when required, depending on XSHIFT ;
        %*;

                    %* set OFFSET, when SHIFTING should be performed;
                    %LOCAL nclasses l_xoffset;
                    %if %qupcase(&xoffset) = %bquote(<DEFAULT>) %then %do;
                        %if %length(&class) > 0 and %sysfunc(findc(&xshift,y,i)) = 1 %then %do;
                            %if &xincrement = 0 %then %let l_xoffset = 0.47;
                            %else %do;
                                proc sql noprint;
                                    select count(distinct _inclassid) into :nclasses from _gral_graphdata_eqa;
                                quit;
                                %let l_xoffset = %sysfunc(min(%sysevalf(0.01 * &nclasses),0.05));
                            %end;
                            %_gral_set_graphoption(plot=&l_idx, cell=1, object=Graph, type=xaxis, attribute=xoffset, value=&l_xoffset);
                            %if %sysfunc(findc(&xvar_table_ny,y,i)) = 1 %then %do;
                                %_gral_set_graphoption(plot=&l_idx, cell=2, object=Graph, type=xaxis, attribute=xoffset, value=&l_xoffset);
                            %end;
                        %end;
                    %end;
                    %else %do;
                        %_gral_set_graphoption(plot=&l_idx, cell=1, object=Graph, type=xaxis, attribute=xoffset, value=&xoffset);
                        %if %sysfunc(findc(&xvar_table_ny,y,i)) = 1 %then %do;
                            %_gral_set_graphoption(plot=&l_idx, cell=2, object=Graph, type=xaxis, attribute=xoffset, value=&xoffset);
                        %end;
                    %end;

        %*;
        %* If line type is STEP then change series definitions to step definitions ;
        %*;

                    %if &linetype = STEP %then %do;
                        data _gral_graphopts;
                            set _gral_graphopts;
                            if type = 'seriesplot' then do;
                                type = 'stepplot';
                                object = tranwrd(object,'series','step');
                            END;
                            if type = 'legend' and attribute =: 'series' then attribute = tranwrd(attribute,'series','step');
                            if attribute = 'plots' then value = tranwrd(value,'seriesplot','stepplot');
                        run;
                    %end;

        %*;
        %* Create graphic or OUTDAT datasets;
        %*;

                    proc sort data=_gral_graphdata;
                        by _classid &xvar;
                        %if %length(&ellipse_fill &bands) > 0 and %length(&class) > 0 %then %do;
                            where classInData = 'Y';
                        %end;
                    run;

                    %if %length(&ellipse_type) > 0 and %length(&ellipse_fill) = 0 and %length(&class) > 0 %then %do;
                        data _gral_graphdata;
                            set _gral_graphdata;
                            if classInData ne 'Y' then &yvar = &L_BIGNUMBER + _n_;
                        run;
                    %end;

                    %local l_filen;
                    %* exchange $var$ texts in file names ;
                    %if %sysfunc(findc(&filename,$)) > 0 %then %do;
                        %_gral_replace_text(instr=&_filename, outvar=_filename, data=_gral_graphdata, replace_with_code=yes, module=&module);
                        %let _filename = %lowcase(%sysfunc(prxchange(s/\s/_/,-1,&_filename)));
                    %end;
                    %else %do;
                        proc sql noprint;
                            select distinct _byid into :l_filen
                            from _gral_graphdata
                            ;
                        quit;
                        %let _filename = &_filename%left(&l_filen);
                    %end;

                    %let _filename = %_gral_check_filename_len(idx=&l_filen, module=&module);

                    %if %length(&outdat) = 0 %then %do;
                        %_gral_create_graph(
                            filename     = &_filename
                          , template2log = &template2log
                          , combo_tag    = &combo_tag
                          , graphstyle   = &style
                          , graphidx     = &l_idx
                          , module       = &module
                        );
                    %end;
                    %else %do;
                        %_gral_create_outdat(
                            filename     = &_filename
                          , template2log = &template2log
                          , combo_tag    = &combo_tag
                          , graphstyle   = &style
                          , graphidx     = &l_idx
                          , outdat       = &outdat
                          , byid         = %left(%_gral_getDataValueList(_gral_graphdata, _byid, distinct=Y))
                          , addoptsonly  = %if &l_ytype_num = 2 %then Y;
                          , module       = &module
                        );
                    %end;

                    %if %symexist(l_has_lloq_footnotes) %then %do;
                        %if &l_has_lloq_footnotes = Y %then %do;
                            data _null_;
                                if _n_ = 1 then do;
                                    call execute('footnote;');
                                end;
                                set sashelp.vtitle (where=(type = 'F' and number > 2));
                                n + 1;
                                call execute(cats('footnote', n) || " '" || trim(text) || "';");
                            run;
                            %let l_has_lloq_footnotes = ;
                        %end;
                    %end;
                %end;
            %end;

            %else %do;  %* no data, so prepare for empty graphic ;
                %put INFO: &module - An empty graphic will be generated because there is insufficient data available.;

                %local l_filen;
                %* exchange $by$ texts in file names ;
                %let _filename = &filename;
                %if %sysfunc(findc(&filename,$)) > 0 %then %do;
                    %_gral_replace_text(instr=&_filename, outvar=_filename, data=_gral_graphdata, replace_with_code=yes, module=&module);
                    %let _filename = %lowcase(%sysfunc(prxchange(s/\s/_/,-1,&_filename)));
                %end;
                %else %do;
                    proc sql noprint;
                        select distinct _byid into :l_filen
                        from _gral_graphdata
                        ;
                    quit;
                    %let _filename = &_filename%left(&l_filen);
                %end;

