%check_param(name = event_var, type = VARIABLE_C, exist = MUST, data = &indat)
%check_param(name = event_select, type = TEXT)
%check_param(name = event_prio, type = VARIABLES, canBeEmpty=Y, exist = MUST, data = &indat)

%check_param(name = adt, type = VARIABLE_N, exist = MUST, data = &indat)
%check_param(name = adtf, type = VARIABLE_C , canBeEmpty=Y, exist = MUST, data = &indat)
%check_param(name = atm, type = VARIABLE_N , canBeEmpty=Y, exist = MUST, data = &indat)
%check_param(name = atmf, type = VARIABLE_C , canBeEmpty=Y, exist = MUST, data = &indat)

%check_param(name = avisitn, type =NUMBER)
%check_param(name = paramcd, type = TEXT, regExp = '^[A-Za-z][A-Za-z0-9]{0,7}$')
