%check_param(name = srcseq, type = VARIABLE_N, exist = MUST, data = &indat)
%IF (%BQUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %GOTO END_MACRO;

%* Check if srcdom is a quoted string or a character variable in subject dataset;
%IF %SYSFUNC(prxmatch("^\s*\'[a-zA-Z0-9_]{1,8}\'\s*$", &srcdom.)) or %SYSFUNC(prxmatch('^\s*\"[a-zA-Z0-9_]{1,8}\"\s*$', &srcdom.)) %THEN %DO;
%END;
%ELSE %DO;
    %check_param(name = srcdom, type = VARIABLE_C , exist = MUST, data = &indat)
%END;
%* Check if srcvar is a quoted string or a character variable in subject dataset;
%IF %SYSFUNC(prxmatch("^\s*\'[a-zA-Z0-9_]{1,8}\'\s*$", &srcvar.)) or %SYSFUNC(prxmatch('^\s*\"[a-zA-Z0-9_]{1,8}\"\s*$', &srcvar.)) %THEN %DO;
%END;
%ELSE %DO;
    %check_param(name = srcvar, type = VARIABLE_C , exist = MUST, data = &indat)
%END;

%check_param(name = srcseq, type = VARIABLE_N , exist = MUST, data = &indat)


%IF (%BQUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %GOTO END_MACRO;

%local _time_vars;
%LET _time_vars = N;

%local _evt_vars;
%let _evt_vars=;
%IF %QTRIM(&adtf.) NE %STR() %THEN %let _evt_vars=&_evt_vars. __adtf;
%IF %QTRIM(&atm.)  NE %STR() %THEN %let _evt_vars=&_evt_vars. __atm;
%IF %QTRIM(&atmf.) NE %STR() %THEN %let _evt_vars=&_evt_vars. __atmf;

%local _start_vars;
%let _start_vars=;
%IF %QTRIM(&startdtf.) NE %STR() %THEN %let _start_vars=&_start_vars. __startdtf;
%IF %QTRIM(&starttm.)  NE %STR() %THEN %let _start_vars=&_start_vars. __starttm;
%IF %QTRIM(&starttmf.) NE %STR() %THEN %let _start_vars=&_start_vars. __starttmf;

 %IF %BQUOTE(&atm.) NE %STR() and %BQUOTE(&starttm.) NE %STR() %THEN %DO;
     %LET _time_vars = Y;
 %END;
 %ELSE %IF %BQUOTE(&atm.) NE %STR() or %BQUOTE(&starttm.) NE %STR() %THEN %DO;
     %log(NOTE, %str(Time is not used for event selection, for use of time event time and start time need to be specified));
 %END;

%IF %BQUOTE(&event_prio.) EQ %STR() and %BQUOTE(&atm.) NE %STR() %THEN %DO;
      %LET event_prio = &atm.;
%END;

%*< Check if either of OUTzz / OUTzz seq is defined in metadata;
%LOCAL _outzz_vars;
%let _outzz_vars = 0;

data _NULL_;
    set &metaLib..&adsDomain;
    if varname in ('OUTzz' 'OUTzzSEQ') then do;
        call symput("_outzz_vars","1");
    end;
RUN;

%*< Check if subjdat unique ******************************* ;
%local _subjdat_unique;
%let _subjdat_unique=1;

%UNQUOTE(** <<< END IGNORE - &sysmacroname;)

proc sort data=&subjdat. out=_cretteobs_000_unique(keep=&subjvar.);
    by &subjvar.;
RUN;
data _null_;
    set _cretteobs_000_unique;
    by &subjvar.;
    if not(first.&subjvar. and last.&subjvar.) then do;
        call symput("_subjdat_unique","0");
    END;
RUN;

%IF &_subjdat_unique. NE 1 %THEN %DO;
    %log(E, SUBJDAT dataset contains repeated SUBJVAR values!)
    %GOTO END_MACRO;
%END;

/*< Subject data, filter for subjects with valid at-risk period */

DATA _cretteobs_000_subjdat;
    SET &subjdat.;
    LENGTH temp_censordetail $200;
    __startdt    = &startdt.;
    %IF %QTRIM(&starttm.) NE %STR() %THEN %DO;
        __starttm    = &starttm.;
    %END;
    %ELSE %DO;
        CALL missing(__starttm);
    %END;

    %IF %QTRIM(&startdtf.) NE %STR() %THEN %STR(__startdtf = &startdtf.;);
    %IF %QTRIM(&starttmf.) NE %STR() %THEN %STR(__starttmf = &starttmf.;);

    if not missing(__startdt) then temp_enddate = &enddt.; /* enddt can be an expression using start date, and it makes no sense when there is no start date */
    temp_enddesc      = &end_desc.;
    temp_endcnsr      = &end_cnsr.;
    temp_censordate   = &censor_date.;
    temp_censordetail = &censor_desc.;
    temp_censorcnsr   = &censor_cnsr.;
    KEEP &keyvars. __startdt &_start_vars. temp_enddate temp_enddesc temp_endcnsr temp_censordate temp_censordetail temp_censorcnsr;
    FORMAT __startdt temp_enddate temp_censordate date9.;
    /* Only subjects with valid at risk period */
    IF nmiss(__startdt, temp_enddate) = 0 AND __startdt <= temp_enddate;

    if not missing(temp_censordate) and temp_censordate < __startdt then do;
        put "WA" "RNING: censored date " temp_censordate " before start date " __startdt " Subject " &subjvar. ;
    END;
RUN;

/* check if there were E or W during the data step using event_select */
%IF &syserr > 3 %THEN %DO;
    %log(E, Please check if in parameters CENSOR_DATE and ENDDT are a valid expressions.);
    %GOTO END_MACRO;
%END;


PROC SORT DATA=_cretteobs_000_subjdat; BY &subjvar.; RUN;

/*< Select events according to EVENT_SELECT */

PROC SORT DATA = &indat.
          OUT  = _cretteobs_000_evsort;
  BY &subjvar. &adt. &event_prio &event_var.;
  WHERE &event_select.;
RUN;

/* check if there were E or W during the data step using event_select */
%IF &syserr > 3 %THEN %DO;
    %log(E, Please check if in EVENT_SELECT is a valid statement.);
    %GOTO END_MACRO;
%END;

/*< Select events within at-risk period */

DATA _cretteobs_001_evselect (KEEP= &subjvar. __adt __evntdesc __cnsr  &_evt_vars. __srcdom __srcvar __srcseq __sel);
    length __evntdesc $200;
    MERGE _cretteobs_000_evsort (IN = A)
          _cretteobs_000_subjdat (IN = B KEEP = &subjvar. __startdt &_start_vars. temp_enddate);
    BY &subjvar.;
    IF A AND B THEN DO;

        __adt = &adt.;
        __evntdesc = &event_var.;
        __cnsr = 0;

        %IF %QTRIM(&adtf.) NE %STR() %THEN %STR(__adtf = &adtf.;);
        %IF %QTRIM(&atm.)  NE %STR() %THEN %STR(__atm  = &atm.;);
        %IF %QTRIM(&atmf.) NE %STR() %THEN %STR(__atmf = &atmf.;);

        __srcdom = put(&srcdom., $8.);
        __srcvar = put(&srcvar., $8.);
        __srcseq = &srcseq.;

        IF nmiss(__startdt, temp_enddate, &adt.) EQ 0 THEN DO;
                 IF __startdt LT &adt. LE temp_enddate THEN __sel = 1;
            ELSE IF __startdt EQ &adt. THEN DO;
                **when time variable is available;
                %IF &_time_vars eq Y %THEN %DO;
                    IF missing(&atm.)               THEN  __sel = 1;
                    ELSE IF __starttm <= &atm. THEN  __sel = 1;
                %END;
                %ELSE %DO;
                     __sel = 1;
                %END;
            END;
        END;
    END;
RUN;

/*< check if any events selected - most steps only if there are events to avoid suspicious log messages */
%UNQUOTE(** >>> START IGNORE - &sysmacroname;)
PROC SQL NOPRINT;
    SELECT count(&subjvar.) INTO :_num_events_ FROM _cretteobs_001_evselect(where=( __sel = 1));
QUIT;

%UNQUOTE(** <<< END IGNORE - &sysmacroname;)

%IF &_num_events_. > 0 %THEN %DO;

/*< take first  event ******************* */

    DATA _cretteobs_002_firstevent(drop= __sel);
        SET _cretteobs_001_evselect(where=( __sel = 1));
        BY &subjvar.;
        IF first.&subjvar.;
    RUN;

    /*< Store all events in at-risk period in OUTxx / OUTxxSEQ  - only if required by metadata*/
    %IF &_outzz_vars. EQ 1 %THEN %DO;
        DATA _cretteobs_003_eventids;
            SET _cretteobs_001_evselect(where=( __sel = 1));
            ATTRIB var_outid_name var_outid_seq FORMAT = $200.;
            RETAIN temp_outid;
            BY &subjvar.;
            IF FIRST.&subjvar. THEN DO;
                temp_outid = 1;
            END;
            ELSE DO;
                temp_outid = temp_outid + 1;
            END;
            /* due to the naming conventions only 99 events can be stored in OUTzz and OUTzzSEQ. */
            IF temp_outid <= 99 then do;
                var_outid_name = compress('__out'!!put(temp_outid, z2.));
                var_outid_seq  = compress('__out'!!put(temp_outid, z2.)!!'seq');
