            END;
            ELSE IF LAST.&subjvar. THEN DO;
                PUT "WAR" "NING: &macro. More than 99 events for " &subjvar.= " Number of events: " temp_outid ;
                PUT "WAR" "NING: &macro. Not all events are shown in the OUTzz and OUTzzSEQ variables" ;
            END;
        RUN;


        * transpose data for collecting all events and saved automatically in __out variable as defined in ID;
        PROC TRANSPOSE DATA = _cretteobs_003_eventids
                       OUT  = _cretteobs_004_eventcolname (DROP = _name_ );
            BY &subjvar.;
            ID var_outid_name;
            VAR __evntdesc;
        RUN;

        PROC TRANSPOSE DATA = _cretteobs_003_eventids
                       OUT  = _cretteobs_004_eventcolseq (DROP = _name_ );
            BY &subjvar.;
            ID var_outid_seq;
            VAR __srcseq;
        RUN;
    %END;

    * join all;
    DATA _cretteobs_020_joindata;
      MERGE _cretteobs_000_subjdat (IN = A)
