        %IF %QTRIM(&adtf.) NE %STR() %THEN %STR(__adtf = " ";);
        %IF %QTRIM(&atm.)  NE %STR() %THEN %STR(__atm  = .;);
        %IF %QTRIM(&atmf.) NE %STR() %THEN %STR(__atmf = " ";);
