/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Add time window variables for time-to-event analysis: STARTDT, ENDDT, CNSRDT
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat  : Input dataset
 *                    outdat : Output dataset
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed: &mosto_param_class., &time_at_risk., &trt_ezn_12., &trt_pla_12., &trt_ezn_26., &trt_pla_26.,&trt_ezn_52., &trt_pla_52.
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : erjli (Yosia Hadisusanto) / date: 04JAN2024
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 15FEB2024
 * Reason           : Add time window for 26 week
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 06MAR2024
 * Reason           : Add condition :For OASIS 3 week 1-12 is only until DAY 84;
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_add_time_window(indat = adsl_ext, outdat = adsl_ext);
 ******************************************************************************/

%MACRO m_add_time_window(indat=, outdat=);

    DATA &outdat.;
        SET &indat. end=eof;
        FORMAT startdt enddt cnsrdt date9.;
        RETAIN miss_trtedt 0;

        IF missing(trtedt) THEN DO;
            trtedt = RFXENDT;
            miss_trtedt = 1;
        END;

        ** Time window week 12;
        IF &mosto_param_class. IN (&trt_ezn_12. &trt_pla_12.) THEN DO;
            startdt = trtsdt;

            IF studyid ne '21810' THEN DO;
                IF not missing(ph2sdt) THEN enddt = ph2sdt-1;
                ELSE                        enddt = min(trtedt+&time_at_risk.,ph1edt+&time_at_risk.,dthdt);
            END;
            ELSE DO;
                ** For OASIS 3 week 1-12 is only until DAY 84;
                enddt = min(trtedt + 14, ph1sdt + 83, dthdt);
            END;
            cnsrdt = enddt;
        END;

        ** Time window week 52;
        IF &mosto_param_class. IN (&trt_ezn_52. &trt_pla_52.) THEN DO;

            ** Start date: first intake of the respective study drug;
            IF &mosto_param_class. = &trt_ezn_52. AND trt02an = 53 THEN startdt = ph2sdt; ** For PLA-EZN switcher;
            ELSE                                                        startdt = trtsdt; ** All others;

            ** For PLA-EZN switcher;
            IF (&mosto_param_class. = &trt_pla_52. AND trt02an = 53)   THEN DO;
                IF not missing(ph2sdt) THEN enddt = ph2sdt-1;
                ELSE                        enddt = min(trtedt+&time_at_risk.,ph1edt+&time_at_risk.,dthdt);
                cnsrdt = enddt;
            END;

            ** All others;
            ELSE DO;
                enddt  = min(trtedt + &time_at_risk., dthdt);
                cnsrdt = enddt;
            END;

        END;

        ** Time window week 26;
        IF &mosto_param_class. IN (&trt_ezn_26. &trt_pla_26.) THEN DO;

            ** Start date: first intake of the respective study drug;
            IF &mosto_param_class. = &trt_ezn_26. AND trt02an = 53 THEN startdt = ph2sdt; ** For PLA-EZN switcher;
            ELSE                                                        startdt = trtsdt; ** All others;

            ** For PLA-EZN switcher;
            IF (&mosto_param_class. = &trt_pla_26. AND trt02an = 53)   THEN DO;
                IF not missing(ph2sdt) THEN enddt = ph2sdt-1;
                ELSE                        enddt = min(trtedt+&time_at_risk.,ph1edt+&time_at_risk.,dthdt);
                cnsrdt = enddt;
            END;

            ** All others;
            ELSE DO;
                IF studyid ne '21810' THEN enddt  = min(trtedt + &time_at_risk., dthdt);
                ELSE                       enddt  = min(trtedt + &time_at_risk., dthdt, startdt + 182 - 1);
                cnsrdt = enddt;
            END;

        END;


        IF eof THEN DO;
            IF miss_trtedt = 1 THEN PUT "WARN" "ING: There are missing TRTEDT. Missing TRTEDT is being replaced with RFXENDT";
        END;
    RUN;

%MEND;

/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Add time window variables for time-to-event analysis: STARTDT,
 *                    ENDDT and CNSRDT for post-basline data
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat  : Input dataset
 *                    outdat : Output dataset
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed: &mosto_param_class., &trt_ezn_12., &trt_pla_12., &trt_ezn_26.,
 *     &trt_pla_26.,&trt_ezn_52., &trt_pla_52.
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : eqczz (Petri Pulkkinen) / date: 21MAY2024
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_add_time_window_lab(indat = adsl_ext, outdat = adsl_ext);
 ******************************************************************************/

%MACRO m_add_time_window_lab(indat=, outdat=);

    DATA &outdat.;
        SET &indat. end=eof;
        FORMAT startdt enddt cnsrdt date9.;
        RETAIN miss_trtedt 0;

        IF missing(trtedt) THEN DO;
            trtedt = RFXENDT;
            miss_trtedt = 1;
        END;

        ** Time window week 12;
        IF &mosto_param_class. IN (&trt_ezn_12. &trt_pla_12.) THEN DO;
            startdt = trtsdt;
            IF not missing(ph2sdt) THEN enddt = ph2sdt; /* excluding measurements after the start day of open-label phase */
            ELSE                        enddt = max(trtedt,ph1edt,ph2edt,rfpendt);
            cnsrdt = enddt;
        END;

        ** Time window week 52;
        IF &mosto_param_class. IN (&trt_ezn_52. &trt_pla_52.) THEN DO;

            ** Start date: first intake of the respective study drug;
            IF &mosto_param_class. = &trt_ezn_52. AND trt02an = 53 THEN startdt = ph2sdt+1; ** For PLA-EZN switcher measurements after the
                                                                                               start day of open-label phase;
            ELSE                                                        startdt = trtsdt; ** All others;

            ** For PLA-EZN switcher;
            IF (&mosto_param_class. = &trt_pla_52. AND trt02an = 53)   THEN DO;
                IF not missing(ph2sdt) THEN enddt = ph2sdt; ** Measurements at or before the start day of open-label phase;
                ELSE                        enddt = max(trtedt,ph1edt,ph2edt,rfpendt);
                cnsrdt = enddt;
            END;

            ** All others;
            ELSE DO;
                enddt  = max(trtedt,ph1edt,ph2edt,rfpendt);
                cnsrdt = enddt;
            END;

        END;

        ** Time window week 26;
        IF &mosto_param_class. IN (&trt_ezn_26. &trt_pla_26.) THEN DO;

            ** Start date: first intake of the respective study drug;
            IF &mosto_param_class. = &trt_ezn_26. AND trt02an = 53 THEN startdt = ph2sdt+1; ** For PLA-EZN switcher;
            ELSE                                                        startdt = trtsdt; ** All others;

            ** For PLA-EZN switcher;
            IF (&mosto_param_class. = &trt_pla_26. AND trt02an = 53)   THEN DO;
                IF not missing(ph2sdt) THEN enddt = ph2sdt;
                ELSE                        enddt = max(trtedt,ph1edt,ph2edt,rfpendt);
                cnsrdt = enddt;
            END;

            ** All others;
            ELSE DO;
                IF studyid ne '21810' THEN enddt  =  max(trtedt,ph1edt,ph2edt,rfpendt);
                ELSE DO;
                    maxdt_tmp=max(trtedt,ph1edt,ph2edt,rfpendt);
                    enddt  = min(maxdt_tmp, startdt + 182 - 1);
                END;
                cnsrdt = enddt;
            END;

        END;


        IF eof THEN DO;
            IF miss_trtedt = 1 THEN PUT "WARN" "ING: There are missing TRTEDT. Missing TRTEDT is being replaced with RFXENDT";
        END;
    RUN;

%MEND;

%MACRO m_anal_datastep(datain, param,timep,dataout,indat_adsl=adsl, where=1)
/ DES = 'MACRO for data step for OASIS analyses';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : MACRO to create data step for OASIS analyses
 * Programming Spec :
 * Validation Level : 1 - Validation by review
 * Parameters       :
 *                      datain : Dataset to be read in
 *                      param  : Variable needed
 *                      timep  : Timepoint, need to given as a list
 *                      dataout : Output dataset
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : erjli (Yosia Hadisusanto) / date: 28DEC2023
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_anal_datastep.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 19JAN2024
 * Reason           : Add reference program
 *                    Add new parameters
 *                    Use extend_data
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_anal_datastep();
 ******************************************************************************/



    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

   * %spro_check_param(name=param1, type=TEXT)
   * %spro_check_param(name=param2, type=TEXT)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
            INFO
          , Version &mversion started
          , addDateTime = Y
          , messageHint = BEGIN)

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

/********************************************************************/
/* Start */
/********************************************************************/

/*****************************
*Read data in
****************************/

    %load_ads_dat(&datain._view  , adsDomain = &datain, adslWhere = &where.);
    %extend_data(indat = &datain._view , outdat = &datain.);
        DATA hfdd;
            SET &datain.;
            WHERE paramcd=&param  AND avisitn IN (&timep ) ;
            KEEP usubjid paramcd  avisitn aval chg trt01pn region1n anl01fl;/*anl01fl=permanent trt discontinuation*/
        RUN;

        /*Take baseline visit from avisit=5. If only baseline available, it has not been populated to other visits*/
        data base;
            SET  &datain.;
            WHERE paramcd=&param AND avisitn=5;
            KEEP usubjid base;
        RUN;

        /*Keep all subjects in FAS*/
        DATA _adsl;
            SET &indat_adsl.;
            IF &where.;
            WHERE fasfl='Y';
            KEEP usubjid fasfl;
        RUN;

        DATA hfdd;
            MERGE _adsl (in=a) hfdd base;
            BY usubjid;
            if a;
        RUN;

        *Add full visit structure for those, who has all visits missing;

        DATA missvis;
            SET hfdd;
            WHERE avisitn=.;
        RUN;


        *Create full visit structure for all subjects with missing avisit;
        PROC SORT DATA=hfdd NODUPKEY OUT=weeks (KEEP=avisitn);BY avisitn;RUN;
        PROC SORT DATA=missvis NODUPKEY OUT=subjects (KEEP=usubjid paramcd base trt01pn region1n);BY usubjid;RUN;

        PROC SQL;
           CREATE TABLE str AS
           SELECT subjects.*,
                  weeks.*
           FROM subjects, weeks
           where avisitn NE .;
        QUIT;

        PROC SORT DATA=str(KEEP=usubjid avisitn);BY usubjid avisitn;RUN;
        PROC SORT DATA=hfdd;BY usubjid avisitn;RUN;
        DATA hfdd2;
            MERGE hfdd str;
            BY usubjid avisitn;
            IF avisitn=. THEN DELETE;
        RUN;


        *Add anl01fl for all subsequent visit per subject;
       /* DATA hfdd3;
            length _anl01fl $5;
            SET hfdd2;
            BY usubjid avisitn anl01fl;

            retain _anl01fl;
            if first.usubjid then _anl01fl='';
            if not missing(anl01fl) then _anl01fl='Yes';

            anl01fl=_anl01fl;
            drop _anl01fl;
        run;*/


        *Calculate number of missing observations and non-missing observations with ICE;
        PROC SORT DATA=hfdd2 out=hfdd_sort;BY avisitn anl01fl;RUN;
        PROC MEANS DATA=hfdd_sort noprint;
            BY avisitn anl01fl;
            VAR aval;
            OUTPUT OUT=missobs n=n nmiss=nmiss;
        RUN;

        /*Baseline can be imputed, if there are at least 2 post BL available. If not, add flag and ignore from analysis*/
        PROC SORT DATA=hfdd2 out=hfdd_sorts;BY usubjid;RUN;
        PROC MEANS DATA=hfdd_sorts(where=(base=.)) noprint;
            BY usubjid;
            VAR aval;
            OUTPUT OUT=missbl n=n nmiss=nmiss;
        RUN;

        DATA missbl;
            SET missbl;
            IF n < 2 THEN missblfl='Y';
            KEEP usubjid missblfl;
        RUN;


        /*Transpose visit to wide format*/
        PROC SORT DATA=hfdd2;BY usubjid paramcd base region1n trt01pn ;RUN;
        PROC TRANSPOSE DATA=hfdd2 OUT=hfdd_t;
            VAR  aval ;
            ID avisitn;
            BY usubjid paramcd base region1n trt01pn ;
        RUN;

        /*Transpose discont indicator flags to wide format*/
        PROC TRANSPOSE DATA=hfdd2 OUT=flag_t;
            VAR anl01fl;
            ID avisitn;
            BY usubjid  ;
        RUN;
*?Updated to take care of missing Week*;
data flag_t ;
    set flag_t   ;
    pos1 = %varnum(flag_t, week_1 ) ;
    if pos1 eq  0 Then week_1 = ""  ;

    pos2 = %varnum(flag_t, week_4 ) ;
    if pos2 eq  0 Then week_4 = ""  ;

    pos3 = %varnum(flag_t, week_8 ) ;
    if pos3 eq  0 Then week_8 = ""  ;

    pos4 = %varnum(flag_t, week_12 ) ;
    if pos4 eq  0 Then week_12 = ""  ;
    DROP   pos:;;
RUN;

data hfdd_t ;
    set hfdd_t   ;
    pos1 = %varnum(hfdd_t, week_1 ) ;
    if pos1 eq  0 Then week_1 = .  ;

    pos2 = %varnum(hfdd_t, week_4 ) ;
    if pos2 eq  0 Then week_4 = .  ;

    pos3 = %varnum(hfdd_t, week_8 ) ;
    if pos3 eq  0 Then week_8 = .  ;

    pos4 = %varnum(hfdd_t, week_12 ) ;
    if pos4 eq  0 Then week_12 = .  ;
RUN;

*?End of the Update*;
        options dkricond=nowarn;
        DATA flag_t2;
            SET flag_t;

            RENAME week_1=flag_disc_w1
                   week_4=flag_disc_w4
                   week_8=flag_disc_w8
                   week_12=flag_disc_w12;
            DROP _NAME_ _LABEL_;
        RUN;

        options dkricond=nowarn;
        *Combine hfdd-data and discont indicator flags;
        DATA anal_;
            MERGE hfdd_t flag_t2 missbl;
            BY usubjid;
            DROP _NAME_ _LABEL_;


         /*Create numerical flagging variable*/
            IF flag_disc_w1="Y" THEN flag_disc_w1n=1; ELSE flag_disc_w1n=0;
            IF flag_disc_w4="Y" THEN flag_disc_w4n=1; ELSE flag_disc_w4n=0;
            IF flag_disc_w8="Y" THEN flag_disc_w8n=1; ELSE flag_disc_w8n=0;
            If flag_disc_w12="Y" THEN flag_disc_w12n=1; ELSE flag_disc_w12n=0;

          /*Create binary variable for tretament and region*/
            if (put(trt01pn, z_trt.)) = "Elinzanetant 120mg" then trt01pn_bin = 1; else trt01pn_bin = 0;
            if (put(region1n, x_region.)) = "North America" then region1n_bin = 1; else region1n_bin = 0;
        RUN;


        DATA &dataout /*anal*/ missbldata;
            SET anal_;
            IF missblfl='Y' THEN OUTPUT missbldata;/*Maybe these observations could be deleted, but if one would like to check*/
            ELSE OUTPUT &dataout;
        RUN;

    /********************************************************************/
    /* End */
    /********************************************************************/

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %end_macro:;

    OPTIONS &l_opts.;
    %log(
            INFO
          , Version &mversion terminated.
          , addDateTime = Y
          , messageHint = END)
    %log(
            INFO
          , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
          , addDateTime = Y
          , messageHint = END)

%MEND m_anal_datastep;

%MACRO m_anal_datastep_menqol(datain, param,timep,dataout,indat_adsl=adsl, where=1)
/ DES = 'MACRO for data step for OASIS analyses';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : MACRO to create data step for OASIS analyses
 * Programming Spec :
 * Validation Level : 1 - Validation by review
 * Parameters       :
 *                      datain : Dataset to be read in
 *                      param  : Variable needed
 *                      timep  : Timepoint, need to given as a list
 *                      dataout : Output dataset
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        :  erjli (Yosia Hadisusanto) / date: 10NOV2023
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_anal_datastep_menqol.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : ereiu (Katharina Meier) / date: 17NOV2023
 * Reason           : # Add macro variables indat_adsl and where
 *                    # Use define and use dataset _adsl (using &indat_adsl) instead of adsl (using ads.adsl)
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 19JAN2024
 * Reason           : Add extend_data
 ******************************************************************************/

