%LOCAL macro mversion _starttime macro_parameter_error;
%LET macro    = &sysmacroname.;
%LET mversion = 1.0;

   * %spro_check_param(name=param1, type=TEXT)
   * %spro_check_param(name=param2, type=TEXT)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
            INFO
          , Version &mversion started
          , addDateTime = Y
          , messageHint = BEGIN)

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

/********************************************************************/
/* Start */
/********************************************************************/

/*****************************
*Read data in
****************************/

    %load_ads_dat(&datain._view  , adsDomain = &datain, adslWhere = &where.);
    %extend_data(indat = &datain._view , outdat = &datain.);
        DATA hfdd;
            SET &datain.;
            WHERE paramcd=&param  AND avisitn IN (&timep ) ;
            KEEP usubjid paramcd  avisitn aval chg trt01pn region1n anl01fl;/*anl01fl=permanent trt discontinuation*/
        RUN;

        /*Take baseline visit from avisit=5. If only baseline available, it has not been populated to other visits*/
        data base;
            SET  &datain.;
            WHERE paramcd=&param AND avisitn=5;
            KEEP usubjid base;
        RUN;

        /*Keep all subjects in FAS*/
        DATA _adsl;
            SET &indat_adsl.;
            IF &where.;
            WHERE fasfl='Y';
            KEEP usubjid fasfl trt01pn region1n;
        RUN;

        DATA hfdd;
            MERGE _adsl (in=a) hfdd base;
            BY usubjid;
            if a;
        RUN;

        /*Create full visit structure for all subjects*/
        PROC SORT DATA=hfdd NODUPKEY OUT=weeks (KEEP=avisitn);BY avisitn;RUN;
        PROC SORT DATA=hfdd NODUPKEY OUT=subjects (KEEP=usubjid paramcd base trt01pn region1n);BY usubjid;RUN;

        PROC SQL;
           CREATE TABLE str AS
           SELECT subjects.*,
                  weeks.*
           FROM subjects, weeks
           where avisitn NE .;
        QUIT;

        PROC SORT DATA=str  ;BY usubjid avisitn;RUN;
        PROC SORT DATA=hfdd ;BY usubjid avisitn;RUN;

        DATA hfdd2;
            MERGE hfdd str;
            BY usubjid avisitn;
            IF avisitn=. THEN DELETE;
        RUN;

       PROC SORT DATA=hfdd2 ;BY usubjid avisitn anl01fl ; RUN;
        *Add anl01fl for all subsequent visit per subject;
        DATA hfdd3;
            length _anl01fl $5;
            SET hfdd2;
            BY usubjid avisitn anl01fl;

            retain _anl01fl;
            if first.usubjid then _anl01fl='';
            if not missing(anl01fl) then _anl01fl='Yes';

            anl01fl=_anl01fl;
            drop _anl01fl;
        run;


        *Calculate number of missing observations and non-missing observations with ICE;
        PROC SORT DATA=hfdd3 out=hfdd3_sort;BY avisitn anl01fl;RUN;
        PROC MEANS DATA=hfdd3_sort noprint;
            BY avisitn anl01fl;
            VAR aval;
            OUTPUT OUT=missobs n=n nmiss=nmiss;
        RUN;

        /*Baseline can be imputed, if there are at least 2 post BL available. If not, add flag and ignore from analysis*/
        PROC SORT DATA=hfdd3 out=hfdd3_sorts;BY usubjid;RUN;
        PROC MEANS DATA=hfdd3_sorts(where=(base=.)) noprint;
            BY usubjid;
            VAR aval;
            OUTPUT OUT=missbl n=n nmiss=nmiss;
        RUN;

        DATA missbl;
            SET missbl;
            IF n < 2 THEN missblfl='Y';
            KEEP usubjid missblfl;
        RUN;


        /*Transpose visit to wide format*/
        PROC SORT DATA=hfdd3;BY usubjid paramcd base region1n trt01pn ;RUN;
        PROC TRANSPOSE DATA=hfdd3 OUT=hfdd_t;
            VAR  aval ;
            ID avisitn;
            BY usubjid paramcd base region1n trt01pn ;
        RUN;

        /*Transpose discont indicator flags to wide format*/
        PROC TRANSPOSE DATA=hfdd3 OUT=flag_t;
            VAR anl01fl;
            ID avisitn;
            BY usubjid  ;
        RUN;

        DATA flag_t2;
            SET flag_t;
            RENAME week_4=flag_disc_w4
                   week_8=flag_disc_w8
                   week_12=flag_disc_w12;
            DROP _NAME_;
        RUN;

        *Combine hfdd-data and discont indicator flags;
        DATA anal_;
            MERGE hfdd_t flag_t2 missbl;
            BY usubjid;
            DROP _NAME_ _LABEL_;

         /*Create numerical flagging variable*/
            IF flag_disc_w4="Y" THEN flag_disc_w4n=1; ELSE flag_disc_w4n=0;
            IF flag_disc_w8="Y" THEN flag_disc_w8n=1; ELSE flag_disc_w8n=0;
            If flag_disc_w12="Y" THEN flag_disc_w12n=1; ELSE flag_disc_w12n=0;

        /*Create binary variable for tretament and region*/
        if (put(trt01pn, z_trt.)) = "Elinzanetant 120mg" then trt01pn_bin = 1; else trt01pn_bin = 0;
        if (put(region1n, x_region.)) = "North America" then region1n_bin = 1; else region1n_bin = 0;
   RUN;

        DATA &dataout /*anal*/ missbldata;
            SET anal_;
            IF missblfl='Y' THEN OUTPUT missbldata;/*Maybe these observations could be deleted, but if one would like to check*/
            ELSE OUTPUT &dataout;
        RUN;

    /********************************************************************/
    /* End */
    /********************************************************************/

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %end_macro:;

    OPTIONS &l_opts.;
    %log(
            INFO
          , Version &mversion terminated.
          , addDateTime = Y
          , messageHint = END)
    %log(
            INFO
          , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
          , addDateTime = Y
          , messageHint = END)

%MEND m_anal_datastep_menqol;

%MACRO M_ANLFN(
       INDAT               =
     , OUTDAT              =
     , DUPOUT              =_DUPOUT
     , VAL                 =AVALC
     , ANLFN               =ANL01FN
     , SUBJIDN             =USUBJID
     , BY                  =PARAMCD
     , BASELINE_VISIT      =&RAND_V.
     , LAST_VISIT          =&LAST_V.
     , VISIT               =
     , TIME                =VISITNUM
     , COMPLFN             =&COMP_COND.
     , OADDOMAIN           =
     , INCLFN              =1
     , UNSCHEDULE_VISITNUM =900000
     , NEWSEQ              =_SUBSEQ
     , OADSEQ              =
     , OUTPOSTBASEFN       =_POSTBASEFN
     , TRTSDT              =TRTSDT
     , TRTSTM              =TRTSTM
)/DES='DERIVE ANALYSIS FLAG';

/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : add Mean daily HF frequency of mod to sev paramcd in ADQSHFSS
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gdcpl (Derek Li) / date: 03APR2014
 * Reference prog   :
 ******************************************************************************/
/* Changed by       : evmqe (Endri Elnadav) / date: 08APR2024
 * Reason           : Update the header
 ******************************************************************************/


***************************************************************************;
*** ANALYSIS FLAG ;
***************************************************************************;

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name = INDAT, type = DATA)
    %spro_check_param(name = OUTDAT, type = DATA)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* Put your macro code here!;
    ***************************************************************************;
    *** PREPARATION ;
    ***************************************************************************;
    %MACRO m_varExist(
           indat =
         , vars  =
    );
        %LOCAL dsid rc return i _cuvar;
        %LET return= ;
        %LET i=1;
        %LET dsid=%sysfunc(open(&indat.));
        %DO %WHILE(%scan(&vars.,&i,%str( )) NE );
            %LET _cuvar=%scan(&vars.,&i,%str( ));
            %LET rc=%sysfunc(varnum(&dsid,&_cuvar));
            %IF &rc.>0 %THEN %LET return=&return &_cuvar.;
            %LET i=%eval(&i+1);
        %END;
        %LET rc=%sysfunc(close(&dsid));
        &return.
    %MEND m_varExist;

    %IF %LENGTH(&OUTDAT)=0 %THEN %LET OUTDAT=&INDAT;
    %LOCAL ANLFL;
    %LET ANLFL=%SUBSTR(&ANLFN,1,%LENGTH(&ANLFN)-1)L;
    DATA _OUTDAT;
        SET &INDAT.;
        _INCLFN=(&INCLFN.);
        %IF %length(&oadseq)>0 %THEN %DO;
            _OADSEQ=&OADSEQ;
        %END;
        %ELSE %IF %length(%m_varExist(indat = &indat, vars = &oaddomain.seq))>0 %THEN %DO;
            _OADSEQ=&oaddomain.seq;
        %END;
        %ELSE %DO;
            _OADSEQ=1;
        %END;
        IF _INCLFN THEN DO;
            &ANLFN.=1;
            IF missing(&VAL.) THEN &ANLFN=.;*MISSING VALUE;
            *IF VISITNUM NE INT(VISITNUM) THEN &ANLFN.=.;*UNSCHEDULED VALUE;
            *IF &TIME NE INT(&TIME.) THEN &ANLFN=.;*UNSCHEDULED VALUE;
            %IF %LENGTH(&UNSCHEDULE_VISITNUM)>0 %THEN %DO;
                IF visitnum=&UNSCHEDULE_VISITNUM THEN &ANLFN.=.;
            %END;
            %IF %LENGTH(&LAST_VISIT)>0 %THEN %DO;
                IF VISITNUM GT &LAST_VISIT. THEN &ANLFN.=.;* POST LAST VISIT;
            %END;
            %IF %LENGTH(&VISIT.)>0 %THEN %DO;
                IF ~(VISITNUM IN (&VISIT.)) THEN &ANLFN.=.;*NON-PROTOCOL DEFINED VISIT;
            %END;
            IF missing(&TIME.) THEN &ANLFN.=.;
        END;
        IF &ANLFN.=1 THEN &ANLFL.='Y';
    RUN;

    ***************************************************************************;
    *** LOV ;
    ***************************************************************************;
    /*      DATA _OUTDAT;*/
    /*            SET _OUTDAT;*/
    /*        IF &ANLFN. AND (VISITNUM EQ &LAST_VISIT.) AND ~(&COMPLFN.) AND ~MISSING(&VAL.) THEN*/
    /*        DO; DTYPE='LOV';END;*/
    /*      RUN;*/

    ***************************************************************************;
    *** Preparation of time order ;
    ***************************************************************************;
    %LOCAL DOM _DAT;
    %LET DOM=&OADDOMAIN.;
    %LET _DAT=%UPCASE(%m_varExist(indat = &INDAT, vars = &DOM._Y &DOM._M &DOM._D &DOM._TM &DOM._TC &DOM.DTC &DOM.STDTC ));
    %LOCAL _TIME;
    %IF %LENGTH(&_DAT)>0 AND %UPCASE(&TIME) NE VISITNUM %THEN %LET _TIME=VISITNUM &_DAT;
    %ELSE %LET _TIME=VISITNUM;
    ***************************************************************************;
    *** Custom deriviation of postbasefn
    ***************************************************************************;
    %IF %length(&outpostbasefn.)>0 %THEN %DO;
        %IF %length(&trtsdt)=0 OR %length(&trtstm)=0 %THEN %DO;
            %PUT %STR(WARN)ING: Macro M_ANLFN: parameter TRTSDT, TRTSTM should not be missing, when &outpostbasefn is used ;
            %GOTO OUTDO;
        %END;
        DATA _outdat;
            SET _outdat;
            FORMAT _trtsdt _testdt date9. _trtstm _testtm time5.;
            CALL missing(_trtsdt, _trtstm,_testdt,_testtm);
            _trtsdt=&trtsdt.;
            _trtstm=&trtstm.;
            %IF %length(%m_varExist(indat = &indat, vars =&dom.dt))>0 %THEN %DO;
                _testdt=&dom.dt;
            %END;
            %IF %length(%m_varExist(indat = &indat, vars =&dom._tm))>0 %THEN %DO;
                IF index("&_DAT.","_TM")>0 THEN DO;
                    IF ~missing(&dom._tm) THEN _testtm=input(&dom._tm,time5.);
                END;
            %END;
            %IF %length(%m_varExist(indat = &indat, vars =&dom._tc))>0 %THEN %DO;
                IF index("&_DAT.","_TC")>0 THEN DO;
                    IF ~missing(&dom._tc) THEN _testtm=input(&dom._tc,time5.);
                END;
            %END;
            %IF %length(%m_varExist(indat = &indat, vars =&dom.stdtc))>0 %THEN %DO;
                IF index("&_DAT.","STDTC")>0 THEN DO;
                    IF ~missing(&dom.sttc) THEN DO;
                        _testdt=input(scan(&dom.stdtc,1,'T'),yymmdd10.);
                        &dom._y=year(_testdt);
                        &dom._m=month(_testdt);
                        &dom._y=day(_testdt);
                        _testtm=input(scan(&dom.stdtc,2,'T'),time5.);
                    END;
                END;
            %END;
            %IF %length(%m_varExist(indat = &indat, vars =&dom.dtc))>0 %THEN %DO;
                IF index("&_DAT.","DTC")>0 THEN DO;
                    IF ~missing(&dom.dtc) THEN DO;
                        _testdt=input(scan(&dom.dtc,1,'T'),yymmdd10.);
                        &dom._y=year(_testdt);
                        &dom._m=month(_testdt);
                        &dom._y=day(_testdt);
                        _testtm=input(scan(&dom.dtc,2,'T'),time5.);
                    END;
                END;
            %END;
            IF ~missing(_trtsdt) THEN DO;
                IF .<year(_trtsdt)<&dom._y THEN &outpostbasefn.=1;
                IF year(_trtsdt)>&dom._y>. THEN &outpostbasefn.=0;
                IF .<year(_trtsdt)=&dom._y AND .<month(_trtsdt)<&dom._m THEN &outpostbasefn.=1;
                IF .<year(_trtsdt)=&dom._y AND month(_trtsdt)>&dom._m>. THEN &outpostbasefn.=0;
                IF .<_trtsdt<_testdt  THEN &outpostbasefn.=1;
                IF _trtsdt>_testdt>.  THEN &outpostbasefn.=0;
                IF .<_trtsdt=_testdt AND (.<_trtstm<_testtm) THEN &outpostbasefn.=1;
                IF .<_trtsdt=_testdt AND (_trtstm>_testtm>.) THEN &outpostbasefn.=0;
            END;*end of dealing with ~missing(_trtsdt);
            IF missing(&outpostbasefn.) THEN &outpostbasefn.=(&TIME.>&baseline_visit.);
        RUN;

        DATA _issuetimeout(LABEL='Record with inconsistent time/visit order flag');
            LENGTH _issuetype $100.;
            LABEL _issuetype='Inconsistency Type';
            SET _outdat;
            KEEP &subjidn. &dom.strf &outpostbasefn. &_TIME. &trtsdt. &trtstm.  &dom.dt: &_Dat. _ISSUEtype;
            IF ~((&outpostbasefn.) EQ (&TIME.>&baseline_visit.)) AND ~missing(&TIME) THEN DO;
                _ISSUETYPE='VISIT NUMBER OR TIMEPOINT NUMBER';
                OUTPUT;
            END;
            IF ~((&outpostbasefn.) EQ (&dom.strf IN ('AFTER' 'DURING' 'DURING/AFTER' 'UNKNOWN'))) AND nmiss(_trtsdt,&dom._m,&dom._y)=0 THEN DO;
                _ISSUETYPE="&dom.STRF";
                OUTPUT;
            END;
        RUN;
    %END;
    %OUTDO:
    ***************************************************************************;
    *** ORDER REPEATED MEASUREMENT ;
    ***************************************************************************;
    PROC SORT DATA=_OUTDAT;
        BY &BY. &SUBJIDN. &ANLFN. &_TIME. &_DAT. _OADSEQ;
    RUN;
    DATA &OUTDAT. &DUPOUT.(KEEP= &BY. &SUBJIDN. &ANLFN. &_TIME &_DAT.  &NEWSEQ. &VAL. _DUPFN LABEL='DUPLICATED RECORD');
        SET _OUTDAT;
        FORMAT _DUPFN NY.;
        CALL missing(_DUPFN);
        BY &BY. &SUBJIDN. &ANLFN. &_TIME;
        IF FIRST.&TIME  THEN CALL missing(&NEWSEQ);
        &NEWSEQ.+1;
        IF ~(FIRST.&TIME AND LAST.&TIME) AND &ANLFN. THEN DO;
            _DUPFN=1;
            OUTPUT &OUTDAT.;
            OUTPUT &DUPOUT.;
        END;
        ELSE OUTPUT &OUTDAT.;
    RUN;
    PROC DELETE data=_outdat;
    RUN;

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )
%MEND M_ANLFN;

