 ******************************************************************************/

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name = INDAT, type = DATA)
    %spro_check_param(name = OUTDAT, type = DATA)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* Put your macro code here!;
    ***************************************************************************;
    *** PREPARATION ;
    ***************************************************************************;
    %LOCAL _TIME _SORTID;
    OPTIONS NONOTES;
    %IF %LENGTH(&OUTDAT)=0 %THEN %LET OUTDAT=&INDAT;
    %LOCAL ANLFL;
    %LET ANLFL=%SUBSTR(&ANLFN,1,%LENGTH(&ANLFN)-1)L;

    DATA _BASEMAIN(LABEL='main data set for baseline derivation') _BASE_OTHER(LABEL='irrevlant of baseline deriviation');
        SET &INDAT.;
        LABEL _SVFN='SCHEDULED VISIT?';
        %IF %length(&basetype)>0 %THEN %DO;
            BASETYPE="&BASETYPE.";
        %END;
        _INCLFN=(&INCLFN.);
        _SVFN=(VISITNUM EQ int(VISITNUM));*FLAG FOR SCHEDULED VISIT;
        %IF %LENGTH(&UNSCHEDULE_VISITNUM)>0 %THEN %DO;
            IF visitnum=&UNSCHEDULE_VISITNUM. THEN _SVFN=0;
        %END;
        _SEQ=&SEQ.;
        _POSTFN=(&TIME.>&BASELINE_VISIT.);
        %IF %LENGTH(&POSTFN.)>0 %THEN %DO;
            _POSTFN=&POSTFN.;
        %END;
        %IF %LENGTH(&UNSCHEDULE_VISITNUM)>0 %THEN %DO;
            IF &USEUVFN.=0 AND (VISITNUM NE int(VISITNUM) OR visitnum=&UNSCHEDULE_VISITNUM) THEN _INCLFN=.;*IF USEUVFN=0 THEN DO NOT USE UNSCHEDULED VISIT ;
        %END;
        %ELSE %DO;
            IF &USEUVFN.=0 AND (VISITNUM NE int(VISITNUM)) THEN _INCLFN=.;*IF USEUVFN=0 THEN DO NOT USE UNSCHEDULED VISIT ;
        %END;

        IF ~missing(&VAL.) AND ~(_POSTFN) AND _INCLFN THEN OUTPUT _BASEMAIN;
        ELSE OUTPUT _BASE_OTHER;*IRRELVANT OF BASELINE DERIVATION;
    RUN;

    ***************************************************************************;
    *** DERIVATION: LAST PRE-BASELINE RECORD;
    ***************************************************************************;

    %IF %UPCASE(&TIME) NE VISITNUM %THEN %LET _TIME=VISITNUM &TIME ;
    %ELSE %LET _TIME=VISITNUM;
    %IF &USEUVFN.=1 or &USEUVFN.=0 %THEN %DO;
        %LET _SORTID= &BY. &SUBJIDN. &_TIME _SEQ;
    %END;
    %ELSE %IF &USEUVFN.=0.5 %THEN %DO;
        %LET _SORTID= &BY. &SUBJIDN. _SVFN &_TIME _SEQ;*ONLY USE UNSCHEDULED VALUE IF THERE IS NO SCHEDULED VALUE;
    %END;

    PROC SORT DATA=_BASEMAIN;
        BY &_SORTID.;
    RUN;

    DATA _BASE_PRE(LABEL='pre-baseline but not last valid') _BASE_base(LABEL='pre-baseline and last valid');*SEPARATE RECORD USED AS BASELINE  AND NOT USED AS BASELINE;
        SET _BASEMAIN;
        BY  &_SORTID.;
        IF LAST.&SUBJIDN. THEN OUTPUT _BASE_BASE;*WILL BE USED TO DERIVE BASELINE RECORD;
        ELSE OUTPUT _BASE_PRE;
    RUN;

    DATA _BASE_ALL(LABEL='all baseline related record');*CREATE BASELINE RECORD;
        SET _BASE_base;
        IF(&TIME EQ &BASELINE_VISIT.) THEN
        DO;* USE OLD RECORD;
            ABLFN=1;
            ABLFL='Y';
            &ANLFN.=1;
            &ANLFL.='Y';
            AVISITN=&BASELINE_AVISIT.;
            OUTPUT ;
        END;
        %IF %length(&NEWFN)>0 %THEN %DO;
            ELSE DO;*NEED TO CREATE NEW RECORD;
                OUTPUT ;
                &NEWFN.=1;
                ABLFN=1;
                ABLFL='Y';
                &ANLFN.=1;
                &ANLFL.='Y';
                AVISITN=&BASELINE_AVISIT.;
                DTYPE='LVPD';
                OUTPUT;
            END;
        %END;
        %ELSE %DO;
            ELSE DO;
                ABLFN=1;
                ABLFL='Y';
                &ANLFN.=1;
                &ANLFL.='Y';
                AVISITN=&BASELINE_AVISIT.;
                OUTPUT;
            END;
        %END;
    RUN;

    ***************************************************************************;
    *** OUTPUT ;
    ***************************************************************************;

    DATA &BASEDATALL.(LABEL="ALL Baseline Record");
        SET _BASE_ALL;
        IF ABLFN; RUN;*ALL BASELINE RECORD;
    %IF %length(&NEWFN.)>0 %THEN %DO;
        DATA &BASEDATNEW.(LABEL="New Baseline Record");
            SET &BASEDATALL.;
            IF &NEWFN.; RUN;*NEW BASELINE RECORD;
    %END;
    DATA &OUTDAT.(LABEL='_base_all+_base_pre+_base_other');*ALL DATA;
        SET  _BASE_ALL _BASE_PRE _BASE_OTHER;
    RUN;

    PROC SORT DATA=&OUTDAT.;
        BY  &BY. &SUBJIDN. &_TIME ABLFN;
    RUN;

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )

%MEND m_base;

%MACRO m_cell_count(input_ds = ,
                   byvar = ,
                   stratum = studyid,
                   treatmgr = ,
                   treatment_code = 1,
                   control_code = 0,
                   response = ,
                   response_code = 1,
                   no_response_code = 0,
                   zero_count = no,
                   output_ds = counted)
/ DES = 'Creation of a SAS data set with aggregated data based on an input data set containing data on individual basis';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: SPRO, SAS 9.4
 *******************************************************************************
 * Purpose          : Creation of a SAS data set with aggregated data based on an input data set containing data on individual basis
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 * *       - input_ds :
 * *         input SAS data set (one or two-level name)
 * *       - byvar, stratum :
 * *         &input_ds variables whose levels generate separate counts, &stratum
 * *         specifying the stratification variable
 * *       - treatmgr, response :
 * *         &input_ds variables containing the treatment group and response data
 * *       - treatment_code, control_code, response_code, no_response_code :
 * *         values of the associated variable that make up the respective category
 * *       - zero_count :
 * *         specifies whether the output data set contains observations with value
 * *         zero for all four cell count variables, if combinations of present
 * *         &byvar and &stratum variable values are missing in &input_ds
 * *       - output_ds :
 * *         output SAS data set (one or two-level name)
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gltlk (Rui Zeng) / date: 12DEC2023
 * Reference prog   : /var/by-sas2p/patdb/std_sg/stat/systems/iapro/iapro1/cell_count.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
 * %m_cell_count(input_ds = all_subj,
 * byvar = aedecod,
 * stratum = studyid,
 * treatmgr = trtgrpn,
 * treatment_code = 1, control_code = 2,
 * response = response,
 * response_code = 1, no_response_code = 0,
 * zero_count = yes,
 * output_ds = counted_pt)
 ******************************************************************************/



    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name=input_ds, type=DATA)
    %spro_check_param(name=byvar, type=VARIABLES, canBeEmpty = Y, mustExist  = Y, data=&input_ds)
    %spro_check_param(name=stratum, type=VARIABLES, mustExist  = Y, data=&input_ds)
    %spro_check_param(name=treatmgr, type=VARIABLES, mustExist  = Y, data=&input_ds)
    %spro_check_param(name=treatment_code, type=NUMBER)
    %spro_check_param(name=control_code, type=NUMBER)
    %spro_check_param(name=response, type=VARIABLES, mustExist  = Y, data=&input_ds)
    %spro_check_param(name=response_code, type=NUMBER)
    %spro_check_param(name=no_response_code, type=NUMBER)
    %spro_check_param(name=zero_count, type=TEXT)
    %spro_check_param(name=output_ds, type=DATA)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
            INFO
          , Version &mversion started
          , addDateTime = Y
          , messageHint = BEGIN)

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* ---------------------------------------------------------------------------------------------
    definition of local macro variables;

       %LOCAL i by_component;

    %* ---------------------------------------------------------------------------------------------
    start the actual macro execution;

       PROC SORT DATA = &input_ds.
                 OUT = ccds01
                       (KEEP = &byvar. &stratum. &treatmgr. &response.);
          BY &byvar. &stratum.;
       RUN;

    %* ---------------------------------------------------------------------------------------------
    count within all present levels of 'by' and 'stratum' variables;

       DATA ccds02
            (KEEP = &byvar. &stratum.
                    treatm_response treatm_no_response contr_response contr_no_response);
          RETAIN treatm_response treatm_no_response
                 contr_response contr_no_response;
          SET ccds01;
          BY &byvar. &stratum.;
          IF first.&stratum.
          THEN DO;
             treatm_response = 0; treatm_no_response = 0;
             contr_response = 0; contr_no_response = 0;
          END;
          IF &treatmgr. IN (&treatment_code.) AND &response. IN (&response_code.)
          THEN treatm_response + 1;
          IF &treatmgr. IN (&treatment_code.) AND &response. IN (&no_response_code.)
          THEN treatm_no_response + 1;
          IF &treatmgr. IN (&control_code.) AND &response. IN (&response_code.)
          THEN contr_response + 1;
          IF &treatmgr. IN (&control_code.) AND &response. IN (&no_response_code.)
          THEN contr_no_response + 1;
          IF last.&stratum.
          THEN OUTPUT;
       RUN;

    %* ---------------------------------------------------------------------------------------------
    generate levels for all present values of 'by' and 'stratum' variables;

       %LET by_component = ;

       %IF %bquote (&byvar.) ^=
       %THEN %DO i = 1 %TO %sysfunc(countw(&byvar., %str( ), q));
          %LET by_component = &by_component. %scan (&byvar., &i., %str ( )) *;
       %END;

       PROC FREQ data = ccds01 noprint;
          table &by_component. &stratum. / out = ccds03 (KEEP = &byvar. &stratum.) sparse;
       RUN;

    %* ---------------------------------------------------------------------------------------------
    fill up the counted data, if required and necessary;

       DATA &output_ds.;
          MERGE ccds02(IN = in_present_levels) ccds03;
          BY &byvar. &stratum.;
       %IF %upcase (&zero_count.) = NO
       %THEN %DO;
          IF in_present_levels;
       %END;
       %ELSE %DO;
          IF NOT in_present_levels
          THEN DO;
             treatm_response = 0; treatm_no_response = 0;
             contr_response = 0; contr_no_response = 0;
          END;
       %END;
       RUN;


    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:;

    PROC DATASETS NOLIST NOWARN;
        DELETE ccds: /MT=DATA;
    QUIT;

    OPTIONS &l_opts.;
    %log(
            INFO
          , Version &mversion terminated.
          , addDateTime = Y
          , messageHint = END)
    %log(
            INFO
          , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
          , addDateTime = Y
          , messageHint = END)

%MEND m_cell_count;

%MACRO m_create_lb_critparam(
       indat           =
     , byvars          =
     , copyvars        =
     , crit1_selection =
     , crit1_cond      =
     , crit2_selection =
     , crit2_cond      =
     , outdat          =
     , paramcd_out     =
) / DES = 'Create new ADLB parameter which checks multiple records for criteria (for example ">=3xULN of ALT or AST and >=1.5xULN Total bilirubin")';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: SPro
 *******************************************************************************
 * Purpose          : Create new ADLB parameter which checks multiple records for criteria (for example ">=3xULN of ALT or AST and >=1.5xULN Total bilirubin")
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat           : Input dataset, usually ADLB after early_ads_processing
 *                    byvars          : By variables in &indat. Each by group is checked for criterion 1 and 2.
 *                    copyvars        : Variables in &indat. that will be copied to &outdat.
 *                    crit1_selection : If condition that specifies which records in &indat. should be check for 1st criterion
 *                    crit1_cond      : If condition for 1st criterion
 *                    crit2_selection : If condition that specifies which records in &indat. should be check for 2nd criterion. Can be empty if there is only one criterion to be checked.
 *                    crit2_cond      : If condition 2nd criterion. Can be empty if there is only one criterion to be checked.
 *                    outdat          : Name of the output dataset with the new derived records
 *                    paramcd_out     : Value of PARAMCD of the new derived records in &outdat.
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gdcpl (Derek Li) / date: 24MAY2023
 * Reference prog   : /var/swan/root/bhc/3427080/21652/stat/main01/dev/analysis/macros/m_create_lb_critparam.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : gdcpl (Derek Li) / date: 20FEB2024
 * Reason           : change example call
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
 *
 * Two Criteria '(>=3xBL of ALT or AST) and >=2xBL Total bilirubin'
 * %m_create_lb_critparam(
 *     indat           = adlb_sort
 *   , byvars          = usubjid lbrefid
 *   , copyvars        = adsname studyid avisitn adt atm
 *   , crit1_selection = paramcd in ('SGOT', 'SGPT')
 *   , crit1_cond      = cmiss(aval, base) = 0 and aval >= 3 * base
 *   , crit2_selection = paramcd in ('BILITOT')
 *   , crit2_cond      = cmiss(aval, base) = 0 and aval >= 2 * base
 *   , outdat          = adlb_critpar1
 *   , paramcd_out     = TESTPAR1
 * )
 *
 * Single Criterion '>=1xULN of ALT or AST'
 * %m_create_lb_critparam(
 *     indat           = adlb_sort
 *   , byvars          = usubjid lbrefid
 *   , copyvars        = adsname studyid avisitn adt atm
 *   , crit1_selection = paramcd in ('SGOT', 'SGPT')
 *   , crit1_cond      = cmiss(aval, anrhi)=0 and aval >= 1 * anrhi
 *   , crit2_selection =
 *   , crit2_cond      =
 *   , outdat          = adlb_critpar2
 *   , paramcd_out     = TESTPAR2
 * )
 ******************************************************************************/

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;


    %spro_check_param(name = indat, type = DATA)
    %spro_check_param(name = byvars, type = VARIABLES, data = &indat.)
    %spro_check_param(name = copyvars, type = VARIABLES, data = &indat.)
    %spro_check_param(name = crit1_selection, type = TEXT)
    %spro_check_param(name = crit1_cond, type = TEXT)
    %spro_check_param(name = crit2_selection, type = TEXT, canBeEmpty = Y)
    %spro_check_param(name = crit2_cond, type = TEXT, canBeEmpty = Y)
    %spro_check_param(name = outdat, type = TEXT)
    %spro_check_param(name = paramcd_out, type = TEXT)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* Put your macro code here!;

    /*< Prepare input data */
    /* Resolve data set options */
    DATA _m_indat0 _m_base;
        SET &indat.;
        OUTPUT _m_indat0;
        IF ablfl='Y' AND NOT missing(paramcd) THEN OUTPUT _m_base;
    RUN;

    *remove unscheduled visit before baseline;
    PROC SQL;
        CREATE TABLE _m_indat AS
               SELECT a.*,b.adt AS _base_dt
               FROM _m_indat0 AS a LEFT JOIN _m_base AS b
               ON a.studyid=b.studyid AND a.usubjid=b.usubjid AND a.parcat1=b.parcat1
                  AND a.parcat2=b.parcat2 AND a.paramcd=b.paramcd;
    QUIT;

    DATA _m_indat;
        SET _m_indat;
        IF n(adt,_base_dt)=2 THEN DO;
            IF avisitn=900000 AND (adt<_base_dt OR ady<1 ) THEN DELETE;
        END;

    RUN;

    PROC SORT DATA=_m_indat PRESORTED;
        BY &byvars;
    RUN;

    /*< Derive new parameters */

    %LOCAL lastbyvar;
    %LET lastbyvar = %scan(&byvars., -1);

    DATA _m_checkcrit;
        SET _m_indat;
        BY &byvars;

        FORMAT crit1_record_present
               crit2_record_present
               crit1_satisfied
               crit2_satisfied
               NY. ;

        RETAIN crit1_record_present
               crit2_record_present
               crit1_satisfied
               crit2_satisfied;

        IF first.&lastbyvar. THEN DO;
            CALL missing(crit1_record_present,
                         crit2_record_present,
                         crit1_satisfied,
                         crit2_satisfied);
        END;

        IF &crit1_selection. THEN DO;
            crit1_record_present = 1;
            IF &crit1_cond. THEN crit1_satisfied = 1;
        END;

        %IF %nrbquote(&crit2_cond.) =   %THEN %DO;
            /* If no 2nd criterion is specified in macro call, pretend that 2nd criterion is always satisfied */
            crit2_record_present = 1;
            crit2_satisfied      = 1;
        %END;
        %ELSE %DO;
            IF &crit2_selection. THEN DO;
                crit2_record_present = 1;
                IF &crit2_cond. THEN crit2_satisfied = 1;
            END;
        %END;

        OUTPUT;

        /* Create new record/parameter */
        IF last.&lastbyvar. THEN DO;
            IF (crit1_record_present = 1 AND crit2_record_present = 1) THEN DO;
                paramcd = "&paramcd_out.";
                paramtyp = "DERIVED";
                CALL missing(aval);
                IF (crit1_satisfied = 1 AND crit2_satisfied = 1) THEN avalc = "Y";
                ELSE avalc = "N";

                OUTPUT;
            END;
        END;
    RUN;

    /*< Save outdat and clean up */
    DATA &outdat.;
        SET _m_checkcrit;

        IF paramcd = "&paramcd_out.";/* Keep only the new derived records */
        IF &post_baseline_cond.;
        if ady>1 and not find(lowcase(visit),'baseline');
        KEEP &byvars. &copyvars. paramcd paramtyp aval avalc adt avisitn ady ablfl visitnum visit;
    RUN;

    /* Delete all temporary _m_ datasets */
    PROC DATASETS NOLIST LIBRARY=work;
        DELETE _m_: / MEMTYPE = data;
        RUN;
    QUIT;

    OPTIONS &l_notes.;
    /*    %PUT %STR(NO)TE: &macro. - Put your note here;*/
    OPTIONS NONOTES;

    OPTIONS &l_opts.;
    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )

%MEND m_create_lb_critparam;

%MACRO m_create_qs_bdi(

) / DES = 'add BDI related ANALYSIS variables and paramcd e.g Total ';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : Create BDI related ANALYSIS variables and paramcd e.g Total
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       : N/A
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 23JAN2024
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_create_qs_bdi.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/



/*******************************************************************************
 * Examples         :
   %m_create_qs_bdi();
 ******************************************************************************/



*** Get data from QS;
*"BDIB122": Total Score;
data adqs_tot;
    set &adsDomain._derive;
    if find(qscat, 'BECK DEPRESSION INVENTORY')>0 and qstestcd ne 'BDIB122';
    if not missing(aval) then naval = aval;
RUN;

* Get the first assessment for each visit only;
proc sort data=adqs_tot;
    by usubjid qscat avisitn adt atm qstestcd;
RUN;

data adqs_ft(keep=usubjid qscat avisitn adt atm);
    set adqs_tot;
    by usubjid qscat avisitn adt atm;
    if first.avisitn;
RUN;

data adqs_tot;
    merge adqs_tot adqs_ft(in=b);
    by usubjid qscat avisitn adt atm;
    if b;
RUN;

* bdi;
proc sql;
    create table bdi as
    select *, sum(naval) as total from adqs_tot
    where find(qscat, 'BECK DEPRESSION INVENTORY')>0
    group by usubjid, qscat, avisitn, adt;
QUIT;

* Total bdi;
data bdi_total(drop=naval total);
    set bdi;
    by usubjid qscat avisitn adt;
    %createCustomVars(adsDomain=adqs, vars=PARAMTYP);
    AVAL=total;
    AVALC=" ";
    QSTESTCD='BDIB999';
    QSORRES=" ";
    QSTEST=" ";
    PARAMTYP="DERIVED";
    if last.adt;
RUN;

data &adsDomain.;
    set &adsDomain._ori bdi_total;
RUN;

/*******************************************************************************
 * End of macro
 ******************************************************************************/

%MEND m_create_qs_bdi;

%MACRO m_create_qs_daily_awake()
/ DES = 'add Mean frequency of night time awakening paramcd';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : add Mean frequency of night time awakening paramcd in ADQSHFSS
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       : N/A
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
