%MACRO m_create_qs_ice(indata=adqs,
                      outdata=adqs)
/ DES = 'Add ICE flag and relevant reasons/sub-reasons for derived parameters in ADQS';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : Add ICE flag and relevant reasons/sub-reasons for derived parameters in ADQS
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indata: input dataset name
 *                    outdata: output dataset name
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 26JAN2024
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_create_qs_ice.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : evmqe (Endri Elnadav) / date: 30JAN2024
 * Reason           : Add  (WHERE=(&studyid_cond.)) to restrict subjects
 ******************************************************************************/


*<******************************************************************************;
*< ANL01FL: ICE flag for Permanent Discontinuation;
*<******************************************************************************;

* Get ICE flag for Permanent Discontinuation from study drug in ADDS ;
proc sort data=ads.adds(WHERE=(&studyid_cond.)) out=ds1(keep=studyid usubjid icereas icestwk astdt aphase ice01fl);
    where ice01fl='Y';
    by studyid usubjid;
RUN;

* Select the latest date for each subject;
proc sql noprint;
    create table ds2 as
           select *
           from ds1
           group by studyid, usubjid
           having astdt=max(astdt)
           order by studyid, usubjid;
QUIT;


* Merge QS records with permanent discontinuation info;
proc sort data=ads.adsl (WHERE=(&studyid_cond.)) out=adsl; by studyid usubjid; run;
proc sort data=&indata.; by studyid usubjid adt ady; RUN;

data ice1_ds;
    merge &indata.(in=a) ds2(rename=(astdt=astdt_ds)) adsl(keep=studyid usubjid saffl randfl);
    by studyid usubjid;
    if a;
RUN;


* Flag permanent discontinuation ICE records till week 12;
data final_ice1_ds;
    set ice1_ds;
    %createCustomVars(adsDomain=adqs, vars=ANL01FL ICEDSRS );
    if 10<=avisitn<=120 then comwk=avisitn/10;
    else comwk=.;
    * For permanent discontinuation ICE flag, only to check week, no need to check day;
    if paramtyp="DERIVED" and 10<=avisitn<=120 and
       (find(parcat1, 'MENOPAUSE-SPECIFIC QUALITY-OF-LIFE QUESTIONNAIRE')>0 or parcat1='PROMIS SLEEP DISTURBANCE SHORT FORM 8B V1.0')
       and ice01fl="Y" and . < icestwk <= comwk and find(paramcd, "MENB8")=0 then do;
        anl01fl = "Y";
        icedsrs = icereas;
    END;
    drop icereas icestwk astdt_ds aphase ice01fl;
RUN;



*<******************************************************************************;
*< ANL02FL: ICE flag for Temporary Treatment Interruption;
*<******************************************************************************;

* Get ICE flag for temporary treatment interruption from ADEX;
data ex(keep=studyid usubjid ice01fl icereas astdt_ex astdy_ex comwk);
    set ads.adex(WHERE=(&studyid_cond.));
    if ice01fl = "Y" and aphase = 'Week 1-12' and astdt ne .;
    comwk=input(compress(paramcd,'','kd'), best.);
    rename astdt=astdt_ex astdy=astdy_ex;
RUN;

proc sort data=ex; by studyid usubjid comwk; run;

proc sort data=final_ice1_ds; by studyid usubjid comwk; RUN;

data ice2_ex;
    merge final_ice1_ds(in=a) ex;
    by studyid usubjid comwk;
    if a;
RUN;

* Flag temporary treatment interruption ICE records till week 12;
data final_ice2_ex;
    set ice2_ex;
    length iceintrs $200.;
    if paramtyp="DERIVED" and 10<=avisitn<=120 and
       (find(parcat1, 'MENOPAUSE-SPECIFIC QUALITY-OF-LIFE QUESTIONNAIRE')>0 or parcat1='PROMIS SLEEP DISTURBANCE SHORT FORM 8B V1.0')
       and ice01fl="Y" and comwk ne . and (.<astdt_ex<=adt or adt=.)
       and find(paramcd, "MENB8")=0 then do;
        anl02fl = "Y";
        iceintrs = icereas;
    END;
    drop ice01fl icereas astdt_ex astdy_ex;
RUN;


*<******************************************************************************;
*< ANL03FL: ICE flag for Prohibited Medication;
*<******************************************************************************;

* Get ICE flag for Concomitant medication interruption from ADCM;
data cm;
    set ads.adcm(WHERE=(&studyid_cond.));
    if ice01fl = "Y" ;
    * Set to a large number for the ICE end week since it is still ongoing;
    if iceenwk eq .  and find(cmenrtpt,"ONGOING") then iceenwk=99;
    keep studyid usubjid ice01fl icestwk iceenwk;
RUN;

proc sort data=cm; by studyid usubjid icestwk iceenwk; run;

* Transpose data in case there are multiple CM records for the same subject;
proc transpose data=cm out=cm_st(drop=_:) prefix=ice_st_;
    by studyid usubjid ice01fl;
    var icestwk;
RUN;

proc transpose data=cm out=cm_en(drop=_:) prefix=ice_en_;
    by studyid usubjid;
    var iceenwk;
RUN;

* Flag Concomitant medication interruption ICE records till week 12;
proc sort data=final_ice2_ex; by studyid usubjid; RUN;

data ice3_cm;
    merge final_ice2_ex(in=a) cm_st cm_en;
    by studyid usubjid;
    if a;
run;

data final_ice3_cm;
    set ice3_cm;

    array start_cm (*) ice_st_:;
    array end_cm (*) ice_en_:;
    if paramtyp="DERIVED" and 10<=avisitn<=120 and
       (find(parcat1, 'MENOPAUSE-SPECIFIC QUALITY-OF-LIFE QUESTIONNAIRE')>0 or parcat1='PROMIS SLEEP DISTURBANCE SHORT FORM 8B V1.0')
        and find(paramcd, "MENB8")=0 then do;
        do i=1 to dim(start_cm);
            if .< start_cm[i] <= comwk <= end_cm[i] then anl03fl = "Y";
        END;
    END;
    drop i ice01fl ice_st_: ice_en_: ;
RUN;


*<******************************************************************************;
*< ANL05FL: VMS flag;
*<******************************************************************************;

* Get VMS flag for VMS treatment from ADCM;
data cm_v;
    set ads.adcm(WHERE=(&studyid_cond.));
    if ice01fl = "Y" and vmsfl = "Y";
    * Set to a large number for the ICE end week since it is still ongoing;
    if iceenwk eq .  and find(cmenrtpt,"ONGOING") then iceenwk=99;
    keep studyid usubjid ice01fl icestwk iceenwk;
RUN;

proc sort data=cm_v; by studyid usubjid icestwk iceenwk; run;

* Transpose data in case there are multiple CM records for the same subject;
proc transpose data=cm_v out=cm_v_st(drop=_:) prefix=ice_v_st_;
    by studyid usubjid ice01fl;
    var icestwk;
RUN;

proc transpose data=cm_v out=cm_v_en(drop=_:) prefix=ice_v_en_;
    by studyid usubjid;
    var iceenwk;
RUN;

* Flag VMS records till week 12;
proc sort data=final_ice3_cm; by studyid usubjid; RUN;

data ice3_cm_v;
    merge final_ice3_cm(in=a) cm_v_st cm_v_en;
    by studyid usubjid;
    if a;
run;

data final_ice3_cm_v;
    set ice3_cm_v;

    array start_cm (*) ice_v_st_:;
    array end_cm (*) ice_v_en_:;
    if paramtyp="DERIVED" and 10<=avisitn<=120 and
       (find(parcat1, 'MENOPAUSE-SPECIFIC QUALITY-OF-LIFE QUESTIONNAIRE')>0 or parcat1='PROMIS SLEEP DISTURBANCE SHORT FORM 8B V1.0')
       and find(paramcd, "MENB8")=0 then do;
        do i=1 to dim(start_cm);
            if .< start_cm[i] <= comwk <= end_cm[i] then anl05fl = "Y";
        END;
    END;
    drop i ice01fl ice_v_st_: ice_v_en_: ;
RUN;


*<******************************************************************************;
*< Output data;
*<******************************************************************************;
data &outdata.;
    set final_ice3_cm_v;
RUN;

%MEND m_create_qs_ice;

%MACRO m_create_qs_ice_hfss(
       indata                    =adqshfss
     , outdata                   =ads.adqshfss
     , paramcd_cond              =%str(paramtyp="DERIVED")
)
/ DES = 'Add ICE flag and relevant reasons/sub-reasons for derived parameters in ADQSHFSS';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : Add ICE flag and relevant reasons/sub-reasons for derived parameters in ADQSHFSS
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indata: input dataset name
 *                    outdatt: output dataset name
 *                    paramcd_cond: condition to select PARAMCDs which need to be flagged for ICE
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 26JAN2024
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_create_qs_ice_hfss.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_create_qs_ice();
 ******************************************************************************/

    *================================================================================================================;
    * ICE: Permanent discontinuation of randomized treatment;
    * bring in ICE from ADDS;
    *================================================================================================================;
    proc sort data=ads.adds out=adds(keep=usubjid icereas ICESTWK);
        where ice01fl='Y';
        by usubjid;
    RUN;

    ** Merge with input data and flag the desired records - ICE: PD of rand trt;
    ** 1) Will be mapped to all weeks following the event, including the current one;
    ** 2) can happen only once for same subjects;
    ** 3) Should be only done until week 12 (day 84);

    data indata_adds;
        merge &indata.(in=a) adds;
        by usubjid;
        if a;

        if 10<=avisitn<=120 then period=1; * from week1 to week12;
        rename icereas=icedsrs;
    RUN;

    ** break the data step into two parts otherwise call missing statement will have wired performance;
    data indata_adds(drop=);
        set indata_adds;

        if &paramcd_cond. and period=1 and avisitn/10>=ICESTWK>.z then anl01fl='Y';
        else do;
            call missing(icedsrs);
        END;
    RUN;

    *================================================================================================================;
    * ICE: Temporary treatment interruption;
    * bring in ICE from ADEX;
    *================================================================================================================;
    data adex;
        set ads.adex(keep=usubjid astdy paramcd icereas ice01fl);
        where ice01fl="Y";
        if missing(icereas) then put "WARN" "ING: ADEX ICE record without a reason for USUBJID=" USUBJID "and ASTDY=" ASTDY;
    RUN;

    proc sort data=adex;
        by usubjid paramcd;
    RUN;

    data indata_adds;
        set indata_adds;
        length linkid $8.;
        if avisitn=10 then linkid="TRTINW1";
        else if avisitn=40 then linkid="TRTINW4";
        else if avisitn=80 then linkid="TRTINW8";
        else if avisitn=120 then linkid="TRTINW12";
    RUN;

    proc sort data=indata_adds;
        by usubjid linkid;
    RUN;

    data indata_adds_adex;
        merge indata_adds(in=a) adex(rename=(paramcd=linkid));
        by usubjid linkid;
        if a;

        length ICEINTRS $200.;
        if &paramcd_cond. and period=1 and ice01fl="Y" then do;
            anl02fl='Y';
            ICEINTRS=strip(icereas);
        END;
    RUN;

    *================================================================================================================;
    * ICE: Intake of prohibited medication having impact on efficacy;
    * bring in ICE from ADCM;
    *================================================================================================================;
    proc sort data=ads.adcm out=adcm(keep=usubjid ICESTWK ICEENWK);
        where ice01fl='Y';
        by usubjid;
    RUN;

    proc transpose data=adcm out=adcm_st(drop=_:) prefix=start_cm;
        by usubjid;
        var icestwk;
    RUN;

    proc transpose data=adcm out=adcm_ed(drop=_:) prefix=end_cm;
        by usubjid;
        var iceenwk;
    RUN;

    data indata_adds_adex_adcm;
        merge indata_adds_adex(in=a drop=icestwk) adcm_st adcm_ed;
        by usubjid;
        if a;
    RUN;

    ** break the data step into two parts otherwise wired performance;

    data indata_adds_adex_adcm;
        set indata_adds_adex_adcm;

        if &paramcd_cond. and period=1 then do;
            array start (*) start_cm: ;
            array end (*) end_cm: ;
            do j=1 to dim(start);
                if not missing(start[j]) then do;
                    if avisitn/10>=start[j]>.z and (avisitn/10<=end[j] or missing(end[j])) then anl03fl='Y';
                END;
            END;
        END;
    RUN;

    *================================================================================================================;
    * ICE: Intake of VMS treatment having impact on efficacy;
    * bring in event from ADCM;
    *================================================================================================================;
    proc sort data=ads.adcm out=adcm2(keep=usubjid ICESTWK ICEENWK);
        where vmsfl='Y' and ice01fl="Y";
        by usubjid;
    RUN;

    proc transpose data=adcm2 out=adcm2_st(drop=_:) prefix=start_cm;
        by usubjid;
        var icestwk;
    RUN;

    proc transpose data=adcm2 out=adcm2_ed(drop=_:) prefix=end_cm;
        by usubjid;
        var iceenwk;
    RUN;

    data indata_adds_adex_adcm2;
        merge indata_adds_adex_adcm(in=a drop= start_cm: end_cm:) adcm2_st adcm2_ed;
        by usubjid;
        if a;
    RUN;

    ** break the data step into two parts otherwise wired performance;

    data indata_adds_adex_adcm2;
        set indata_adds_adex_adcm2;

        if &paramcd_cond. and period=1 then do;
            array start (*) start_cm: ;
            array end (*) end_cm: ;
            do k=1 to dim(start);
                if not missing(start[k]) then do;
                    if avisitn/10>=start[k]>.z and (avisitn/10<=end[k] or missing(end[k])) then anl05fl='Y';
                END;
            END;
        END;
    RUN;

    data &outdata.;
        set indata_adds_adex_adcm2;
    RUN;

%MEND m_create_qs_ice_hfss;

%MACRO m_create_qs_isi(

) / DES = 'add ISI related ANALYSIS variables and paramcd e.g Total ';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : Create ISI related ANALYSIS variables and paramcd e.g Total
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       : N/A
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 26JAN2024
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_create_qs_isi.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_create_qs_isi();
 ******************************************************************************/



*** Get data from QS;
data adqs_tot;
    set &adsDomain._derive (where=(QSCAT in ('ISI')));
    if not missing(aval) then naval = aval;
RUN;

* Get the first assessment for each visit only;
proc sort data=adqs_tot;
    by usubjid qscat avisitn adt atm qstestcd;
RUN;

data adqs_ft(keep=usubjid qscat avisitn adt atm);
    set adqs_tot;
    by usubjid qscat avisitn adt atm;
    if first.avisitn;
RUN;

data adqs_tot;
    merge adqs_tot adqs_ft(in=b);
    by usubjid qscat avisitn adt atm;
    if b;
RUN;

* ISI;
proc sql;
    create table isi as
    select *, sum(naval) as total from adqs_tot
    where QSCAT="ISI"
    group by usubjid, qscat, avisitn, adt;
QUIT;

* Total ISI;
data isi_total(drop=naval total);
    set isi;
    by usubjid qscat avisitn adt;
    AVAL=total;
    AVALC=" ";
    QSTESTCD='ISIB0999';
    QSORRES=" ";
    QSTEST=" ";
    PARAMTYP="DERIVED";
    if last.adt;
RUN;

data &adsDomain.;
    set &adsDomain. isi_total;
RUN;

/*******************************************************************************
 * End of macro
 ******************************************************************************/

%MEND m_create_qs_isi;

%MACRO m_create_qs_menqol(
) / DES = 'add MENQOL related ANALYSIS variables and paramcd e.g Total ';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : Create MENQOL related ANALYSIS variables and paramcd e.g Total
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       : N/
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 26JAN2024
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_create_qs_menqol.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : evmqe (Endri Elnadav) / date: 30JAN2024
 * Reason           : Add (WHERE=(&studyid_cond.)) to restrict adsl
 *                    Add studyid to merge
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_create_qs_menqol();
 ******************************************************************************/



data _adqs_tot;
    set &adsDomain._derive ;
    if find(qscat, 'MENOPAUSE-SPECIFIC QUALITY-OF-LIFE QUESTIONNAIRE')>0;
RUN;


*< Bring in treatment group from adsl;
proc sort data=ads.adsl(WHERE=(&studyid_cond.)) out=_adsl(keep=studyid usubjid trt01an trt01pn);
    where fasfl="Y";
    by studyid usubjid;
RUN;

proc sort data=_adqs_tot;
    by studyid usubjid qscat adt qstestcd;
RUN;

data _adqs_totnew;
    merge _adqs_tot(in=a) _adsl;
    by studyid usubjid;
    if a;
RUN;

*< Start Imputation;
* Select MENQOL for in person visits;
* For Baseline (avisitn=5),week 1(avisitn=10),4(avisitn=40),8(avisitn=80),12(avisitn=120),16(avisitn=160),26(avisitn=260) and 30(avisitn=700000);
data _adqs_impu;
    set _adqs_totnew;
    if avisitn in (5,10,40,80,120,160,260,700000) then output _adqs_impu;
RUN;

* MENQOL QSORRES is the score value if QSTESTCD containing A, e.g. MENB101A;
* MENQOL QSORRES is the YES/NO value if QSTESTCD without A, e.g. MENB101;
data _menqol_yesno
     _menqol_score(keep=studyid domain adsname usubjid qscat parcat1 parcat2 adt atm ady qstestcd avisitn qsorres qsstresc aval avalc qsevlint qsevintx);
    set _adqs_impu;
    if index(qstestcd,"A") > 0 then output _menqol_score;
    else output _menqol_yesno;
RUN;

data _menqol_yn_a;
    set _menqol_yesno(drop=qsstresc aval avalc rename=(qsorres=_qsorres_yesno));
    qstestcd = compress(catx('',qstestcd,'A'));
RUN;

proc sort data=_menqol_yn_a; by studyid domain adsname usubjid qscat parcat1 parcat2 qstestcd avisitn adt atm ady qsevlint qsevintx; RUN;
proc sort data=_menqol_score; by studyid domain adsname usubjid qscat parcat1 parcat2 qstestcd avisitn adt atm ady qsevlint qsevintx; RUN;

* Combine yesno data with score value;
data _menqol_both;
    merge _menqol_yn_a(in=a) _menqol_score;
    by studyid domain adsname usubjid qscat parcat1 parcat2 qstestcd avisitn adt atm ady qsevlint qsevintx;
    if a then _yesno=1;
run;

* Convert aval to score as per table 6-2 in the SAP;
data _menqol_both;
    set _menqol_both;
    if find(upcase(_qsorres_yesno), "NO") then do;
        qsorres=_qsorres_yesno;
        _aval_sc=1;
    end;

    if not missing (aval) then _aval_sc=aval+2;
RUN;

* Use the first assessment for multiple assessments in the same week;
proc sort data=_menqol_both;
    by studyid usubjid qscat avisitn adt atm ady qstestcd;
RUN;

data _menqol_ft(keep=studyid usubjid qscat avisitn adt atm ady);
    set _menqol_both;
    by studyid usubjid qscat avisitn adt atm ady qstestcd;
    if first.avisitn;
RUN;

data _menqol_first;
    merge _menqol_both _menqol_ft(in=b);
    by studyid usubjid qscat avisitn adt atm ady;
    if b;
RUN;


*< Output MENQOL 29 items;
data menqol_item(drop=_qstestcd);
    set _menqol_first;
    _qstestcd=qstestcd;

    if not missing(_aval_sc) then aval=_aval_sc;
        else aval=.;
    avalc="";
    if substr(qstestcd,8)='A' then qstestcd=substr(_qstestcd,1,4)||"8"||substr(_qstestcd,6,2);
        else qstestcd="";
    qsorres="";
    qstest="";
    paramtyp="DERIVED";
    if not missing (qstestcd);
RUN;


*< Preparation for imputation;
* Check domains;
data _menqol_info(drop=num);
    set _menqol_first;
    num = input(substr(scan(qstestcd,1,"A"),6), best.);
    * Domain 1: Vasomotor 1-3;
    if 1 le num  le 3 then _cat=1;
    * Domain 2: Psychosocial 4-10;
    if 4 le num le 10 then _cat=2;
    * Domain 3: Physical 11-26;
    if 11 le num le 26 then _cat=3;
    * Domain 4: Sexual 27-29;
    if 27 le num le 29 then _cat=4;
RUN;


* Select all avisits and qstestcd;
proc sql;
    create table _adqs_avisitn as
    select distinct avisitn, adsname, domain, qstestcd, _cat
    from _menqol_info;
QUIT;


* Select all subjects;
proc sql;
    create table _adqs_usubjid as
    select distinct studyid, usubjid, trt01an, trt01pn,trtsdt
    from ads.adsl(WHERE=(&studyid_cond.))
    where fasfl="Y";
QUIT;

proc sql;
    create table _adqs_cat as
    select distinct qscat, qsscat, parcat1, parcat2, qsevlint, qsevintx
    from _adqs_totnew;
QUIT;

* Create a dummy data for all subjects with all avisits;
proc sql;
    create table _adqs_dummy as
    select *
    from _adqs_usubjid, _adqs_cat, _adqs_avisitn
    order by studyid, domain, adsname, usubjid, qscat, qsscat, parcat1, parcat2, avisitn, qstestcd, _cat, trt01an, trt01pn, trtsdt;
QUIT;

* Separate dummy data before and after week 12;
data _adqs_dummy_wk12 _adqs_dummy_aft12;
    set _adqs_dummy;
    if avisitn<=120 then output _adqs_dummy_wk12;
    else output _adqs_dummy_aft12;
RUN;

* Get info of at least one record for the week;
proc sort data=_menqol_info(keep=studyid usubjid avisitn _cat) out=_one_visitn nodupkey;
    by studyid usubjid avisitn _cat;
RUN;

* Only select dummy data after week 12 for avisitn with at least one record;
proc sort data=_one_visitn; by studyid usubjid avisitn _cat; run;
proc sort data=_adqs_dummy_aft12; by studyid usubjid avisitn _cat; run;

data _adqs_dummy_post12;
    merge _adqs_dummy_aft12(in=a) _one_visitn(in=b);
    by studyid usubjid avisitn _cat;
    if a and b;
RUN;

* Combine dummy data before week 12 for every subject and after week 12 with at least one record;
data _adqs_dummy2;
    set _adqs_dummy_wk12
        _adqs_dummy_post12;
RUN;

proc sort data=_adqs_dummy2;
    by studyid domain adsname usubjid qscat qsscat parcat1 parcat2 avisitn qstestcd _cat trt01an trt01pn trtsdt;
RUN;

* Check whether the subject skips questions;
proc sort data=_menqol_info;
    by studyid domain adsname usubjid qscat qsscat parcat1 parcat2 avisitn qstestcd _cat trt01an trt01pn trtsdt;
RUN;

data _menqol_check;
    merge _menqol_info(in=a drop=qsevlint qsevintx ) _adqs_dummy2;
    by studyid domain adsname usubjid qscat qsscat parcat1 parcat2 avisitn qstestcd _cat trt01an trt01pn trtsdt;
    if a then _qsfl="Y";
    else _qsfl="N";
RUN;

*<Impute 1: Impute missing item score when the participant skipped questions;
* Check eligible participant for imputation;
proc sql;
    create table _m1_count as
    select studyid, usubjid, avisitn, adt, _cat, count(usubjid) as _scount from _menqol_info
    where usubjid in (select usubjid from _menqol_check where _qsfl='Y')
    group by studyid, usubjid, avisitn, adt, _cat
    order by studyid, usubjid, avisitn, adt, _cat;
QUIT;


* Check the participants has responded to more than one half of the domain items;
* i.e. at least two items in the vasomotor domain, two items in the sexual domain;
* four items in the psychosocial domain and nine items in the physical domain;
data _m1_subj_impute;
    set _m1_count;
    if _cat=1 and _scount>=2 then _morefl="Y";
    else if _cat=2 and _scount>=4 then _morefl="Y";
    else if _cat=3 and _scount>=9 then _morefl="Y";
    else if _cat=4 and _scount>=2 then _morefl="Y";
    else _morefl="N";
RUN;

proc sort data=_menqol_check; by studyid usubjid avisitn _cat; RUN;
proc sort data=_m1_subj_impute; by studyid usubjid avisitn _cat; RUN;

data _m1_fl1;
    merge _menqol_check(in=a) _m1_subj_impute(keep=studyid usubjid avisitn _cat _morefl);
    by studyid usubjid avisitn _cat;
    if a;
    if missing(_morefl) then _morefl="N";
RUN;

* Check whether half of the participants must have responded to this qstestcd and avisitn;
* As per Stats, use trt01pn since we need FAS;
proc sql;
    create table _m1_counthalf1 as
           select studyid, trt01pn, count(distinct usubjid) as _n_total
           from ads.adsl(WHERE=(&studyid_cond.))
           where fasfl="Y"
           group by studyid, trt01pn;
QUIT;

proc sql;
    create table _m1_counthalf2 as
           select studyid, qstestcd, avisitn, trt01pn, n(_aval_sc) as _n_value
           from _m1_fl1
           where _qsfl="Y"
           group by studyid, qstestcd, avisitn, trt01pn;
QUIT;

* Create flag for half of the participants;
proc sort data=_m1_fl1; by studyid trt01pn; run;
proc sort data=_m1_counthalf1; by studyid trt01pn; run;
data _m1_fl1_tt;
    merge _m1_fl1(in=a) _m1_counthalf1;
    by studyid trt01pn;
    if a;
RUN;

proc sort data=_m1_fl1_tt; by studyid qstestcd avisitn trt01pn; run;
data _m1_fl1_ff;
    merge _m1_fl1_tt(in=a) _m1_counthalf2;
    by studyid qstestcd avisitn trt01pn;
    if a;
RUN;

data _m1_fl2;
    set _m1_fl1_ff;
    if nmiss(_n_value, _n_total)=0 and _n_value ge _n_total/2 then _halffl="Y";
    else _halffl="N";
RUN;


* Impute missing item score at baseline;
proc sql;
    create table _m1_base as
           select *, round(mean(_aval_sc)) as _c_mean
           from _m1_fl2
           where avisitn = 5
           group by studyid, avisitn, qstestcd;
QUIT;

data _m1_base;
    set _m1_base;
    if _qsfl="N" and _morefl="Y" and _halffl="Y" and missing(_aval_sc) and not missing(_c_mean) then do;
        _aval_sc=_c_mean;
        _impute1=1;
    end;
RUN;

* Impute missing item score at post-randomization;
proc sql;
    create table _m1_post as
           select *, round(mean(_aval_sc)) as _c_mean
           from _m1_fl2
           where avisitn > 5
           group by studyid, avisitn, qstestcd, trt01pn;
QUIT;

data _m1_post;
    set _m1_post;
    if _qsfl="N" and _morefl="Y" and _halffl="Y" and missing(_aval_sc) and not missing(_c_mean) then do;
        _aval_sc=_c_mean;
        _impute1=1;
    end;
RUN;

* Combine base and post data;
data _m1_final;
    set _m1_base _m1_post;
RUN;


*<Impute 2: Impute missing item score when the participant answered "yes" but did not indicate "how bothered";
data _m2_todo;
    set _m1_final;
    if find(upcase(_qsorres_yesno), "YES")>0 and missing(qsorres) then _toimpu2="Y";
    else _toimpu2="N";
RUN;

proc sql;
