documents.sourceText:
merge _m2_todo _m2_yes;
        by studyid usubjid avisitn _cat;
    RUN;

    data _m2_fyes1 (drop=_yes_dm_mean);
        set _m2_todo_1;
        if _toimpu2="Y" and _morefl="Y" then do;
            _aval_sc=_yes_dm_mean;
            _impute2=1;
        end;
    RUN;

    * If she answered 'no' to all other domain items, impute it from the mean of all other subjects who responded 'yes';
    proc sql;
        create table _m2_yes_1 as
               select studyid, usubjid, avisitn, _cat, count(usubjid) as _n_yes
               from _m2_todo
               where find(upcase(_qsorres_yesno), "YES")>0
               group by studyid, usubjid, avisitn, _cat
               order by studyid, usubjid, avisitn, _cat;
    QUIT;

    proc sql;
        create table _m2_yes_2 as
               select studyid, usubjid, avisitn, _cat, count(usubjid) as _n_all
               from _m2_todo
               group by studyid, usubjid, avisitn, _cat
               order by studyid, usubjid, avisitn, _cat;
    QUIT;

    data _m2_yes_allno(keep=studyid usubjid avisitn _cat _allnofl);
        merge _m2_yes_1(in=a) _m2_yes_2;
        by studyid usubjid avisitn _cat;
        if nmiss(_n_yes, _n_all)=0 and _n_yes=1 and _n_all ge 2 then do;
            _allnofl="Y";
            output;
        end;
    RUN;

    proc sort data=_m2_yes_allno; by studyid usubjid avisitn _cat; run;
    proc sort data=_m2_fyes1; by studyid usubjid avisitn _cat; run;

    data _m2_todo_2;
        merge _m2_fyes1(in=a) _m2_yes_allno;
        by studyid usubjid avisitn _cat;
        if a;
    RUN;

    * Impute the value at baseline;
    proc sql;
        create table _m2_cd_base as
               select studyid, avisitn, qstestcd, round(mean(_aval_sc)) as _item_mean_b
               from _m2_todo
               where avisitn = 5
               group by studyid, avisitn, qstestcd;
    QUIT;

    proc sort data=_m2_cd_base; by studyid avisitn qstestcd; run;
    proc sort data=_m2_todo_2; by studyid avisitn qstestcd; run;

    data _m2_impu_b;
        merge _m2_todo_2 _m2_cd_base;
        by studyid avisitn qstestcd;
        if find(upcase(_qsorres_yesno), "YES")>0 and _allnofl="Y" and _morefl="Y" and aval=. and _item_mean_b ^=. then do;
            _aval_sc=_item_mean_b;
            _impute3=1;
        end;
    RUN;
    proc sort data=_m2_impu_b; by studyid usubjid qscat avisitn qstestcd; run;

    * Impute the value at post-randomization;
    proc sql;
        create table _m2_cd_post as
               select studyid, avisitn, qstestcd, trt01pn, round(mean(_aval_sc)) as _item_mean_p
               from _m2_todo
               where avisitn > 5
               group by studyid, avisitn, qstestcd, trt01pn;
    QUIT;

    proc sort data=_m2_cd_post; by studyid avisitn qstestcd trt01pn; run;
    proc sort data=_m2_impu_b; by studyid avisitn qstestcd trt01pn; run;

    data _m2_impu_p(drop=_item_mean_b _item_mean_p);
        merge _m2_impu_b _m2_cd_post;
        by studyid avisitn qstestcd trt01pn;
        if  find(upcase(_qsorres_yesno), "YES")>0 and _allnofl="Y" and _morefl="Y" and _halffl="Y" and aval=. and not _item_mean_p ^=. then do;
            _aval_sc=_item_mean_p;
            _impute4=1;
        end;
    RUN;

    proc sort data=_m2_impu_p out=_m2_final;
        by qscat trt01pn avisitn studyid usubjid qstestcd;
    run;
%END;
%else %do;
    data _m2_final;
        set _m2_todo;
        _impute2=.;
        _impute3=.;
        _impute4=.;
        _allnofl=.;
    RUN;
%END;

*< END Imputation;



*< Calculate domain score and total score;
* Calculate domain score;
proc sql;
    create table _f_dm2 as
    select studyid, usubjid, avisitn, _cat, mean(_aval_sc) as _mean_domain
    from _m2_final
    group by studyid, usubjid, avisitn, _cat
    order by studyid,usubjid, avisitn, _cat;
QUIT;

* Set the Domain Score to missing if it has missing item score in this domain;
data _f_dm1_ck(keep=studyid usubjid avisitn _cat _scoremiss);
    set _m2_final;
    if missing(_aval_sc) and upcase(strip(qsorres))^="1: NO";
    _scoremiss="Y";
RUN;

proc sort data=_f_dm1_ck nodupkey; by studyid usubjid avisitn _cat; RUN;

data _f_dm_mean;
    merge _f_dm2 _f_dm1_ck;
    by studyid usubjid avisitn _cat;
    if _scoremiss="Y" then call missing(_mean_domain);
RUN;

* Calculate Total Score;
proc sql;
    create table _f_tot as
    select *, mean(_mean_domain) as _mean_total from _f_dm_mean
    group by studyid, usubjid, avisitn
    order by studyid, usubjid, avisitn, _cat;
QUIT;


* Combine with original dataset;
proc sort data=_m2_final; by studyid usubjid avisitn _cat; run;

data _final_mean;
    merge _m2_final(in=a) _f_tot;
    by studyid usubjid avisitn _cat;
    if a;
    drop _qsorres_yesno _yesno _qsfl _morefl _allnofl _n_value _n_total _halffl _c_mean _impute1 _toimpu2 _impute2 _impute3 _impute4 _scoremiss ;
RUN;

proc sort data=_final_mean; by studyid usubjid avisitn adt; RUN;



*< Output MENQOL TOTAL score and domain score;
* MENQOL TOTAL score;
data menqol_total(drop=_mean_total _mean_domain _cat);
    set _final_mean;
    by studyid usubjid avisitn adt;
    AVAL=_mean_total;
    AVALC=" ";
    QSTESTCD='MENB999';
    QSORRES=" ";
    QSTEST=" ";
    PARAMTYP="DERIVED";
    if last.avisitn;
RUN;

* MENQOL Domain 1 - Vasomotor;
data menqol_d1(drop=_mean_total _mean_domain _cat);
    set _final_mean;
    by studyid usubjid avisitn adt;
    where _cat=1;
    AVAL=_mean_domain;
    AVALC=" ";
    QSTESTCD='MENB995';
    QSORRES=" ";
    QSTEST=" ";
    PARAMTYP="DERIVED";
    if last.avisitn;
RUN;

* MENQOL Domain 2 - Psychosocial;
data menqol_d2(drop=_mean_total _mean_domain _cat);
    set _final_mean;
    by studyid usubjid avisitn adt;
    where _cat=2;
    AVAL=_mean_domain;
    AVALC=" ";
    QSTESTCD='MENB996';
    QSORRES=" ";
    QSTEST=" ";
    PARAMTYP="DERIVED";
    if last.avisitn;
RUN;

* MENQOL Domain 3 - Physical;
data menqol_d3(drop=_mean_total _mean_domain _cat);
    set _final_mean;
    by studyid usubjid avisitn adt;
    where _cat=3;
    AVAL=_mean_domain;
    AVALC=" ";
    QSTESTCD='MENB997';
    QSORRES=" ";
    QSTEST=" ";
    PARAMTYP="DERIVED";
    if last.avisitn;
RUN;

* MENQOL Domain 4 - Sexual;
data menqol_d4(drop=_mean_total _mean_domain _cat);
    set _final_mean;
    by studyid usubjid avisitn adt;
    where _cat=4;
    AVAL=_mean_domain;
    AVALC=" ";
    QSTESTCD='MENB998';
    QSORRES=" ";
    QSTEST=" ";
    PARAMTYP="DERIVED";
    if last.avisitn;
RUN;


*< Combine all datasets;
data &adsDomain.;
    set &adsDomain. menqol_item menqol_total menqol_d1 menqol_d2 menqol_d3 menqol_d4;
RUN;

proc datasets nolist nowarn;
    delete _:;
QUIT;

/*******************************************************************************
 * End of macro
 ******************************************************************************/

%MEND m_create_qs_menqol;

%MACRO m_create_qs_promis(

) / DES = 'add PROMIS related ANALYSIS variables and paramcd e.g Total ';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : Create PROMIS related ANALYSIS variables and paramcd e.g Total
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       : N/A
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 26JAN2024
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_create_qs_promis.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : evmqe (Endri Elnadav) / date: 30JAN2024
 * Reason           : Add &studyid_cond. to restrict ADSL
 *                    Add merge by studyid
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_create_qs_promis();
 ******************************************************************************/



data adqs_tot;
    set &adsDomain._derive (where=(QSCAT in ('PROMIS SLEEP DISTURBANCE SHORT FORM 8B V1.0')));
    if not missing(aval) then naval = aval;
RUN;

* Get the first assessment for each visit only;
proc sort data=adqs_tot;
    by studyid usubjid qscat avisitn adt atm qstestcd;
RUN;

data adqs_ft(keep=studyid usubjid qscat avisitn adt atm);
    set adqs_tot;
    by studyid usubjid qscat avisitn adt atm qstestcd;
    if first.avisitn;
RUN;

data _promis_info;
    merge adqs_tot adqs_ft(in=b);
    by studyid usubjid qscat avisitn adt atm;
    if b;
RUN;


* Select all avisits and qstestcd;
proc sql;
    create table _promis_avisitn as
    select distinct avisitn, adsname, domain, qstestcd
    from adqs_tot;
QUIT;

* Select all subjects;
proc sql;
    create table _promis_usubjid as
    select distinct studyid, usubjid, trt01an, trt01pn, trtsdt
    from ads.adsl(WHERE=(&studyid_cond.))
    where fasfl="Y";
QUIT;

proc sql;
    create table _promis_cat as
    select distinct qscat, qsscat, parcat1, parcat2, qsevlint, qsevintx
    from _promis_info;
QUIT;

* Create a dummy data for all subjects with all avisits;
proc sql;
    create table _promis_dummy as
    select *
    from _promis_usubjid, _promis_cat, _promis_avisitn
    order by studyid, domain, adsname, usubjid, qscat, qsscat, parcat1, parcat2, avisitn, qstestcd;
QUIT;

* Separate dummy data before and after week 12;
data _promis_dummy_wk12 _promis_dummy_aft12;
    set _promis_dummy;
    if avisitn<=120 then output _promis_dummy_wk12;
    else output _promis_dummy_aft12;
RUN;

* Get info of at least one record for the week;
proc sort data=_promis_info(keep=studyid usubjid avisitn) out=_one_visitn nodupkey;
    by studyid usubjid avisitn;
RUN;

* Only select dummy data after week 12 for avisitn with at least one record;
proc sort data=_one_visitn; by studyid usubjid avisitn; run;
proc sort data=_promis_dummy_aft12; by studyid usubjid avisitn; run;

data _promis_dummy_post12;
    merge _promis_dummy_aft12(in=a) _one_visitn(in=b);
    by studyid usubjid avisitn;
    if a and b;
RUN;

* Combine dummy data before week 12 for every subject and after week 12 with at least one record;
data _promis_dummy2;
    set _promis_dummy_wk12
        _promis_dummy_post12;
RUN;

proc sort data=_promis_dummy2;
    by studyid domain adsname usubjid qscat qsscat parcat1 parcat2 avisitn qstestcd;
RUN;

* Check whether the subject skips questions;
proc sort data=_promis_info;
    by studyid domain adsname usubjid qscat qsscat parcat1 parcat2 avisitn qstestcd;
RUN;

data _promis_tot;
    merge _promis_info(drop=trtsdt qsevlint qsevintx) _promis_dummy2(in=b);
    by studyid domain adsname usubjid qscat qsscat parcat1 parcat2 avisitn qstestcd;
    if b;
RUN;


* PROMIS raw score;
proc sql;
    create table promis_tt as
    select *, sum(naval) as total from _promis_tot
    where QSCAT='PROMIS SLEEP DISTURBANCE SHORT FORM 8B V1.0'
    group by studyid, usubjid, qscat, avisitn, adt;
QUIT;

* Convert to T-Score according to SAP table 6-1: Sleep Disturbance 8b - Conversion Table;
data promis;
    set promis_tt;
    attrib tscore format=4.1;
    select(total);

    when(8)  tscore  = 28.9;
    when(9)  tscore  = 33.1;
    when(10) tscore  = 35.9;
    when(11) tscore  = 38.0;
    when(12) tscore  = 39.8;
    when(13) tscore  = 41.4;
    when(14) tscore  = 42.9;
    when(15) tscore  = 44.2;
    when(16) tscore  = 45.5;
    when(17) tscore  = 46.7;
    when(18) tscore  = 47.9;
    when(19) tscore  = 49.0;
    when(20) tscore  = 50.1;
    when(21) tscore  = 51.2;
    when(22) tscore  = 52.2;
    when(23) tscore  = 53.3;
    when(24) tscore  = 54.3;
    when(25) tscore  = 55.3;
    when(26) tscore  = 56.3;
    when(27) tscore  = 57.3;
    when(28) tscore  = 58.3;
    when(29) tscore  = 59.4;
    when(30) tscore  = 60.4;
    when(31) tscore  = 61.5;
    when(32) tscore  = 62.6;
    when(33) tscore  = 63.7;
    when(34) tscore  = 64.9;
    when(35) tscore  = 66.1;
    when(36) tscore  = 67.5;
    when(37) tscore  = 69.0;
    when(38) tscore  = 70.8;
    when(39) tscore  = 73.0;
    when(40) tscore  = 76.5;
    otherwise tscore=.;
    end;
RUN;

* PSDSB998: Total Score raw of PROMIS sleep disturbance short form 8B V1.0;
data promis_total_raw(drop=naval total tscore);
    set promis;
    by studyid usubjid qscat avisitn adt;
    AVAL=total;
    AVALC=" ";
    QSTESTCD='PSDSB998';
    QSORRES=" ";
    QSTEST=" ";
    PARAMTYP="DERIVED";
    if last.avisitn;
RUN;

* PSDSB999: Total T-Score of PROMIS sleep disturbance short form 8B V1.0;
