%MEND m_create_qs_promis;

%MACRO m_create_qs_sleepiness()
/ DES = 'Sleepiness scale paramcd';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : Add sleepiness scale paramcd in ADQSHFSS
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       : N/A
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 26JAN2024
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_create_qs_sleepiness.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_create_qs_sleepiness();
 ******************************************************************************/

*** Get data from QS;
    data sleep;
        set &adsDomain. (where=(QSCAT in ('SLEEPINESS SCALE V1.0') and dupfl^='Y'));
        if  AVALCN = 'NOT AT ALL' then naval=0;
        else if  AVALCN = 'A LITTLE BIT' then naval=1;
        else if  AVALCN = 'SOMEWHAT' then naval=2;
        else if  AVALCN = 'QUITE A BIT' then naval=3;
        else if  AVALCN = 'VERY MUCH' then naval=4;
    RUN;

    **** Daily mean of morning, afternoon and evening (item 1 -3) ;
    proc sort data=sleep;
        by usubjid avisitn adt qsevintx;
    RUN;

    proc sql;
        create table mean_time as
        select *, mean(naval) as mean, count (distinct adt) as days from sleep
        where avisitn ne .
        group by usubjid,avisitn,qsevintx;

        create table days_all as
        select usubjid, avisitn, count (distinct adt) as days_all from sleep
        where avisitn ne .
        group by usubjid,avisitn;
    QUIT;

    proc sort data=mean_time;
        by usubjid avisitn qsevintx adt;
    RUN;

    data time_final;
        set mean_time;
        by usubjid avisitn qsevintx;
        if last.qsevintx then output;
    RUN;

    * mean daily total score ;
    proc sql;
        create table mean_daily as
        select *, mean(naval) as daily_mean from mean_time
        where avisitn ne .
        group by usubjid,avisitn,adt;
    QUIT;

    ** keep one record (of the daily mean) per day to calculate daily mean of the week;
    proc sort data=mean_daily;
        by usubjid avisitn adt descending days;
    RUN;

    data mean_daily2;
        set mean_daily;
        by usubjid avisitn adt;
        if first.adt then output;
    RUN;

    ** merge the overall available days for each week: days_all;
    data mean_daily2;
        merge mean_daily2(in=a) days_all;
        by usubjid avisitn;
        if a;
    RUN;

    proc sql;
        create table total_final as
        select *, mean(daily_mean) as total_mean from mean_daily2
        where avisitn ne .
        group by usubjid,avisitn;
    QUIT;

    proc sort data=total_final;
        by usubjid avisitn adt;
    RUN;

    data total_final(drop=mean);
        set total_final;
        by usubjid avisitn adt;
        if last.avisitn then output;
    RUN;

    ** FY: ADT for derived PARAMCDs is updated to theoretical end of week in d_adqshfss per stat request;

    **** Daily mean of morning, afternoon and evening (item 1 -3) ;

    data time_final2(drop=naval mean days);
        set time_final;
        if QSEVINTX="MORNING" then QSTESTCD = 'SLSB0996';
        else if QSEVINTX="AFTERNOON" then QSTESTCD = 'SLSB0997';
        else if QSEVINTX="EVENING" then QSTESTCD = 'SLSB0998';

        PARAMTYP = 'DERIVED';
        QSORRES  = " ";
        QSTEST   = " ";
        AVALC    = " ";
        atptn    = .;
        QSDTC    = " ";
        AVAL = mean;

        if avisitn=5 then do;
            if days < 11 then do;
                AVAL=.;
            END;
        END;

        if avisitn ne 5 then do;
            if days < 5 then do;
                AVAL=.;
            END;
        END;

    RUN;

    * mean daily total score ;
    data total_final2(drop=naval daily_mean days days_all);
        set total_final;

        QSTESTCD = 'SLSB0999';
        PARAMTYP = 'DERIVED';
        QSORRES  = " ";
        QSTEST   = " ";
        AVALC    = " ";
        atptn    = .;
        QSDTC    = " ";

        AVAL = total_mean;

        if avisitn=5 then do;
            if days_all < 11 then do;
                AVAL=.;
            END;
        END;

        if avisitn ne 5 then do;
            if days_all < 5 then do;
                AVAL=.;
            END;
        END;

    RUN;

    data sleep_final;
        set time_final2 total_final2;
    RUN;

    data &adsDomain.;
        set &adsDomain. sleep_final;
    RUN;

    proc datasets nolist lib=work;
        delete mean_daily mean_daily2 mean_time sleep sleep_final time_final total_final time_final2 total_final2 days_all;
    quit;

%MEND m_create_qs_sleepiness;

%MACRO m_cum_inc(
       indat           =
     , pop_cond        =
     , class           = &mosto_param_class.
     , class_fmt       = _trtgrp.
     , page            =
     , alpha           = 0.05
     , timelist        =
     , time_fmt        = best.
     , timelist_display =
     , xtime           = DAYS
     , xlabel          = Days
     , ylabel          = Cumulative Event Rate
     , title_fig_ny    = NO
     , outtype         = TABLE
     , km_type         = CUMULATIVE
     , yend            =
     , outdat          =
     , fig_file        =
     , titfoot_scale   = 1
     , show_censored   = YES
     , debug           = NO
     , _style          = presentation
)
/ DES = 'Creation of table and figure for Cumulative incidence risk';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Creation of table and figure for Cumulative incidence risk
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat            : ADTTE input dataset
 *                    pop_cond         : Population condition
 *                    class            : Treatment class
 *                    class_fmt        : Format for class
 *                    page             : Page variable
 *                    alpha            : Level of confidence interval
 *                    timelist         : Timelist for the table and figure.
 *                    time_fmt         : Format attached to timelist
 *                    timelist_display : To restrict timelist displayed in the table for some classes. Separated by # for each class:
 *                                       Example: If we have week 12 and week 52, we want to show for week 12 only days: 0 1 28 56 84
 *                                          0 1 28 56 84  - &trt_ezn_12.
 *                                        # 0 1 28 56 84  - &trt_pla_12.
 *                    xtime            : Specifies a time factor for the X axis which converts days to weeks or months. WEEKS and MONTHS cause the values in XVAR to be divided by 7 and 30
 *                    xlabel           : Label for the X axis
 *                    ylabel           : Label for the Y axis
 *                    title_fig_ny     : Title for figure.
 *                    outtype          : Output type: TABLE/FIGURE
 *                    km_type          : Specifies the type of Kaplan-Meier plot to be displayed: CUMULATIVE/SURVIVAL
 *                    yend             : Enforce the end tick value for the Y axis
 *                    outdat           : Output dataset
 *                    fig_file         : Output figure filename. Default: &prog.
 *                    titfoot_scale    : Specifies scales for the horizontal title and footnote space on the graphic.
 *                    show_censored    : Specifies whether scatterpoint markers for the censored observations should be displayed
 *                    debug            : if DEBUG=YES then temporary datasets created in this macro are not deleted
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : erjli (Yosia Hadisusanto) / date: 10JAN2024
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : evmqf (Rowland Hale) / date: 05APR2024
 * Reason           : - Set STYLE to presentation for coloured lines in K-M plot
 *                    - Set SHOW_CENSORED default to YES
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 08APR2024
 * Reason           : Add style
 ******************************************************************************/

/*******************************************************************************
 * Examples:
 * %m_cum_inc(
 *   indat    = adsl
 * , timelist =  0 1 28 56 84 112 140 168 196 224 252 280 308 336 364
 * , timelist_display = 0 1 28 56 84  - &trt_ezn_12.
 *                    # 0 1 28 56 84  - &trt_pla_12.
 * )
 *
 * %m_cum_inc(
 *   indat    = adae_tte
 * , pop_cond = &saf_cond.
 * , timelist = &timelist_week12_figure.
 * , outtype  = FIGURE
 * )
 ******************************************************************************/

    %LOCAL macro mversion _starttime ;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes l_miss;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;
    %LET l_miss = %sysfunc(getoption(missing));

    OPTIONS NONOTES NOSOURCE NOFMTERR;
    OPTIONS MISSING='';

    %spro_check_param(name = indat      , type = DATA)
    %spro_check_param(name = class      , type = VARIABLES, data = indat)
    %spro_check_param(name = class_fmt  , type = FORMAT, canBeEmpty = YES)
    %spro_check_param(name = page       , type = VARIABLES, data = indat, canBeEmpty = YES)
    %spro_check_param(name = alpha      , type = NUMBER)
    %spro_check_param(name = outtype    , type = ONE_OF TABLE FIGURE)
    %spro_check_param(name = km_type    , type = ONE_OF CUMULATIVE SURVIVAL)
    %spro_check_param(name = pop_cond   , type = TEXT, canBeEmpty = YES)
    %spro_check_param(name = timelist   , type = TEXT, canBeEmpty = YES)
    %spro_check_param(name = time_fmt   , type = FORMAT, canBeEmpty = YES)
    %spro_check_param(name = timelist_display, type = TEXT, canBeEmpty = YES)
    %spro_check_param(name = xtime      , type = TEXT, canBeEmpty = YES)
    %spro_check_param(name = xlabel     , type = TEXT, canBeEmpty = YES)
    %spro_check_param(name = ylabel     , type = TEXT, canBeEmpty = YES)
    %spro_check_param(name = title_fig_ny, type = YESNO)
    %spro_check_param(name = yend       , type = NUMBER, canBeEmpty = YES)
    %spro_check_param(name = outdat     , type = text, canBeEmpty = YES)
    %spro_check_param(name = fig_file   , type = FILE, canBeEmpty = YES)
    %spro_check_param(name = titfoot_scale, type = TEXT, canBeEmpty = YES)
    %spro_check_param(name = show_censored, type = YESNO)
    %spro_check_param(name = debug      , type = YESNO)

    DATA m_lifetest;
        SET &indat.;
        ATTRIB &class. FORMAT=&class_fmt.;
        %IF %LENGTH(&pop_cond.) > 0 %THEN %DO;
            IF &pop_cond.;
        %END;
    RUN;

    PROC SORT DATA=m_lifetest;
        BY &page. &class.;
    RUN;

    ODS LISTING CLOSE;
    %* Calculate Kaplan-Meier estimates;
    PROC LIFETEST data      = m_lifetest
                  outsurv   = m_km
                  method    = km
                  alpha     = &alpha.
                  atrisk
        %IF %upcase(&outtype.) = TABLE %THEN %DO;
            timelist  = &timelist.
        %END;
        ;
        TIME aval*cnsr(1);
        BY &page.;
        STRATA &class.;
        ODS OUTPUT ProductLimitEstimates = m_ple;
    RUN;
    ODS LISTING;

    %* Create Table;
    %IF %upcase(&outtype.) = TABLE %THEN %DO;

        PROC SORT DATA = m_km;
            BY &page. &class. aval;
        RUN;

        DATA m_est1;
            SET m_km;
            BY &page. &class. aval;
            IF FIRST.aval;
        RUN;

        PROC SORT DATA = m_ple;
            BY &page. &class. aval;
        RUN;

        DATA m_est2;
            MERGE m_ple (IN=a DROP=stratum RENAME=(survival=survival2))
                  m_est1(IN=b);
            BY &page. &class. aval;
            IF a;
        RUN;

        %LOCAL ci_level;
        %LET ci_level = %sysevalf((1 - &alpha.) * 100);

        DATA m_est3;
            SET m_est2;
            ATTRIB timelist LABEL='Relative days' FORMAT=&time_fmt.;
            LABEL failed       = 'n'
                  numberatrisk = 'N'
                  cumpr        = 'Cum. inc (%)'
                  kmci         = "&ci_level.% CI (Lower-Upper limit)";

            IF NOT missing(failure)     THEN fail  = failure * 100;
            IF NOT missing(sdf_lcl)     THEN fciu  = 100 * (1-sdf_lcl);
            IF NOT missing(sdf_ucl)     THEN fcil  = 100 * (1-sdf_ucl);
            IF NOT missing(fail)        THEN cumpr = strip(put(fail,6.2));
            IF fcil > 0 AND fciu > 0    THEN kmci  = trim(put(fcil,6.2)) ||' - '|| trim(put(fciu,6.2));
        RUN;

        %IF %length(&outdat.) > 0 %THEN %DO;
            DATA &outdat.;
                SET m_est3;
            RUN;
        %END;

        %IF %LENGTH(&timelist_display.) > 0 %THEN %DO;
            %LOCAL i element timelist_element class_element;

            DATA m_est3;
                SET m_est3;

                %DO i=1 %TO %sysfunc(countw(&timelist_display., #));
                    %LET element = %scan(&timelist_display., &i, #);
                    %LET timelist_element = %scan(&element, 1, -);
                    %LET class_element    = %scan(&element, 2, -);
                    IF &class. = &class_element. THEN DO;
                        IF timelist IN (&timelist_element.);
                    END;
                %END;
            RUN;
        %END;

        %datalist(
            data       = m_est3
          , page       = &page.
          , by         = timelist
          , sidebyside = &class
          , var        = failed numberatrisk cumpr kmci
          , optimal    = YES
        )
    %END;

    %* Create Figure;
    %ELSE %IF %upcase(&outtype.) = FIGURE %THEN %DO;

        %IF %upcase(&km_type) = CUMULATIVE %THEN %DO;
            %* Set Max of y-axis;
            PROC SQL NOPRINT;
                SELECT ceil(max((1-survival) * 100)) / 100 INTO: max_y FROM m_ple;
            QUIT;
        %END;

        DATA m_ple;
            SET m_ple;
            ATTRIB timelist FORMAT=&time_fmt.;
            timelist = aval;
        RUN;

        %KaplanMeierPlot(
            data          = m_ple
          , xvar          = timelist
          , censor_var    = censor
          , by            = &page.
          , class         = &class.
          , class_data    = m_lifetest
          , show_censored = &show_censored.
          , atriskdata    = m_ple
          , km_type       = &km_type.
          , desc_footnote = NO
          , style         = &_style.
          , xtime         = &xtime.
          , xticklist     = &timelist.
          , xlabel        = &xlabel.
          , ylabel        = &ylabel.
          , title_ny      = &title_fig_ny.
          , titfoot_scale = &titfoot_scale.
        %IF %upcase(&km_type.) = CUMULATIVE AND %LENGTH(&yend.) = 0 %THEN %DO;
            , yend          = &max_y.
        %END;
        %IF %LENGTH(&yend.) > 0 %THEN %DO;
            , yend          = &yend.
        %END;
        %IF %LENGTH(&fig_file.) > 0 %THEN %DO;
            , filename      = &fig_file.
        %END;
        %ELSE %DO;
            , filename      = &prog.
        %END;
        )
    %END;

    %* Delete all datasets with prefix m_:;
    %IF %upcase(%substr(&debug.,1,1)) NE Y %THEN %DO;
        PROC DATASETS LIBRARY=work NOLIST NOWARN;
            DELETE m_:;
            RUN;
    %END;

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    OPTION MISSING="&l_miss.";

%MACRO m_dfdr(input_ds =, soc_ds =, decod = aedecod, alpha1 = 0.05, alpha2 = 0.01, probz =, var =, dfdr_p_val= &var._dfdr_p_val, output_ds =)
/ DES = 'Create new double False Discovery Rate p-value';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: SPRO, SAS 9.4
 *******************************************************************************
 * Purpose          : Create new double False Discovery Rate p-value
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 * Parameters       :
 *       - input_ds :
 *         input SAS data set with RD(CIs) or RR(CIs) and two-sided p-value(probz) for Risk Difference or Risk Ratio estimate
 *       - soc_ds :
 *         input SAS dataset with AEs SOC and PTs list
 *       - decod:
 *         AEDECOD variable or MLG variable
 *       - alpha1 :
 *         dFDR p-value < alpha1, the default 0.05
 *       - probz :
 *         two-sided p-value for Risk Difference or Risk Ratio estimate
 *       - alpha2 :
 *         dFDR p-value < alpha2, the default 0.01
 *       - var :
 *         variable for RD(CIs) or RR(CIs)
 *       - dfdr_p_val:
 *         new double False Discovery Rate p-value
 *       - output_ds :
 *         output SAS data set (one or two-level name)
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gltlk (Rui Zeng) / date: 27JUL2023
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 10AUG2023
 * Reason           : Add IF in line 146, 150
 ******************************************************************************/
/* Changed by       : gltlk (Rui Zeng) / date: 12DEC2023
 * Reason           : add parameter decod
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
 * %m_dfdr(input_ds = results_rd, soc_ds = adae_sub, alpha1 = 0.05, alpha2 = 0.01, var = rd_ci, output_ds = riskdiff);

 ******************************************************************************/

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name = input_ds, type=DATA)
    %spro_check_param(name = soc_ds, type=DATA)
    %spro_check_param(name = alpha1, type = NUMBER)
    %spro_check_param(name = alpha2, type = NUMBER)
    %spro_check_param(name = var, type = VARIABLES, mustExist  = Y, data = &input_ds)
    %spro_check_param(name = output_ds, type = DATA)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
            INFO
          , Version &mversion started
          , addDateTime = Y
          , messageHint = BEGIN)

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    PROC SORT DATA = &soc_ds. OUT = soc_pt NODUPKEY;
        BY aesoc &decod.;
    RUN;

    PROC SQL;
        CREATE TABLE res_soc_pt AS SELECT
               a.*, b.aesoc
               FROM &input_ds. a
               LEFT JOIN soc_pt b ON a.&decod. = b.&decod.
               ORDER BY aesoc, &decod.;
    QUIT;

    *calculate FDR adjusted p-values within SOC i -> p_i_j_schlange;
    PROC MULTTEST inpvalues=res_soc_pt(RENAME=(&probz.=raw_p)) fdr out=p_i_j_schlange noprint;
        BY aesoc;
    RUN;
    PROC SORT DATA=p_i_j_schlange;
        BY aesoc fdr_p raw_p;
    RUN;

    *identify minimum FDR adjusted p-value within SOC -> p_i_star;
    DATA p_i_star(KEEP=aesoc &decod. p_i_star);
        SET p_i_j_schlange;
        BY aesoc fdr_p raw_p;
        IF FIRST.aesoc;
        p_i_star=fdr_p;
    RUN;

    *calculate FDR adjusted p-value for those minimum values and get representative p-value for SOC i -> p_i_star_schlange;
    PROC MULTTEST inpvalues=p_i_star (RENAME=(p_i_star=raw_p)) fdr out=p_i_star_schlange(RENAME=(fdr_p=p_i_star_schlange)) noprint;
    RUN;
    PROC SORT DATA=p_i_star_schlange;
        BY aesoc &decod.;
    RUN;

    *identify PTs within SOCs with representative p_i_star_schlange <= 0.05;
    DATA selected_pts;
        MERGE p_i_star_schlange(KEEP=aesoc p_i_star_schlange) res_soc_pt;
        BY aesoc;
        IF .Z < p_i_star_schlange <= 0.05;
    RUN;

    PROC SQL;
        SELECT count(*) INTO: obs
               FROM selected_pts;
    QUIT;

    %IF &obs NE 0 %THEN %DO;
        *calculate FDR-adjusted p-value for those selected PTs -> p_i_j_schlange_F;
        PROC MULTTEST inpvalues=selected_pts (RENAME=(&probz.=raw_p)) fdr out=p_i_j_schlange_f(RENAME=(fdr_p=p_i_j_schlange_F)) noprint;
        RUN;

        PROC SORT DATA = p_i_j_schlange_f(KEEP=&decod. p_i_j_schlange_f);
            BY &decod.;
        RUN;

        DATA &output_ds(RENAME=(p_i_j_schlange_f=&dfdr_p_val.));
            MERGE &input_ds. p_i_j_schlange_f;
            BY &decod.;
            %IF &alpha1. > &alpha2. %THEN %DO;
                     IF .z < p_i_j_schlange_f < &alpha2. THEN &var. = catx(' ', &var., '**');
                ELSE IF .z < p_i_j_schlange_f < &alpha1. THEN &var. = catx(' ', &var., '*');
            %END;
            %ELSE %DO;
                     IF .z < p_i_j_schlange_f < &alpha1. THEN &var. = catx(' ', &var., '**');
                ELSE IF .z < p_i_j_schlange_f < &alpha2. THEN &var. = catx(' ', &var., '*');
            %END;
        RUN;
    %END;
    %ELSE %DO;
        DATA &output_ds;
            SET &input_ds.;
            CALL missing(&dfdr_p_val);
        RUN;
    %END;

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    PROC DATASETS NOLIST NOWARN;
        DELETE soc_pt &input_ds.2 pi_stern: pij_schlange: pvalues/MT=DATA;
    QUIT;

    OPTIONS &l_opts.;
    %log(
            INFO
          , Version &mversion terminated.
          , addDateTime = Y
          , messageHint = END)
    %log(
            INFO
          , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
          , addDateTime = Y
          , messageHint = END)

%MEND m_dfdr;

%MACRO m_dup(
       INDAT          =
     , OUTDAT         =
     , ANLFN          =ANL01FN
     , SUBJIDN        =USUBJID
     , TIME           =VISITNUM
     , BY             =PARAMCD
     , BASELINE_VISIT =&RAND_V.
     , POSTFN         =
     , ANLBEFORE      =LAST
     , ANLAFTER       =FIRST
     , INCLFN         =1
     , SEQ            =
)/ DES = 'Check duplicated records';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Check duplicated records
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *           INDAT  : INPUT DATA SET, REQUIRED
 *           OUTDAT : OUTPUT DATA SET,IF MISSING, INDAT WILL BE USED, OPTIONAL.
 *           ANLFN  : VARIABLE NAME OF ANLAYSIS FLAG, REQUIRED
 *           SUBJIDN: SUBJECT ID, REQUIRED
 *           BY     : ORDER VARIABLE EG: BY=PARAMCD BY=PARCAT1N PARAMCD, REQUIRED
 *           TIME   : VISIT VARIABLE, DEFAULT IS VISITNUM, REQUIRED
 *           BASELINE_VISIT: RANDOMIZATION VISIT NUMBER, REQUIRED
 *           POSTFN : INDICTOR VARIABLE FOR POST BASELINE, OPTIONAL
 *           INCLFN : INPUT INDICATOR FOR INCLUSION IN ANALYSIS.
 *                    EG: INCLFN=(PARAMCD IN 'VA'), REQUIRED, REQUIRED
 *           ANLBEFORE: WHICH RECORD USED FOR PRE-TREATMENT IF MULTIPLE RECORD EXISTS DEFAULT: LAST
 *           ANLAFTER: WHICH RECORD USED FOR POST-TREATMENT IF MULTIPLE RECORD EXISTS DEFAULT: FIRST
 *           SEQ    : RECORD ORDER SEQ=LBSEQ/EXSEQ/XOSEQ/_SUBSEQ(CUSTOM SEQUENCE),REQUIRED
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gdcpl (Derek Li) / date: 19OCT2023
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_dup();
 ******************************************************************************/

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name = INDAT, type = TEXT)
    %spro_check_param(name = OUTDAT, type = TEXT)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* Put your macro code here!;

    %IF %LENGTH(&OUTDAT)=0 %THEN %LET OUTDAT=&INDAT;
    %LOCAL ANLFL;
    %LET ANLFL=%SUBSTR(&ANLFN,1,%LENGTH(&ANLFN)-1)L;
    DATA _DUPMAIN _DUPOTHER;
        SET &INDAT.;
        _POSTFN=(int(&TIME.)>&BASELINE_VISIT.);
        %IF %LENGTH(&POSTFN.)>0 %THEN %DO;
            _POSTFN=&POSTFN.;
        %END;
        IF &INCLFN. THEN OUTPUT _DUPMAIN;
        ELSE OUTPUT _DUPOTHER;
    RUN;

    PROC SORT DATA=_DUPMAIN;
        BY &BY. &SUBJIDN. &ANLFN. &TIME. &SEQ.;
    RUN;

    DATA _DUPMAIN;
        SET _DUPMAIN;
        BY &BY. &SUBJIDN. &ANLFN. &TIME. &SEQ.;
        IF  _POSTFN AND ~&ANLAFTER..&TIME. THEN &ANLFN=.;
        IF ~_POSTFN AND ~&ANLBEFORE..&TIME. THEN &ANLFN=.;
        IF &ANLFN.=. THEN CALL missing(&ANLFL.);
    RUN;

    DATA &OUTDAT.;
        SET _DUPMAIN _DUPOTHER;
    RUN;

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )

%MEND m_dup;

%MACRO m_exp_adj_inc_rate(
       indat       =
     , indat_adsl  =
     , indat_mosto =
     , by          =
     , class       = &mosto_param_class.
     , outdat      =
     , cnsr        = CNSR
     , debug       = NO
) / DES = 'Macro to calculate the Exposure-Adjusted Incidence Rates (EAIR)';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Macro to calculate the Exposure-Adjusted Incidence Rates (EAIR)
 * Programming Spec : Study size and exposure-adjusted IRs are calculated as following:
 *                    For each study and treatment group, the exposure-adjusted incidence
 *                    (= number of participants with event / sum of exposure days) is multiplied
 *                    by the proportion of the study exposure to the total exposure across studies.
 *                    Results are then added up across all studies for each treatment group.
 *                    With this, the resulting study size and exposure-adjusted IR per treatment group corresponds to a weighted exposure-adjusted IR,
 *                    where each study is weighted according to the amount of exposure available within the study.
 *                    Results are provided per 100 person-years, where one person-year is defined as 365.25 days.
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat        : ADTTE input dataset. It must contain censor (CNSR) variable.
 *                    indat_adsl   : ADSL input dataset
 *                    indat_mosto  : Mosto dataset to be merged with AEIRs to be printed
 *                    by           : Subgroup by variable
 *                    class        : Treatment variable
 *                    outdat       : Output dataset. If missing then print.
 *                    cnsr         : Censor variable in INDAT dataset. Assume CNSR=0 if there is event. CNSR=1 if there is no event (CENSORED)
 *                    debug        : if DEBUG = YES then temporary datasets created in this macro are not deleted
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed: mosto_param_harmonized_outdat = yes
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : erjli (Yosia Hadisusanto) / date: 04JAN2024
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/*******************************************************************************
 * Examples:
 * %m_exp_adj_inc_rate(
 *     indat       = adtte_outdat
 *   , indat_adsl  = adsl
 *   , indat_mosto = inc_print_outdat
 *   , by          = AGEGR1N
 *   , class       = TRT01AN
 * )
 ******************************************************************************/
    %LOCAL macro mversion _starttime ;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes l_miss;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    %LET l_miss = %sysfunc(getoption(missing));

    OPTIONS NONOTES NOSOURCE NOFMTERR;
    OPTIONS MISSING='';

    %spro_check_param(name = indat      , type = DATA)
    %spro_check_param(name = indat_adsl , type = DATA)
    %spro_check_param(name = indat_mosto, type = DATA)
    %spro_check_param(name = cnsr       , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = by         , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = class      , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = outdat     , type = text, canBeEmpty = YES)
    %spro_check_param(name = debug      , type = YESNO)

    DATA m_indat_adtte; SET &indat.;        RUN;
    DATA m_indat_adsl;  SET &indat_adsl.;   RUN;
    DATA m_indat_mosto; SET &indat_mosto.;  RUN;

    %LOCAL adsl_vars adsl_var_in_indat merge_vars;
    %LET adsl_vars          = %getvarlist(indat=m_indat_adsl);
    %LET adsl_var_in_indat  = %getvarlist(indat=m_indat_adtte, varlist=&adsl_vars.);
    %LET merge_vars         = %updateVarlist(&adsl_vars.,&adsl_var_in_indat., mode=DROP);

    %* Merge ADSL variables;
    %mergeDat(baseDat = m_indat_adtte, keyDat = m_indat_adsl(KEEP=&subj_var. &merge_vars.), by = &subj_var.)

    PROC SORT DATA = m_indat_adtte; BY &by. studyid; RUN;

    %* Calculate number of participants with the event per study (CNSR=0);
    PROC FREQ data=m_indat_adtte noprint;
        BY &by. studyid;
        TABLES &cnsr. * &class. /out = m_freq;
    RUN;

    PROC SORT DATA = m_indat_adtte; BY &by. studyid &class.; RUN;

    %* Calculate sum of exposure days per study (risktime);
    %* Sum of exposure days is defined as
    %* The sum of time to first AE occurrence if a treatment-emergent event occurred (AVAL when CNSR=0) +
    %* the sum of treatment duration with time at risk after treatment end if no treatment-emergent event occurred (AVAL when CNSR=1);
    PROC MEANS DATA = m_indat_adtte NOPRINT;
        BY &by. studyid &class.;
        VAR aval;
        OUTPUT OUT=m_risktime SUM=risktime;
    RUN;
    %mergeDat(baseDat = m_freq, keyDat = m_risktime, by = &by. studyid &class.)

    %* Calculate study exposure;
    PROC MEANS DATA=m_indat_adtte NOPRINT;
        BY &by. studyid;
        VAR aval;
        OUTPUT OUT=m_study_exposure(KEEP=&by. studyid study_exposure) SUM=study_exposure;
    RUN;
    %mergeDat(baseDat = m_freq, keyDat = m_study_exposure, by = &by. studyid)

    %* Calculate total exposure across studies;
    PROC MEANS DATA=m_indat_adtte NOPRINT;
        BY &by.;
        VAR aval;
        OUTPUT OUT=m_total_exposure(KEEP=&by. total_exposure) SUM=total_exposure;
    RUN;
    %mergeDat(baseDat = m_freq, keyDat = m_total_exposure, by = &by.)

    %* Derive Exposure adjusted incidence rate (100 person-years) : EAIR;
    %* For each study and treatment group, the exposure-adjusted incidence
    %* (= number of participants with event / sum of exposure days)
    %* is multiplied by the proportion of the study exposure to the total exposure across studies.;

    %* Formula: [(number of participants with the event per study)/(sum of exposure days per study/365.25 * 100)] * (study exposure)/(total exposure across studies);
    DATA m_exp_adj_inc_rates_per_study;
        SET m_freq;
        ATTRIB eair LABEL = "Exposure adjusted incidence rate (100 person-years)" FORMAT=8.2;
        IF cnsr = 0 THEN DO;
            IF count > 0 THEN eair = ((count / (risktime/365.25)) * 100) * (study_exposure / total_exposure);
            ELSE              eair = 0;
        END;
    RUN;

    PROC SORT DATA=m_exp_adj_inc_rates_per_study; BY &by. &class.; RUN;

    %* EAIR are then added up across all studies for each treatment group.;
    PROC MEANS DATA=m_exp_adj_inc_rates_per_study NOPRINT;
        BY &by. &class.;
        VAR eair;
        OUTPUT OUT=m_exp_adj_inc_rates SUM=eair;
    RUN;

    PROC SORT DATA=m_exp_adj_inc_rates(KEEP=&class.) OUT = m_class NODUPKEY;
        BY &class.;
    RUN;

    PROC RANK DATA=m_class OUT=m_class_rank TIES=HIGH;
        VAR &class.;
        RANKS class;
    RUN;
    %mergeDat(baseDat = m_exp_adj_inc_rates, keyDat = m_class_rank, by = &class.)

    %IF %dsattrn(dataset = m_exp_adj_inc_rates, attrib = NOBS) > 0
    %THEN %DO;
        %* Transpose and create eair_ columns for each class;
        PROC TRANSPOSE DATA = m_exp_adj_inc_rates
                       OUT  = m_exp_adj_inc_rates_t(KEEP=&by. eair_:)
                       PREFIX=eair_;
            BY &by.;
            VAR eair;
            ID class;
            IDLABEL &class.;
        RUN;

        %* Merge m_indat_mosto with eair;
        %mergeDat(baseDat = m_indat_mosto, keyDat = m_exp_adj_inc_rates_t, by = &by.)
    %END;

    %* Get _COL variables from M_INDAT_MOSTO;
    PROC SQL NOPRINT;
        SELECT name INTO :col_numbers SEPARATED BY ' '
        FROM sashelp.vcolumn
        WHERE   upcase(libname) = 'WORK'
            AND upcase(memname) = 'M_INDAT_MOSTO'
            AND upcase(name) LIKE '_COL%'
            ;
    QUIT;

    %* Create spaces for layout;
    %LOCAL space symbol;
    %LET symbol = $;
    %LET space = %sysfunc(repeat(%str(&symbol.), 8));

    %* Check if outdat needs to be created or not;
    %IF %LENGTH(&outdat.) = 0 %THEN %DO;
        %LET outdat = m_outdat;
    %END;

    %* Merge the _COL variables with AEIR and saved it in &indat_mosto. dataset;
    DATA &outdat.(DROP=n_: ir_: big_n_:);
        SET m_indat_mosto;

        %LOCAL i col_num;
        %DO i = 1 %TO %sysfunc(countw(&col_numbers.));
            %LET col_num = %scan(&col_numbers., &i);

            n_&i.     = scan(&col_num., 1, 'N');
            ir_&i.    = put(eair_&i., 8.2);
            big_n_&i. = scan(&col_num., 2, 'N');
            IF not missing(&col_num.) THEN DO;
                &col_num. = tranwrd(catt(n_&i.,"&space.",ir_&i.,' N', big_n_&i., "&space.#n (%)&space.&space.IR* (100 person-years)"), "&symbol.", ' ');
            END;
        %END;
    RUN;

    %* Create INP for outdat;
    DATA &outdat.inp;
        SET &indat_mosto.inp;
        IF keyword = 'DATA' THEN value = "&outdat.";
    RUN;

    %* If missing outdat then call datalist to print;
    %IF %upcase(&outdat.) = M_OUTDAT %THEN %DO;
        %mosto_param_from_dat(data = &outdat.inp, var = config)
        %datalist(&config)
    %END;

    %* Delete all datasets with prefix m_:;
    %IF %upcase(%substr(&debug.,1,1)) NE Y %THEN %DO;
        PROC DATASETS LIBRARY=work NOLIST NOWARN;
            DELETE m_:;
            RUN;
    %END;

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    OPTION MISSING="&l_miss.";

    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )


%MEND;

