 * Purpose          : Impute start date for ADAE or ADCM
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat    : Input dataset (adae or adcm)
 *                               If ADSL variables TRTSDT TRT01AN TRT02AN PH2SDT are not present, they will be added
 *                    sp_stdtc : Name of SP variable with character start date (should be AESTDTC or CMSTDTC)
 *                    outdat   : Name of output dataset
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed: &adsDomain. (should be ADAE or ADCM)
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gltlk (Rui Zeng) / date: 19SEP2023
 * Reference prog   :/var/swan/root/bhc/3427080/21652/stat/main01/dev/analysis/macros/m_impute_astdt.sas (epjgw (Roland Meizis) / date: 13JUN2023)
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 21SEP2023
 * Reason           : Add TRT02AN and dropped variables that are created within the macro
 ******************************************************************************/
/* Changed by       : gltlk (Rui Zeng) / date: 22SEP2023
 * Reason           : Add case when &sp_stdtc has time part
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
 *
 * Imputing ASTDT for ADAE
 * %m_impute_astdt(
 *        indat    = adae
 *      , sp_stdtc = aestdtc
 *      , adsDomain = ADAE
 *      , outdat   = adae2
 * )
 *
 * Imputing ASTDT for ADCM
 * %m_impute_astdt(
 *         indat    = adcm
 *       , sp_stdtc = cmstdtc
 *       , adsDomain = ADCM
 *       , outdat   = adcm2
 * )
 ******************************************************************************/


    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name=indat,    mustExist=Y,                type=DATA)
    %spro_check_param(name=sp_stdtc, mustExist=Y,  data=&indat., type=VARIABLES_C)
    %spro_check_param(name=outdat,                               type=TEXT)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
            INFO
          , Version &mversion started
          , addDateTime = Y
          , messageHint = BEGIN)

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* Put your macro code here!;

    /* Resolve data set options */
    data _m_indat;
        set &indat.;
    run;

    proc sort data=_m_indat;
        by studyid usubjid;
    run;

    /* Check input dataset for variables TRTSDT TRT01AN TRT02AN PH2SDT and merge from ADSL if necessary */
    %local adsl_vars adsl_var_in_indat;

    %let adsl_vars = TRTSDT TRT01AN TRT02AN PH2SDT;
    %let adsl_var_in_indat = %getvarlist(indat=&indat., varlist=&adsl_vars.);

    %if %sysfunc(countw(&adsl_var_in_indat.%str( ))) NE 4 %then %do;
        data _m_adsl (drop=&adsl_var_in_indat.);
            set ads.adsl (keep=studyid usubjid &adsl_vars.);
        run;

        data _m_indat;
            merge _m_indat (in=_in_indat)
                  _m_adsl;
            by studyid usubjid;

            if _in_indat;
        run;
    %end;


    /* Imputation of (partially) missing start and end date as per SAP*/
    data &outdat.(DROP=acttrtsdt placebosdt rangestdt rangeendt %updateVarlist(&adsl_vars.,&adsl_var_in_indat., mode=DROP));
        set _m_indat;

        %createCustomVars(adsDomain=&adsDomain., vars=astdt astdtf);
        attrib acttrtsdt placebosdt rangestdt rangeendt format=date9.;

        /* Derive start date of active treatment and placebo */
        if trt01an = 53 then do;     /* Elinzanetant 120mg */
            acttrtsdt = trtsdt;
            call missing(placebosdt);
        end;
        else if trt01an = 9901 then do;      /* Placebo */
            placebosdt = trtsdt;
            if not missing(ph2sdt) and not missing(trt02an) then acttrtsdt = ph2sdt;
            else call missing(acttrtsdt);
        end;

        if length(compress(&sp_stdtc.)) = 16 then do; /* Date of the form YYYY-MM-DDTMM:SS */
            astdt = input(scan(&sp_stdtc., 1, 'T'), yymmdd10.);
            call missing(astdtf);
        end;
        else if length(compress(&sp_stdtc.)) = 10 then do; /* Date of the form YYYY-MM-DD */
            astdt = input(&sp_stdtc., yymmdd10.);
            call missing(astdtf);
        end;
        /* Derive ASTDTF and imputation range end and start as per SAP */
        else if length(compress(&sp_stdtc.)) = 7 then do; /* Date of the form YYYY-MM */
            astdtf = 'D';
            /* Calculate imputation range */
            rangestdt =                    input(substr(&sp_stdtc.,1,7)||"-01",yymmdd10.); /* First day of the month */
            rangeendt = min(intnx('month', input(substr(&sp_stdtc.,1,7)||"-01",yymmdd10.), 0, 'ending'), aendt); /* Last day of the month capped by CM end date */
        end;
        else if length(compress(&sp_stdtc.)) in (4, 9) then do; /* Date of the form YYYY or YYYY---DD */
            astdtf = 'M';
            /* Calculate imputation range */
            rangestdt =     input(substr(&sp_stdtc.,1,4)||"-01-01",yymmdd10.); /* First day of the year */
            rangeendt = min(input(substr(&sp_stdtc.,1,4)||"-12-31",yymmdd10.), aendt); /* Last day of the year capped by CM end date */
        end;
        else if missing(&sp_stdtc.) then do;
            call missing(astdt, astdtf);
        end;
        else put "WARN" "NING: Problem with ASTDT imputation, unexpected &sp_stdtc. value " usubjid= &sp_stdtc.= astdt= astdtf=;

        /* Impute start date as per SAP */
        if not missing(astdtf) then do;
            if      rangestdt <= acttrtsdt  <= rangeendt then astdt = acttrtsdt;
            else if rangestdt <= placebosdt <= rangeendt then astdt = placebosdt;
            else    astdt = rangestdt;
        end;
    RUN;


    proc datasets nolist LIBRARY=work;
        delete _m_: / memtype = data;
        run;
    quit;

    OPTIONS &l_notes.;
/*    %PUT %STR(NO)TE: &macro. - Put your note here;*/
    OPTIONS NONOTES;

    %end_macro:;

    OPTIONS &l_opts.;
    %log(
            INFO
          , Version &mversion terminated.
          , addDateTime = Y
          , messageHint = END)
    %log(
            INFO
          , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
          , addDateTime = Y
          , messageHint = END)

%MEND m_impute_astdt;

%MACRO m_inc_100_patyears(
      indat          =
    , indat_adsl     =
    , by             =
    , class          = &mosto_param_class.
    , censordt       =
    , enddt          = &censordt.
    , startdt        =
    , var            =
    , triggercond    =
    , evlabel        =
    , anytxt         =
    , outdat         =
    , debug          = NO
) / DES = 'Macro to calculate number of subjects and study size and exposure-adjusted incidence rate';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Macro to calculate number of subjects and study size and exposure-adjusted incidence rate
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       : indat       : Input dataset
 *                    indat_adsl  : ADSL input dataset
 *                    by          : Subgroup by variable
 *                    class       : Treatment variable
 *                    censordt    : Censor date variable. Must exist in indat_adsl
 *                    enddt       : Time window end date. Must exist in indat_adsl
 *                    startdt     : Start date variable. Must exist in indat_adsl
 *                    var         : List of variables for events categorization
 *                    triggercond : Trigger condition which defines an event
 *                    evlabel     : Event label used for incidence_print
 *                    anytxt      : Anytxt used for incidence_print
 *                    outdat      : Output dataset. If missing then print.
 *                    debug       : if DEBUG = YES then temporary datasets created in this macro are not deleted
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed: mosto_param_harmonized_outdat = yes
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : erjli (Yosia Hadisusanto) / date: 10SEP2024
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/*******************************************************************************
 * Examples:
 * %m_inc_100_patyears(
 *     indat       = adae_ext
 *   , indat_adsl  = adsl_ext
 *   , censordt    = enddt
 *   , startdt     = startdt
 *   , var         = aebodsys aedecod
 *   , triggercond = not missing(aedecod)
 *   , evlabel     = Primary system organ class#   Preferred term#   MedDRA version &v_meddra.
 *   , anytxt      = Number of subjects with at least one such event
 * )
 ******************************************************************************/
    %LOCAL macro mversion _starttime ;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes l_miss;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    %LET l_miss = %sysfunc(getoption(missing));

    OPTIONS NONOTES NOSOURCE NOFMTERR;
    OPTIONS MISSING='';

    %spro_check_param(name = indat      , type = DATA)
    %spro_check_param(name = indat_adsl , type = DATA)
    %spro_check_param(name = by         , type = VARIABLES, data = indat_adsl, canBeEmpty = YES)
    %spro_check_param(name = class      , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = censordt   , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = startdt    , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = enddt      , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = var        , type = VARIABLES, data = indat)
    %spro_check_param(name = triggercond, type = TEXT)
    %spro_check_param(name = evlabel    , type = TEXT, canBeEmpty = YES)
    %spro_check_param(name = anytxt     , type = TEXT, canBeEmpty = YES)
    %spro_check_param(name = outdat     , type = text, canBeEmpty = YES)
    %spro_check_param(name = debug      , type = YESNO)

    %* Call incidence print to calculate number of subjects with events;
    %incidence_print(
        data        = &indat.
      , data_n      = &indat_adsl.
      , page        = &by.
      , var         = &var.
      , triggercond = &triggercond.
      , evlabel     = &evlabel.
      , anytxt      = &anytxt.
      , outdat      = m_outdat_mosto
      , outpat      = m_inc_pat
      , together    =
    )

    %* Create ADSL shell;
    DATA m_adsl_shell(KEEP = &subj_var. &class. &censordt. &startdt. &enddt.);
        SET &indat_adsl.;
    RUN;

    %* Create unique events based on &var. event variables;
    PROC SORT DATA = m_outdat_mosto
              OUT  = m_index(KEEP = &var.) NODUPKEY;
        BY &var.;
    RUN;

    %* Cartesian product to create ADTTE shell;
    DATA m_adtte_shell;
        SET m_adsl_shell;
        DO i = 1 TO n;
            %* For every observation in m_adsl_shell, read in each observation in m_index;
            SET m_index POINT=i NOBS=n;
            OUTPUT;
        END;
    RUN;

    %* Get event dataset;
    DATA m_input;
        SET &indat.;
        IF &triggercond.;
        IF NOT missing(astdt);
    RUN;

    %LOCAL i level_var level_var_prev pos by_vars;

    %* Get first event date for each level of &var. for each subject;
    %DO i = 1 %TO %sysfunc(countw(&var.)) + 1;

        %LET level_var = %scan(&var., -&i.);
        /* Get the position of level_var in var */
        %LET pos = %INDEX(&var, &level_var);

        /* Extract everything before level_var */
        %IF &pos. > 1 %THEN %DO;
            %LET by_vars = %SUBSTR(&var, 1, &pos.-1);
        %END;
        %ELSE %DO;
            %LET by_vars =;
        %END;

        PROC SORT DATA = m_input;
            BY &subj_var. &by_vars. &level_var. astdt;
        RUN;

        DATA m_first_event_&level_var.(KEEP=&subj_var. &var. astdt);
            SET m_input;
            BY &subj_var. &by_vars. &level_var.;

            %IF %LENGTH(&level_var.) > 0 %THEN %DO;
                IF FIRST.&level_var. THEN DO;
                    %IF %LENGTH(&level_var_prev.) > 0 %THEN %DO;
                        CALL missing(%sysfunc(tranwrd(&level_var_prev., %str( ), %str(,))));
                    %END;
                    OUTPUT;
                END;
            %END;
            %ELSE %DO;
                IF FIRST.&subj_var. THEN DO;
                    %IF %LENGTH(&level_var_prev.) > 0 %THEN %DO;
                        CALL missing(%sysfunc(tranwrd(&level_var_prev., %str( ), %str(,))));
                    %END;
                    OUTPUT;
                END;
            %END;
        RUN;

        %LET level_var_prev = &level_var_prev. &level_var.;
    %END;

    %* Stack them together;
    DATA m_stack_first_event;
        SET m_first_event_:;
    RUN;

    %* Merge with m_inc_pat to get only subjects who have incidence;
    %mergeDat(
        baseDat           = m_stack_first_event
      , keyDat            = m_inc_pat(KEEP=&subj_var. &var. _aeind WHERE=(_aeind = 1))
      , outDat            = m_inc_pat_event
      , by                = &subj_var. &var.
      , dropNonKeyDatRecs = Y
    )

    %* Join the ADTTE with event date;
    %mergeDat(
        baseDat = m_adtte_shell
      , keyDat  = m_inc_pat_event
      , outDat  = m_adtte_astdt
      , by      = &subj_var. &var.
    )

    %* Calculate the AVAL;
    %* Time to first EVENT occurrence if an event occurred (AVAL when CNSR=0);
    %* Time to censored date if no event occured (AVAL when CNSR=1);
    DATA m_adtte_outdat(DROP=&class. &censordt. &startdt. &enddt.);
        SET m_adtte_astdt;
        IF NOT missing(&startdt.) THEN DO;
            IF NOT missing(astdt) and  &startdt. <= astdt <= &enddt. THEN DO;
                cnsr = 0;
                aval = astdt - &startdt. + 1;
            END;
            ELSE DO;
                cnsr = 1;
                aval = &censordt. - &startdt. + 1;
            END;
        END;
    RUN;

    %* Calculate the Exposure-Adjusted Incidence Rates (EAIR);
    %m_exp_adj_inc_rate(
        indat       = m_adtte_outdat
      , indat_adsl  = &indat_adsl.
      , indat_mosto = m_outdat_mosto
      , by          = &by. &var.
      , class       = &class.
      , outdat      = &outdat.
      , debug       = &debug.
    )

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    OPTION MISSING="&l_miss.";

    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )

%MEND;

%MACRO m_lb_trtemfl(
       indat         =
     , adsdomain     =
     , outdat        =
)
/ DES = 'create the LB treatment emergent flag for each phase';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : create the analysis flag for each phase
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat : input dataset
 *                    adsdomain : ADS domain
 *                    outdat: output dataset
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gdcpl (Derek Li) / date: 15FEB2024
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_lb_trtemfl();
 ******************************************************************************/

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name = indat, type = data)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* Put your macro code here!;
    DATA tmp_indatx;
        SET &indat.;
    RUN;


    PROC SQL NOPRINT;
        *< SUBJ_LST: Get subject list with visits after week 12 and before EOT;
        SELECT DISTINCT usubjid INTO :subj_lst SEPARATED BY '", "'
               FROM sp.sv
               WHERE visitnum=85 and studyid='21810'
               ;
        *<SUBJ_o3_lst: Get subject list with visit after week 12 and before EOT for OASIS-3 study;
        select distinct usubjid into :subj_o3_lst separated by '", "'
               from SP.SV
               where studyid='21810' and 85<visitnum<352;

        *< Create a dataset with week 12 visit for OASIS studies;
        create table sv_w12 as
               select studyid,usubjid,svstdtc
               from sp.sv
               where visitnum=85 and studyid in ('21810') and svoccur='Y' and epoch='TREATMENT'
               order by studyid,usubjid
               ;
    QUIT;



    proc sort data=tmp_indatx;
        by studyid usubjid;
    RUN;

    data tmp_indatx;
        merge tmp_indatx(in=a)  sv_w12;
        by studyid usubjid;
        if a;
        format sv_w12 date9.;
        if not missing(svstdtc) then sv_w12=input(svstdtc,yymmdd10.);
    RUN;

    *< Get complete treatment information for OASIS-3 study;
    proc sql noprint;
        create table ds_o3 as
               select studyid,usubjid,dsstdtc
               from sp.ds(where=(studyid='21810'))
               where dsdecod='COMPLETED' and epoch='TREATMENT'
               order by studyid,usubjid
               ;
        *<SUBJ_o3_cmp_lst: complete treatment subject list;
        select distinct usubjid into :subj_o3_cmp_lst separated by '", "'
        from ds_o3;
    QUIT;

    data tmp_indatx;
        merge tmp_indatx(in=a) ds_o3(in=b);
        by studyid usubjid;
        if a;
        format dsdt date9.;
        if b then dsdt=input(dsstdtc,yymmdd10.);
    RUN;

    %IF %bquote(&adsdomain.)=%str( ) %THEN %LET adsdomain=&indat.;

    DATA tmp_indatx;
        SET tmp_indatx;
        FORMAT lbdt trtsdt1 trtsdt2 trtsdt3 trtedt1 trtedt2 trtedt3 date9.;
        IF NOT missing(lbdtc) THEN lbdt=input(scan(lbdtc,1,'T'),?? yymmdd10.);


        *TRT01FL week1-12: TRTSDT1 TRTEDT1, TRT02FL week12-52: TRTSDT2 TRTEDT2, TRTEMFL week1-52: TRTSDT3 TRTEDT3;
        if studyid='21686' then do;
            trtsdt1=trtsdt;
            trtsdt3=trtsdt;
            if trtedt ne . then do;
                trtedt1=trtedt+14;
                trtedt3=trtedt+14;
            end;
        END;
        else if studyid in ('21652','21651') then do;
            *week 1-52;
            trtsdt1=trtsdt;
            trtsdt3=trtsdt;
            if trtedt ne . then do;
                trtedt3=trtedt+14;
            END;
            *for week 1-12;
            **not start phase 2;
            if missing(ph2sdt) then do;
                if not missing(trtedt) then trtedt1=trtedt+14;
            END;
            **start with phase 2;
            else do;
                ***?measurements before TRTSDT and after the start day of open-label (PH2SDT ) phase are excluded. ;
                trtedt1=ph2sdt;
            END;
            ***For PLB-EZN switchers;
            if trt01an ne 53 and trt02an=53 then do;
                if not missing(ph2sdt) then do;
                    trtsdt2=ph2sdt;
                    if trtedt ne . then do;
                        trtedt2=trtedt+14;
                    END;
                end;

            END;


        END;
        else if studyid='21810' then do;
            *week 1-52;
            trtsdt1=trtsdt;
            trtsdt3=trtsdt;
            if trtedt ne . then do;
                trtedt3=trtedt+14;
            END;
            *week 1-12;
            ****measurement before TRTSDT are excluded. Also measurements after TRTEDT + 14 or date of study day 84, which one is earleir,  are excluded.;
           *when week 12/14 available;
           if usubjid in ("&subj_lst") then do;
               if usubjid in ("&subj_o3_cmp_lst.") then trtedt1=sv_w12;
               else if usubjid not in ("&subj_o3_cmp_lst.") then do;
                   if trtedt>sv_w12>. then trtedt1=sv_w12;
                   else trtedt1=min(trtedt+14,trtsdt+83);;
               end;

           END;
           else do;
               trtedt1=min(trtedt+14,trtsdt+83);
           END;


        END;


    RUN;

    data &outdat.;
        set tmp_indatx;
        %createCustomVars(
            adsDomain = &adsdomain.
          , vars      = trtemfl TRTEFL1 TRTEFL2
        )
        ;
        format TRTEFL1 TRTEFL2 ;

        *TRTEMFL;
        IF trtedt3 NE . THEN DO;
            IF (anrind IN('HIGH') AND   base_anrind IN ("NORMAL" "LOW") AND   nmiss(lbdt, trtsdt3, trtedt3)=0 AND  trtsdt3 <= lbdt <= trtedt3)
            OR (anrind IN('LOW') AND   base_anrind IN ("NORMAL" "HIGH") AND   nmiss(lbdt, trtsdt3, trtedt3)=0 AND  trtsdt3 <= lbdt <= trtedt3) THEN trtemfl='Y';
        END;
        ELSE DO;
            IF (anrind = 'HIGH' AND base_anrind IN("NORMAL" "LOW") AND nmiss(lbdt, trtsdt3)=0 AND  trtsdt3 <= lbdt )
            OR (anrind = 'LOW' AND base_anrind IN("NORMAL" "HIGH") AND nmiss(lbdt, trtsdt3)=0 AND  trtsdt3 <= lbdt ) THEN trtemfl='Y';
        END;

        *TRTEFL1;
        IF trtedt1 NE . THEN DO;
            IF (anrind IN('HIGH') AND   base_anrind IN ("NORMAL" "LOW") AND   nmiss(lbdt, trtsdt1, trtedt1)=0 AND  trtsdt1 <= lbdt <= trtedt1)
            OR (anrind IN('LOW') AND   base_anrind IN ("NORMAL" "HIGH") AND   nmiss(lbdt, trtsdt1, trtedt1)=0 AND  trtsdt1 <= lbdt <= trtedt1) THEN TRTEFL1='Y';
        END;
        ELSE DO;
            IF (anrind = 'HIGH' AND base_anrind IN("NORMAL" "LOW") AND nmiss(lbdt, trtsdt1)=0 AND  trtsdt1 <= lbdt )
            OR (anrind = 'LOW' AND base_anrind IN("NORMAL" "HIGH") AND nmiss(lbdt, trtsdt1)=0 AND  trtsdt1 <= lbdt ) THEN TRTEFL1='Y';
        END;

        *TRTEFL2;
        IF trt02an=53 then do;
            if trtedt1 NE . THEN DO;
               IF (anrind IN('HIGH') AND   base_anrind IN ("NORMAL" "LOW") AND   nmiss(lbdt, trtsdt2, trtedt2)=0 AND  trtsdt2 < lbdt <= trtedt2)
                  OR (anrind IN('LOW') AND   base_anrind IN ("NORMAL" "HIGH") AND   nmiss(lbdt, trtsdt2, trtedt2)=0 AND  trtsdt2 < lbdt <= trtedt2) THEN TRTEFL2='Y';
            END;
            ELSE DO;
                IF (anrind = 'HIGH' AND base_anrind IN("NORMAL" "LOW") AND nmiss(lbdt, trtsdt2)=0 AND  trtsdt2 < lbdt )
                OR (anrind = 'LOW' AND base_anrind IN("NORMAL" "HIGH") AND nmiss(lbdt, trtsdt2)=0 AND  trtsdt2 < lbdt ) THEN TRTEFL2='Y';
            END;
        end;

        *if studyid='21810' and avisitn=700000 then call missing(trtemfl, TRTEFL1, TRTEFL2);
    RUN;

    PROC DELETE data=tmp_indatx ;

    RUN;
