%macro m_mmrm_rubin (ds1, ds2, ds3,param) / DES = 'Combine results with Rubin rule';

/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Macro to create Combine results with Rubin rule
 * Programming Spec :
 * Validation Level : 1 - Validation by review
 * Parameters       :
 *                    Ds1   : Dataset to be read in
 *                    Ds2   : Dataset to be read in
 *                    Ds3   : Dataset to be read in
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : erjli (Yosia Hadisusanto) / date: 28DEC2023
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_mmrm_rubin.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 19JAN2024
 * Reason           : Add p-value study / study*treatment interaction
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %mmrm_rubin (estim  , lsmeans );

 ******************************************************************************/



  %LOCAL macro mversion _starttime macro_parameter_error;
  %LET macro    = &sysmacroname.;
  %LET mversion = 1.0;

 * %spro_check_param(name=param1, type=TEXT)
 * %spro_check_param(name=param2, type=TEXT)

  %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

  %LET _starttime = %SYSFUNC(datetime());
  %log(
          INFO
        , Version &mversion started
        , addDateTime = Y
        , messageHint = BEGIN)

  %LOCAL l_opts l_notes;
  %LET l_notes = %SYSFUNC(getoption(notes));

  %LET l_opts = %SYSFUNC(getoption(source))
                %SYSFUNC(getoption(notes))
                %SYSFUNC(getoption(fmterr))
  ;

  OPTIONS NONOTES NOSOURCE NOFMTERR;

/********************************************************************/
/* Start */
/********************************************************************/


/*******************************************************************************
 *Combine results with Rubin's rule
 *******************************************************************************/

* Difference in LS Means *;

PROC SORT DATA=&ds1. ;
    BY label  _imputation_;
RUN;

PROC MIANALYZE DATA=&ds1.;
    BY label;
    MODELEFFECTS estimate;
    STDERR stderr;
ODS OUTPUT ParameterEstimates=&ds1._tot;
RUN;


/*<Save estim-dataset for future use*/

data tlfmeta.&param._estim_s;
    set &ds1._tot;
RUN;

* Divide two-sided p-Value by 2 to get one-sided p-value ;
DATA &ds1._tot;
    SET &ds1._tot;
    IF tValue < 0 THEN Probt_1 = Probt/2;
    ELSE Probt_1 = 1-Probt/2;
    FORMAT probt_1 pvalue6.4;
    LABEL probt_1='1-sided p-value';
RUN;

DATA &ds1._tot p_value_study;
    SET &ds1._tot;
    IF upcase(label) EQ "STUDY" THEN OUTPUT p_value_study;
    ELSE                             OUTPUT &ds1._tot;
RUN;

DATA p_value_study(KEEP=row p_value_study);
    SET p_value_study;
    row = 999;
    p_value_study=strip(put(probt,pvalue6.4));
RUN;

*Table Programming *;

data  table_l2 ;
    length line3 line4 Line5 $200. ;
    set &ds1._tot;
    line3  = cat (strip(put(estimate,12.2)) , ' (', strip(put(StdErr,12.2)), ')');
    line4  = cat (strip(put(LCLmean,12.2)) , ', ', strip(put(UCLmean,12.2)) );
    line5  =  strip(put(probt_1, pvalue6.4))  ;


    week =  Put(strip(compress(Label, ' ' ,'Kd')) , 4.) ;
    keep label Line: week ;
RUN;
proc sort data  = table_l2 ;
    by week label ;
RUN;

proc transpose data =  table_l2  out = t_l2 ;
    by week  label ;
    var Line3 line4 line5 ;
RUN;

data t_l2  ;
    length Col0 comment   $200. ;
    set t_l2;
    if upcase(_name_) = "LINE3" then do;
        comment = "Difference in LS-Means (SE)";
        row1 = 3 ;
    end ;

    if upcase(_name_) = "LINE4" then do ;
        comment = "95% CI for Difference in LS-Means";
        row1 = 4 ;
    end ;

    if upcase(_name_) = "LINE5" then do ;
        comment = "p-value (one-sided)";
        row1 = 5 ;
    end ;

    Row =  input (strip(week) , 3. ) ;
    Col0  = Cat  ("Week " , Put (week , 3. ));

    Label col1 = "Elinzanetant 120mg vs. Placebo"
          Col0  = "Time";

run;

/*<Save estim-dataset for future use*/

data tlfmeta.&ds1._tot_&param._o2;
    set &ds1._tot;
    time="Week"||''||COMPBL(compress(label,'','kd'));
    label time="Time point";
RUN;


/* LS Means */
PROC SORT DATA=&ds2.;
    BY trt01pn avisitn  _imputation_;
RUN;

PROC MIANALYZE DATA=&ds2.;
    BY trt01pn avisitn;
    MODELEFFECTS estimate;
    STDERR stderr;
   ODS OUTPUT ParameterEstimates=&ds2._tot;
RUN;

/*<Save estim-dataset for future use*/

data tlfmeta.&param._lsmean_s;
    set &ds2._tot;
run;

DATA &ds2._tot ;
    set &ds2._tot;
 if avisitn in (1,4,8,12) then   avisitn = avisitn *10 ;
run;

data &ds2._tot;
    set &ds2._tot;
    *Display model based estimates +/- SEs for week 1, week 4 and week 12 -- Updated Sep8th*;
     where avisitn in (10 40 120);
    format avisitn z_avisit.  estimate 12.2 ;
    se_low=estimate-stderr;
    se_upp=estimate+stderr;
RUN;

data  table_l0 ;
    length line1 line2   $200. ;
    set &ds2._tot ;
    line1  = cat (strip(put(estimate,12.2)) , ' (', strip(put(StdErr,12.2)), ')');
    *line2  = cat (strip(put(se_low,12.2)) , ', ', strip(put(se_upp,12.2)) );
    *Updated here for 95% tables*;
    line2  = cat (strip(put(LCLmean,12.2)) , ', ', strip(put(UCLmean,12.2)) );
    Row = avisitn / 10 ;
    if Row ^= 8  ;

    keep trt01pn avisitn  Line:   Row ;
RUN;

proc sort data  = table_l0 ;
    by Row trt01pn ;
    format trt01pn ;
RUN;

proc transpose data =  table_l0
     out = t_l0  prefix = Col_;
    by Row   ;
    var  Line1 line2   ;
    id trt01pn;
RUN;


data t_l0  ;
    length Col0 comment col_100  col_101  $200. ;
    set t_l0 ;
    if upcase(_name_) = "LINE1" then do ;
        comment = "LS-Means (SE)";row1 = 1 ;
    end ;

    if upcase(_name_) = "LINE2" then do ;
        comment = "95% CI for LS-Means"; row1 = 2 ;
    end ;


    Col0  = Cat  ("Week ",  strip(Put (Row , 3. ))  );
    Label col_100 = "Elinzanetant 120mg"
          col_101 = "Placebo"
          Col0  = "Time";

run;

%IF %UPCASE(&ds3.) = MXPARMS %THEN %DO;
    PROC SORT DATA=&ds3. out=&ds3._sort;
        BY effect _imputation_;
    RUN;

    data &ds3._sort;
        set &ds3._sort(where=(upcase(effect)="TRT01PN*STUDYID" and DF ne .));
        label=effect;
    run;

    PROC MIANALYZE DATA=&ds3._sort;
        BY effect;
        MODELEFFECTS estimate;
        STDERR stderr;
    ODS OUTPUT ParameterEstimates=&ds3._tot;
    RUN;

    data p_value_interaction(keep=row p_value_interaction);
        set mxparms_tot;
        row = 999;
        p_value_interaction=strip(put(probt,pvalue6.4));
    RUN;

    DATA t_study_interaction(KEEP=row row1 col0 p_value_study_interaction);
        MERGE p_value_study p_value_interaction;
        BY row;
        ATTRIB p_value_study_interaction LABEL = "p-value study / study*treatment interaction";
        ATTRIB Col0 LABEL = "Time";
        Col0 = "Overall";
        row1 = 0;
        p_value_study_interaction = p_value_study || "/" || p_value_interaction;
    RUN;
%END;

/*Calculate n from anal-dataset, changed 02Oct2023 by KL*/
proc sort data=anal;by usubjid trt01pn region1n base;run;
proc transpose data=anal OUT=anal_trans ;
    by usubjid trt01pn region1n base;
    var Week_1 Week_4 Week_8 Week_12;
RUN;

DATA anal_trans;
    SET anal_trans;
    IF _name_='Week_1' THEN avisitn=10;
    ELSE IF _name_='Week_4' THEN avisitn=40;
    ELSE IF _name_='Week_8' THEN avisitn=80;
    ELSE IF _name_='Week_12' THEN avisitn=120;

    rename col1=aval;
run;

PROC SQL;
    CREATE TABLE subjn (where = (avisitn ^= 80) ) AS
    SELECT COUNT(usubjid) as n,avisitn,trt01pn
    FROM anal_trans WHERE aval is not null /*12Sep2023 KL added where statement*/
    GROUP BY trt01pn,avisitn
    order by avisitn , trt01pn ;
QUIT;

proc transpose data =  subjn  out = t_0  prefix = Colp_;
    by avisitn   ;
    var  n   ;
    id trt01pn;
    format trt01pn ;
run;


data t_0  ;
    length Col0 comment col_100 col_101 $200. ;
    set t_0 ;
    if upcase(_name_) = "N" then comment = "n";

    Row = avisitn / 10 ;
    row1 = 0 ;
    col_100 = strip(put( Colp_100 , 4. ) ) ;
    col_101 = strip(put( Colp_101 , 4. ) ) ;  ;
    drop Colp_100 Colp_101 ;
    Col0  = Cat  ("Week ",  strip(Put ( (avisitn / 10) , 3. ))  );
run;


proc sql;
    create table bign  as
    select count(usubjid) as bign, trt01pn
    from adsl
    group by trt01pn
    order by   trt01pn ;

quit;

proc sort data = hfdd
     out = tby (keep = paramcd) nodupkey ;
    by paramcd ;
RUN;




%mend m_mmrm_rubin ;

%MACRO m_overview_100_patyears(
      indat          =
    , indat_adsl     =
    , indat_mosto    =
    , m_all_subjects = _mm_subject
    , delimiter_cond = #
    , by             =
    , class          = &mosto_param_class.
    , censordt       =
    , startdt        =
    , enddt          =
    , event_var      =
    , adt            =
    , outdat         =
    , debug          = NO
) / DES = 'Macro to calculate overview of number of subjects and study size and exposure-adjusted incidence rate';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Macro to calculate overview of number of subjects and study size and exposure-adjusted incidence rate.
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       : indat             : Input dataset
 *                    indat_adsl        : ADSL input dataset
 *                    indat_mosto       : Mosto output from %m_overview_tab_response
 *                    m_all_subjects    : Subject level incidence dataset M_ALL_SUBJECTS from %m_overview_tab_response which contains subject incidences
 *                    delimiter_cond    : Delimiter used for separating condition and label used in %m_overview_tab_response. Example: aesdth = 'Y' # AE with outcome death
 *                    by                : Subgroup by variable
 *                    class             : Treatment variable
 *                    censordt          : Censor date variable. Must exist in indat_adsl
 *                    startdt           : Time window start date. Must exist in indat_adsl
 *                    enddt             : Time window end date. Must exist in indat_adsl
 *                    event_var         : List of variables for events categorization
 *                    adt               : Event date. Must exist in indat
 *                    outdat            : Output dataset. If missing then print.
 *                    debug             : if DEBUG = YES then temporary datasets created in this macro are not deleted
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed: mosto_param_harmonized_outdat = yes
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : erjli (Yosia Hadisusanto) / date: 04JAN2024
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples:
 *
 * %overview_tab(
 *    data     = adae_ext
 *  , data_n   = adsl_ext
 *  , misstext = Missing
 *  , outdat   = out_table
 *  , freeline =
 *  , groups   =  "<DEL>"                                           * "<DEL>                                              # Number (%) of subjects with treatment-emergent adverse events"
 *                "not missing(aeterm)"                             * "not missing(aeterm)                                # Any AE"
 *                "not missing(aeterm)" * "<DEL>" * "max(asevn)"    * "<DEL>                                              # Maximum intensity for any AE"
 *                "aerel = 'Y'"                                     * "aerel = 'Y'                                        # Any study drug-related AE"
 *                "aerel = 'Y'" * "<DEL>" * "max(asevn)"            * "<DEL>                                              # Maximum intensity for study drug-related AE"
 *                "aerelpr = 'Y'"                                   * "aerelpr = 'Y'                                      # Any AE related to procedures required by the protocol"
 *                "not missing(aeacn)"                              * "<DEL>                                              # Action taken with study drug"  * 'aeacn' * 'aeacn # <DEL>'
 *                "assiny = 'Y'"                                    * "assiny = 'Y'                                       # Any AE of special safety interest**"
 *                "aeser = 'Y'"                                     * "aeser = 'Y'                                        # Any SAE"* "aesreas" * 'aesreas #  <DEL>'
 *                "aeser = 'Y' and aerel = 'Y'"                     * "aeser = 'Y' and aerel = 'Y'                        # Any study drug-related SAE"
 *                "aeser = 'Y' and aerelpr = 'Y'"                   * "aeser = 'Y' and aerelpr = 'Y'                      # Any SAE related to procedures required by the protocol"
 *                "aeser = 'Y' and aeacn = 'DRUG WITHDRAWN'"        * "aeser = 'Y' and aeacn = 'DRUG WITHDRAWN'           # Any SAE leading to discontinuation of study drug"
 *                "aeser = 'Y' and not missing(aeacn)"              * "<DEL>                                              # Action taken with SAE"  * 'aeacn' * "aeser = 'Y' and aeacn # <DEL>"
 *                "aesdth = 'Y'"                                    * "aesdth = 'Y'                                       # AE with outcome death"
 * )
 *
 * %m_overview_100_patyears(
 *    indat       = adae_ext
 *  , indat_adsl  = adsl_ext
 *  , indat_mosto = out_table
 *  , censordt    = cnsrdt
 *  , startdt     = startdt
 *  , enddt       = enddt
 *  , event_var   = aedecod
 *  , adt         = astdt
 *  , outdat      = overall_eair_week52
 * );
 ******************************************************************************/
    %LOCAL macro mversion _starttime ;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes l_miss;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    %LET l_miss = %sysfunc(getoption(missing));

    OPTIONS NONOTES NOSOURCE NOFMTERR;
    OPTIONS MISSING='';

    %spro_check_param(name = indat          , type = DATA)
    %spro_check_param(name = indat_adsl     , type = DATA)
    %spro_check_param(name = indat_mosto    , type = DATA)
    %spro_check_param(name = m_all_subjects , type = DATA)
    %spro_check_param(name = delimiter_cond , type = ONE_OF # � $)
    %spro_check_param(name = by             , type = VARIABLES, data = indat_adsl, canBeEmpty = YES)
    %spro_check_param(name = class          , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = censordt       , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = startdt        , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = enddt          , type = VARIABLES, data = indat_adsl)
    %spro_check_param(name = event_var      , type = VARIABLES, data = indat)
    %spro_check_param(name = adt            , type = VARIABLES, data = indat)
    %spro_check_param(name = outdat         , type = text, canBeEmpty = YES)
    %spro_check_param(name = debug          , type = YESNO)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %* Pre-processing to cleanse and restructure 'indat_mosto' dataset;
    DATA m_indat_mosto;
        SET &indat_mosto.;
        IF index(_name_, "&delimiter_cond.") > 0 THEN _name_ = scan(_name_, 2, "&delimiter_cond.");
        IF strip(_name_) = '<DEL>' THEN DELETE;
    RUN;

    %* Duplicating the data for further processing;
    DATA m_indat_mostoinp;
        SET &indat_mosto.inp;
    RUN;

    %* Cleaning and restructuring 'm_all_subjects' dataset: _name_cond # _mergevar1_;
    DATA m__all_subjects;
        SET &m_all_subjects.;
        ATTRIB _name_cond LENGTH=$200;

        IF UPCASE(_mergevar1_) NOT IN ('DUMMY FOR BIG N');
        IF NOT missing(_mergevar3_) THEN _name_cond = cats(scan(_mergevar1_, 1, "&delimiter_cond."),'=', '"',_mergevar3_, '"');
        ELSE                             _name_cond = scan(_mergevar1_, 1, "&delimiter_cond.");

        _name_ = scan(_mergevar1_, 2, "&delimiter_cond.");

        IF index(_name_cond, '<DEL>') > 0   THEN DELETE;

        _order_ = _mergeid_;
    RUN;

    %* Extracting distinct name conditions, which contains the condition for each event;
    PROC SQL;
        CREATE TABLE m_name_cond AS
        SELECT DISTINCT _name_cond, _order_
        FROM m__all_subjects;
    QUIT;

    %* Preparing the call_execute statement to create ADTTE observations for each distinct name condition;
    DATA m_call;
        SET m_name_cond;
        ATTRIB call_execute LENGTH=$1000.;
        call_execute =  '%create_adtte_obs'
                     !! '('
                     !! "  indat        = &indat."
                     !! ", subjdat      = &indat_adsl"
                     !! ", outdat       = m_adtte_out" !! strip(vvalue(_N_))
                     !! ", startdt      = &startdt."
                     !! ", enddt        = &enddt."
                     !! ", censor_date  = &censordt."
                     !! ", censor_desc  = 'CENSORED'"
                     !! ", event_var    = &event_var."
                     !! ", event_select = " !! strip(_name_cond)
                     !! ", adt          = &adt."
                     !! ", avisitn      = " !! strip(vvalue(_order_))
                     !! ", paramcd      = EVENT"
                     !! ')'
                     ;
    RUN;

    %* Run call execute;
    DATA _NULL_;
        SET m_call;
        CALL execute('%nrstr(' !! strip(call_execute) !! ')');
    RUN;

    %* Stack all m_out datasets;
    DATA m_adtte_stack;
        SET m_adtte_out:;
        RENAME avisitn=_order_;
    RUN;

    %* Calculate exposure-adjusted incidence rate;
    %m_exp_adj_inc_rate(
        indat       = m_adtte_stack
      , indat_adsl  = &indat_adsl.
      , indat_mosto = m_indat_mosto
      , by          = &by. _order_
      , class       = &class.
      , outdat      = &outdat.
      , debug       = YES
    )

    %* Delete all datasets with prefix m_ except M_ALL_SUBJECTS;
    %IF %upcase(%substr(&debug.,1,1)) NE Y %THEN %DO;

        PROC SQL NOPRINT;
            SELECT memname
            INTO :ds_to_delete SEPARATED BY ' '
            FROM dictionary.tables
            WHERE  libname =    'WORK'
               AND memname LIKE 'M_%'
               AND upcase(memname) NE %upcase("&m_all_subjects.");
        QUIT;

        PROC DATASETS LIBRARY=work NOLIST NOWARN;
            DELETE &ds_to_delete.;
        RUN;

    %END;

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    OPTION MISSING="&l_miss.";
    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )

%MEND m_overview_100_patyears;

