    %spro_check_param(name = outdat         , type = text, canBeEmpty = YES)
    %spro_check_param(name = debug          , type = YESNO)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %* Pre-processing to cleanse and restructure 'indat_mosto' dataset;
    DATA m_indat_mosto;
        SET &indat_mosto.;
        IF index(_name_, "&delimiter_cond.") > 0 THEN _name_ = scan(_name_, 2, "&delimiter_cond.");
        IF strip(_name_) = '<DEL>' THEN DELETE;
    RUN;

    %* Duplicating the data for further processing;
    DATA m_indat_mostoinp;
        SET &indat_mosto.inp;
    RUN;

    %* Cleaning and restructuring 'm_all_subjects' dataset: _name_cond # _mergevar1_;
    DATA m__all_subjects;
        SET &m_all_subjects.;
        ATTRIB _name_cond LENGTH=$200;

        IF UPCASE(_mergevar1_) NOT IN ('DUMMY FOR BIG N');
        IF NOT missing(_mergevar3_) THEN _name_cond = cats(scan(_mergevar1_, 1, "&delimiter_cond."),'=', '"',_mergevar3_, '"');
        ELSE                             _name_cond = scan(_mergevar1_, 1, "&delimiter_cond.");

        _name_ = scan(_mergevar1_, 2, "&delimiter_cond.");

        IF index(_name_cond, '<DEL>') > 0   THEN DELETE;

        _order_ = _mergeid_;
    RUN;

    %* Extracting distinct name conditions, which contains the condition for each event;
    PROC SQL;
        CREATE TABLE m_name_cond AS
        SELECT DISTINCT _name_cond, _order_
        FROM m__all_subjects;
    QUIT;

    %* Preparing the call_execute statement to create ADTTE observations for each distinct name condition;
    DATA m_call;
        SET m_name_cond;
        ATTRIB call_execute LENGTH=$1000.;
        call_execute =  '%create_adtte_obs'
                     !! '('
                     !! "  indat        = &indat."
                     !! ", subjdat      = &indat_adsl"
                     !! ", outdat       = m_adtte_out" !! strip(vvalue(_N_))
                     !! ", startdt      = &startdt."
                     !! ", enddt        = &enddt."
                     !! ", censor_date  = &censordt."
                     !! ", censor_desc  = 'CENSORED'"
                     !! ", event_var    = " !! scan(_name_cond,1,'=')
                     !! ", event_select = " !! strip(_name_cond)
                     !! ", adt          = &adt."
                     !! ", avisitn      = " !! strip(vvalue(_order_))
                     !! ", paramcd      = EVENT"
                     !! ')'
                     ;
    RUN;

    %* Run call execute;
    DATA _NULL_;
        SET m_call;
        CALL execute('%nrstr(' !! strip(call_execute) !! ')');
    RUN;

    %* Stack all m_out datasets;
    DATA m_adtte_stack;
        SET m_adtte_out:;
        RENAME avisitn=_order_;
    RUN;

    %* Calculate exposure-adjusted incidence rate;
    %m_exp_adj_inc_rate(
        indat       = m_adtte_stack
      , indat_adsl  = &indat_adsl.
      , indat_mosto = m_indat_mosto
      , by          = &by. _order_
      , class       = &class.
      , outdat      = &outdat.
      , debug       = YES
    )

    %* Delete all datasets with prefix m_ except M_ALL_SUBJECTS;
    %IF %upcase(%substr(&debug.,1,1)) NE Y %THEN %DO;

        PROC SQL NOPRINT;
            SELECT memname
            INTO :ds_to_delete SEPARATED BY ' '
            FROM dictionary.tables
            WHERE  libname =    'WORK'
               AND memname LIKE 'M_%'
               AND upcase(memname) NE %upcase("&m_all_subjects.");
        QUIT;

        PROC DATASETS LIBRARY=work NOLIST NOWARN;
            DELETE &ds_to_delete.;
        RUN;

    %END;

