    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* Put your macro code here!;
    DATA tmp_indatx;
        SET &indat.;
    RUN;
    %local O_3;
    %let O_3=N;
    proc sql noprint;
        select count(*) into :n_o3 trimmed
               from tmp_indatx
               where studyid='21810'
               ;
    QUIT;
    %if &n_o3.>0 %then %let O_3=Y;

    PROC SQL NOPRINT;
        *< SUBJ_LST: Get subject list with visits after week 12 and before EOT;
        SELECT DISTINCT usubjid INTO :subj_lst SEPARATED BY '", "'
               FROM sp.sv
               WHERE 85<visitnum<352
               ;
        *<SUBJ_o3_lst: Get subject list with visit on/after week 12 and before EOT for OASIS-3 study;
        %if &O_3.=Y %then %do;
        SELECT DISTINCT usubjid INTO :subj_o3_lst SEPARATED BY '", "'
               FROM SP.SV
               WHERE studyid='21810' AND 85<=visitnum<352  /*AND epoch='TREATMENT'*/ AND svoccur = 'Y';
        %end;
        %else %let subj_o3_lst=%str( );

        *< Create a dataset with week 12 visit for OASIS studies;
        CREATE TABLE sv_w12 AS
        SELECT studyid,usubjid,svstdtc
              FROM sp.sv
              WHERE visitnum =85 AND studyid IN ('21651','21652','21810')
              ORDER BY studyid,usubjid
              ;

        CREATE TABLE sv_w12_s AS
        SELECT studyid,usubjid,svstdtc
              FROM sp.sv
              WHERE visitnum =85 AND studyid IN ('21651','21652')
              ORDER BY studyid,usubjid
              ;

        CREATE TABLE sv_w16_s AS
        SELECT studyid,usubjid,svstdtc
              FROM sp.sv
              WHERE visitnum =106 AND studyid IN ('21651','21652')
              ORDER BY studyid,usubjid
              ;

        CREATE TABLE sv_w20_s AS
        SELECT studyid,usubjid,svstdtc
              FROM sp.sv
              WHERE visitnum =134 AND studyid IN ('21651','21652')
              ORDER BY studyid,usubjid
              ;
        CREATE TABLE sv_w12_trt AS
        SELECT studyid,usubjid,svstdtc
              FROM sp.sv
              WHERE visitnum =85 AND studyid IN ('21810') and svoccur='Y' and epoch='TREATMENT'
              ORDER BY studyid,usubjid
              ;
        *< Get week 16/18 data from O3;
        CREATE TABLE sv_w18 AS
        SELECT studyid,usubjid,svstdtc
              FROM sp.sv
              WHERE visitnum =120 AND studyid IN ('21810')
              ORDER BY studyid,usubjid
              ;
        CREATE TABLE sv_w18_trt AS
        SELECT studyid,usubjid,svstdtc
              FROM sp.sv
              WHERE visitnum =120 AND studyid IN ('21810') and svoccur='Y' and epoch='TREATMENT'
              ORDER BY studyid,usubjid
              ;
        *< Get EOT data from O3;
        CREATE TABLE sv_eot AS
        SELECT studyid,usubjid,svstdtc
              FROM sp.sv
              WHERE visitnum =600000 AND studyid IN ('21810')
              ORDER BY studyid,usubjid
              ;
        CREATE TABLE sv_eot_trt AS
        SELECT studyid,usubjid,svstdtc
              FROM sp.sv
              WHERE visitnum =600000 AND studyid IN ('21810') and svoccur='Y' and epoch='TREATMENT'
              ORDER BY studyid,usubjid
              ;

    QUIT;

    DATA _adsl;
        SET ads.adsl(KEEP=studyid usubjid ph2sdt trt01an trt02an trtsdt trtedt);
    RUN;
    PROC SORT DATA=_adsl;
        BY studyid usubjid;
    RUN;

    PROC SORT DATA=tmp_indatx;
        BY studyid usubjid;
    RUN;

    DATA tmp_indatx;
        MERGE tmp_indatx(IN=a) _adsl sv_w12(RENAME=(svstdtc=_svw12)) sv_w18(RENAME=(svstdtc=_svw18))
              sv_eot(RENAME=(svstdtc=_sveot))
              sv_w12_trt(RENAME=(svstdtc=_svw12_t)) sv_w18_trt(RENAME=(svstdtc=_svw18_t))
              sv_eot_trt(RENAME=(svstdtc=_sveot_t))
              sv_w16_s(rename=(svstdtc=_sv_w16_s))
              sv_w20_s(rename=(svstdtc=_sv_w20_s))
              ;
        BY studyid usubjid;
        IF a;
        FORMAT sv_w12 sv_w18 sv_eot sv_w12_t sv_w18_t sv_eot_t sv_w16_s sv_w20_s date9.;
        IF NOT missing(_svw12) THEN sv_w12=input(_svw12,yymmdd10.);
        IF NOT missing(_svw18) THEN sv_w18=input(_svw18,yymmdd10.);
        IF NOT missing(_sveot) THEN sv_eot=input(_sveot,yymmdd10.);

        IF NOT missing(_svw12_t) THEN sv_w12_t=input(_svw12_t,yymmdd10.);
        IF NOT missing(_svw18_t) THEN sv_w18_t=input(_svw18_t,yymmdd10.);
        IF NOT missing(_sveot_t) THEN sv_eot_t=input(_sveot_t,yymmdd10.);

        IF NOT missing(_sv_w16_s) THEN sv_w16_s=input(_sv_w16_s,yymmdd10.);
        IF NOT missing(_sv_w20_s) THEN sv_w20_s=input(_sv_w20_s,yymmdd10.);
