            *Include all available scheduled visits from baseline up to and including IA visit "Week 12/14";
            IF 5<=avisitn<=121 THEN
            %scan(&aflag_list, 1, %str( )) ='Y';
            IF adt>ph2sdt>. and %scan(&aflag_list, 1, %str( )) ='Y' and trt02an=53 then call missing(%scan(&aflag_list, 1, %str( )) );

            *For FU: always shown no matter when happened;
            IF 600000<avisitn<900000 THEN DO;
