            *For Eot and UNS: if not start open label phase/phase 2, missing PH2SDT means not start open label phase;
            IF avisitn IN (600000) THEN DO;
                IF missing(ph2sdt) THEN
                    %scan(&aflag_list, 1, %str( ))='Y';
