                IF sv_w16_s<ph2sdt<=sv_w20_s and 161<avisitn<600000 THEN
                    %scan(&aflag_list, 2, %str( ))='Y';
                *Switch > week 20 and <= week 26, week 26 will be used;
                IF ph2sdt>sv_w20_s and 200<avisitn<600000 THEN
                    %scan(&aflag_list, 2, %str( ))='Y';
                *For Eot;
                IF avisitn in (600000,700000) AND NOT missing(ph2sdt) THEN DO;
                    IF adt>ph2sdt /*AND usubjid IN ("&subj_lst")*/ THEN
                        %scan(&aflag_list, 2, %str( )) ='Y';
                END;
                *For UNS;

/*                IF avisitn=900000 AND &overall_aflag='Y' AND NOT missing(ph2sdt) THEN DO;*/
/*                    IF adt>ph2sdt *//*AND usubjid IN ("&subj_lst")*//* THEN*/
/*                        %scan(&aflag_list, 2, %str( )) ='Y';*/
/*                END;*/
            END;
        END;
