                            W
                          , "Week 12/14 visit happened after PH2SDT: " ADT= PH2SDT=
                          , messageType = DS
                        )
                        ;
                    END;
                END;
            END;
        %END;

    RUN;

    *<For post-baseline flag anl04fl, anl05fl, anl06fl, anl07fl;
    %IF %upcase(&post_base_list.)=Y %THEN %DO;
        DATA &outdat.;
            SET &outdat.;
            %createCustomVars(
                adsDomain = &adsdomain.
              , vars      = anl04fl anl05fl anl06fl anl07fl
            )
            ;
            * ANL07FL: for week 1-52 measurements before TRTSDT are excluded;
            *<SWITCH-1 and OASIS-3: measurement before TRTSDT are excluded.;
            IF studyid IN ('21686','21810') AND not (missing(aval) and missing(avalc)) THEN DO;
                IF ADT>TRTSDT>. THEN anl07fl='Y';
                if ablfl ne 'Y' and adt=trtsdt and adt>. then anl07fl='Y';
            END;

            *<OASIS1-2;
            IF studyid IN ('21651','21652') and not (missing(aval) and missing(avalc)) THEN DO;
                *start double-blind phase with EZN;
                IF trt01an=53 then do;
                    if adt>trtsdt>. THEN anl07fl='Y';
                    if ablfl ne 'Y' and adt=trtsdt and adt>. then anl07fl='Y';
                END;

                *start double-blind phase with PLB;
                IF trt01an=9901 AND trt02an=53 AND adt>ph2sdt>. THEN anl07fl='Y' ;
            END;

            *<ANL06FL for week 1-26 from study OASIS-3;
            IF studyid IN ('21810') and not (missing(aval) and missing(avalc)) THEN DO;
                IF ANL07FL='Y' AND ADY<=182 THEN anl06fl='Y';
            END;
            ELSE DO;
                ANL06FL=ANL07FL;
            END;

            *<ANL04FL: for week 1-12;
            *SWITCH-1:  measurements before TRTSDT are excluded;
            IF studyid='21686' AND not (missing(aval) and missing(avalc)) THEN do;
                if adt>trtsdt>. then anl04fl='Y';
                if ablfl ne 'Y' and adt=trtsdt and adt>. then anl04fl='Y';
            end;

            ELSE IF studyid IN ('21651','21652') AND not (missing(aval) and missing(avalc))  THEN DO;
                *OASIS studies - subjects who did not start Open Label phase/phase 2: measurements before TRTSDT are excluded;
                IF missing(ph2sdt) THEN DO;
                    IF adt>trtsdt>. THEN anl04fl='Y';
                    if ablfl ne 'Y' and adt=trtsdt and adt>. then anl04fl='Y';
                END;
                *OASIS studies - subjects who started Open Label phase/phase 2: measurements before TRTSDT and after the start day of open-label (PH2SDT ) phase are excluded.;
                ELSE DO;
                    *measurements before TRTSDT and after the start day of open-label (PH2SDT ) phase are excluded.;
                    IF trtsdt<adt<=ph2sdt THEN anl04fl='Y';
                    if ablfl ne 'Y' and adt=trtsdt and adt>. then anl04fl='Y';
                    *if EOT/UNS visit happened after PH2SDT but no other regular visit after week 12/14;
                    /*
                    IF avisitn IN (600000, 900000) THEN DO;
                        IF adt>=trtsdt>. AND usubjid NOT IN ("&subj_lst.") THEN anl04fl='Y';
                    END;
                    */
                END;

                *<for PLA-EZN switchers;
                IF trt02an=53 AND NOT missing(ph2sdt) THEN DO;
                    IF adt>ph2sdt>. /*AND usubjid IN ("&subj_lst")*/ THEN anl05fl ='Y';
                END;
            END;

            *For 21810;
            ELSE IF STUDYID='21810' AND not (missing(aval) and missing(avalc)) THEN DO;
                if ablfl ne 'Y' and adt=trtsdt and adt>. then anl04fl='Y';
                **?When week12/14 is available;
                if not missing(sv_w12) then do;
                    if .<trtsdt<adt<=sv_w12 THEN anl04fl ='Y';;
                END;
                **?When week 12/14 is not available;
                ELSE DO;
                    ***?Not complete treatment and no visit after week 12/14;
                    IF usubjid NOT IN ("&subj_o3_cmp_lst") AND usubjid NOT IN ("&subj_o3_lst") AND adt>trtsdt>. THEN anl04fl ='Y';
                    ***?Not complete treatment and no visit week 12/14 but have other scheduled visit;
                    IF usubjid NOT IN ("&subj_o3_cmp_lst") AND .<trtsdt<adt AND adt<=sv_eot THEN anl04fl='Y'; ;
                END;

            END;

        RUN;

    %END;

    PROC DELETE data=tmp_indatx _adsl;

    RUN;
    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )

%MEND m_phase_anlxfl;

%MACRO m_phase_extrime(
       indat             =
     , adsdomain         =
     , outdat            =
     , paramlist         =
     , by                =
     , criteria_func     =max(aval)
     , criteria_var_text =
)
/ DES = 'Derive the extrime criteria by phase';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: SWAN pure sas
 *******************************************************************************
 * Purpose          : Derive the extrime criteria by phase
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat : the input dataset
 *                    outdat : the output dataset
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gdcpl (Derek Li) / date: 12FEB2024
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_phase_extrime(
           indat=advs
         , outdat=advs
         , paramlist=paramcd in ('SYSBP' 'DIABP')
         , by=studyid usubjid paramcd
         , criteria_func=max(aval)
         ,criteria_var_text=1#ANL04FL#MAX POST BASELINE VALUE DURING PHASE 1
                            @2#ANL05FL#MAX POST BASELINE VALUE DURING PHASE 2
                            @3#ANL06FL#MAX POST BASELINE VALUE

   );
 ******************************************************************************/

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name = indat, type = data)
    %spro_check_param(name = outdat, type = data)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;
    %IF %bquote(&adsdomain.)=%str( ) %THEN %LET adsdomain=&indat.;
    %* Put your macro code here!;
    DATA _temp0;
        SET &indat.;
    RUN;

    DATA _temp1 _temp2;
        SET _temp0;
        IF  &paramlist. THEN output _temp1;
        ELSE OUTPUT _temp2;
    RUN;
    %LOCAL v sqlbyvar lastby;
    %LET v=1;
    %LET lastby = %scan(&by.,-1,%str( ));

    %DO %WHILE(%scan(&by.,&v,%str( )) NE );
        %IF &v.=1 %THEN %LET sqlbyvar=%scan(&by.,&v.,%str( ));
        %ELSE %LET sqlbyvar=&sqlbyvar., %scan(&by.,&v.,%str( ));
        %LET v=%eval(&v.+1);
    %END;
    %LOCAL i;
    %DO i=1 %TO 4;
        %LOCAL _crit_full _crit _crit_txt _anl;
        %LET _crit_full=%scan(&criteria_var_text.,&i.,@);
        %LET _crit=%scan(&_crit_full,1,#);
        %LET _crit_txt=%scan(&_crit_full,3,#);
        %LET _anl=%scan(&_crit_full,2,#);
        PROC SQL;
            CREATE TABLE _temp1_01 AS
                   SELECT *,&criteria_func. AS _flagav
                   FROM _temp1
                   GROUP BY &sqlbyvar.,&_anl.
                   ;
        QUIT;

        DATA _temp1(drop=_flagav);
            SET _temp1_01;
            %createCustomVars(
                adsDomain = &adsdomain.
              , vars      = crit&_crit. crit&_crit.fl
            )
            ;

            IF aval=_flagav and &_anl='Y' THEN DO;
                crit&_crit.="&_crit_txt";
                crit&_crit.fl='Y';
            END;
        RUN;

        PROC SORT DATA=_temp1;
            BY &by.;
        RUN;
        PROC DELETE data=_temp1_01;

        RUN;
    %END;


    DATA _temp3;
        SET _temp1 _temp2;
    RUN;
    PROC SORT DATA=_temp3 OUT=&outdat.;
        BY &by.;
    RUN;

    PROC DATASETS LIB=work mtype=data;
        DELETE _temp:;
    QUIT;

    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )

%MEND m_phase_extrime;

%MACRO m_propit(var=,exlow=,addlow=,fflag=Y,uplist=)
       / DES = 'Change race and ethnicity in required format';
/*******************************************************************************
