%MACRO m_select_subject( indat          =
                       , outdat         = &indat.
                       , refdat         = SP.DM
                       , subjvar        = USUBJID
                       , where          = ARMCD IN ('ELIN120' 'PLA' 'PLA_ELIN120')
                       , wherescrnfail  = ARMCD IN ('SCRNFAIL')
                       , removescrnfail = Y
                       ) / DES = 'Filter dataset by subjects - depends on armcd';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Filter dataset by subjects - depens on armcd
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *     indat         : in dataset
 *     outdat        : out dataset
 *     refdat        : reference dataset                                      (default: SP.DM)
 *     subjvar       : subject variable                                       (default: USUBJID)
 *     where         : where statement to KEEP all the subject                (default: ARMCD IN ('ELIN120' 'PLA' 'PLA_ELIN120'))
 *     wherescrnfail : where statement to get all screen failure subjects     (default: ARMCD IN ('SCRNFAIL'))
 *     removescrnfail: Y                                                      (default: Y)
 * SAS Version      : Linux 9.4
 *
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 16AUG2023
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_select_subject();
 ******************************************************************************/

%*** Sorting data and filter as needed;
PROC SORT DATA = &indat.     OUT = tss_001_indat                                 PRESORTED; BY &subjvar.; RUN;
PROC SORT DATA = &refdat.    OUT = tss_001_scrnfail  (WHERE = (&wherescrnfail.)) PRESORTED; BY &subjvar.; RUN;
PROC SORT DATA = &refdat.    OUT = tss_001_select    (WHERE = (&where.))         PRESORTED; BY &subjvar.; RUN;

%*** Filter subject;
DATA &outdat.;
    MERGE tss_001_indat        (IN = _data)
          tss_001_select       (IN = _keep KEEP = &subjvar.)
          tss_001_scrnfail     (IN = _scfl KEEP = &subjvar.)
          ;
    BY &subjvar.;
    IF _data;
    %IF &removescrnfail. = Y %THEN %DO;
        IF _scfl THEN DELETE;
        IF _keep;
    %END;
    %ELSE %DO;
        IF _keep or _scfl;
    %END;
RUN;

%PUT %STR(NO)TE: %dsattrn(dataset = &indat. , attrib = NOBS) has been read from INDAT (&indat.));
%PUT %STR(NO)TE: %dsattrn(dataset = &outdat., attrib = NOBS) has been written to OUTDAT (&outdat.));

%MEND m_select_subject;

%MACRO m_svisit2avisit(indat=ads.&adsDomain.,outdat=ads.&adsDomain., EOT=WEEK26)
/ DES = 'MACRO FOR CREATING AVISIT OUT OF VISIT INFORMATION';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: SPro
 *******************************************************************************
 * Purpose          : MACRO FOR CREATING AVISIT OUT OF VISIT INFORMATION
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat  : input data
 *                    outdat : output data
 *                    EOT    : Choose between values EOT or WEEK26
 *                              EOT    : Map VISITNUM=600000 to avisitn= 600010 (Week 26/End of trial)
 *                              WEEK26 : Map VISITNUM=600000 to avisitn= 260 (Week 26)
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 30JAN2024
 * Reference prog   : /var/swan/root/bhc/3427080/21651/stat/main01/prod/analysis/macros/m_visit2avisit.sas
 *******************************************************************************
 * Change History   :
 ******************************************************************************/



/*******************************************************************************
 * Examples         :
   %m_visit2avisit();
 ******************************************************************************/

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name=indat, type=DATA)
    %spro_check_param(name=outdat, type=DATA)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
            INFO
          , Version &mversion started
          , addDateTime = Y
          , messageHint = BEGIN)

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;



    /********************************************************************/
    /* Start */
    /********************************************************************/
    /*< AVISITN Analysis Visit (N)*/
    /****
     * AVISITN contains the visit number as observed (i.e., from SDTM VISITNUM), derived visit numbers, time window numbers, conceptual
    description numbers (such as Average, Endpoint, etc.), or a combination of any of these. Has to be defined in SAP/TLF.
     ***/
    DATA &outdat.;
        SET &indat;

/**** Visit mapping for study 21651 and 21652 ************/

    IF studyid in ("21651" "21652") THEN DO;

        %createcustomvars(adsDomain=&adsDomain., vars=avisitn);
        /* for now, take codes from visitnum */
        avisitn = .;
        /*for all ADS datasets where Visit needs to map to AVISITN*/

        IF      VISITNUM=0 then do;                  avisitn= 0; end;       /*Screening */
        ELSE IF VISITNUM=5 then do;                  avisitn= 5; end;    /*Baseline*/
        ELSE IF VISITNUM=10 then do;                 avisitn= 40; end;   /*Week 4*/
        ELSE IF VISITNUM=20 then do;                 avisitn= 80; end;    /*Week 8*/
        ELSE IF VISITNUM=30 then do;                 avisitn= 120; end;    /*Week 12*/
        ELSE IF VISITNUM=40 then do;                 avisitn= 160; end;    /*Week 16*/
        ELSE IF VISITNUM=50 then do;                 avisitn= 200; end;    /*Week 20*/
        ELSE IF VISITNUM=500000 then do;             avisitn= 500000; end;    /*Close liver observation*/
        ELSE IF VISITNUM=700000 then do;             avisitn= 700000; end;  /*ENDO.FUP visit*/
        ELSE IF VISITNUM=900000 then do;             avisitn= 900000; end;  /*Unscheduled*/
        ELSE IF VISITNUM=600000 then do;
            %IF %upcase(&EOT)=EOT %THEN %DO;          avisitn= 600010; %END;    /*Week 26/EOT*/
            %ELSE %IF %upcase(&EOT)=WEEK26 %THEN %DO; avisitn= 260; %END;  /*Week 26*/
        END;


END;



IF avisitn = . and "&adsDomain." ^= "ADQS" THEN DO;
     PUT "WARNING: AVISITN is missing. " _N_= usubjid= visitnum=;
END;



RUN;

OPTIONS &l_opts.;

%MEND m_svisit2avisit;

%MACRO m_switcher_avisit2(
       indat  =
     , trtvar =&mosto_param_class.
     , byvar  =paramcd
)
/ DES = 'Do the avisitn shift for switchers';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Do the avisitn shift for switchers
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat : the input dataset
 *                  :
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gdcpl (Derek Li) / date: 02APR2024
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_switcher_avisit2();
 ******************************************************************************/

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name = indat, type = dataset)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* Put your macro code here!;
    PROC sort data=&indat. out=all_visit(keep= avisitn) nodupkey;
        by  avisitn ;
        where 121<avisitn<360;
    RUN;


    proc sql;
        create table temp_dummy as
               select *
               from (select distinct studyid,usubjid,  &trtvar., &trtvar._ori
               %if %UPCASE(&byvar) ne USUBJID %then %do;
               ,  &byvar.
               %end;
                     from &indat.) as a, all_visit as b
               where 1=1
               ;

    QUIT;

    proc sort data=&indat;
        by studyid usubjid  &trtvar. &trtvar._ori &byvar. avisitn;
    RUN;

    proc sort data= temp_dummy;
        by  studyid usubjid  &trtvar. &trtvar._ori &byvar. avisitn;
    RUN;

    data _temp1;
        merge &indat.(in=a) temp_dummy(in=b);
        by  studyid usubjid  &trtvar. &trtvar._ori &byvar. avisitn;
        if b and not a then _del_flag=1;
    RUN;

    DATA _tp1 _tp2;
        SET _temp1;
        IF &trtvar. IN (6) AND &trtvar._ori=9901
           AND (121<avisitn<600000 ) THEN OUTPUT _tp1;
        ELSE OUTPUT _tp2;
    RUN;

    PROC SORT DATA=_tp1 PRESORTED;
        BY studyid usubjid &byvar. avisitn;
    RUN;
    %LET lastby=%SCAN(&byvar.,-1,%str( ));
    DATA _tp1;
        SET _tp1;
        BY studyid usubjid &byvar. avisitn;
        pre_av=lag(avisitn);
        IF FIRST.&lastby. THEN do;
            _ord=1;
            call missing(pre_av);
        END;
        ELSE _ord+1;
    RUN;

    DATA &indat.;
        SET _tp1(IN=a) _tp2;
        LABEL avisitn='IA visit';
        IF a THEN DO;
            IF _ord=1 THEN avisitn=40;*Week 4 (switcher);
            ELSE IF _ord=2 THEN DO;
                if round(avisitn,10)-round(pre_av,10)=40 then avisitn=80;*Week 8 (switcher);
                if round(avisitn,10)-round(pre_av,10)=80 then avisitn=121;*Week 12/14 (switcher);
            END;

            ELSE IF _ord=3 THEN avisitn=121;*Week 12/14 (switcher);
        END;
        if  _del_flag=1 then delete;
    RUN;

    PROC DELETE data=_tp1 _tp2;

    RUN;
    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:
    ;

    OPTIONS &l_opts.;
    %log(
        INFO
      , Version &mversion terminated.
      , addDateTime = Y
      , messageHint = END
    )
    %log(
        INFO
      , Runtime: %SYSFUNC(putn(%SYSFUNC(datetime())-&_starttime., F12.2)) seconds!
      , addDateTime = Y
      , messageHint = END
    )

%MEND m_switcher_avisit2;

%MACRO m_trtice() / DES = 'Create ICE parameters in ADEX';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: pure SAS
 *******************************************************************************
 * Purpose          : Create ICE parameters in ADEX
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gltlk (Rui Zeng) / date: 08OCT2023
 * Reference prog   : /var/swan/root/bhc/3427080/21652/stat/main01/dev/analysis/macros/m_trtice.sas (gmrpb (Fiona Yan) / date: 29JUN2023)
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_trtice();
 ******************************************************************************/

** Get subject latest date in study from ADSL.RFPENDT and ADSL.LVDT, whichever is later;
** If at least one of them is missing, generate a user warning and use today date before DBL;
** Once DBL, there should not be such warning;
** This date will be used to determine if subject enter relevant week window;
** If subject did not enter the week window, no ICE record will be created for the target week;
** There will be another check to remove ADEX ICE after permanent discontinuation of treatment in the end of this macro;
data adsl(keep=studyid usubjid day_end trtsdt);
    set ads.adsl(where=(randfl="Y" and not missing(trtsdt) and studyid in ('21651', '21652')));
    if nmiss(rfpendt,lvdt)>0 then do;
        day_end=today()-trtsdt+1; *ongoing subject;
        put "WARN" "ING: Subject=" USUBJID "is still in the study. Should not be the case once DBL.";
    END;
    else day_end=max(rfpendt,lvdt)-trtsdt+1;
RUN;

*< Intercurrent Events (ICEs): in Efficacy analysis for OASIS 1 and OASIS 2;
** ICE of temp treatment interruption (SAP section 6.5.1) - only for week 1,4,8,12;
data ec_80a ec_5_7a;
   set sp.ec;
   where eccat="STUDY INTERVENTION, DIARY" and ecdose>0 and ecoccur="Y" and studyid in ('21651', '21652'); *based on the eDiary;

   ** if actual date= planned date or if actual date=planned+1 and time up to 2am ;
   ** THEN dosing date=planned date, otherwise dosing date = actual date;
   if index(ECSTDTC,'T')>0 then do;
      if not (input(scan(ECSTDTC,2,'T'),time5.)>input('02:00',time5.)) then do;
          ECSTDTC= put(input(scan(ECSTDTC,1,'T'),yymmdd10.)-1,yymmdd10.);
          ecstdy=ecstdy-1;
      END;

   END;

   if 1<=ecstdy<=84 then output ec_80a; *to check 80% condition;
   if ecdose>0 then dose=1;
   if 2<=ecstdy<=8 or 15<=ecstdy<=28 or 43<=ecstdy<=56 or 71<=ecstdy<=84 then output ec_5_7a; *to check 5/7 days condition;
RUN;

proc sql;
    create table ec_80b_wk4 as
    select studyid, usubjid, sum(ecdose)/56 as comp_wk4
    from ec_80a
    where 1<=ecstdy<=28
    group by studyid, usubjid;

    create table ec_80b_wk8 as
    select studyid, usubjid, sum(ecdose)/112 as comp_wk8
    from ec_80a
    where 1<=ecstdy<=56
    group by studyid, usubjid;

    create table ec_80b_wk12 as
    select studyid, usubjid, sum(ecdose)/168 as comp_wk12
    from ec_80a
    where 1<=ecstdy<=84
    group by studyid, usubjid;
QUIT;

proc sort data=ec_5_7a;
    by studyid usubjid;
RUN;

proc transpose data=ec_5_7a out=ec_5_7b(drop=_:) prefix=day;
    by studyid usubjid;
    id ecstdy;
    var dose;
RUN;

** in case some subject do not have any dose since day 2 but received dose;
proc sort data=sp.ec out=ec_sub(keep=studyid usubjid) nodupkey;
    where eccat="STUDY INTERVENTION, DIARY" and ECMOOD="PERFORMED" and studyid in ('21651', '21652');
    by studyid usubjid;
RUN;

data ec_5_7b;
    merge ec_5_7b ec_sub;
    by studyid usubjid;

    if sum(of day2-day8, 0)>=5 then comp2_wk1=1;
    else comp2_wk1=0;
    comp2_wk4=0;
    comp2_wk8=0;
    comp2_wk12=0;

    array w4_day (14) day15-day28;
    array w8_day (14) day43-day56;
    array w12_day (14) day71-day84;

    do i=1 to 8;
        if sum(0,w4_day[i],w4_day[i+1],w4_day[i+2],w4_day[i+3],w4_day[i+4],w4_day[i+5],w4_day[i+6])>=5 then comp2_wk4+1;
        if sum(0,w8_day[i],w8_day[i+1],w8_day[i+2],w8_day[i+3],w8_day[i+4],w8_day[i+5],w8_day[i+6])>=5 then comp2_wk8+1;
        if sum(0,w12_day[i],w12_day[i+1],w12_day[i+2],w12_day[i+3],w12_day[i+4],w12_day[i+5],w12_day[i+6])>=5 then comp2_wk12+1;
    END;
RUN;

data ec;
    merge ec_80b_wk4 ec_80b_wk8 ec_80b_wk12 ec_5_7b(in=a keep=studyid usubjid comp2_wk:);
    by studyid usubjid;
RUN;

data ec2;  *may contain dummy, will be remove later using day_end;
    set ec;
    %createCustomVars(adsDomain=adex, vars = APHASE PARAMCD AVALC PARAMTYP);
    length reason $200;  *manual-assigned reason: may be replaced by ECADJ later if non-missing ECADJ in relevant week window;
    aphase="Week 1-12";
    paramtyp="DERIVED";

    ** week1: Treatment taken on <5/7 days;
    paramcd="TRTINW1";
    if comp2_wk1=1 then avalc="N";
    else do;
        avalc="Y";
        reason="< 5/7 Days";
    END;
    output;

    ** Week 4: Treatment taken <80% during weeks 1-4 OR treatment taken on <5/7 days during any 7-day during week 3/4;
    paramcd="TRTINW4";
    reason="";
    if comp2_wk4=8 and comp_wk4>=0.8 then avalc="N";
    else do;
        avalc="Y";
        if not (comp2_wk4=8) and not (comp_wk4>=0.8) then reason="< 80% Compliance and < 5/7 Days";
        else if not (comp2_wk4=8) then reason="< 5/7 Days";
        else reason="< 80% Compliance";
    END;
    output;

    ** Week 8: Treatment taken <80% during weeks 1-8 OR treatment taken on <5/7 days during any 7-day during week 7/8;
    paramcd="TRTINW8";
    reason="";
    if comp2_wk8=8 and comp_wk8>=0.8 then avalc="N";
    else do;
        avalc="Y";
        if not (comp2_wk8=8) and not (comp_wk8>=0.8) then reason="< 80% Compliance and < 5/7 Days";
        else if not (comp2_wk8=8) then reason="< 5/7 Days";
        else reason="< 80% Compliance";
    END;
    output;

    ** Week 12: Treatment taken <80% during weeks 1-12 OR treatment taken on <5/7 days during any 7-day during week 11/12;
    paramcd="TRTINW12";
    reason="";
    if comp2_wk12=8 and comp_wk12>=0.8 then avalc="N";
    else do;
        avalc="Y";
        if not (comp2_wk12=8) and not (comp_wk12>=0.8) then reason="< 80% Compliance and < 5/7 Days";
        else if not (comp2_wk12=8) then reason="< 5/7 Days";
        else reason="< 80% Compliance";
    END;
    output;
RUN;

** remove dummy;
proc sort data=ec2;
    by studyid usubjid paramcd;
RUN;

data ec3;
    merge ec2(in=a) adsl;
    by studyid usubjid;
    if a;
    if (paramcd="TRTINW1" and day_end>=2) or
       (paramcd="TRTINW4" and day_end>=15) or
       (paramcd="TRTINW8" and day_end>=43) or
       (paramcd="TRTINW12" and day_end>=71);
RUN;

** replace ECADJ with manual-assigned reason if ECADJ exist;
data ecadj;
    set sp.ec(keep=studyid usubjid ecadj ecstdy ecendy);
    where not missing(ecadj) and ecadj^="**";
    %createCustomVars(adsDomain=adex, vars = paramcd);

    if not (ecstdy>8 or .<ecendy<2) and nmiss(ecstdy,ecendy)<2 then do;
        paramcd="TRTINW1";
        output;
    END;

    if not (ecstdy>28 or .<ecendy<15) and nmiss(ecstdy,ecendy)<2 then do;
        paramcd="TRTINW4";
        output;
    END;

    if not (ecstdy>56 or .<ecendy<43) and nmiss(ecstdy,ecendy)<2 then do;
        paramcd="TRTINW8";
        output;
    END;

    if not (ecstdy>84 or .<ecendy<71) and nmiss(ecstdy,ecendy)<2 then do;
        paramcd="TRTINW12";
        output;
    END;
RUN;

proc sort data=ecadj nodupkey;
    by studyid usubjid paramcd ecadj;
RUN;

data ecadj;
    set ecadj;
    ** per shell update, want sentence case;
    ecadj=substr(ecadj,1,1)||lowcase(substr(ecadj,2));
RUN;

proc transpose data=ecadj out=ecadj2(drop=_:) prefix=ecadj;
    by studyid usubjid paramcd;
    var ecadj;
RUN;

data ec4;
    merge ec3(in=a) ecadj2;
    by studyid usubjid paramcd;
    if a;

    if avalc="Y" and not missing(ecadj1) then reason=catx(',', of ecadj:);
RUN;

** determine ASTDT (if <80% then start of the week window, if <5/7 only then the third 0 in the earliest 7-consecutive-day window);
data astdt;
    set ec_5_7b(drop=i);

    if sum(of day2-day8, 0)<5 then w1=2; *the start day of 7-consecutive-day condition for week1 is day 2;

    ** to determine the start day of the earliest 7-consecutive-day condition for week 4,8,12;
    array w4_day (14) day15-day28;
    array w8_day (14) day43-day56;
    array w12_day (14) day71-day84;

    w4=.;
    w8=.;
    w12=.;

    do i=1 to 8;
        if sum(0,w4_day[i],w4_day[i+1],w4_day[i+2],w4_day[i+3],w4_day[i+4],w4_day[i+5],w4_day[i+6])<5 and missing(w4) then w4=14+i;
        if sum(0,w8_day[i],w8_day[i+1],w8_day[i+2],w8_day[i+3],w8_day[i+4],w8_day[i+5],w8_day[i+6])<5 and missing(w8) then w8=42+i;
        if sum(0,w12_day[i],w12_day[i+1],w12_day[i+2],w12_day[i+3],w12_day[i+4],w12_day[i+5],w12_day[i+6])<5 and missing(w12) then w12=70+i;
    END;
RUN;

proc transpose data=astdt out=astdt2;
    by studyid usubjid w:;
    var day:;
RUN;

data astdt2;
    set astdt2;
    length day 8.;
    day=input(strip(substr(_name_,4)), 8.);
    if missing(col1) and (.<w1<=day<=sum(w1,6) or .<w4<=day<=sum(w4,6) or .<w8<=day<=sum(w8,6) or .<w12<=day<=sum(w12,6));
    if 2<=day<=8 then week=1;
    else if 15<=day<=28 then week=4;
    else if 43<=day<=56 then week=8;
    else if 71<=day<=84 then week=12;
RUN;

proc sort data=astdt2;
    by studyid usubjid week day;
RUN;

data astdt2;
    set astdt2;
    by studyid usubjid week day;
    if first.week then zero=1;
    else zero+1;
RUN;

data astdt3(keep=studyid usubjid paramcd day);
    set astdt2(where=(zero=3));
    %createCustomVars(adsDomain=adex, vars = paramcd);
    paramcd="TRTINW"||strip(put(week, best.));
RUN;

proc sort data=astdt3;
    by studyid usubjid paramcd;
RUN;

data ice_final;
    merge ec4(in=a) astdt3;
    by studyid usubjid paramcd;
    if a;

    %createCustomVars(adsDomain = adex, vars = astdt astdy parcat1 ice01fl icereas);
    parcat1="by eDiary";
    if avalc = "Y" then ice01fl = "Y";
    if ice01fl ="Y" then icereas = strip(reason);
    if comp_wk4<0.8 and paramcd="TRTINW4" then astdy=15;
    if comp_wk8<0.8 and paramcd="TRTINW8" then astdy=43;
    if comp_wk12<0.8 and paramcd="TRTINW12" then astdy=71;
    if missing(astdy) and avalc="Y" then astdy=day;
    if not missing(astdy) then astdt=astdy+trtsdt-1;
    format astdt date9.;
RUN;

/** Extra guidance from stat: after permanent discontinuation from treatment, there should be no ICE record of temporary treatment interruption **/
** get PD subjects from DS;
proc sort data=sp.ds out=pd_subj(keep=studyid usubjid);
    where epoch="TREATMENT" and dsdecod^="COMPLETED" and missing(dsscat);
    by studyid usubjid;
RUN;

** get last dosing date from ADSL.TRTEDT;
data ice_final(drop=trtedt randdt);
    merge ice_final(in=a) pd_subj(in=b) ads.adsl(keep=studyid usubjid trtedt randdt);
    by studyid usubjid;
    if a;

    if b and not missing(trtedt) then do;
        if (trtedt-randdt+1)<=1 and paramcd in ("TRTINW1" "TRTINW4" "TRTINW8" "TRTINW12") then delete;
        else if 1<(trtedt-randdt+1)<=14 and paramcd in ("TRTINW4" "TRTINW8" "TRTINW12") then delete;
        else if 14<(trtedt-randdt+1)<=42 and paramcd in ("TRTINW8" "TRTINW12") then delete;
        else if 42<(trtedt-randdt+1)<=70 and paramcd in ("TRTINW12") then delete;
    END;

documents.summary:
if b and missing(trtedt) then put "WARN" "NING:" usubjid "has permanent discontinued based on DS but no last dosing date available.";
RUN;

%MEND m_trtice;

documents.sourceText:
if b and missing(trtedt) then put "WARN" "NING:" usubjid "has permanent discontinued based on DS but no last dosing date available.";
RUN;

%MEND m_trtice;

%MACRO m_visit2avisit(
       indat   =
     , outdat  =
     , outvar  = AVISITN
     , subjvar = STUDYID USUBJID
) / DES = 'Derivation of AVISITN based on VISIT';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Filter dataset by subjects - depens on armcd
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *     indat        : in dataset
 *     outdat       : out dataset
 *     outvar       : output variable
 *     subjvar      : subject variable
 * SAS Version      : Linux 9.4
 *
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gdcpl (Derek Li) / date: 31JAN2024
 * Reference prog   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_visit2avisit(indat=advs,outdat=advs_01);
 ******************************************************************************/

%*** Step 1: Get data;
    DATA tvav_001_indat;
        SET &indat.;
        %*** Check if AVISITN already exist in INDAT;
        %*** If yes, drop this variable and re-derive;
        %IF %varnum(&indat., &outvar.) > 0 %THEN %DO;
            DROP &outvar.;
        %END;
    RUN;
    PROC SORT DATA=tvav_001_indat PRESORTED;
        BY &subjvar.;
    RUN;

    %*** Step 2: VISIT -> AVISIT definition;
    DATA tvav_010_def;
        SET tvav_001_indat;
        IF studyid IN ('21686') THEN DO;
            IF 0 <= visitnum < 1        THEN DO;
                &outvar. = 0;
            END;/*Screening visit*/
            ELSE IF      visitnum = 1        THEN DO;
                &outvar. = 5;
            END;/*Baseline visit*/
            ELSE IF      visitnum = 15       THEN DO;
                &outvar. = 20;
            END;/*Week 2 visit*/
            ELSE IF      visitnum = 29       THEN DO;
                &outvar. = 40;
            END;/*Week 4 visit*/
            ELSE IF      visitnum = 57       THEN DO;
                &outvar. = 80;
            END;/*Week 8 visit*/
            ELSE IF      visitnum = 85       THEN DO;
                &outvar. = 120;
            END;/*Week 12 visit*/
            ELSE IF      visitnum = 700000   THEN DO;
                &outvar. = 700000;
            END;/*ENDO.FUP visit*/
            ELSE IF      visitnum = 900000   THEN DO;
                &outvar. = 900000;
            END;/*Unscheduled*/
        END;

        IF studyid IN ('21651','21652') THEN DO;
            IF 0 <= visitnum < 1        THEN DO;
                &outvar. = 0;
            END;/*Screening visit*/
            ELSE IF      visitnum = 1        THEN DO;
                &outvar. = 5;
            END;/*Baseline visit*/
            ELSE IF      visitnum = 22       THEN DO;
                &outvar. = 40;
            END;/*Week 4 visit*/
            ELSE IF      visitnum = 50       THEN DO;
                &outvar. = 80;
            END;/*Week 8 visit*/
            ELSE IF      visitnum = 85       THEN DO;
                &outvar. = 120;
            END;/*Week 12 visit*/
            ELSE IF      visitnum = 106      THEN DO;
                &outvar. = 160;
            END;/*Week 16 visit*/
            ELSE IF      visitnum = 134      THEN DO;
                &outvar. = 200;
            END;/*Week 20 visit*/
            ELSE IF      visitnum = 500000   THEN DO;
                &outvar. = 500000;
            END;/*Close liver observation*/
            ELSE IF      visitnum = 600000   THEN DO;
                &outvar. = 600000;
            END;
            ELSE IF      visitnum = 700000   THEN DO;
                &outvar. = 700000;
            END;/*ENDO.FUP visit*/
            ELSE IF      visitnum = 900000   THEN DO;
                &outvar. = 900000;
            END;/*Unscheduled*/
        END;

        IF studyid IN ('21810') THEN DO;
            IF 0 <= visitnum < 1         THEN DO;
                &outvar. = 0;
            END;/*Screening visit*/
            ELSE IF      visitnum = 1         THEN DO;
                &outvar. = 5;
            END;/*Baseline visit*/
            ELSE IF      visitnum = 22        THEN DO;
                &outvar. = 40;
            END;/*Week 4 visit*/
            ELSE IF      visitnum = 50        THEN DO;
                &outvar. = 80;
            END;/*Week 8 visit*/
            ELSE IF      visitnum = 85        THEN DO;
                &outvar. = 120;
            END;/*Week 12 visit*/
            ELSE IF      visitnum = 120       THEN DO;
                &outvar. = 180;
            END;/*Week 18 visit*/
            ELSE IF      visitnum = 162       THEN DO;
                &outvar. = 240;
            END;/*Week 24 visit*/
            ELSE IF      visitnum = 197       THEN DO;
                &outvar. = 300;
            END;/*Week 30 visit*/
            ELSE IF      visitnum = 246       THEN DO;
                &outvar. = 360;
            END;/*Week 36 visit*/
            ELSE IF      visitnum = 281       THEN DO;
                &outvar. = 420;
            END;/*Week 42 visit*/
            ELSE IF      visitnum = 351       THEN DO;
                &outvar. = 520;
            END;/*Week 52 visit*/
            ELSE IF      visitnum = 500000    THEN DO;
                &outvar. = 500000;
            END;/*Close liver observation*/
            ELSE IF      visitnum = 600000    THEN DO;
                &outvar. = 600000;
            END;
            ELSE IF      visitnum = 700000    THEN DO;
                &outvar. = 700000;
            END;/*ENDO.FUP visit*/
            ELSE IF      visitnum = 900000    THEN DO;
                &outvar. = 900000;
            END;/*Unscheduled*/
        END;
    RUN;

    PROC SQL NOPRINT;
        SELECT DISTINCT usubjid INTO :subj_lst SEPARATED BY '", "'
               FROM tvav_010_def
               WHERE (studyid IN ('21651','21652') AND &outvar.=260)
               OR (studyid IN ('21810') AND &outvar.=520)
               ;
    QUIT;
    *setting per IA SAP;
    DATA _dscomp (KEEP = &SUBJVAR. DSSTDT_comp _complfl);
        SET sp.ds;
        FORMAT _complfl $1.;
        IF     epoch   =   'TREATMENT'
           AND dscat   =   'DISPOSITION EVENT'
           AND dsdecod EQ  'COMPLETED'
           AND dsscat  NE  "INFORMED CONSENT" THEN DO;
           FORMAT DSSTDT_comp date9.;
           DSSTDT_comp = input(dsstdtc, ?? e8601da.);
           _complfl='Y';
           OUTPUT;
        END;
    RUN;

    PROC SORT DATA=_dscomp;
        BY &SUBJVAR.;
    RUN;

    DATA tvav_010_def     (DROP = _complfl);
        MERGE tvav_010_def  (IN = _data)
            _dscomp      (KEEP = &subjvar. _complfl);
        BY &subjvar.;

        IF _complfl='Y' AND visitnum = 600000
        %IF &sqlobs.>0 %THEN %DO;
            and usubjid NOT IN ("&subj_lst.")
        %END;
        THEN DO;
        IF studyid IN ('21651','21652') THEN &outvar. = 260;*week 26;
        IF studyid IN ('21810')         THEN &outvar. = 520;*week 52;
        END;

        IF _data;
    RUN;

    PROC DELETE DATA=_dscomp;

    RUN;

    *IA special visit setting;
    DATA tvav_030_def;
        SET tvav_010_def;
        IF &outvar. IN (120)     THEN &outvar. = 121;* Week 12/14 (switcher);
        IF &outvar. IN (160,180) THEN &outvar. = 161;* Week 16/18;
        IF &outvar. IN (240,260) THEN &outvar. = 241;* Week 24/26;
    RUN;

    %**** Check for missing AVISITN;
    PROC SORT NODUPKEY DATA = tvav_030_def
                       OUT  = tvav_040_check;
        BY visitnum visit &outvar.;
    RUN;

    %IF %dsattrn(dataset = tvav_040_check, attrib = NLOBS)>0 AND %upcase(&stage)=DEV %THEN %DO;
        DATA _NULL_;
            SET tvav_040_check(WHERE = (missing(&outvar.)));
            PUT "ERR" "OR: Missing definition of &outvar. " VISIT= VISITNUM=;
        RUN;
    %END;

    %*** Step 3: Store to outdat;
    DATA &outdat.;
        SET tvav_030_def;
    RUN;

    PROC DELETE data=tvav_030_def tvav_040_check tvav_010_def tvav_001_indat;

    RUN;



%MEND m_visit2avisit;

%MACRO m_wrap_risk_difference(
       indat           =
     , indat_adsl      =
     , m_all_subjects  = _mm_subject
     , class           = &mosto_param_class.
     , active          =
     , compare         =
     , keyvars         = studyid usubjid
     , stratum         = studyid
     , zero_exclusion  = YES
     , zero_term_rr    = 0.5
     , zero_term_rd    = 0
     , correction_type = STRATUM_SIZE
     , ci_level        = 0.05
     , het_p_display   = NO
     , stratum_type    = POOL
     , risk_ratio      = NO
     , outdat          =
     , debug           = NO
)/ MINOPERATOR DES = 'Wrapper macro to add risk difference and risk ratio';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: ###choose: TOSCA, initstudy, GMS, GDD, pure SAS###
 *******************************************************************************
 * Purpose          : Wrapper macro to add risk difference and risk ratio
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *                    indat             : Input dataset from outdat of %overview_tab or %incidence_print
 *                    indat_adsl        : Input ADSL dataset
 *                    m_all_subjects    : Subject level incidence dataset such as _MM_SUBJECT from %overview_tab / INC_PAT from %incidence_print which contains subject incidences
 *                    class             : Treatment variable
 *                    active            : Treatment code for the Active treatment
 *                    compare           : Treatment code for the comparator (usually Placebo)
 *                    keyvars           : Key variables to identify unique subjects, such as STUDYID, USUBJID
 *                    stratum           : Variable used for stratification
 *                    zero_exclusion    : Determination whether strata with zero total response (zero response in both arms) or zero total no response are excluded
 *                    zero_term_rr      : zero_term_rr (Zero Term for Risk Ratio)
 *                    zero_term_rd        zero_term_rd (Zero Term for Risk Difference)
 *                                        Both zero_term_rr/zero_term_rd are numeric value applied in continuity corrections for strata for which
 *                                        zero cell values prohibit calculations, i.e. more than one zero value
 *                                        leading to a marginal total of 1 in the respective treatment/control group.
 *                    correction_type   : Type of continuity correction: CONSTANT, STRATUM_SIZE
 *                    ci_level          : Specification of the confidence interval to be calculated. Default (0.05) means a 95% CI
 *                    het_p_display     : Determination whether display p-value of heterogeneity
 *                    stratum_type      : POOL: create Risk Difference and CIs based on stratified Mantel-Haenszel for Pool
 *                                        STUDY: create Risk Difference and CIs based on Wald for Study
 *                    outdat            : Output dataset. If missing then print.
 *                    debug             : if DEBUG=YES then temporary datasets created in this macro are not deleted
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed: MOSTO_PARAM_HARMONIZED_OUTDAT should be set to YES in order to have the same OUTDAT structure from Mosto macros
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         : For subgroup analysis it is assumed that PAGE parameter is used in %overview_tab/%incidence_print
 *******************************************************************************
 * Author(s)        : erjli (Yosia Hadisusanto) / date: 31AUG2023
 * Reference prog   :
 *******************************************************************************
 * Change History   :
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 08SEP2023
 * Reason           : Update to work with META_SUBJ created by %overview_tab
 ******************************************************************************/
/* Changed by       : gltlk (Rui Zeng) / date: 22NOV2023
 * Reason           : update default value for zero_exclusion, and replace zero_term with zero_term_rr and zero_term_rd
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
   %m_wrap_risk_difference(
 *     indat           = out_table
 *   , indat_adsl      = adsl_ext
 *   , class           = &mosto_param_class.
 *   , active          = &trt_ezn_12.
 *   , compare         = &trt_pla_12.
 *   , zero_term       = 0.5
 *   , correction_type = stratum_size
 *   , outdat          = out_table_riskdiff
 *   , debug           = YES
 *   , het_p_display   = NO
 * )
 ******************************************************************************/

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %* Save all input datasets into WORK for further processing;
    DATA m_indat;           SET &indat.;            RUN;
    DATA m_indat_adsl;      SET &indat_adsl.;       RUN;
    DATA m__all_subjects;   SET &m_all_subjects.;   RUN;

    %spro_check_param(name = indat          , type = DATA)
    %spro_check_param(name = indat_adsl     , type = DATA)
    %spro_check_param(name = m_all_subjects , type = DATA)
    %spro_check_param(name = class          , type = VARIABLES, data = m_indat_adsl)
    %spro_check_param(name = active         , type = text)
    %spro_check_param(name = compare        , type = text)
    %spro_check_param(name = keyvars        , type = VARIABLES, data = m_indat_adsl)
    %spro_check_param(name = stratum        , type = VARIABLES, data = m_indat_adsl)
    %spro_check_param(name = zero_exclusion , type = YESNO)
    %spro_check_param(name = zero_term_rr   , type = NUMBER)
    %spro_check_param(name = zero_term_rd   , type = NUMBER)
    %spro_check_param(name = correction_type, type = ONE_OF CONSTANT STRATUM_SIZE)
    %spro_check_param(name = ci_level       , type = NUMBER)
    %spro_check_param(name = het_p_display  , type = YESNO)
    %spro_check_param(name = stratum_type   , type = ONE_OF POOL STUDY)
    %spro_check_param(name = risk_ratio     , type = YESNO)
    %spro_check_param(name = outdat         , type = text, canBeEmpty = YES)
    %spro_check_param(name = debug          , type = YESNO)

    %IF %upcase(%substr(&mosto_param_harmonized_outdat.,1,1)) NE Y %THEN %DO;
        %log(E,MOSTO_PARAM_HARMONIZED_OUTDAT should be set to YES in order to have the same OUTDAT structure from OVERVIEW_TAB or INCIDENCE_PRINT, _macro=&macro.);
        %RETURN;
    %END;

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
        INFO
      , Version &mversion started
      , addDateTime = Y
      , messageHint = BEGIN
    )

    %LOCAL l_opts l_notes l_miss;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    %LET l_miss = %sysfunc(getoption(missing));

    OPTIONS NONOTES NOSOURCE NOFMTERR;
    OPTIONS MISSING='';

    %* Get INP dataset;
    %LOCAL _indatinp;
    %LET _indatinp = %sysfunc(strip(%scan(&indat., 1, '(')))inp;

    %* Get PAGE variable if available;
    %LOCAL by;
    %LET by = %getDataValueList(&_indatinp.(WHERE=(keyword = 'PAGE')), value);

    %* Pre-processing for INC_PAT, which is created by %INCIDENCE_PRINT;
    %IF _AEIND IN %upcase(%getvarlist(m__all_subjects)) %THEN %DO;

        PROC SQL NOPRINT;
            SELECT name INTO :_index_vars SEPARATED BY ' , '
            FROM sashelp.vcolumn
            WHERE   upcase(libname) = 'WORK'
                AND upcase(memname) = 'M_INDAT'
                AND upcase(name) LIKE '_IC_VAR%'
                ;
        QUIT;

        DATA m__all_subjects;
            SET m__all_subjects;
            ATTRIB _index_ LENGTH=$2000;
            _index_ = catx('#', &_index_vars.);
            IF _aeind = 1; %* Keep subjects only with incidences: _aeind = 1;
        RUN;

        DATA m_indat;
            SET m_indat;
            ATTRIB _index_ LENGTH=$2000;
            _index_ = catx('#', &_index_vars.);
