    %ELSE %IF _MERGEID_ IN %upcase(%getvarlist(m__all_subjects)) %THEN %DO;
        DATA m__all_subjects;
            SET m__all_subjects;
            ATTRIB _index_ LENGTH=$2000;
            _index_ = catx('#', vvalue(_mergeid_));
            &class. = class;
        RUN;

        DATA m_indat;
            SET m_indat;
            ATTRIB _index_ LENGTH=$2000;
            _index_ = catx('#', vvalue(_order_));
        RUN;
    %END;
    %ELSE %DO;
        %log(E,Value in parameter m_all_subjects is not valid!, _macro=&macro.);
        %RETURN;
    %END;

    %* Select only not missing _COL#_ from overview_tab/incidence_print;
    PROC SQL NOPRINT;
        SELECT catx(' ', 'not missing(', name, ')') INTO :not_missing_list SEPARATED BY ' AND '
        FROM sashelp.vcolumn
        WHERE   upcase(libname) = 'WORK'
            AND upcase(memname) = 'M_INDAT'
            AND upcase(name) LIKE '_COL%'
            ;
    QUIT;

    %* Join _index_ with selected ADSL variables;
    PROC SORT DATA = m_indat(WHERE=(&not_missing_list))
              OUT  = m_index(KEEP=_index_) NODUPKEY;
        BY _index_;
    RUN;

    %* Cartesian product to get every combination of _index_;
    DATA m_adsl_shell(KEEP= &keyvars &stratum. &class. &by. _index_);
        SET m_indat_adsl(WHERE=(&class. IN (&active., &compare.)));
        DO i = 1 TO n;
            %* For every observation in adsl_ext, read in each observation in _index_;
            SET m_index POINT=i NOBS=n;
            OUTPUT;
        END;
    RUN;

    %* m__all_subjects is created by %overview_tab;
    PROC SORT DATA = m__all_subjects OUT= m_all_subjects_sort;
        BY &keyvars. &stratum. &class. &by. _index_;
    RUN;

    %* Set response and non-response to all subjects data;
    DATA m_adsl_resp(KEEP=&keyvars. &stratum. &by. treatmgr _index_ response);
        MERGE m_adsl_shell          (IN = a)
              m_all_subjects_sort   (IN = b);
        BY &keyvars. &stratum. &class. &by. _index_;
        IF a;
        IF b THEN response = 1;
        ELSE      response = 0;

        ATTRIB treatmgr LABEL = "Treatment (active vs compare)" FORMAT = ny.;
             IF &class. = &active.  THEN treatmgr = 1;
        ELSE IF &class. = &compare. THEN treatmgr = 0;
    RUN;

    PROC SORT DATA = m_adsl_resp OUT = m_all_subj NODUPKEY;
        BY &keyvars. &stratum. &by. treatmgr _index_;
    RUN;

    %* Creating frequency table that will be adjusted before calculating the risk difference;
    %m_cell_count(
        input_ds       = m_all_subj
