    %ELSE %DO;
        DATA rdds01;
            SET &input_ds.;
        RUN;
    %END;

    %* ---------------------------------------------------------------------------------------------
    check for not empty treatment arms (required for risk difference calculation) and do not proceed calculation for terms in case of findings;
    *The risk difference is not presented if one group has value 0.;
    DATA rdds02_01 rdds02_del;
        SET rdds01;
        IF &treatm_response. + &treatm_no_response. = 0 OR &contr_response. + &contr_no_response. = 0
        THEN OUTPUT rdds02_del;
        OUTPUT rdds02_01;
    RUN;

    PROC SORT DATA = rdds02_del NODUPKEY;
        BY &byvar.;
    RUN;
    PROC SORT DATA = rdds02_01;
        BY &byvar.;
    RUN;
    DATA rdds02_02;
        MERGE rdds02_01(IN=a) rdds02_del(IN=b KEEP = &byvar.);
        BY &byvar.;
        IF a = 1 AND b = 0;
    RUN;
    PROC SQL;
        SELECT count(*) INTO: nobs FROM rdds02_02;
    QUIT;

    %IF &nobs EQ 0 %THEN %DO;
