            _treatm = &treatm_response. + &treatm_no_response.;
            _contr = &contr_response. + &contr_no_response.;
            IF _treatm = 0 OR _contr = 0
             THEN CALL symput ('ok', '0');
            ELSE DO;
                _factor = 2 * &zero_term. *_contr * _treatm / (_treatm + _contr);
                _zt_t = _factor / _contr;
                _zt_c = _factor / _treatm;
            END;
        RUN;

        %IF &ok. = 0
        %THEN %GOTO end_macro;
    %END;

    %IF %bquote (%upcase (&correction_type.)) = CONSTANT
     %THEN %DO;
        DATA rdds02;
            SET rdds02;
            _zt_t = &zero_term.;
            _zt_c = &zero_term.;
        RUN;
    %END;

    DATA rdds03 (KEEP = &byvar. &stratum. _strata_order _corr_tr _corr_t
                         _corr_cr _corr_c _t_response _treatm _c_response _contr _corr_tot);
        SET rdds02;
        /*only if studies with total 0 events are to be excluded. If other case, need to change below conditions*/
        IF (&treatm_response. = 0 OR &contr_response. = 0) AND
         (&treatm_response. + &contr_response. NE 0)
        THEN DO;
            _corr_tr = &treatm_response. + _zt_t;
            _corr_tnr = &treatm_no_response. + _zt_t;
            _corr_cr = &contr_response. + _zt_c;
            _corr_cnr = &contr_no_response. + _zt_c;
        END;
        ELSE DO;
            _corr_tr = &treatm_response.;
            _corr_tnr = &treatm_no_response.;
            _corr_cr = &contr_response.;
            _corr_cnr = &contr_no_response.;
        END;
        _strata_order = _N_;
        _t_response = &treatm_response.;
        _treatm = &treatm_response. + &treatm_no_response.;
        _c_response = &contr_response.;
        _contr = &contr_response. + &contr_no_response.;
        _total = _treatm + _contr;
        _corr_t = _corr_tr + _corr_tnr;
        _corr_c = _corr_cr + _corr_cnr;
        _corr_tot = _corr_t + _corr_c;
    RUN;

    *Change dataset for PROC STDRATE/FREQ usage;
    DATA rdds04;
        SET rdds03;
        *stratified, aggregated, binary data for active treatment group;
        &treatmgr. = 1;
        n_resp = _corr_tr;
        total = _corr_t;
        OUTPUT;
        *stratified, aggregated, binary data for control treatment group;
        &treatmgr. = 2;
        n_resp = _corr_cr;
        total = _corr_c;
        OUTPUT;
    RUN;

    *< ===== Risk Difference for Pool =====;
    %IF %bquote(%upcase(&stratum_type.)) = POOL %THEN %DO;
        *< Risk Difference (95% CI);
        ODS LISTING CLOSE;
        ODS OUTPUT Effect = ftest_rd StrataEffect = StrataEffect_rd
        %IF %upcase(%SUBSTR(&het_p_display, 1, 1)) = Y %THEN StrataStats = res_strat_rd;
        ;
        PROC stdrate data = rdds04 alpha = &ci_level.
                  method = mh
                  stat = risk
                  effect = diff
                  ;
        by &byvar.;
        population group = &treatmgr. event = n_resp total = total;
        strata &stratum. / order = data stats(cl=none) effect;
        RUN;
        ODS LISTING;

        *< p-value of heterogeneity;
        %IF %upcase(%SUBSTR(&het_p_display, 1, 1)) = Y %THEN %DO;
            PROC SORT DATA = res_strat_rd;
                BY &byvar. &stratum. &treatmgr.;
            RUN;

            PROC TRANSPOSE DATA = res_strat_rd OUT = res_strat_rd_t1(RENAME=(col1 = trt_resp col2 = contr_resp));
                BY &byvar. &stratum.;
                VAR ObservedEvents;
            RUN;

            PROC TRANSPOSE DATA = res_strat_rd OUT = res_strat_rd_t2 (RENAME=(col1 = trt_total col2 = contr_total));
                BY &byvar. &stratum.;
                VAR NObs;
            RUN;

            DATA p_hetero_rd;
                MERGE res_strat_rd_t1 (DROP = _NAME_ _LABEL_)
                       res_strat_rd_t2 (DROP = _NAME_ _LABEL_);
                BY &byvar. &stratum.;
            RUN;

            DATA p_hetero_rd2;
                MERGE p_hetero_rd ftest_rd;
                BY &byvar.;
                RD = (trt_resp/trt_total) - (contr_resp/contr_total);
                SE_RD = sqrt((trt_resp * (trt_total - trt_resp))/(trt_total**3) + (contr_resp * (contr_total - contr_resp))/(contr_total**3));

                test_stat = (1/SE_RD**2)* (RD - riskdiff)**2;

            RUN;

            PROC TRANSPOSE DATA =  p_hetero_rd2 OUT = p_hetero_rd_t;
                BY &byvar.;
                VAR test_stat;
            RUN;

            DATA &output_ds.(KEEP = &byvar. rd_ci rd_het_p probz riskdiff LowerCL UpperCL
                              RENAME = (probz = rd_probz riskdiff = rd LowerCL = rd_LowerCL UpperCL = rd_UpperCL)
                             );
                MERGE p_hetero_rd_t ftest_rd;
                BY &byvar.;

                ATTRIB rd_het_p LABEL="p-value of heterogeneity" FORMAT=pvalue6.4;
                ATTRIB rd_ci LABEL="Risk Difference (%) #(95% CI)" LENGTH = $30;

                het_test_stat = sum(of col:);
                ncol = n(of col:);*get number of studies;
                IF ncol > 1 THEN DO;
                    rd_het_p = 1 - cdf('CHISQUARE', het_test_stat, ncol-1);*adapt degrees of freedom depending on number of studies (n-1);
                END;
                ELSE DO;
                    CALL missing(rd_het_p);
                END;

                riskdiff = riskdiff*100;*Convert risk difference to risk difference (%);
                LowerCL  = LowerCL*100;*Convert risk difference to risk difference (%);
                UpperCL  = UpperCL*100;*Convert risk difference to risk difference (%);
                IF ^missing(riskdiff) THEN rd = put(round(riskdiff, 0.01), 12.2);
                IF nmiss(LowerCL, UpperCL) = 0 THEN CIs = "(" || compress(put(round(LowerCL, 0.01), 8.2)) || ", " || compress(put(round(UpperCL, 0.01), 8.2)) || ")";
                rd_ci = strip(rd) || " " || strip(CIs);
            RUN;
        %END;
        %ELSE %DO;
            DATA &output_ds.(KEEP = &byvar. rd_ci probz riskdiff LowerCL UpperCL RENAME = (probz = rd_probz riskdiff = rd LowerCL = rd_LowerCL UpperCL = rd_UpperCL));
                SET ftest_rd;
                ATTRIB rd_ci LABEL="Risk Difference (%) #(95% CI)" LENGTH = $30;

                riskdiff = riskdiff*100;*Convert risk difference to risk difference (%);
                LowerCL  = LowerCL*100;*Convert risk difference to risk difference (%);
                UpperCL  = UpperCL*100;*Convert risk difference to risk difference (%);
                IF ^missing(riskdiff) THEN rd = put(round(riskdiff, 0.01), 12.2);
                IF nmiss(LowerCL, UpperCL) = 0 THEN CIs = "(" || compress(put(round(LowerCL, 0.01), 8.2)) || ", " || compress(put(round(UpperCL, 0.01), 8.2)) || ")";
                rd_ci = strip(rd) || " " || strip(CIs);
            RUN;
        %END;
    %END;
    %ELSE %DO;
        *< ===== Risk Difference for Individual study =====;
        DATA rdds06;
            SET rdds04;
            response = 1;
            count = n_resp;
            OUTPUT;
            response = 0;
            count = total - n_resp;
            OUTPUT;
        RUN;

        PROC SORT DATA = rdds06;
            BY &byvar. &stratum.;
        RUN;

        ODS LISTING CLOSE;
        ODS OUTPUT PdiffCLs = asymp_rd;
        PROC FREQ data = rdds06;
            BY &byvar. &stratum.;
            TABLES &treatmgr. * response / riskdiff(column = 2 cl = wald equal(null = 0)) alpha = &ci_level.;
            WEIGHT count;
        RUN;
        ODS LISTING;

        DATA &output_ds.;
            SET asymp_rd;
            ATTRIB rd_ci LABEL="Risk Difference (%) #(95% CI)" LENGTH = $30;

            riskdifference = riskdifference*100;*Convert risk difference to risk difference (%);
            LowerCL  = LowerCL*100;*Convert risk difference to risk difference (%);
            UpperCL  = UpperCL*100;*Convert risk difference to risk difference (%);
            IF ^missing(riskdifference) THEN rd = put(round(riskdifference, 0.01), 12.2);
            IF nmiss(LowerCL, UpperCL) = 0 THEN CIs = "(" || compress(put(round(LowerCL, 0.01), 8.2)) || ", " || compress(put(round(UpperCL, 0.01), 8.2)) || ")";
            rd_ci = strip(rd) || " " || strip(CIs);
            KEEP &byvar. &stratum. rd_ci;
        RUN;
    %END;

    %* ---------------------------------------------------------------------------------------------
    write results to the output data set;

    PROC SORT DATA = &output_ds. PRESORTED;
        BY &byvar.;
    RUN;

    %LET err_cond = ;

    %* ---------------------------------------------------------------------------------------------
    start execution of statements intended for the end of macro execution;

    %END_MACRO:
    ;

    %* ---------------------------------------------------------------------------------------------
    delete any data sets, that were created temporarily during macro execution;
    %IF %upcase(%substr(&debug.,1,1)) NE Y %THEN %DO;
        PROC DATASETS NOLIST NOWARN;
            DELETE rdds:
            %IF %upcase(%SUBSTR(&het_p_display, 1, 1)) = Y AND %bquote(%upcase(&stratum_type.)) = POOL AND &nobs NE 0 %THEN res_strat_:
            p_hetero_:;
            /MT=DATA;
        QUIT;
    %END;

    %* ---------------------------------------------------------------------------------------------
    print messages in case of precondition violations, and %spro_check_param would check for other precondition violations;
    %IF &err_cond. = corr_type
    %THEN %DO;

