%MACRO mh_risk_ratio (
       input_ds           = counted
     , byvar              =
     , stratum            = studyid
     , treatmgr           = &mosto_param_class.
     , treatm_response    = treatm_response
     , treatm_no_response = treatm_no_response
     , contr_response     = contr_response
     , contr_no_response  = contr_no_response
     , zero_exclusion     = yes
     , zero_term          = 0.5
     , correction_type    = stratum_size
     , ci_level           = 0.05
     , het_p_display      = yes
     , stratum_type       = pool
     , output_ds          = m_riskratio
     , debug              = NO
)/ DES = 'Create Risk Ratio based on stratified Mantel-Haenszel and unstratified Wald for Study';
/*******************************************************************************
 * Bayer AG
 * Macro rely on: SPRO, SAS 9.4
 *******************************************************************************
 * Purpose          : Create Risk Ratio based on stratified Mantel-Haenszel and unstratified Wald for Study
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * Parameters       :
 *       - input_ds :
 *         input SAS data set (one or two-level name)
 *       - byvar :
 *         &input_ds variables whose levels generate separate analyses
 *       - stratum :
 *         &input_ds variable used for stratification
 *       - treatmgr:
 *         variable name used for the treatment group, not required variable in the input cell count data
 *       - treatm_response, treatm_no_response,
 *         contr_response, contr_no_response :
 *         &input_ds variables containing the cell count data
 *       - zero_exclusion :
 *         determination whether strata with zero total response (zero response
 *         in both arms) or zero total no response are excluded
 *       - zero_term :
 *         numeric value applied in continuity corrections for strata for which
 *         zero cell values prohibit calculations, i.e. more zero values than in
 *         one of the no response cells (the method depends on &correction_type,
 *         see below)
 *         - the default (0) means that no correction is performed
 *       - correction_type :
 *         type of continuity correction
 *         - available values correspond to Sweeting, Sutton and Lambert (Statist.
 *           Med. 2004, 23:1351-1375)
 *             CONSTANT, STRATUM_SIZE, EMPIRICAL
 *       - ci_level :
 *         specification of the confidence interval to be calculated
 *         - the default (0.05) means a 95% CI
 *       - het_p_display :
 *         determination whether display p-value of heterogeneity
 *       - stratum_type :
 *         pool: create Risk Difference and CIs based on stratified Mantel-Haenszel for Pool
 *         study: create Risk Difference and CIs based on Wald for Study
 *       - output_ds :
 *         output SAS data set (one or two-level name)
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Preconditions    :
 *     Macrovar. needed:
 *     Datasets  needed:
 *     Ext.Prg/Mac used:
 * Postconditions   :
 *     Macrovar created:
 *     Output   created:
 *     Datasets created:
 * Comments         :
 *******************************************************************************
 * Author(s)        : gltlk (Rui Zeng) / date: 28MAR2024
 * Reference prog   : /var/by-sas2p/patdb/std_sg/stat/systems/iapro/iapro1/mh_relative_risk.sas  (M.A.R.C.O. GmbH & Co. KG: Frank Brockmann)
 *******************************************************************************
 * Change History   :
 ******************************************************************************/

/*******************************************************************************
 * Examples         :
 * Create Risk Ratio and CIs based on stratified Mantel-Haenszel for Pool;
   *%mh_risk_ratio (input_ds = counted_pt,
                    byvar = aedecod,
                    stratum = studyid,
                    zero_exclusion = yes,
                    zero_term = 0.5,
                    correction_type = stratum_size,
                    ci_level = 0.05,
                    stratum_type = pool,
                    output_ds = results_rr);

* Create Risk Ratio and CIs based on unstratified Wald for Study;
* %mh_risk_ratio(input_ds = counted,
                    byvar = aedecod,
                    stratum = studyid,
                    zero_exclusion = yes,
                    zero_term = 0.5,
                    correction_type = stratum_size,
                    ci_level = 0.05,
                    stratum_type = study,
                    output_ds = results);

 ******************************************************************************/

***************************************;
* zero cell correction;
* Risk Ratio (95% CI);
* p-value of heterogeneity(for stratified Mantel-Haenszel for Pool only);
***************************************;

    %LOCAL macro mversion _starttime macro_parameter_error;
    %LET macro    = &sysmacroname.;
    %LET mversion = 1.0;

    %spro_check_param(name = input_ds, type=DATA)
    %spro_check_param(name = byvar, type = VARIABLES, mustExist  = Y, data = &input_ds)
    %spro_check_param(name = stratum, type = VARIABLES, mustExist  = Y, data = &input_ds)
    %spro_check_param(name =  treatmgr, type = TEXT)
    %spro_check_param(name = treatm_response, type = VARIABLES, mustExist  = Y, data = &input_ds)
    %spro_check_param(name = treatm_no_response, type = VARIABLES, mustExist  = Y, data = &input_ds)
    %spro_check_param(name = contr_response, type = VARIABLES, mustExist  = Y, data = &input_ds)
    %spro_check_param(name = contr_no_response, type = VARIABLES, mustExist  = Y, data = &input_ds)
    %spro_check_param(name = zero_exclusion, type = YESNO)
    %spro_check_param(name = zero_term, type = NUMBER)
    %spro_check_param(name = correction_type, type = TEXT)
    %spro_check_param(name = ci_level, type = NUMBER)
    %spro_check_param(name = het_p_display, type = YESNO)
    %spro_check_param(name = output_ds, type = DATA)

    %IF (%QUOTE(&macro_parameter_error.) EQ %STR(1)) %THEN %RETURN;

    %LET _starttime = %SYSFUNC(datetime());
    %log(
            INFO
          , Version &mversion started
          , addDateTime = Y
          , messageHint = BEGIN)

    %LOCAL l_opts l_notes;
    %LET l_notes = %SYSFUNC(getoption(notes));

    %LET l_opts = %SYSFUNC(getoption(source))
                  %SYSFUNC(getoption(notes))
                  %SYSFUNC(getoption(fmterr))
    ;

    OPTIONS NONOTES NOSOURCE NOFMTERR;

    %* ---------------------------------------------------------------------------------------------
    definition of local macro variables;

       %LOCAL err_cond i ok lastby;

    %* ---------------------------------------------------------------------------------------------
    check the &correction_type parameter - must be 'stratum_size' (default), 'constant', or
    'empirical' (all not case-sensitive);

       %LET err_cond = corr_type;

       %IF %bquote (%upcase (&correction_type.)) ^= CONSTANT AND
           %bquote (%upcase (&correction_type.)) ^= STRATUM_SIZE AND
           %bquote (%upcase (&correction_type.)) ^= EMPIRICAL
       %THEN %GOTO end_macro;

       %* ---------------------------------------------------------------------------------------------
       check the &stratum_type parameter - must be 'pool' (default) or 'study' (both not
       case-sensitive);

         %LET err_cond = stratum_type;

         %IF %bquote (%upcase (&stratum_type.)) ^= POOL AND
             %bquote (%upcase (&stratum_type.)) ^= STUDY
         %THEN %GOTO end_macro;

    %* ---------------------------------------------------------------------------------------------
    start the actual macro execution;

       %LET i = 0;
       %IF &byvar. ^=
       %THEN %DO %UNTIL (&lastby. = );
          %LET i = %eval (&i. + 1);
          %LET lastby = %scan (&byvar., &i., %str ( ));
       %END;
       %IF &i. > 1
       %THEN %LET lastby = %scan (&byvar., %eval (&i. - 1), %str ( ));

       %IF &byvar. ^=
       %THEN %DO;
          PROC SORT DATA = &input_ds. OUT = rrds01;
             BY &byvar.;
          RUN;
       %END;
       %ELSE %DO;
          DATA rrds01;
             SET &input_ds.;
          RUN;
       %END;

       %* ---------------------------------------------------------------------------------------------
        determination whether strata with zero total response (zero response in both arms) or zero total no response are excluded;
       DATA rrds02;
          SET rrds01;
           %IF %upcase(%SUBSTR(&zero_exclusion., 1, 1)) = Y
           %THEN %DO;
              IF (&treatm_response. = 0 AND &contr_response. = 0) OR
                 (&treatm_no_response. = 0 AND &contr_no_response. = 0)
              THEN DELETE;
           %END;
       RUN;

       %* ---------------------------------------------------------------------------------------------
       For study RD(CIs)/RRs(CIs): For the risk differences and risk ratios cannot take normal approximation to show the confidence intervals, the risk difference (CIs) / risk ratio (CIs) will not be shown in table;
       *(the values do not satisfy the requirement for normal approximation, i.e. there are fewer than 5 successes (events of interest) or failures (non-events) in both comparison group);
       %IF %bquote(%upcase(&stratum_type.)) = STUDY %THEN %DO;
           DATA rrds02;
               SET rrds02;
               IF (&treatm_response. < 5 AND &contr_response. < 5) OR
                (&treatm_no_response. < 5 AND &contr_no_response. < 5)
               THEN DELETE;
           RUN;
           PROC SQL;
               SELECT count(*) INTO: nobs2 FROM rrds02;
           QUIT;

           %IF &nobs2 EQ 0 %THEN %DO;
               DATA &output_ds.;
                   SET rrds02;
                   ATTRIB rr_ci LABEL="Risk Ratio #(95% CI)" LENGTH = $30;
                   rr_ci = '';
                   KEEP &byvar. &stratum. rr_ci;
               RUN;
               %LET err_cond = ;
               %GOTO end_macro;
           %END;
       %END;

       %* ---------------------------------------------------------------------------------------------
       For Pool Mantel-Haenszel RD(CIs)/RR(CIs): For the risk differences and risk ratios cannot take normal approximation to show the confidence intervals, the risk difference (CIs) / risk ratio (CIs) will not be shown in table;
       *(the values do not satisfy the requirement for normal approximation, i.e. there are fewer than 5 successes (events of interest) or failures (non-events) in both comparison group);
       %IF %bquote(%upcase(&stratum_type.)) = POOL %THEN %DO;
           PROC SORT DATA = rrds02;
               BY &byvar. &stratum.;
           RUN;

           DATA rrds02_tot;
               SET rrds02;
               BY &byvar. &stratum.;
               RETAIN t_&treatm_response. t_&contr_response. t_&treatm_no_response. t_&contr_no_response.;
               IF first.&byvar. then t_&treatm_response. = &treatm_response.;
               ELSE t_&treatm_response. = t_&treatm_response. + &treatm_response.;
               IF first.&byvar. then t_&contr_response. = &contr_response.;
               ELSE t_&contr_response. = t_&contr_response. + &contr_response.;
               IF first.&byvar. then t_&treatm_no_response. = &treatm_no_response.;
               ELSE t_&treatm_no_response. = t_&treatm_no_response. + &treatm_no_response.;
               IF first.&byvar. then t_&contr_no_response. = &contr_no_response.;
               ELSE t_&contr_no_response. = t_&contr_no_response. + &contr_no_response.;

               IF last.&byvar.;
               KEEP &byvar. t_&treatm_response. t_&contr_response. t_&treatm_no_response. t_&contr_no_response.;
           RUN;

           DATA rrds02;
               MERGE rrds02 rrds02_tot;
               BY &byvar.;

documents.summary:
