           PROC SQL;
               SELECT count(*) INTO: nobs2 FROM rrds02;
           QUIT;

           %IF &nobs2 EQ 0 %THEN %DO;
               DATA &output_ds.;
                   SET rrds02;
                   ATTRIB rr_ci LABEL="Risk Ratio #(95% CI)" LENGTH = $30;
                   ATTRIB rr_het_p LABEL="p-value of heterogeneity" FORMAT=pvalue6.4;
                   rr_ci = '';
                   CALL missing(of rr rr_LowerCL rr_UpperCL rr_probz rr_het_p);
                   KEEP &byvar. rr_ci rr_probz %IF %upcase(%SUBSTR(&het_p_display, 1, 1)) = Y %THEN rr_het_p; rr rr_LowerCL rr_UpperCL;
               RUN;
               %LET err_cond = ;
               %GOTO end_macro;
           %END;
       %END;

       *< zero cell correction;
       %IF %bquote (%upcase (&correction_type.)) = EMPIRICAL
       %THEN %DO;
          DATA rrds02_1 (KEEP = &byvar. &stratum. _risk_t _risk_c _d);
             SET rrds02 (WHERE = (&treatm_response. ^= 0 AND &treatm_no_response. ^= 0 AND
                                  &contr_response. ^= 0 AND &contr_no_response. ^= 0));
               *** there remain only strata without zero cells ***;
             _tr = &treatm_response.;
             _tnr = &treatm_no_response.;
             _treatm = _tr + _tnr;
             _cr = &contr_response.;
             _cnr =

documents.sourceText:
IF (t_&treatm_response. < 5 AND t_&contr_response. < 5) OR
                (t_&treatm_no_response. < 5 AND t_&contr_no_response. < 5)
               THEN DELETE;
           RUN;

           PROC SQL;
               SELECT count(*) INTO: nobs2 FROM rrds02;
           QUIT;

           %IF &nobs2 EQ 0 %THEN %DO;
               DATA &output_ds.;
                   SET rrds02;
                   ATTRIB rr_ci LABEL="Risk Ratio #(95% CI)" LENGTH = $30;
                   ATTRIB rr_het_p LABEL="p-value of heterogeneity" FORMAT=pvalue6.4;
                   rr_ci = '';
                   CALL missing(of rr rr_LowerCL rr_UpperCL rr_probz rr_het_p);
                   KEEP &byvar. rr_ci rr_probz %IF %upcase(%SUBSTR(&het_p_display, 1, 1)) = Y %THEN rr_het_p; rr rr_LowerCL rr_UpperCL;
               RUN;
               %LET err_cond = ;
               %GOTO end_macro;
           %END;
       %END;

       *< zero cell correction;
       %IF %bquote (%upcase (&correction_type.)) = EMPIRICAL
       %THEN %DO;
          DATA rrds02_1 (KEEP = &byvar. &stratum. _risk_t _risk_c _d);
             SET rrds02 (WHERE = (&treatm_response. ^= 0 AND &treatm_no_response. ^= 0 AND
                                  &contr_response. ^= 0 AND &contr_no_response. ^= 0));
               *** there remain only strata without zero cells ***;
             _tr = &treatm_response.;
             _tnr = &treatm_no_response.;
             _treatm = _tr + _tnr;
             _cr = &contr_response.;
             _cnr = &contr_no_response.;
             _contr = _cr + _cnr;
             _total = _treatm + _contr;
             IF _total > 0
             THEN DO;
                _risk_t = _tr * _contr / _total;
                _risk_c = _cr * _treatm / _total;
                _d = (_treatm * _contr * (_tr + _cr) -
                      _tr * _cr * _total) / _total ** 2;
             END;
          RUN;

          PROC MEANS DATA = rrds02_1
                     NOPRINT;
          %IF &byvar. ^=
          %THEN %DO;
             BY &byvar.;
          %END;
             CLASS &stratum.;
             OUTPUT OUT = rrds02_2 SUM = ;
          RUN;

          DATA rrds02_3 (DROP = &stratum. _freq_ _type_ _risk_t _risk_c);
             SET rrds02_2 (WHERE = (_type_ = 0));   *pooled risks;
             _pooled_est = _risk_t / _risk_c;
               *** _pooled_est is always defined after the above selection of strata ***;
          RUN;

    %* ---------------------------------------------------------------------------------------------
    check for the presence of pooled estimates and not empty treatment arms (required for this
    continuity correction type) and abort in case of findings;

          %LET err_cond = empirical; %LET ok = 1;

          DATA rrds02 (DROP = _pooled_est _treatm _contr _ratio);
          %IF &byvar. ^=
          %THEN %DO;
             MERGE rrds02 rrds02_3;
             BY &byvar.;
          %END;
          %ELSE %DO;
             IF _N_ = 1
             THEN SET rrds02_3;
             SET rrds02;
          %END;
             _treatm = &treatm_response. + &treatm_no_response.;
             _contr = &contr_response. + &contr_no_response.;
             IF _pooled_est = . OR _treatm = 0 OR _contr = 0
             THEN CALL symput ('ok', '0');
             ELSE DO;
                _ratio = _contr / _treatm;
                _zt_t = 2 * &zero_term. * _pooled_est / (_ratio + _pooled_est);
                _zt_c = 2 * &zero_term. * _ratio / (_ratio + _pooled_est);
             END;
          RUN;

          %IF &ok. = 0
          %THEN %GOTO end_macro;
       %END;

       %IF %bquote (%upcase (&correction_type.)) = STRATUM_SIZE
       %THEN %DO;

    %* ---------------------------------------------------------------------------------------------
    check for not empty treatment arms (required for this continuity correction type) and abort
    in case of findings;

          %LET err_cond = stratum_size; %LET ok = 1;

          DATA rrds02 (DROP = _treatm _contr _factor);
             SET rrds02;
             _treatm = &treatm_response. + &treatm_no_response.;
             _contr = &contr_response. + &contr_no_response.;
             IF _treatm = 0 OR _contr = 0
             THEN CALL symput ('ok', '0');
             ELSE DO;
                _factor = 2 * &zero_term. *_contr * _treatm / (_treatm + _contr);
                _zt_t = _factor / _contr;
                _zt_c = _factor / _treatm;
             END;
          RUN;

          %IF &ok. = 0
          %THEN %GOTO end_macro;
       %END;

       %IF %bquote (%upcase (&correction_type.)) = CONSTANT
       %THEN %DO;
          DATA rrds02;
             SET rrds02;
             _zt_t = &zero_term.;
             _zt_c = &zero_term.;
          RUN;
       %END;

       DATA rrds03 (KEEP = &byvar. &stratum. _strata_order _corr_tr _corr_t
                           _corr_cr _corr_c _t_response _treatm _c_response _contr);
          SET rrds02;
          /*only if studies with total 0 events are to be excluded. If other case, need to change below conditions*/
          IF (&treatm_response. = 0 OR &contr_response. = 0) AND
             (&treatm_response. + &contr_response. NE 0)
          THEN DO;
             _corr_tr = &treatm_response. + _zt_t;
             _corr_tnr = &treatm_no_response. + _zt_t;
             _corr_cr = &contr_response. + _zt_c;
             _corr_cnr = &contr_no_response. + _zt_c;
          END;
          ELSE DO;
             _corr_tr = &treatm_response.;
             _corr_tnr = &treatm_no_response.;
             _corr_cr = &contr_response.;
             _corr_cnr = &contr_no_response.;
          END;
          _strata_order = _N_;
          _t_response = &treatm_response.;
          _treatm = &treatm_response. + &treatm_no_response.;
          _c_response = &contr_response.;
          _contr = &contr_response. + &contr_no_response.;
          _total = _treatm + _contr;
          _corr_t = _corr_tr + _corr_tnr;
          _corr_c = _corr_cr + _corr_cnr;
          _corr_tot = _corr_t + _corr_c;
       RUN;

    *Change dataset for PROC STDRATE/FREQ usage;
    DATA rrds04;
        SET rrds03;
        *stratified, aggregated, binary data for active treatment group;
        &treatmgr. = 1;
        n_resp = _corr_tr;
        total = _corr_t;
        OUTPUT;
        *stratified, aggregated, binary data for control treatment group;
        &treatmgr. = 2;
        n_resp = _corr_cr;
        total = _corr_c;
        OUTPUT;
    RUN;

    *< =====  Risk Ratio for Pool =====;
    %IF %bquote(%upcase(&stratum_type.)) = POOL %THEN %DO;
        *< Risk Ratio (95% CI);
        ODS LISTING CLOSE;
        ODS OUTPUT Effect = ftest_rr StrataEffect = StrataEffect_rr %IF %upcase(%SUBSTR(&het_p_display, 1, 1)) = Y %THEN StrataStats = res_strat_rr;;
        PROC stdrate data = rrds04 alpha = &ci_level.
                 method = mh
                 stat = risk
                 effect = RATIO
                 ;
            by &byvar.;
            population group = &treatmgr. event = n_resp total = total;
            strata &stratum. / order = data stats(cl=none) effect;
        RUN;
        ODS LISTING;

        *< p-value of heterogeneity;
        %IF %upcase(%SUBSTR(&het_p_display, 1, 1)) = Y %THEN %DO;
            PROC SORT DATA = res_strat_rr;
                BY &byvar. &stratum. &treatmgr.;
            RUN;

            PROC TRANSPOSE DATA = res_strat_rr OUT = res_strat_rr_t1(RENAME = (col1 = trt_resp col2 = contr_resp));
                BY &byvar. &stratum.;
                VAR ObservedEvents;
            RUN;

            PROC TRANSPOSE DATA = res_strat_rr OUT = res_strat_rr_t2 (RENAME = (col1 = trt_total col2 = contr_total));
                BY &byvar. &stratum.;
                VAR NObs;
            RUN;

            DATA p_hetero_rr;
                MERGE res_strat_rr_t1 (DROP = _NAME_ _LABEL_)
                      res_strat_rr_t2 (DROP = _NAME_ _LABEL_);
                BY &byvar. &stratum.;
            RUN;

            DATA p_hetero_rr2;
                MERGE p_hetero_rr ftest_rr;
                BY &byvar.;
                *p-value of heterogeneity is only calculated if there are no zero cells;
                logRR = log((trt_resp/trt_total)/(contr_resp/contr_total));
                SE_logRR = sqrt(1/trt_resp + 1/contr_resp - 1/trt_total - 1/contr_total);
                test_stat = (1/SE_logRR **2)*(logRR - logratio)**2;
            RUN;

            PROC TRANSPOSE DATA = p_hetero_rr2 OUT = p_hetero_rr_t;
                BY &byvar.;
                VAR test_stat;
            RUN;

            DATA &output_ds.(KEEP = &byvar. rr_ci rr_het_p probz riskratio LowerCL UpperCL
                             RENAME = (probz = rr_probz riskratio = rr LowerCL = rr_LowerCL UpperCL = rr_UpperCL)
                            );
                MERGE p_hetero_rr_t ftest_rr;
                BY &byvar.;

                ATTRIB rr_het_p LABEL="p-value of heterogeneity" FORMAT=pvalue6.4;
                ATTRIB rr_ci LABEL="Risk Ratio #(95% CI)" LENGTH = $30;

                het_test_stat = sum(of col:);
                ncol = n(of col:);
                IF ncol > 1 THEN DO;
                    rr_het_p = 1 - cdf('CHISQUARE', het_test_stat, ncol-1);  *adapt degrees of freedom depending on number of studies (n-1);
                END;
                ELSE DO;
                    CALL missing(rr_het_p);
                END;

                IF ^missing(riskratio) THEN rr = put(round(riskratio, 0.01), 12.2);
                IF nmiss(LowerCL, UpperCL) = 0 THEN CIs = "(" || compress(put(round(LowerCL, 0.01), 8.2)) || ", " || compress(put(round(UpperCL, 0.01), 8.2)) || ")";
                rr_ci = strip(rr) || " " || strip(CIs);
            RUN;
        %END;
        %ELSE %DO;
            DATA &output_ds.(KEEP = &byvar. rr_ci probz riskratio LowerCL UpperCL RENAME = (probz = rr_probz riskratio = rr LowerCL = rr_LowerCL UpperCL = rr_UpperCL));
                SET ftest_rr;
                ATTRIB rr_ci LABEL="Risk Ratio #(95% CI)" LENGTH = $30;

                IF ^missing(riskratio) THEN rr = put(round(riskratio, 0.01), 12.2);
                IF nmiss(LowerCL, UpperCL) = 0 THEN CIs = "(" || compress(put(round(LowerCL, 0.01), 8.2)) || ", " || compress(put(round(UpperCL, 0.01), 8.2)) || ")";
                rr_ci = strip(rr) || " " || strip(CIs);
            RUN;
        %END;
    %END;
    %ELSE %DO;
    *< ===== Risk Ratio for Individual study =====;
        DATA rrds06;
            SET rrds04;
            response = 1;
            count = n_resp;
            OUTPUT;
            response = 0;
            count = total - n_resp;
            OUTPUT;
        RUN;

        PROC SORT DATA = rrds06;
            BY &byvar. &stratum.;
        RUN;

        ODS LISTING CLOSE;
        ODS OUTPUT RelativeRisks = asymp_rr(WHERE = (Statistic = "Relative Risk (Column 2)"));
        PROC FREQ data = rrds06;
            BY &byvar. &stratum.;
            TABLES &treatmgr. * response / relrisk (column = 2) alpha = &ci_level.;
            WEIGHT count;
        RUN;
        ODS LISTING;

        DATA &output_ds.;
            SET asymp_rr;
            ATTRIB rr_ci LABEL="Risk Ratio #(95% CI)" LENGTH = $30;

            IF ^missing(value) THEN rr = put(round(value, 0.01), 12.2);
            IF nmiss(LowerCL, UpperCL) = 0 THEN CIs = "(" || compress(put(round(LowerCL, 0.01), 8.2)) || ", " || compress(put(round(UpperCL, 0.01), 8.2)) || ")";
            rr_ci = strip(rr) || " " || strip(CIs);
            KEEP &byvar. &stratum. rr_ci;
        RUN;
    %END;

    %* ---------------------------------------------------------------------------------------------
    write results to the output data set;
    PROC SORT DATA = &output_ds. PRESORTED;
      BY &byvar.;
    RUN;

    %LET err_cond = ;


    OPTIONS &l_notes.;
    %PUT %STR(NO)TE: &macro. - Put your note here;
    OPTIONS NONOTES;

    %END_MACRO:;

