/*
 * Purpose          : add ADQSHFSS to AD
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Pre-conditions   :
 * Post-conditions  :
 * Comments         :
 *******************************************************************************
 * Author(s)        : gdcpl (Derek Li) / date: 17MAY2023
 * Reference prog   :
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 11JAN2024
 * Reason           : Update as ADQSHFSS available in Compound ADSMETA.AD
 ******************************************************************************/
/* Changed by       : ereiu (Katharina Meier) / date: 26JAN2024
 * Reason           : Delete not needed memname
 ******************************************************************************/
/* Changed by       : erjli (Yosia Hadisusanto) / date: 15FEB2024
 * Reason           : Remove ADPR and ADFAPR, ADMK
 ******************************************************************************/

data adsmeta.ad;
    set adsmeta.ad;
    if memname='ADQS' then do;
        method='QS(where=(QSCAT NOT IN ("TWICE DAILY HOT FLASH DIARY V2.0", "SLEEPINESS SCALE V1.0")))';
    END;
    ELSE IF memname='ADQSHFSS' then do;
        method='QS(where=(QSCAT IN ("TWICE DAILY HOT FLASH DIARY V2.0", "SLEEPINESS SCALE V1.0")))';
    END;
    ELSE if memname in ('ADCE' 'ADDV' 'ADFACE' 'ADXK') then delete;
RUN;

** Remove ADPR and ADFAPR;
DATA adsmeta.ad;
    SET adsmeta.ad;
    IF memname in ('ADPR', 'ADFAPR', 'ADMK') THEN DELETE;
RUN;

%endprog;

