    members  = adsmeta.adae
  , vars     = CQzzCD
  , deri_txt = "The customized query (CQ) name or name of the AE of special interest category based on a grouping of MedDRA terms. Would be blank for terms that are not in the CQ. Derivation is described in SAP 5.1 Coding conditions applicable for AESIs and also in TLF specification as footnotes: cq01cd for Potential AESI - Liver event, cq02cd for Somnolence or fatigue, cq03cd for Phototoxicity, cq04cd for Post-menopausal uterine bleeding, cq05cd for Abuse potential, cq06cd for Accidents and injuries, cq07cd for Postural hypotension, falls, black outs, syncope, dizziness, ataxia, fractures."
);

%setADSMeta(
    members  = adsmeta.adae
  , vars     = AESREAS
  , method   = '=%_adamap_create_adae_aesreas(vars=AESCONG AESDISAB AESDTH AESHOSP AESLIFE AESMIE AESONGFU)'
  , deri_txt = 'Concatenation of labels from AE.AESCONG, AE.AESDISAB, AE.AESDTH, AE.AESHOSP, AE.AESLIFE, AE.AESMIE and AE.AESONGFU (with comma), if variable contains Y.'
);

%setADSMeta(
    members  = adsmeta.adae
  , vars     = ASTDY AENDY
  , deri_way = 3
);

%setADSMeta(
    members  = adsmeta.adae
  , vars     = APHASE
  , deri_txt = "Set 'Week 1-12' or 'Week 13-52' based on the Adverse event start date and treatment phase start and end date from ADSL."
);

%setNotUsed(
    metaDat = adsmeta.adae
  , varList = ADURN ARELN
  , notUsed = X
)

%removeNotUsed(members = ADAE);

** Correct varseq and keyvar;
DATA adsmeta.adae;
    SET adsmeta.adae;
    IF varname = 'AESEQ' THEN CALL MISSING(keyvar);
RUN;



%endprog;

