  , deri_txt = 'Derived from distinct value of WHO-DD dataset WHODD_BNA_ING_DD_DDA_DD variable BASE_SUB_NAME by using SUPPCM.CMDRECNO. Base substance name of the appropriate Bayer Drug Grouping'
);

*use ONTRxxFL instead of CONFL, remove CONFL from IA metadata;
*PRMEDEF is removed from OASISI 2;
%setADSMeta(
    members = adsmeta.adcm
  , vars    = CONFL ICEREAS SUB_NAME SUB_NAM2 PRMEDEF ICE02FL AETFL
  , notuse  = X
);

%removeNotUsed(members = adcm);

** Update keyvar;
%setAdsMeta(
    members  = adsmeta.adcm
  , vars     = CMSEQ
  , keyvar = .
);

%setAdsMeta(
    members  = adsmeta.adcm
  , vars     = VMSFL
  , deri_txt =  %str(Derived. Set to 'Y' if any VMS treatment as defined in the protocol were used that influence efficacy. Please refer to OASIS 1 and OASIS 2 SAPs section 6.5.2  (Permanent discontinuation of randomized treatment) for more details.)
);

%setAdsMeta(
    members  = adsmeta.adcm
  , vars     = ICEENWK
  , deri_txt =  %str(Only filled for records with ICE01FL = 'Y'. Contains the number of the last week flagged for the intercurrent event.
First the end date of impact on efficacy is calculated as AENDY plus impact duration from preliminary list of prohibited concomitant medication in OASIS-1 and OASIS-2 SAPs section 6.5.3.
If this end date occurs on and after the 3rd day of the week, the respective week will be flagged.
If the end date for the impact on efficacy occurs on the 1st or 2nd day of the week, the respective week should not be flagged and only the previous week will be flagged.
If intake of CM is ongoing, the value will be missing.)
);

%setAdsMeta(
    members  = adsmeta.adcm
  , vars     = PROHIBFL
  , deri_txt =  %str(Derived. Set to 'Y' if any prohibited concomitant medication as defined in the protocol were used that influence efficacy.
Please refer to OASIS-1 and OASIS-2 SAPs section 6.5.3 (Intake of prohibited concomitant medication having impact on efficacy) for more details.)
);

