    members  = ADSMETA.ADEX
  , vars     = APHASE
  , deri_txt = %str(Treatment phase like 'Week 1-12' and 'Week 13-26' are determined based on the exposure start/ end date and treatment phase start and end date from ADSL, as per study schema.
Treatment phase like 'Week 1-52' and 'Overall' are determined based on the day of first study drug intake up to and including the day of last study drug intake.
For SWITCH-1, OASIS1 and OASIS2, treatment phase like 'Week 1-26' are determined based on the day of first study drug intake up to and including the day of last study drug intake.
For OASIS3, treatment phase like 'Week 1-26' are determined based on the day of first study drug intake up to day 182.)
)

%setADSMeta(
    members  = ADSMETA.ADEX
  , vars     = ASTDT
  , deri_txt = %str(Derived from EX.EXSTDTC for collected data when PARAMCD="TRT"; set to treatment start date when PARAMCD ="DURWDR" or PARAMCD="DURWGR" or PARAMCD="DURW";
else for intercurrent event parameters, set to the date of temporary interruption starting to impact efficacy.)
)

