    members  = ADSMETA.ADEX
  , vars     = PARCAT3
  , deri_txt = %str(Derived based on the purpose of the parameters. If for efficacy analysis purpose then set to 'Efficacy', otherwise if for safety analysis purpose set to 'Safety'.)
)

%setADSMeta(
    members  = ADSMETA.ADEX
  , vars     = TRTAN
  , deri_txt = %str(Derived based on ADSL.TRT01AN, ADSL.TRT02AN and APHASE if PARAMCD in ("DURWDR", "DURWGR", "DURW", 'COMPLPRC', 'COMPLPRC', 'TOTDOSE').)
)

