/*******************************************************************************
 * Bayer AG
 * Study            :
 * Proj/Subst/GIAD  : 3427080 / BAY 3427080, ELINZANETANT BAY3427080 NK1-3 RA Vasomotor Symptoms
 *******************************************************************************
 *Name of program**************************************************************/
%iniprog(name = d_adae)
/*
 * Purpose          : Derive ADAE
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Pre-conditions   :
 * Post-conditions  :
 * Comments         :
 *******************************************************************************
 * Author(s)        : erjli (Yosia Hadisusanto) / date: 04MAR2024
 * Reference prog   :
 ******************************************************************************/

%early_ads_processing(adsDomain = ADAE)

** Select subjects to be analyzed and remove screening failures;
%m_select_subject(indat = ads.adae, outdat = adae)

%mergeDat(
    baseDat = adae
  , keyDat  = ads.adsl(KEEP=&subj_var. ph1sdt ph1edt ph2sdt ph2edt trt01an trt02an trtsdt trtedt)
  , by      = &subj_var.
)

** Partially missing AE end date will be imputed as the latest possible date of AE imputation range.;
** Completely missing end date will not be imputed and presumed to be ongoing.;
DATA adae_01;
    SET adae;

    ** Impute AENDT: last month of the year or last day of the month for a partially missing end date;
    IF missing(aendt) THEN DO;
        IF lengthn(aeendtc) = 7 %* yyyy-mm; THEN DO;
            aendt = intnx('month',input(aeendtc,anydtdte7.),0,'E');** last day of the month;
            aendtf = 'D';
        END;
        ELSE IF lengthn(aeendtc) = 4 %* yyyy; THEN DO;
            aendt = mdy(12,31,input(scan(aeendtc,1,'-'),best8.));** last month of the year;
            aendtf = 'M';
        END;
    END;
RUN;

** Impute AE start date and create ASTDT and ASTDTF;
%m_impute_astdt(
    indat     = adae_01
  , sp_stdtc  = aestdtc
  , adsDomain = ADAE
  , outdat    = adae_01_imputed
)

** Derive APHASE to categorize AE event to which treatment phase: "Week 1-12" or  "Week 13-52";
DATA adae_02_aphase;
    SET adae_01_imputed;
    %createCustomVars(adsDomain = adae, vars = aphase)

    IF n(astdt,ph1sdt,ph1edt) = 3 THEN DO;
        ** For OASIS 3: Only TEAEs that start during the first 12 weeks of treatment (i.e., This includes TEAEs that have an onset starting from the first study drug intake date up to day 84, inclusive) are considered.;
        IF studyid EQ '21810' THEN DO;
            IF ph1sdt <= astdt <=  min(trtedt + 14, ph1sdt + 83)             THEN aphase = "Week 1-12";
        END;
        ** 14-day treatment-emergent window for EZN 120 mg (week 1-12) and Placebo (week 1-12) will only be applied for
           participants from SWITCH-1 or for participants from OASIS 1 or 2 who discontinued during the first 12 weeks.;
        ELSE DO;
            IF ph1sdt <= astdt <= ph1edt + 14                                THEN aphase = "Week 1-12";
        END;
    END;
    ELSE IF missing(ph1edt) AND n(astdt,ph1sdt)=2 AND astdt >= ph1sdt        THEN aphase = "Week 1-12";
    ELSE IF astdt EQ . AND ph2sdt EQ .                                       THEN aphase = "Week 1-12";

    IF studyid NE '21810' THEN DO;;
        IF  n(astdt,ph2sdt,ph2edt) = 3 AND (ph2sdt <= astdt <= ph2edt + 14)      THEN aphase = "Week 13-52";
        ELSE IF  missing(ph2edt) AND n(astdt,ph2sdt) = 2  AND astdt >= ph2sdt    THEN aphase = "Week 13-52";
        ELSE IF astdt EQ . AND ph2sdt NE .                                       THEN aphase = "Week 13-52";
    END;
    ELSE DO; /* For OASIS 3*/
        IF  n(astdt,ph1sdt) = 2 AND astdt >  min(trtedt + 14, ph1sdt + 83)   THEN aphase = "Week 13-52";
    END;
RUN;

** Derive treatment emergent flag TRTEMFL;

DATA ts;
    SET sp.ts END=eof;
    OUTPUT;
    ** In the SWITCH-1 single study analysis, TEAE is defined as any adverse events with the onset date on or after the date and time of first dosing with randomized study treatment.;
    ** However, for this IA, TEAEs will be defined in line with OASIS 1-3 single study analyses;
    ** i.e., any adverse event occurring or worsening on or after the date of the first dose of study drug up to 14 days after the date of the last dose of study drug.;
    IF eof THEN DO;
        studyid  = '21686';
        tsparmcd = 'TIMEW';
        tsval    = '14';
        OUTPUT;
    END;
RUN;

%mergeDat(
    baseDat = sp.ex(WHERE=(NOT missing(exstdtc) and epoch NE "RUN-IN"))
  , keyDat  = ads.adsl(WHERE=(NOT missing(trtsdt)) KEEP= &subj_var. trtsdt trtedt)
  , outDat  = ex
  , by      = &subj_var.
)

DATA ex1;
    SET ex;
    ** ongoing subject should have missing ENDTC as per ADSL;
    IF NOT missing(exendtc) AND trtedt EQ . THEN exendtc = "";
RUN;

** TEAEs: any adverse event occurring or worsening on or after the date of the first dose of study drug up to 14 days after the date of the last dose of study drug.;
%setteaeflag(
    aeDat         = adae_02_aphase
  , trtDat        = ex1
  , timeWindowDat = ts(WHERE=(tsparmcd ='TIMEW'))
  , aeGroupVar    =
  , nonTeaeCrfVar =
  , outDat        = adae_03_trtemfl
  , doPreSteps    = N
)

** For SWITCH-1, pre-treatment adverse events are defined as the adverse events occurring during the time window between screening visit 2 and the first study drug intake.;
DATA switch_ae_lowerrange(KEEP=&subj_var. ae_lowerrange);
    SET sp.sv(WHERE=(studyid = '21686' AND visit = 'Screening 2, day -14'));
    ATTRIB ae_lowerrange FORMAT=date9.;
    ae_lowerrange = input(svstdtc, yymmdd10.);
RUN;

** For OASIS 1-3, pre-treatment adverse events are defined as adverse events which are related to the protocol study procedure occurring between the signing of ICF and first study drug intake.;
DATA oasis_ae_lowerrange(KEEP=&subj_var. ae_lowerrange);
    SET ads.adsl(WHERE=(studyid NE '21686'));
    ATTRIB ae_lowerrange FORMAT=date9.;
    ae_lowerrange = rficdt;
RUN;

DATA ae_lowerrange;
    SET switch_ae_lowerrange
        oasis_ae_lowerrange;
RUN;

%mergeDat(baseDat = adae_03_trtemfl, keyDat = ae_lowerrange, by = &subj_var.)

** Derive Pre-Post Treatment Flag;
DATA adae_04_pre_post_flag;
    SET adae_03_trtemfl;
    %createCustomVars(adsDomain = adae, vars = prefl postfl)
    ** Pre-treatment adverse events refer to adverse events starting before the day of the first study drug.;
    ** For SWITCH-1, pre-treatment adverse events are defined as the adverse events occurring during the time window between screening visit 2 and the first study drug intake.;
    ** For OASIS 1-3, pre-treatment adverse events are defined as adverse events which are related to the protocol study procedure occurring between the signing of ICF and first study drug intake.;
    IF n(astdt,trtsdt) = 2 AND ae_lowerrange <= astdt < trtsdt  THEN prefl = 'Y';
    IF astdt = trtsdt AND aestrf = 'BEFORE'                     THEN prefl = 'Y';

    ** Post-treatment adverse events are defined as all adverse events starting after the date of the last treatment + 14 days.;
    IF n(astdt,trtedt) = 2 AND astdt > trtedt + 14              THEN postfl = 'Y';

    /*removing Phase for POSTFL or PREFL EQ Y*/
     IF postfl EQ "Y" OR prefl EQ "Y" THEN DO;
         CALL missing(aphase);
     END;

RUN;

** Check AEs;
DATA adae_05_check_1;
    SET adae_04_pre_post_flag;

    ** In the SWITCH-1 single study analysis, TEAE is defined as any adverse events with the
       onset date on or after the date and time of first dosing with randomized study treatment.
       However, for this IA, TEAEs will be defined in line with OASIS 1-3 single study analyses,
       i.e., any adverse event occurring or worsening on or after the date of the first dose of
       study drug up to 14 days after the date of the last dose of study drug. ;
    IF aetrtem NE trtemfl AND aetrtem NE 'N' and studyid NE '21686' THEN DO;
        PUT "WAR" "NING: Please check AETERMN vs TRTEMFL " &subj_var. aetrtem= TRTEMFL=;
    END;

    IF trtemfl = 'N' THEN call missing(trtemfl);
RUN;

DATA adae_05_check_2;
    SET adae_05_check_1;

    IF  trtemfl EQ "Y" AND (postfl EQ 'Y' OR prefl EQ "Y" ) THEN DO;
        PUT "WAR" "NING: Please check POSTFL vs TRTEMFL " &subj_var. prefl= postfl= trtemfl=;
    END;
RUN;

DATA adae_05_check;
    SET adae_05_check_2;

    IF NOT missing(astdt) AND missing(prefl) AND missing(postfl) AND missing(aphase) THEN DO;
        PUT "WARN" "ING: Adverse Event is not categorized to Pre-/Post-/Aphase. Please check:" usubjid= aeseq= astdt= aphase= prefl= postfl= trtedt=;
    END;

    IF not missing(trtemfl) AND missing(aphase) THEN DO;
        PUT "WARN" "ING: Adverse Event is treatment emergent, but aphase is missing. Please check:" usubjid= aeseq= astdt= trtemfl= aphase= trtedt=;
    END;

    IF aeterm EQ "" THEN DO;
        CALL MISSING(trtemfl, aphase);
    END;

RUN;

** Select respective SMQs;
%smq_select(
    indat     = meddra.smq_view_sub
  , outdat    = smq4aesi
  , smqcode   = 20000009 20000007 20000008 20000015     /*Any condition potentially triggering close liver observation*/
                SMQ_90000101 SMQ_90001186               /*Somnolence or fatigue*/
                SMQ_90000142                            /*Photosensitivity*/
                SMQ_90001246                            /*Post-menopausal uterine bleeding*/
  , smqtype   = SMQ BMQ MLG
  , smqsearch = _ALL_
)

** Join SMQ information to ADAE;
PROC SQL;
    CREATE TABLE adae_060_aesi AS
       SELECT a.*
            , b.smq_code
       FROM adae_05_check           AS a
       LEFT JOIN smq4aesi           AS b
       ON a.aeptcd=input(b.pt_code,best.);
QUIT;

** For subjects with a medical history of hysterectomy (For hysterectomy the PTs Hysterectomy, Hysterosalpingectomy, Hysterosalpingo-oophorectomy and Radical hysterectomy are considered), the AESI postmenopausal bleeding should not be included.;
DATA hysterectomy(KEEP=&subj_var. hysterectomy);
    SET sp.mh(WHERE=(mhdecod in ('Hysterectomy' 'Hysterosalpingectomy' 'Hysterosalpingo-oophorectomy' 'Radical hysterectomy')));
    ATTRIB hysterectomy LABEL = "Subjects with a medical history of hysterectomy" FORMAT=ny.;
    hysterectomy = 1;
RUN;

PROC SORT DATA=hysterectomy NODUPKEY; BY &subj_var.; RUN;

%mergeDat(baseDat = adae_060_aesi, keyDat = hysterectomy, by = &subj_var.)

** Derive CQ##CD;
DATA adae_061_aesi;
    SET adae_060_aesi;
    %createCustomVars(
        adsDomain = adae
      , vars      = CQ01CD  CQ02CD  CQ03CD  CQ04CD
    )

    IF    smq_code IN( '20000009' '20000007' '20000008' '20000015')
       OR aessiny EQ "Y"  THEN DO;
        cq01cd = 1;%** Z_CQNAM.1 [Any condition potentially triggering close liver observation];
    END;

    IF smq_code IN( 'SMQ_90000101' 'SMQ_90001186')
      OR aeptcd EQ 10040985 /*SAP: In addition to MLGs above, include PT Sleep disorder due to general medical condition, hypersomnia type;*/
    THEN DO;
        cq02cd = 2;%** Z_CQNAM.2 [Somnolence or fatigue];
    END;

    IF smq_code IN( 'SMQ_90000142')  THEN DO;
        cq03cd = 3;%** Z_CQNAM.3 [Phototoxicity];
    END;

    ** For subjects with a medical history of hysterectomy (For hysterectomy the PTs Hysterectomy, Hysterosalpingectomy, Hysterosalpingo-oophorectomy and Radical hysterectomy are considered), the AESI postmenopausal bleeding should not be included.;
    IF smq_code IN( 'SMQ_90001246') and hysterectomy NE 1 THEN DO;
        cq04cd = 4;%** Z_CQNAM.4 [Post-menopausal uterine bleeding];
    END;

RUN;

** Derive ASSINY;
DATA adae_061_aesi;
    SET adae_061_aesi;
    %createCustomVars(adsDomain = adae, vars = ASSINY)
    IF N(cq01cd,cq02cd,cq03cd,cq04cd) > 0 THEN ASSINY = 'Y';
    IF prefl EQ "Y" THEN CALL MISSING(ASSINY); ** AE Special interest is not counted for pre-treatment;
RUN;

