%early_ads_processing(adsDomain = ADCM)

%*Select subjects;
%m_select_subject(
    indat          = ads.adcm
  , outdat         = adcm
  , removescrnfail = Y
)

DATA adsl;
    SET ADS.adsl;
    KEEP studyid usubjid trtsdt trtedt randdt saffl ph1: ph2: tr01sdt tr01edt tr02sdt tr02edt;
RUN;

PROC SORT DATA = adsl;
    BY studyid usubjid;
RUN;

PROC SORT DATA = adcm;
    BY studyid usubjid cmseq;
RUN;

DATA adcm;
    MERGE adcm (IN = _in_adcm)
          adsl;
    BY studyid usubjid;

    IF _in_adcm;
RUN;

*< Include BASE_SUB_NAME from WHODRUG dictionary;
** Retrieve substance name from whodd.whodd_bna_ing_dd_dda_dd;
PROC SQL NOPRINT;
    CREATE TABLE master_base AS
            SELECT DISTINCT cmdrecno, base_sub_name
            FROM adcm AS adcm
            LEFT JOIN whodd.whodd_bna_ing_dd_dda_dd AS ing
            ON adcm.cmdrecno = ing.drecno
    WHERE NOT missing(base_sub_name)
    ORDER BY cmdrecno, base_sub_name;
QUIT;

*create Substance Name zz;
DATA master_base2;
    SET master_base;
    BY cmdrecno base_sub_name;
    IF FIRST.cmdrecno THEN ind = 1;
    ELSE ind + 1 ;
    indc = strip(put(ind, z2.));
    KEEP cmdrecno base_sub_name ind indc;
RUN;

PROC TRANSPOSE DATA = master_base2 OUT = master_base3 PREFIX = s_name;
    BY cmdrecno;
    VAR base_sub_name;
    ID indc;
RUN;

PROC SORT DATA = adcm;
    BY cmdrecno;
RUN;

** Merge variables to the main dataset;
DATA adcm2;
    MERGE adcm(IN=_x)
          master_base3;
    BY cmdrecno;
    IF _x;
RUN;

PROC SORT DATA=adcm2;
    BY studyid usubjid cmseq;
RUN;

*< Impute start date as specified in SAP;
%m_impute_astdt(
         indat    = adcm2
       , sp_stdtc = cmstdtc
       , adsDomain = ADCM
       , outdat   = adcm3
)

*< Derive study day and flags for Prior medication, Concomitant medication and Post-treatment medication;
DATA adcm4;
    SET adcm3;

    * Derive relative study days;
    %createCustomVars(adsDomain=adcm, vars=astdy aendy);
    IF nmiss(astdt, randdt) = 0 THEN DO;
        IF randdt <= astdt THEN astdy = astdt - randdt + 1;
                           ELSE astdy = astdt - randdt;
    END;
    IF nmiss(aendt, randdt) = 0 THEN DO;
        IF randdt <= aendt THEN aendy = aendt - randdt + 1;
                           ELSE aendy = aendt - randdt;
    END;

    IF NOT missing(trtsdt) AND CMCAT NE 'MEDICATION OF INTEREST' THEN DO;
        ** Prior Medication: Medication taken before start of the study drug intake, (regardless of when it ended).;
        %createCustomVars(adsDomain=adcm, vars=prefl);
        IF missing(astdt) OR (.z < astdt < trtsdt) THEN prefl = "Y";

        ** Concomitant medication: Medication taken during treatment phase, i.e., between first and last study drug intake (regardless of when it started or ended).;
        ** For EZN 120 mg (week 1-12), Placebo (week 1-12) and Total (week 1-12), the first and last study drug refer to the first and last study drug of the first 12 weeks.;
        %createCustomVars(adsDomain=adcm, vars=ontr01fl ontr02fl);
        ** For OASIS 3: CMs taken during the first 12 weeks of treatment up to day 84(inclusive) are considered.;
        IF studyid EQ '21810' THEN DO;
            IF NOT missing(ph1sdt) THEN DO;
                IF    (ph1sdt <= astdt <= min(ph1sdt + 83, trtedt))                 /* for early discontinuation subjects, gap between trtedt and ph1sdt + 84 which trtedt < ph1sdt + 83*/
                   OR (astdt < ph1sdt AND (ph1sdt <= aendt OR missing(aendt))) /* includes missing astdt */
                   THEN ontr01fl = 'Y';
            END;
            IF NOT missing(ph2sdt) OR ph1edt > ph1sdt + 83 THEN DO;
                IF    (ph1sdt + 84 <= astdt <= min(ph2edt, trtedt))                 /* for early discontinuation subjects, gap between trtedt and ph2edt which trtedt < ph2edt*/
                   OR (astdt < min(ph1sdt + 84, trtedt) AND (ph1sdt + 84 <= aendt OR missing(aendt))) /* includes missing astdt */
                   THEN ontr02fl = 'Y';
            END;
        END;
        ELSE DO;
            IF NOT missing(ph1sdt) THEN DO;
                IF    (ph1sdt <= astdt <= min(ph1edt, trtedt))                 /* for early discontinuation subjects, gap between trtedt and ph1edt which trtedt < ph1edt*/
                   OR (astdt < ph1sdt AND (ph1sdt <= aendt OR missing(aendt))) /* includes missing astdt */
                   THEN ontr01fl = 'Y';
            END;
            IF NOT missing(ph2sdt) THEN DO;
                IF    (ph2sdt <= astdt <= min(ph2edt, trtedt))                 /* for early discontinuation subjects, gap between trtedt and ph2edt which trtedt < ph2edt*/
                   OR (astdt < ph2sdt AND (ph2sdt <= aendt OR missing(aendt))) /* includes missing astdt */
                   THEN ontr02fl = 'Y';
            END;
        END;

        *add flag for EZN 120 mg (week 1-26) and Placebo (week 1-26): except those starting after day 182 in OASIS 3.;
        %createCustomVars(adsDomain=adcm, vars=ontr03fl);
        IF studyid EQ '21810' THEN DO;
            IF astdt > ph1sdt + 181 THEN ontr03fl = '';
            ELSE ontr03fl = ontr02fl;
        END;
        ELSE DO;
            ontr03fl = ontr02fl;
        END;

         ** Post-treatment medication: Start of medication is after a patient's last treatment date (see section 4.1.2:  last treatment date);
         %createCustomVars(adsDomain=adcm, vars=fupfl);
         IF astdt > trtedt > .z THEN fupfl = "Y";
    END;
RUN;


*< VMS treatment flag;
* Select alternative VMS treatment by drug grouping;
** As per Table 2-1 Final list of alternative VMS treatment by drug grouping;
DATA vms_group(KEEP=drecno dseq1 dseq2 dgcodel: dgname:);
    SET whoddsdg.sdg_bdg_dtoi;
    IF    (                      dgcodel1 =   "5"  AND dgcodel2 =   "2")      /* Oestrogens */
       OR (                      dgcodel1 =   "5"  AND dgcodel2 =   "3")      /* Progestogens */
       OR (dgcodel0 = "1633" AND dgcodel1 = "111"  AND dgcodel2 = "113")      /* Selective serotonin reuptake inhibitors (SSRI) */
       ;
RUN;

* Sort and remove duplicates, we only need recno and seq1 for identifying VMS treatment;
PROC SORT DATA=vms_group(RENAME=(drecno=cmdrecno dseq1=cmdseq1)) OUT=vms_group2(KEEP=cmdrecno cmdseq1) NODUPKEY;
    BY cmdrecno cmdseq1;
RUN;

PROC SORT DATA=adcm4;
    BY cmdrecno cmdseq1 cmdseq2;
RUN;

* Merge with ADCM and flag VMS for the records in VMS drug group list;
DATA adcm4_vms1;
    MERGE adcm4      (IN=_in_cm)
          vms_group2 (IN=_in_vms);
    BY cmdrecno cmdseq1;
    IF _in_cm;

    %createCustomVars(adsDomain=adcm, vars=VMSFL);
    IF studyid IN ('21651' '21652') AND CMCAT NE 'MEDICATION OF INTEREST' AND _in_vms THEN vmsfl = "Y";
RUN;

* Select alternative VMS treatment by drug names;
** As per Table 2-2 Final list of alternative VMS treatment by drug names;
DATA vms_drug(KEEP=cmdrecno cmdseq1 cmdseq2);
    SET whodd.whodrug;
    IF  drecno="005389" AND dseqno1="02" AND dseqno2="057" ;         /* Oxybutin */
    RENAME drecno=cmdrecno dseqno1=cmdseq1 dseqno2=cmdseq2;
RUN;

PROC SORT DATA=vms_drug;
    BY cmdrecno cmdseq1 cmdseq2;
RUN;

PROC SORT DATA=adcm4_vms1;
    BY cmdrecno cmdseq1 cmdseq2;
RUN;

* Merge with ADCM and flag VMS for the records in VMS drug list;
DATA adcm4_vms2;
    MERGE adcm4_vms1 (IN=_in_cm)
          vms_drug   (IN=_in_vms);
    BY cmdrecno cmdseq1 cmdseq2;
    IF _in_cm;

    %createCustomVars(adsDomain=adcm, vars=VMSFL);
    IF studyid IN ('21651' '21652') AND CMCAT NE 'MEDICATION OF INTEREST' AND _in_vms THEN vmsfl = "Y";
RUN;


