documents.sourceText:
/*******************************************************************************
 * Bayer AG
 * Study            :
 * Proj/Subst/GIAD  : 3427080 / BAY 3427080, ELINZANETANT BAY3427080 NK1-3 RA Vasomotor Symptoms
 *******************************************************************************
 *Name of program**************************************************************/
%iniprog(name = d_adds, print2file = N)
;
/*
 * Purpose          : Derivation of ADDS
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Pre-conditions   :
 * Post-conditions  :
 * Comments         :
 *******************************************************************************
 * Author(s)        : gdcpl (Derek Li) / date: 20FEB2024
 * Reference prog   : /var/swan/root/bhc/3427080/21652/stat/main01/dev/analysis/pgms/d_adds.sas (gnrty (Ashu Pandey) / date: 05SEP2023)
 ******************************************************************************/

%early_ads_processing(adsDomain = ADDS)
;

%m_select_subject(
    indat          = ads.adds
  , outdat         = adds
  , removescrnfail = N
)
;

/**** Sorting all the required domains for analysis*/
PROC SORT DATA = adds OUT = ds;
    BY studyid usubjid dsseq;
RUN;
PROC SORT DATA = ads.adsl OUT = adsl(KEEP = studyid usubjid trtsdt trtedt randdt ph1sdt ph1edt ph2sdt ph2edt scrnflfl saffl) NODUPKEY;
    BY studyid usubjid ;
RUN;
PROC SORT DATA = ads.adcm OUT = adcm(KEEP = studyid usubjid usubjid cmtrt astdt aendt cmenrtpt ontr01fl ontr02fl prefl cmseq astdtf astdy
                RENAME = (astdt = cmstdt aendt = cmendt astdy = cmstdy));
    BY studyid usubjid cmseq cmtrt;
RUN;

PROC SORT DATA = sp.cm OUT = cm(KEEP = studyid usubjid cmseq cmstdtc cmendtc cmtrt cmdrecno cmdseq1);
    BY studyid usubjid cmseq cmtrt;
RUN;
PROC SORT DATA = sp.sv OUT = sv_records(KEEP = studyid usubjid visitnum visit svstdtc svstdy svendy svendtc svoccur) NODUPKEY  ;
    BY studyid usubjid;
    WHERE visitnum EQ 85 AND svoccur NE "N";
RUN;

*Special handling rule for OASIS-3;

/**** Derive phase dates to be used for APHASE based off eCRF data ****/

*================================================================================================================;
* Add Phase1 and Phase2 start and end date.
*
* Phase1 starts: randomization (as the first dose will be taken on site, this should match the data in Rave);
* Phase1 ends: Week 12 assessment date or for participants who discontinued early, study drug discontinuation date
* or EOT assessment date, whichever is later

* Phase2 starts: Week 12 assessment date + 1 (identified based on the eCRF entry).;
* Phase2 ends: end of treatment period date (for participants who completed the treatment period) or
            the study drug discontinuation date or EOT assessment date whichever is later (for participants who discontinue from treatment/study prematurely during the second phase)
*================================================================================================================;

* bring in scheduled visit date for week 12 and EOT assessment date;
data sv;
    set sp.sv;
    format svendt date9.;
    svendt = input(svendtc, ?? e8601da.);
RUN;

proc sort data=sv out=sv_w12(keep=studyid usubjid svendt rename=(svendt=svenwk12));
    by studyid usubjid;
    where visitnum=85 and EPOCH ne "POST-TREATMENT";
RUN;

proc sort data=sv out=sv_eot(keep=studyid usubjid svendt rename=(svendt=sveneot));
    by studyid usubjid;
    where visitnum=600000;
RUN;


* bring in treatment period end date (for early discontinuation) from DS and next EPOCH info;
proc sort data=sp.ds(where=(studyid='21810')) out=ds_et(keep=studyid usubjid dsstdtc dsnext) nodupkey;
    by studyid usubjid;
    where epoch='TREATMENT' and dscat='DISPOSITION EVENT' and dsdecod ne 'COMPLETED' and dsscat^="INFORMED CONSENT";
RUN;

data ds_et(drop=dsstdtc);
    set ds_et;
    format DSSTDT_et date9.;
    DSSTDT_et = input(dsstdtc, ?? e8601da.);
RUN;

* bring in treatment period end date (for treatment completer) from DS;
proc sort data=sp.ds(where=(studyid='21810')) out=ds_cmpl(keep=studyid usubjid dsstdtc) nodupkey;
    by studyid usubjid;
    where epoch='TREATMENT' and dscat='DISPOSITION EVENT' and dsdecod eq 'COMPLETED' and dsscat^="INFORMED CONSENT";
RUN;

data ds_cmpl(drop=dsstdtc);
    set ds_cmpl;
    format DSSTDT_cmpl date9.;
    DSSTDT_cmpl = input(dsstdtc, ?? e8601da.);
RUN;

data adsl (drop=svenwk12 sveneot dsnext dsstdt_et dsstdt_cmpl);
   merge adsl(in=a) sv_w12 sv_eot ds_et ds_cmpl;
   by studyid usubjid;
   if a;
   * %createCustomVars(adsDomain=adsl, vars=PH1SDT PH1EDT PH2SDT PH2EDT);
   if studyid='21810' then do;
       call missing(ph1sdt,ph1edt, ph2sdt, ph2edt);
         PH1SDT = randdt; *randomization;

        if not missing(svenwk12) then PH1EDT=svenwk12-1;
        else if saffl="N" and not missing(randdt) then ph1edt=randdt;
        else if nmiss(DSSTDT_et,sveneot)<2 then PH1EDT=max(DSSTDT_et,sveneot); *a Note message may in log due to data not available yet of ongoing treatment period;
        else if not missing(ph1sdt) then put "WARN" "ING: Weird case for PH1EDT for usubjid=" usubjid ". May due to ongoing. Please check.";

        if not missing(svenwk12) then PH2SDT=svenwk12;
        else PH2SDT=.;
   END;

RUN;


/**** Preparing ADDS dataset*************/
DATA adds_prepare(DROP = astdt RENAME = (up_astdt = ASTDT));
    MERGE ds(IN=a) adsl(IN=b) sv_records;
    BY studyid usubjid;
    IF a;
    /*Date calculation , taking last exposure date for subject from adsl.trtedt.
    Also checking for which subjects there is impact and what's the difference of days between DS and EX*/

    FORMAT up_astdt  date9.;

    if studyid ne '21810' then do;
        IF lowcase(epoch) = "treatment" AND astdt NE trtedt AND trtedt NE . AND dsscat EQ "" THEN DO;
            up_astdt = trtedt;
            check = "Y";
        END;
        ELSE DO;
            check = "";
            up_astdt = astdt;
        END;
    END;
    else up_astdt=astdt;

    %createCustomVars(adsDomain = adds, vars = aphase astdy)

    /*DY calculation*/

    IF nmiss(randdt,up_astdt) = 0 THEN astdy = up_astdt - randdt +(up_astdt>=randdt);
    ELSE astdy = .;

    /*Subjects who discontinued prior to day 82 , day will be calculated ADSL.TRTEDT - ADSL.RANDT + 1*/

    IF scrnflfl EQ "N" AND astdy NE . AND astdy LE 82 AND dscat = "DISPOSITION EVENT" AND dsscat EQ "" AND lowcase(epoch) = "treatment"
        AND dsterm NE "COMPLETED" THEN ice = "Y";
    ELSE ice = "";

    /*Phase Calculation*/

    IF  lowcase(epoch) = "treatment" AND dsscat EQ "" THEN DO;
        if studyid ne '21810' then do;
            IF nmiss(up_astdt, ph1sdt, ph1edt) = 0 AND up_astdt GE ph1sdt AND up_astdt LE ph1edt THEN aphase="Week 1-12";
            ELSE IF nmiss(up_astdt, ph2sdt, ph2edt) = 0 AND up_astdt GE ph2sdt AND up_astdt LE ph2edt THEN aphase="After week 12";
        END;
        else do;
            if not missing(trtsdt) then do;
                if nmiss(up_astdt, ph1sdt, ph1edt) = 0 and up_astdt ge ph1sdt and up_astdt le ph1edt then aphase="Week 1-12";
                else if nmiss(up_astdt, ph2sdt) = 0 and up_astdt ge ph2sdt then aphase="After week 12";
            END;
        END;
    END;
    ELSE DO;
        aphase = "";
    END;
RUN;

PROC SORT DATA=adds_prepare;
    BY studyid usubjid astdt;
RUN;

/**********ADCM and CM merging********************/
DATA for_vms;
    MERGE adcm(IN =a) cm;
    IF a;
    BY studyid usubjid cmseq cmtrt;
RUN;

PROC SQL;
    CREATE TABLE adsl_cm AS
    SELECT a.*,b.randdt, b.trtsdt, b.trtedt, b.ph1sdt, b.ph1edt, b.ph2sdt, b.ph2edt
           FROM for_vms AS a LEFT JOIN adsl AS b
           ON a.studyid=b.studyid AND a.usubjid =b.usubjid;
QUIT;

PROC SORT DATA=adsl_cm;
    BY cmdrecno cmdseq1;
RUN;

/******************************************************************************
*VMS medication flag;
******************************************************************************/
*< adding prohibited medication list based on the excel shared by stats;
DATA sdg;
    SET whoddsdg.sdg_bdg_dtoi;
    IF (dgcodel1 ="5" AND dgcodel2 IN ("2", "3"))
       OR (dgcodel0= "1633" AND dgcodel1 = "111" AND dgcodel2 = "113");
    RENAME drecno = cmdrecno dseq1 =cmdseq1;
    KEEP drecno dseq1;
RUN;

PROC SORT DATA=sdg OUT = medication NODUPKEY;
    BY cmdrecno cmdseq1;
RUN;

DATA vmsfl;
    MERGE adsl_cm(IN=a) medication(IN=b);
    BY cmdrecno cmdseq1;
    IF a;
    IF b THEN vmsfl = "Y";
    ELSE IF cmdrecno = "005389" AND cmdseq1 = "02" AND cmdseq1 = "057" THEN vmsfl = "Y";
    ELSE vmsfl = "";
    IF vmsfl NE "";
    IF cmstdt NE . AND randdt NE . AND cmstdt GE randdt THEN drug_vms = "Y";
    ELSE drug_vms = "";
    KEEP studyid usubjid cmstdt cmendt cmstdy vmsfl drug_vms ph: randdt cmenrtpt;
    IF drug_vms NE "";
RUN;

PROC SORT DATA=vmsfl ;
    BY studyid usubjid drug_vms;
RUN;

*remove multiple records;
DATA vmsfl;
    SET vmsfl;
    BY studyid usubjid drug_vms;
    IF LAST.drug_vms;
RUN;

DATA adds_prepare2;
    MERGE adds_prepare(IN=a) vmsfl( DROP = randdt ph: WHERE = (drug_vms NE ""));
    BY studyid usubjid;
    IF a;
    _dsdecod = strip(strip(substr(dsdecod,1,1))||strip(lowcase(substr(dsdecod,2))));
    %createCustomVars(
        adsDomain = adds
      , vars      = ice01fl icereas icesreas astdt ICESTWK
    )
    ;

    /***************ICE flags*************************/

    IF drug_vms NE "" AND ice NE "" THEN DO ;
        ice01fl="Y";
        icereas=(_dsdecod);
        icesreas="For participants who initiate alternative VMS treatment";
    END;

    ELSE IF drug_vms EQ "" AND ice NE "" THEN DO ;
        ice01fl="Y";
        icereas=(_dsdecod);
        icesreas="For participants who remained untreated/on background therapy";
    END;

    ELSE IF find(lowcase(dsterm),"covid") LT 1 AND dsdecod NOT IN ("COMPLETED" "ADVERSE EVENT" "LACK OF EFFICACY")
            AND ice NE "" THEN DO ;
        ice01fl="Y";
        icereas=(_dsdecod);
    END;

    ELSE IF  find(lowcase(dsterm),"covid")  AND ice NE "" THEN DO ;
        ice01fl="Y";
        icereas=(_dsdecod);
    END;

    ELSE DO;
        ice01fl = "";
        icereas= "";
        icesreas="";
    END;

    /*****Calculating duration what week*****/

    IF ice01fl NE "" THEN DO;
        IF randdt NE . AND astdt NE . THEN cal_week = ceil((astdy)/7);
        ELSE cal_week = .;
        IF randdt NE . AND astdt NE . THEN rem_days = mod(astdy,7);
        ELSE rem_days = .;

        IF rem_days EQ 6  AND cal_week NE 1 THEN week = cal_week+1;
        ELSE IF rem_days EQ 0 THEN week = cal_week +1;
        ELSE IF rem_days NE . AND rem_days LE 6 THEN week = cal_week;

    END;

    IF week NE . AND week LE 1 AND astdy GT 1 THEN ICESTWK = 1;
    ELSE IF week NE . AND week LE 1 AND astdy EQ 1 THEN ICESTWK = 0;
    ELSE IF week NE . THEN ICESTWK=  week;
RUN;

DATA ads.adds;
    SET adds_prepare2;
RUN;

/* Finalize and save in ADS lib */

%late_ads_processing(adsDomain = adds)
;

%endprog()

/*******************************************************************************
 * Bayer AG
 * Study            :
 * Proj/Subst/GIAD  : 3427080 / BAY 3427080, ELINZANETANT BAY3427080 NK1-3 RA Vasomotor Symptoms
 *******************************************************************************
 *Name of program**************************************************************/
   %iniprog(name = d_adex);
/*
 * Purpose          : Derivation of ADEX
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Pre-conditions   :
 * Post-conditions  :
 * Comments         :
 *******************************************************************************
 * Author(s)        : gltlk (Rui Zeng) / date: 04DEC2023
 * Reference prog   :
 ******************************************************************************/
/* Changed by       : gltlk (Rui Zeng) / date: 08APR2024
 * Reason           : updated for AVALCA1N for ISS treatment duration
 *                    added phase 'Week 1-26' data for ISS parameters.
 *                    updated for paramcd = 'TOTDSCRF' to include not treated FAS subjects
 ******************************************************************************/

*early processing is done in d_adex_pre.sas;
%*Select subjects;
%m_select_subject(
    indat          = ads.adex
  , outdat         = adex
  , removescrnfail = Y
)

PROC SORT DATA = adex;
    BY studyid usubjid;
RUN;

*<*****************************************************************************;
*< Custom Derivation;
*<*****************************************************************************;

** PARAMCD = TRT;
** populate PARCAT1/AVAL;
** SAP(4.4.2): If the date for end of exposure is not available in eCRF, the last day of drug intake from eDiary will be used to determine the end of exposure.;
PROC SQL;
    CREATE TABLE seq_max AS
    SELECT studyid, usubjid, max(exseq) AS seq_max
    FROM adex
    WHERE cmiss(exstdtc,exendtc)<2
    GROUP BY studyid, usubjid;
QUIT;

DATA trt;
    MERGE adex(IN=a) ads.adsl(KEEP=studyid usubjid trtedt) seq_max;
    BY studyid usubjid;
    IF a;
    %createCustomVars(adsDomain = adex, vars = PARCAT1 AVAL)
    parcat1="by eCRF";
    aval=exdose;

    IF exseq=seq_max AND missing(exendtc) THEN aendt=trtedt;
RUN;

**********************************************;
*IA Efficacy parameters;
**********************************************;
*The analyses described in this section will be presented for the FAS, in line with the analyses outlined in Section 5.6.1 of both the OASIS 1 and OASIS 2 SAPs,
*except for the exclusion of treatment compliance by study drug.;

** treatment duration (weeks): PARAMCD = DURW - by phase (I,II,overall), based on CRF;
** populate APHASE/ASTDT/AENDT/PARCAT1/AVAL/PARAMTYP/TRTAN;
** SAP: Treatment duration will be defined as the number of days from the day of first study drug intake up to and;
** including the day of last study drug intake and will be summarized using descriptive statistics by treatment group, by study drug, and overall.;
PROC SORT DATA=sp.ec OUT=durw;
    WHERE studyid IN ('21651', '21652') AND eccat="STUDY INTERVENTION" AND cmiss(ecstdtc,ecendtc)<2 AND missing(ECDOSMOD) AND missing(ECADJ) AND ecoccur='Y';
    BY studyid usubjid;
RUN;

DATA durw;
    SET durw;
    ecstdt=input(ecstdtc, yymmdd10.);
    ecendt=input(ecendtc, yymmdd10.);
    FORMAT ecstdt ecendt date9.;
RUN;

PROC TRANSPOSE DATA=durw OUT=t_durw1(DROP=_:) PREFIX=ecstdt;
    BY studyid usubjid;
    VAR ecstdt;
    ID ecspid;
RUN;

PROC TRANSPOSE DATA=durw OUT=t_durw2(DROP=_:) PREFIX=ecendt;
    BY studyid usubjid;
    VAR ecendt;
    ID ecspid;
RUN;

DATA durw_crf;  *potential note about Missing values were generated as a result of performing an operation on missing values due to ongoing subject;
    MERGE t_durw1(IN=ec1) t_durw2(IN=ec2)
          ads.adsl(IN=adsl KEEP=studyid usubjid ph1edt ph2sdt trt01an trtedt);
    BY studyid usubjid;
    IF ec1;

    ** If the date for end of exposure is not available in eCRF, the last day of drug intake from eDiary will be used to determine the end of exposure;
    IF NOT missing(ecstdt1) AND nmiss(ecendt1,ecstdt2,ecendt2)=3 THEN ecendt1=trtedt;
    ELSE IF NOT missing(ecstdt2) AND missing(ecendt2) AND ecstdt2<=trtedt THEN ecendt2=trtedt;

    %createCustomVars(adsDomain = adex, vars = PARAMCD PARCAT1 APHASE ASTDT AENDT AVAL TRTAN);
    paramcd="DURW";
    parcat1="by eCRF";

    ** Phase I;
    APHASE="Week 1-12";
    ASTDT=ecstdt1;
    AENDT=ifn(missing(ph2sdt),ecendt1,ph1edt);
    AVAL=(aendt-astdt+1)/7;
    IF trt01an=53 THEN trtan=1;
    ELSE IF trt01an=9901 THEN trtan=0;
    OUTPUT;

    ** Phase II;
    IF NOT missing(ph2sdt) THEN DO;
        APHASE="Week 13-26";
        ASTDT=ph2sdt;
        AENDT=ecendt2;
        AVAL=(aendt-astdt+1)/7;
        trtan=1;
        OUTPUT;
    END;

    ** Overall;
    IF trt01an=53 THEN DO; *53 - Elinzanetant 120mg;
        APHASE="Overall";
        ASTDT=ecstdt1;
        IF NOT missing(ph2sdt) THEN AENDT=max(ecendt1,ecendt2, ph2sdt-1);
        ELSE AENDT=ecendt1;
        AVAL=(aendt-astdt+1)/7;
        TRTAN=1;
        OUTPUT;
    END;
    ELSE IF trt01an=9901 THEN DO; *9901 - Placebo - Elinzanetant 120mg;
        APHASE="Overall";
        ASTDT=ecstdt1;
        AENDT=ifn(missing(ph2sdt),ecendt1,ph1edt);
        AVAL=(aendt-astdt+1)/7;
        trtan=0;
        OUTPUT;
        IF NOT missing(ph2sdt) THEN DO;
            ASTDT=ph2sdt;
            AENDT=ecendt2;
            AVAL=(aendt-astdt+1)/7;
            trtan=1;
            OUTPUT;
        END;
    END;
RUN;

DATA durw_crf;
    SET durw_crf;
    IF missing(aval) THEN DO;
        PUT "WAR" "NING: USUBJID=" usubjid "APHASE=" aphase "still ongoing. Duration is temporally removed.";
        DELETE;
    END;
RUN;

DATA durw_crf2;
    SET durw_crf;
    %createCustomVars(adsDomain = adex, vars = PARCAT2);
    parcat2="by study drug";
    OUTPUT;
    parcat2="by treatment group";
    CALL missing(trtan);
    OUTPUT;
RUN;

PROC SORT DATA=durw_crf2;
    BY studyid usubjid parcat1 parcat2 trtan aphase;
RUN;

DATA durw_crf3;
    SET durw_crf2;
    BY studyid usubjid parcat1 parcat2 trtan aphase;
    RETAIN aval_sum overall_astdt;

    IF FIRST.aphase THEN DO;
        aval_sum=aval;
        order=1;
        overall_astdt=astdt;
    END;
    ELSE DO;
        aval_sum=aval_sum+aval;
        order=2;
    END;
    FORMAT overall_astdt date9.;
RUN;

DATA durw_crf_final;
    SET durw_crf3;
    BY studyid usubjid parcat1 parcat2 trtan aphase order;
    IF parcat2="by treatment group" AND aphase="Overall" AND order=2 THEN DO;
        astdt=overall_astdt;
        aval=aval_sum;
    END;
    IF LAST.aphase;
RUN;

** extent of exposure: Total Amount of Dose (mg)  + Actual Daily Dose (mg) - by phase (I,II,overall), based on CRF + eDiary;
** populate APHASE/PARCAT1/AVAL;
** SAP: The extent of exposure to elinzanetant will be summarized as the total amount of study drug intake in grams (in table, in dataset we use mg);
** and the average daily dose in mg using descriptive statistics per treatment group and overall. ;

** PARAMCD = TOTDOSE - based on CRF (DA);
** OASIS1: add below check due to DIL-DF#75;
PROC FREQ data=sp.da noprint;
    table usubjid*dasmnum*datestcd/out=da_check;
    where studyid IN ('21651', '21652');
RUN;

DATA _NULL_;
    SET da_check;
    IF count>1 THEN PUT "WARN" "ING: USUBJID=" USUBJID "DASMNUM=" DASMNUM "DATESTCD=" DATESTCD "has more than one entry. Need to add to DIL-DF#75.";
RUN;

PROC SORT DATA=sp.da OUT=da NODUPKEY;
    BY studyid usubjid dasmnum datestcd;
    WHERE studyid IN ('21651', '21652');
    FORMAT datestcd;
RUN;

PROC TRANSPOSE DATA=da OUT=totdose_da(DROP=_:);
    BY studyid usubjid dasmnum;
    ID datestcd;
    VAR dastresn;
RUN;

*? DIL DF#32 - Some records with DATESTCD=DISPAMT are with DADTC missing.;
*? Per tolu's response, this is due to ongoing data input. Should not be the case in the end.;
*? currently if missing date and PH2SDT is not missing, set to phase 2;
DATA da_date;
    SET da(WHERE=(datestcd="DISPAMT"));
    dadt=input(dadtc,yymmdd10.);
    KEEP studyid usubjid dasmnum dadt;
    FORMAT dadt date9.;
RUN;

DATA totdose_crf;
    MERGE totdose_da da_date;
    BY studyid usubjid dasmnum;
RUN;

DATA totdose_crf2;
    MERGE totdose_crf(IN=a) ads.adsl(KEEP=studyid usubjid ph2sdt trt01an fasfl);
    BY studyid usubjid;
    IF a;

    IF fasfl = 'Y';            *Screen failure subjects are included in IA pool DA data, we should not create total dose for them.;
    IF missing(dispamt) THEN dispamt=0;
    IF missing(lostamt) THEN lostamt=0;
    IF missing(retamt) THEN retamt=0;
    %createCustomVars(adsDomain = adex, vars = PARAMCD PARCAT1 AVAL);
    paramcd="TOTDOSE";
    parcat1="by eCRF";
    aval=(dispamt-lostamt-retamt)*60;
    ncap = (dispamt-lostamt-retamt);
RUN;

DATA totdose_crf3;
    SET totdose_crf2;
    %createCustomVars(adsDomain = adex, vars = aphase);

    IF dadt>=ph2sdt>. OR (dadt=. AND NOT missing(ph2sdt)) THEN aphase="Week 13-26";
    ELSE DO;
        aphase="Week 1-12";
        IF trt01an=9901 THEN aval=0;  *active drug dosage is 0 mg for Placebo;
    END;
    OUTPUT;

    aphase="Overall";
    OUTPUT;
RUN;

PROC SQL;
    CREATE TABLE totdose_crf_final AS
    SELECT studyid, usubjid, aphase, paramcd, parcat1, sum(aval) AS AVAL, sum(ncap) AS totcap
    FROM totdose_crf3
    GROUP BY studyid, usubjid, aphase, paramcd, parcat1;
QUIT;


** PARAMCD = TOTDOSE - based on eDiary;
DATA totdose_ediary;
    SET sp.ec(WHERE=(studyid IN ('21651', '21652') AND eccat="STUDY INTERVENTION, DIARY" AND ecdose^=0 AND ecoccur="Y"));

    ** if actual date= planned date or if actual date=planned+1 and time up to 2am ;
    ** THEN dosing date=planned date, otherwise dosing date = actual date;
    IF index(ECSTDTC,'T')>0 THEN DO;
        IF NOT (input(scan(ECSTDTC,2,'T'),time5.)>input('02:00',time5.)) THEN ECSTDTC= put(input(scan(ECSTDTC,1,'T'),yymmdd10.)-1,yymmdd10.);
    END;

    ecstdt=input(ecstdtc,yymmdd10.);

    FORMAT ecstdt date9.;
    KEEP studyid usubjid ecdose ecstdt;
RUN;

PROC SORT DATA=totdose_ediary;
    BY studyid usubjid;
RUN;

DATA totdose_ediary2;
    MERGE totdose_ediary(IN=a) ads.adsl(KEEP=studyid usubjid ph1sdt ph1edt ph2sdt ph2edt trt01an);
    BY studyid usubjid;
    IF a;
RUN;

DATA totdose_ediary3;
    SET totdose_ediary2;
    %createCustomVars(adsDomain = adex, vars = PARAMCD PARCAT1 AVAL aphase);
    paramcd="TOTDOSE";
    parcat1="by eDiary";
    aval=ecdose*60;
    ncap = ecdose;

    IF ecstdt>=ph2sdt>. THEN aphase="Week 13-26";
    ELSE DO;
        aphase="Week 1-12";
        IF trt01an=9901 THEN aval=0;  *active drug dosage is 0 mg for Placebo;
    END;
    OUTPUT;

    APHASE="Overall";
    OUTPUT;
RUN;

PROC SQL;
    CREATE TABLE totdose_ediary_final AS
    SELECT studyid, usubjid, aphase, paramcd, parcat1, ph1sdt, ph1edt, ph2sdt, ph2edt, sum(aval) AS AVAL, sum(ncap) AS totcap, min(ecstdt) AS ecstdt_first FORMAT=date9., max(ecstdt) AS ecstdt_last FORMAT=date9.
    FROM totdose_ediary3
    GROUP BY studyid, usubjid, aphase, paramcd, parcat1, ph1sdt, ph1edt, ph2sdt, ph2edt;
QUIT;


** PARAMCD = ACDLYDS - based on CRF;
PROC SQL;
    CREATE TABLE acdlyds_crf AS
    SELECT studyid, usubjid, aphase, paramcd, parcat1, sum(aval)*7 AS durd_crf
    FROM durw_crf_final
    WHERE parcat2="by treatment group"
    GROUP BY studyid, usubjid, aphase, paramcd, parcat1;
QUIT;

DATA acdlyds_crf_final;
    MERGE acdlyds_crf(IN=a DROP=paramcd) totdose_crf_final(IN=b);
    BY studyid usubjid aphase parcat1;
    paramcd="ACDLYDS";
    IF nmiss(aval,durd_crf)=0 AND durd_crf^=0 THEN aval=aval/durd_crf;
    ELSE CALL missing(aval);

    IF NOT a OR NOT b THEN DO;
        * PUT "WAR" "NING: USUBJID=" usubjid "APHASE=" aphase "PARCAT1=" parcat1 ", daily dose is not calculated due to either duration or total dose not available.";
        DELETE;
    END;
RUN;

