** PARAMCD = ACDLYDS - based on eDiary;
PROC SQL;
    CREATE TABLE acdlyds_ediary AS
    SELECT *, max(ecstdt_last) AS last_trt FORMAT=date9.
    FROM totdose_ediary_final
    GROUP BY studyid, usubjid;
QUIT;

DATA acdlyds_ediary_final;
    MERGE acdlyds_ediary(IN=a) acdlyds_crf(IN=b KEEP=studyid usubjid aphase durd_crf);
    BY studyid usubjid aphase;
    IF a;

    paramcd="ACDLYDS";
    IF NOT missing(durd_crf) THEN aval=aval/durd_crf;
    ELSE DO;
        PUT "WAR" "NING: USUBJID=" usubjid "APHASE=" aphase "PARCAT1=" parcat1 ", daily dose is not calculated due to either duration or total dose not available.";
        DELETE;
    END;
RUN;

** treatment compliance (%) - further 3 groups - by phase (I,II,overall), based on CRF + eDiary;
** populate APHASE/PARCAT1/AVAL/AVALCA1N;
** SAP: The compliance (as percentage) will be calculated as: 100 * Number of capsules taken / Number of planned capsules;
** The number of planned capsules is calculated as: treatment duration * 2. All capsules, including the placebo capsules, will be counted.;
** For participants who withdraw prematurely from the study drug, compliance will be calculated up to the time of last dose.;
** The compliance will be summarized descriptively by treatment group and overall.;
** In addition, percentage of compliance will be categorized into 3 groups, less than 80%, 80 to 120% and greater than 120%, ;
** and the categories will be summarized by treatment group, by study drug, and overall. ;

** PARAMCD = COMP

documents.sourceText:
** PARAMCD = ACDLYDS - based on eDiary;
PROC SQL;
    CREATE TABLE acdlyds_ediary AS
    SELECT *, max(ecstdt_last) AS last_trt FORMAT=date9.
    FROM totdose_ediary_final
    GROUP BY studyid, usubjid;
QUIT;

DATA acdlyds_ediary_final;
    MERGE acdlyds_ediary(IN=a) acdlyds_crf(IN=b KEEP=studyid usubjid aphase durd_crf);
    BY studyid usubjid aphase;
    IF a;

    paramcd="ACDLYDS";
    IF NOT missing(durd_crf) THEN aval=aval/durd_crf;
    ELSE DO;
        PUT "WAR" "NING: USUBJID=" usubjid "APHASE=" aphase "PARCAT1=" parcat1 ", daily dose is not calculated due to either duration or total dose not available.";
        DELETE;
    END;
RUN;

** treatment compliance (%) - further 3 groups - by phase (I,II,overall), based on CRF + eDiary;
** populate APHASE/PARCAT1/AVAL/AVALCA1N;
** SAP: The compliance (as percentage) will be calculated as: 100 * Number of capsules taken / Number of planned capsules;
** The number of planned capsules is calculated as: treatment duration * 2. All capsules, including the placebo capsules, will be counted.;
** For participants who withdraw prematurely from the study drug, compliance will be calculated up to the time of last dose.;
** The compliance will be summarized descriptively by treatment group and overall.;
** In addition, percentage of compliance will be categorized into 3 groups, less than 80%, 80 to 120% and greater than 120%, ;
** and the categories will be summarized by treatment group, by study drug, and overall. ;

** PARAMCD = COMPLPRC - based on CRF, eDiary;
DATA totdose_temp(KEEP=studyid usubjid parcat1 aphase totcap);
    SET totdose_crf_final totdose_ediary_final;
RUN;

DATA durd_temp(KEEP=studyid usubjid parcat1 aphase durd);
    SET acdlyds_crf_final(RENAME=(durd_crf=durd)) acdlyds_ediary_final(RENAME=(durd_crf=durd));
RUN;

PROC SORT DATA=totdose_temp;
    BY studyid usubjid parcat1 aphase;
RUN;

PROC SORT DATA=durd_temp;
    BY studyid usubjid parcat1 aphase;
RUN;

DATA complprc_trtgrp;
    MERGE totdose_temp(IN=a) durd_temp(IN=b);
    BY studyid usubjid parcat1 aphase;

    %createCustomVars(adsDomain = adex, vars = AVAL AVALCA1N parcat2 paramcd);
    parcat2="by treatment group";
    paramcd="COMPLPRC";
    IF nmiss(totcap,durd)=0 AND durd^=0 THEN aval=totcap*100/(2*durd);
    ELSE DO;
        * PUT "WAR" "NING: USUBJID=" usubjid "APHASE=" aphase "PARCAT1=" parcat1 "PARCAT2=" parcat2 ", compliance is not calculated due to either duration or total capsule not available.";
        DELETE;
    END;
    IF .<round(aval,0.0000000000001)<80 THEN avalca1n=7;
    ELSE IF 80<=round(aval,0.0000000000001)<=120 THEN avalca1n=8;
    ELSE IF 120<round(aval,0.0000000000001) THEN avalca1n=9;
RUN;

** ICE part;
%m_trtice;

** combine and add ADSNAME/STUDYID/ASTDY/AENDY/PARAMTYP info;
DATA eff_final;
    SET durw_crf_final totdose_crf_final totdose_ediary_final acdlyds_crf_final acdlyds_ediary_final complprc_trtgrp ice_final;
RUN;

DATA eff_final;
    set eff_final;
    ** per new request, add AVALCA1N for overall duration by treatment group (< 4 weeks, 4 - < 12 weeks, 12 - < 25 weeks, >= 25 weeks);
    IF paramcd="DURW" AND aphase="Overall" AND parcat2="by treatment group" THEN DO;
        IF .z<aval<4 THEN avalca1n=21;
        ELSE IF 4<=aval<12 THEN avalca1n=22;
        ELSE IF 12<=aval<25 THEN avalca1n=23;
        ELSE IF 25<=aval THEN avalca1n=24;
    END;

    ** update PARAMCD to deal with PARCAT issue;
    IF paramcd="ACDLYDS" AND parcat1="by eCRF" THEN paramcd="ACDDCRF";
    ELSE IF paramcd="ACDLYDS" AND parcat1="by eDiary" THEN paramcd="ACDDDRY";
    ELSE IF paramcd="COMPLPRC" AND parcat1="by eCRF" AND parcat2="by treatment group" THEN paramcd="CMPCRFGR";
    ELSE IF paramcd="COMPLPRC" AND parcat1="by eDiary" AND parcat2="by treatment group" THEN paramcd="CMPDRYGR";
    ELSE IF paramcd="DURW" AND parcat1="by eCRF" AND parcat2="by study drug" THEN paramcd="DURWDR";
    ELSE IF paramcd="DURW" AND parcat1="by eCRF" AND parcat2="by treatment group" THEN paramcd="DURWGR";
    ELSE IF paramcd="TOTDOSE" AND parcat1="by eCRF" THEN paramcd="TOTDSCRF";
    ELSE IF paramcd="TOTDOSE" AND parcat1="by eDiary" THEN paramcd="TOTDSDRY";
RUN;


**********************************************;
*IA Safety parameters;
**********************************************;
** SAP(4.4.2): For EZN 120 mg (week 1-12) and Placebo (week 1-12) all measures will be presented for week 1-12.;
** For All EZN 120 mg (week 1-52) and All Placebo (week 1-52) all measures will be presented up to week 52.;

** SAP(4.4.2): Treatment duration will be presented based on the data collected via the eCRF.;
** If the date for end of exposure is not available in eCRF, the last day of drug intake from eDiary will be used to determine the end of exposure.;

** treatment duration (weeks): PARAMCD = DURW - by phase (Week 1-12, Week 1-26, Week 1-52), based on CRF;
** populate APHASE/ASTDT/AENDT/PARCAT1/AVAL/PARAMCD/TRTAN;
** SAP(4.4.2): Treatment duration will be defined as the number of days from the day of first study drug intake up to and including the day of last study drug intake;
** and will be summarized using descriptive statistics by integrated analysis treatment group.;

** For OASIS-1/OASIS-2 studies, SP.EC is CRF collected data, after unblinded, subjects will have two records (besides the ones for dose modification if any) even if they only received E120, if they received part 2 drug.;
** EX is derived data, only one record in EX for ELZ only subjects;
** So use SP.EC for OASIS-1/OASIS-2/OASIS-3 studies;

PROC SORT DATA=sp.ec OUT=saf_durw;
    WHERE eccat="STUDY INTERVENTION" AND cmiss(ecstdtc,ecendtc)<2 AND missing(ECDOSMOD) AND missing(ECADJ) AND ecoccur='Y';
    BY studyid usubjid;
RUN;

DATA saf_durw;
    SET saf_durw;
    ecstdt=input(ecstdtc, yymmdd10.);
    if length(ecendtc)=10 then ecendt=input(ecendtc, yymmdd10.);
    else ecendt=.;
    FORMAT ecstdt ecendt date9.;
RUN;

PROC TRANSPOSE DATA=saf_durw OUT=saf_t_durw1(DROP=_:) PREFIX=ecstdt;
    BY studyid usubjid;
    VAR ecstdt;
    ID ecspid;
RUN;

PROC TRANSPOSE DATA=saf_durw OUT=saf_t_durw2(DROP=_:) PREFIX=ecendt;
    BY studyid usubjid;
    VAR ecendt;
    ID ecspid;
RUN;

DATA saf_durw_ec;
    MERGE saf_t_durw1(IN=ec1) saf_t_durw2(IN=ec2) ads.adsl(IN=adsl KEEP=studyid usubjid ph1sdt ph1edt ph2sdt trt01an trt02an trtedt);
    BY studyid usubjid;
    IF ec1;
RUN;

** SWITCH-1 study: we use EX domain as EC was not introduced at the time of this study. EX holds the information of study dug start / end date as per eCRF;
DATA saf_durw_ex;
    SET sp.ex;
    WHERE studyid = '21686' AND epoch = 'TREATMENT' AND cmiss(exstdtc,exendtc)<2;
    ecstdt1 = input(scan(exstdtc, 1, 'T'), yymmdd10.);
    ecendt1 = input(scan(exendtc, 1, 'T'), yymmdd10.);
    FORMAT ecstdt1 ecendt1 date9.;
    KEEP studyid usubjid ecstdt1 ecendt1 extrt;
RUN;

PROC SORT DATA = saf_durw_ex;
    BY studyid usubjid;
RUN;

* IA ADSL for OASIS-3:
* Derive APHASE for eCRF - Week 1-12 will be defined from start of study treatment until (T3 visit date -1) and Week 13-52 as T3 visit date until end of study treatment intake;
* So use phase dates from IA ADSL directly.;
DATA saf_durw_ex2;
    MERGE saf_durw_ex(IN=a) ads.adsl(IN=adsl KEEP=studyid usubjid ph1sdt ph1edt ph2sdt trt01an trt02an trtedt);
    BY studyid usubjid;
    IF a and adsl;     %*Select subjects for IA analysis;

    *the participant(2168616043) was randomized to Elinzanetant and received in the last month placebo by mistake;
    *for the calculation of exposure and compliance, only consider the part the participant received Elinzanetant.;
    IF trt01an = 53 AND extrt = 'PLACEBO' THEN DELETE;
RUN;

DATA saf_durw_crf;
    SET saf_durw_ec saf_durw_ex2;

    ** If the date for end of exposure is not available in eCRF, the last day of drug intake from eDiary will be used to determine the end of exposure;
    IF NOT missing(ecstdt1) AND nmiss(ecendt1,ecstdt2,ecendt2)=3 THEN ecendt1=trtedt;
    ELSE IF NOT missing(ecstdt2) AND missing(ecendt2) AND ecstdt2<=trtedt THEN ecendt2=trtedt;

    %createCustomVars(adsDomain = adex, vars = PARAMCD PARCAT1 APHASE ASTDT AENDT AVAL TRTAN);
    paramcd = "DURW";
    parcat1 = "by eCRF";

    ** Week 1-12;
    APHASE = "Week 1-12";
    ASTDT = ecstdt1;
    AENDT = ifn(missing(ph2sdt),ecendt1,ph1edt);
    AVAL = (aendt-astdt+1)/7;
    IF trt01an = 53 THEN DO; TRTAN = 1; OUTPUT; END;
    ELSE IF trt01an = 9901 THEN DO; TRTAN = 0; OUTPUT; END;

    ** Week 1-52;
    IF trt01an = 53 THEN DO;     *53 - Elinzanetant 120mg;
        APHASE = "Week 1-52";
        ASTDT = ecstdt1;
        AENDT = max(ecendt1,ecendt2);
        AVAL = (aendt-astdt+1)/7;
        TRTAN = 1;
        OUTPUT;
    END;
    ELSE IF trt01an = 9901 THEN DO;     *9901 - Placebo;
        APHASE="Week 1-52";
        IF missing(trt02an) THEN DO;   *Placebo only;
            ASTDT = ecstdt1;
            AENDT = max(ecendt1,ecendt2);
            AVAL = (aendt-astdt+1)/7;
            TRTAN = 0;
            OUTPUT;
        END;
        ELSE IF trt02an = 53 THEN DO;   *Switchers: Placebo - Elinzanetant 120mg;
            *Placebo;
            ASTDT = ecstdt1;
            AENDT = ifn(missing(ph2sdt),ecendt1,ph1edt);
            AVAL = (aendt-astdt+1)/7;
            TRTAN = 0;
            OUTPUT;
            *Elinzanetant 120mg;
            IF NOT missing(ph2sdt) THEN DO;
                ASTDT = ph2sdt;
                AENDT = ecendt2;
                AVAL = (aendt-astdt+1)/7;
                TRTAN = 1;
                OUTPUT;
            END;
        END;
    END;

    ** Week 1-26;
    IF trt01an = 53 THEN DO;     *53 - Elinzanetant 120mg;
        APHASE = "Week 1-26";
        ASTDT = ecstdt1;
        IF studyid EQ '21810' THEN DO;
            AENDT = min(ecendt1, ph1sdt + 181);
        END;
        ELSE DO;
            AENDT = max(ecendt1,ecendt2);
        END;
        AVAL = (aendt-astdt+1)/7;
        TRTAN = 1;
        OUTPUT;
    END;
    ELSE IF trt01an = 9901 THEN DO;     *9901 - Placebo;
        APHASE="Week 1-26";
        IF missing(trt02an) THEN DO;   *Placebo only;
            ASTDT = ecstdt1;
            IF studyid EQ '21810' THEN AENDT = min(ecendt1, ph1sdt + 181);
            ELSE AENDT = max(ecendt1,ecendt2);
            AVAL = (aendt-astdt+1)/7;
            TRTAN = 0;
            OUTPUT;
        END;
        ELSE IF trt02an = 53 THEN DO;   *Switchers: Placebo - Elinzanetant 120mg;
            *Placebo;
            ASTDT = ecstdt1;
            AENDT = ifn(missing(ph2sdt),ecendt1,ph1edt);
            AVAL = (aendt-astdt+1)/7;
            TRTAN = 0;
            OUTPUT;
            *Elinzanetant 120mg;
            IF NOT missing(ph2sdt) THEN DO;
                ASTDT = ph2sdt;
                AENDT = ecendt2;
                AVAL = (aendt-astdt+1)/7;
                TRTAN = 1;
                OUTPUT;
            END;
        END;
    END;
RUN;

DATA saf_durw_crf_final;
    SET saf_durw_crf;
    IF missing(aval) THEN DO;
        PUT "WAR" "NING: USUBJID=" usubjid "APHASE=" aphase "still ongoing. Duration is temporally removed.";
        DELETE;
    END;

    %createCustomVars(adsDomain = adex, vars = AVALCA1N);
    * OASIS studies updated AVALCA1N category for treatment duration;
    IF .z<aval<4 THEN avalca1n=21;
    ELSE IF 4<=aval<12 THEN avalca1n=22;
    ELSE IF 12<=aval<23 THEN avalca1n=25;
    ELSE IF 23<=aval<50 THEN avalca1n=26;
    ELSE IF 50<=aval THEN avalca1n=27;
RUN;

** SAP(4.4.2): Extent of exposure and compliance will be calculated and presented based on the ePRO daily instrument 'Study drug intake documentation'.;
** extent of exposure: TOTDOSE - Total Amount of Dose (mg)  + ACDLYDS - Actual Daily Dose (mg) - by phase (Week 1-12, Week 1-26, Week 1-52), based eDiary;

** eDiary data - for OASIS studies stored in EC domain and for SWITCH-1 stored in QS domain;
** PARAMCD = TOTDOSE - Total Amount of Dose (mg) - based on eDiary;

*OASIS-1, OASIS-2, OASIS-3: eDiary data in EC domain;
DATA saf_totdose_ediary;

