documents.sourceText:
SET sp.ec(WHERE=(eccat="STUDY INTERVENTION, DIARY" AND ecdose^=0 AND ecoccur="Y"));

    ** if actual date= planned date or if actual date=planned+1 and time up to 2am ;
    ** THEN dosing date=planned date, otherwise dosing date = actual date;
    IF index(ECSTDTC,'T')>0 THEN DO;
        IF NOT (input(scan(ECSTDTC,2,'T'),time5.)>input('02:00',time5.)) THEN ECSTDTC= put(input(scan(ECSTDTC,1,'T'),yymmdd10.)-1,yymmdd10.);
    END;

    ecstdt=input(ecstdtc,yymmdd10.);
    FORMAT ecstdt date9.;
    KEEP studyid usubjid ecdose ecstdt;
RUN;

PROC SORT DATA=saf_totdose_ediary;
    BY studyid usubjid;
RUN;

*for OASIS-3, use phase date(PH1EDT) from CRF to cut-off for 'Week 1-12';
DATA saf_totdose_ediary2;
    MERGE saf_totdose_ediary(IN=a) ads.adsl(KEEP=studyid usubjid ph1sdt ph1edt ph2sdt ph2edt trt01an trt02an);
    BY studyid usubjid;
    IF a;
RUN;

*SWITCH-1: eDiary data in QS domain;
DATA saf_totdose_ediary_switch;
    SET sp.qs(WHERE=(qstestcd = 'HFDB301' AND qsstresn = 1));  *HFDB3-Have You Taken Study Medic;
RUN;

%mergeDat(
    baseDat = saf_totdose_ediary_switch
  , keyDat  = ads.adsl(KEEP=studyid usubjid ph1sdt ph1edt ph2sdt ph2edt trt01an trt02an trtsdt trtedt saffl)
  , by      = studyid usubjid
)

DATA saf_totdose_ediary_switch2;
    SET saf_totdose_ediary_switch;
    ecstdt = input(scan(qsdtc, 1, 'T'), yymmdd10.);
    FORMAT ecstdt date9.;
    IF epoch NE 'RUN-IN' AND saffl = 'Y';
RUN;

DATA saf_totdose_ediary3;
    SET saf_totdose_ediary2 saf_totdose_ediary_switch2;
    %createCustomVars(adsDomain = adex, vars = PARAMCD PARCAT1 AVAL APHASE TRTAN);
    paramcd="TOTDOSE";
    parcat1="by eDiary";
    IF studyid = '21686' THEN aval = 3*40;          *SWITCH-1 - 120mg per day: 40mg/capsule, 4 capsules per day, 3 capsules active drug and 1 capsule placebo;
    ELSE aval = ecdose*60;                          *OASIS 1, OASIS 2, OASIS 3 - 120mg per day: 60mg/capsule, 2 capsules per day;

    IF studyid = '21686' THEN ncap = 4;             *SWITCH-1: 4 capsules per day;
    ELSE ncap = ecdose;                             *OASIS 1, OASIS 2, OASIS 3 - 120mg per day: 2 capsules per day;

    ** Week 1-12;
    IF ecstdt <= ph1edt OR missing(ph1edt) THEN DO;
        APHASE="Week 1-12";
        IF trt01an = 53 THEN DO; TRTAN = 1; OUTPUT; END;
        ELSE IF trt01an = 9901 THEN DO;
            TRTAN = 0;
            aval = 0;                   *active drug dosage is 0 mg for Placebo;
            OUTPUT;
        END;
    END;

    ** Week 1-52;
    IF trt01an = 53 THEN DO;            *53 - Elinzanetant 120mg;
        APHASE="Week 1-52";
        TRTAN = 1;
        OUTPUT;
    END;
    ELSE IF trt01an = 9901 THEN DO;     *9901 - Placebo;
        APHASE="Week 1-52";
        IF missing(trt02an) THEN DO;   *Placebo only;
            TRTAN = 0;
            aval = 0;                  *active drug dosage is 0 mg for Placebo;
            OUTPUT;
        END;
        ELSE IF trt02an = 53 THEN DO;    *Switchers: Placebo - Elinzanetant 120mg;
            IF .< ecstdt <= ph1edt THEN DO;
                TRTAN = 0;               *Placebo;
                aval = 0;                *active drug dosage is 0 mg for Placebo;
                OUTPUT;
            END;
            ELSE IF ecstdt >= ph2sdt>. THEN DO;
                 TRTAN = 1;             *Elinzanetant 120mg;
                 OUTPUT;
            END;
        END;
    END;

    ** Week 1-26;
    IF trt01an = 53 THEN DO;            *53 - Elinzanetant 120mg;
        APHASE="Week 1-26";
        IF studyid EQ '21810' THEN DO;
            IF .< ecstdt <= ph1sdt + 181 THEN DO;
                TRTAN = 1;
                OUTPUT;
            END;
        END;
        ELSE DO;
            TRTAN = 1;
            OUTPUT;
        END;
    END;
    ELSE IF trt01an = 9901 THEN DO;     *9901 - Placebo;
        APHASE="Week 1-26";
        IF missing(trt02an) THEN DO;   *Placebo only;
            IF studyid EQ '21810' THEN DO;
                IF .< ecstdt <= ph1sdt + 181 THEN DO;
                    TRTAN = 0;
                    aval = 0;                  *active drug dosage is 0 mg for Placebo;
                    OUTPUT;
                END;
            END;
            ELSE DO;
                TRTAN = 0;
                aval = 0;                  *active drug dosage is 0 mg for Placebo;
                OUTPUT;
            END;
        END;
        ELSE IF trt02an = 53 THEN DO;    *Switchers: Placebo - Elinzanetant 120mg;
            IF .< ecstdt <= ph1edt THEN DO;
                TRTAN = 0;               *Placebo;
                aval = 0;                *active drug dosage is 0 mg for Placebo;
                OUTPUT;
            END;
            ELSE IF ecstdt >= ph2sdt>. THEN DO;
                 TRTAN = 1;             *Elinzanetant 120mg;
                 OUTPUT;
            END;
        END;
    END;
RUN;

PROC SQL;
    CREATE TABLE saf_totdose_ediary_final AS
    SELECT studyid, usubjid, aphase, trtan, paramcd, parcat1, ph1sdt, ph1edt, ph2sdt, ph2edt, sum(aval) AS AVAL, sum(ncap) AS totcap, min(ecstdt) AS ecstdt_first FORMAT=date9., max(ecstdt) AS ecstdt_last FORMAT=date9.
    FROM saf_totdose_ediary3
    GROUP BY studyid, usubjid, aphase, trtan, paramcd, parcat1, ph1sdt, ph1edt, ph2sdt, ph2edt;
QUIT;


DATA saf_durd_temp(KEEP=studyid usubjid aphase durd trtan);
    SET saf_durw_crf_final;
    durd = aval*7;   *Treatment duration in days;
RUN;

PROC SORT DATA=saf_durd_temp;
    BY studyid usubjid aphase trtan;
RUN;

PROC SORT DATA=saf_totdose_ediary_final;
    BY studyid usubjid aphase trtan;
RUN;

** PARAMCD = ACDLYDS - Actual Daily Dose (mg) - based on eDiary;
DATA saf_acdlyds_ediary_final;
    MERGE saf_totdose_ediary_final(IN=a) saf_durd_temp(IN=b);
    BY studyid usubjid aphase trtan;

    paramcd = "ACDLYDS";
    totdose = aval;
    IF nmiss(totdose,durd)=0 AND durd^=0 THEN aval = totdose/durd;
    ELSE DO;
        PUT "WAR" "NING: USUBJID=" usubjid "APHASE=" aphase "PARCAT1=" parcat1  ", average daily dose is not calculated due to either duration or total capsule not available.";
        DELETE;
    END;
RUN;

** SAP(4.2.2): The compliance (as percentage) will be calculated as: 100 * Number of capsules taken / Number of planned capsules;
** The number of planned capsules is calculated as: treatment duration * 2 for OASIS1-3, treatment duration * 4 for SWITCH-1.;
** All capsules, including the placebo capsules, will be counted.;
** For participants who withdraw prematurely from the study drug, compliance will be calculated up to the time of last dose.;
** The compliance will be summarized descriptively by integrated analysis treatment group;
** In addition, percent of compliance will be categorized into 3 groups, less than 80%, 80 % to 120% and greater than 120%,;
** and the categories will be summarized by integrated analysis treatment group;

** treatment compliance (%) - by phase (Week 1-12, Week 1-52), based on eDiary;
** populate APHASE/PARCAT1/AVAL/AVALCA1N;
** PARAMCD = COMPLPRC - based on eDiary;
PROC SORT DATA=saf_totdose_ediary_final OUT=saf_totdose_temp(KEEP=studyid usubjid parcat1 aphase totcap trtan);
    BY studyid usubjid aphase trtan;
RUN;

DATA saf_complprc;
    MERGE saf_totdose_temp(IN=a) saf_durd_temp(IN=b);
    BY studyid usubjid aphase trtan;

    %createCustomVars(adsDomain = adex, vars = AVAL AVALCA1N PARAMCD);
    paramcd="COMPLPRC";
    *daily number of capsules;
    IF studyid = '21686' THEN n_plan = 4;
    ELSE n_plan = 2;
    IF nmiss(totcap,durd) = 0 AND durd ^= 0 THEN aval = 100*totcap/(n_plan*durd);
    ELSE DO;
       * PUT "WAR" "NING: USUBJID=" usubjid "APHASE=" aphase "PARCAT1=" parcat1  ", compliance is not calculated due to either duration or total capsule not available.";
        DELETE;
    END;
    IF .<aval<80 THEN avalca1n=7;
    ELSE IF 80<=aval<=120 THEN avalca1n=8;
    ELSE IF 120<aval THEN avalca1n=9;
RUN;

** combine and add ADSNAME/PARAMTYP info;
DATA saf_final;
    SET saf_durw_crf_final saf_totdose_ediary_final saf_acdlyds_ediary_final saf_complprc;
RUN;

*set up efficacy and safety parameters;
DATA final(DROP = aseq);
    SET trt eff_final(IN = eff) saf_final(IN = saf);

    %createCustomVars(adsDomain = adex, vars = PARCAT3);
    IF eff THEN parcat3 = 'Efficacy';
    ELSE IF saf THEN parcat3 = 'Safety';
    ELSE parcat3 = '';

    adsname="ADEX";
    IF paramcd^="TRT" THEN paramtyp="DERIVED";

RUN;

PROC SORT DATA=final;
    BY studyid usubjid;
RUN;

DATA ads.adex;
    MERGE final(IN=a) ads.adsl(KEEP=studyid usubjid randdt);
    BY studyid usubjid;
    IF a;

    IF NOT missing(astdt) THEN astdy=astdt-randdt +(astdt>=randdt);
    IF NOT missing(aendt) THEN aendy=aendt-randdt +(aendt>=randdt);
RUN;

*<*****************************************************************************;
*< Late ADS processing;
*<*****************************************************************************;

%late_ads_processing(adsDomain = adex)

%endprog()

