DATA adex_010;
    MERGE adex_001 (IN = _data)
          sp.dm     (KEEP = studyid usubjid actarmcd);
    BY studyid usubjid;
    IF _data THEN DO;
            IF epoch EQ "RUN-IN"                                           THEN aperiod = .;  /* Run In */
       ELSE IF studyid = '21651' AND actarmcd = 'ELIN120'     AND taetord = 3 THEN aperiod = 1;
       ELSE IF studyid = '21651' AND actarmcd = 'PLA_ELIN120' AND taetord = 2 THEN aperiod = 1;
       ELSE IF studyid = '21651' AND actarmcd = 'PLA_ELIN120' AND taetord = 3 THEN aperiod = 2;

       ELSE IF studyid = '21652' AND actarmcd = 'ELIN120'     AND taetord = 3 THEN aperiod = 1;
       ELSE IF studyid = '21652' AND actarmcd = 'PLA_ELIN120' AND taetord = 2 THEN aperiod = 1;
       ELSE IF studyid = '21652' AND actarmcd = 'PLA_ELIN120' AND taetord = 3 THEN aperiod = 2;

       ELSE IF studyid = '21686' AND actarmcd = 'ELIN120'     AND taetord = 3 THEN aperiod = 1;
       ELSE IF studyid = '21686' AND actarmcd = 'PLA'         AND taetord = 3 THEN aperiod = 1;

       ELSE IF studyid = '21810' AND actarmcd = 'PLA'         AND taetord = 2 THEN aperiod = 1;
       ELSE IF studyid = '21810' AND actarmcd = 'ELIN120'     AND taetord = 2 THEN aperiod = 1;
       ELSE DO;
           PUT 'ERR' 'OR: Undefined EX. Will be deleted! ' usubjid= actarmcd= taetord=;
           DELETE;
       END;

       OUTPUT;
    END;

    paramtyp = '';
    aphase = '';
RUN;

data ads.adex;
    set adex_010;
RUN;

%late_ads_processing(adsDomain = adex, finalise = N)

%endprog()

