*drop screen failure patients;
%m_select_subject(
    indat  = ads.adlb
  , outdat = adlb_001
)
;

%createCustomVars(
    adsdomain = ADLB
  , target    = log
)
;

%m_visit2avisit(indat = ADLB_001, outdat = ADLB_002)
;

*get TRTSDT/TRTSDTM from SP.EX instead of ADSL as it will not available before ADVS;
PROC SORT DATA=sp.ex(WHERE=(epoch NE 'RUN-IN')) OUT=ex;
    BY studyid usubjid /*exseq*/ exstdtc;
RUN;

DATA ex(KEEP=studyid usubjid trtsdt trtstm);
    SET ex;
    BY studyid usubjid /*exseq*/ exstdtc;
    FORMAT trtsdt date9. trtstm time5.;
    IF NOT missing(exstdtc) THEN DO;
        trtsdt=input(scan(exstdtc,1,'T'),yymmdd10.);
        IF index(exstdtc,'T') THEN trtstm=input(scan(exstdtc,2,'T'),time5.);
    END;
    ELSE DO;
        PUT 'ERR' 'OR: missing exposure date. Imputation needed ???' usubjid =;
        DELETE;
    END;
RUN;

DATA ex;
    SET ex;
    BY studyid usubjid;
    IF FIRST.usubjid THEN OUTPUT;
RUN;

PROC SQL;
    CREATE TABLE rand_ AS
           SELECT studyid,usubjid,dsstdtc
           FROM sp.ds
           WHERE dsdecod='RANDOMIZED'
           ORDER BY studyid,usubjid
           ;
QUIT;

DATA rand_(DROP=dsstdtc);
    SET rand_;
    FORMAT trtsdt_r date9. trtstm_r time5.;
    trtsdt_r=input(scan(dsstdtc,1,'T'),yymmdd10.);
    IF index(dsstdtc,'T') THEN trtstm_r=input(scan(dsstdtc,2,'T'),time5.);
RUN;

DATA ex;
    MERGE ex rand_;
    BY studyid usubjid;
    FORMAT trtsdt_tmp date9.;
    trtsdt_tmp=trtsdt;
    trtsdt=ifn(trtsdt>.,trtsdt,trtsdt_r);
    IF NOT missing(trtsdt) THEN trtstm=ifn(trtstm>.,trtstm,trtstm_r);
RUN;

%mergeDat(
    baseDat           = ADLB_002
  , keyDat            = ex
  , outDat            = ADLB_003
  , by                = studyid usubjid
  , dropNonKeyDatRecs = N
)
;

DATA adsl;
    SET ads.adsl(KEEP=studyid usubjid randdt trtsdt trtedt trt01an trt02an ph2sdt);
    adsl_trtsdt=ifn(trtsdt>.,trtsdt,randdt);
    drop trtsdt randdt;
RUN;

%mergeDat(
    baseDat           = ADLB_003
  , keyDat            = adsl
  , outDat            = ADLB_003
  , by                = studyid usubjid
  , dropNonKeyDatRecs = N
)
;

data _null_;
    set adlb_003;
    if trtsdt ne adsl_trtsdt then do;
       %log(D,"different first dose date " TRTSDT= ADSL_TRTSDT+, messageType=DS)
    END;
RUN;

DATA ADLB_004;
    SET ADLB_003;
    *Delete LBTESTCD=LBALL to keep consist with individual study;
    IF lbtestcd='LBALL' THEN DELETE;

    IF LBTESTCD='CYURIAC' THEN DO;
        paramn=337200;
        paramcd='CY_URIHC';
    END;

    *call missing(trtstm);
    /* Copy from study codes
    * apply rule for aval values below LLOQ acc. to SAP using LBLLOQ variable:
    * "Values below the lower limit of quantification (LLOQ) will be set to LLOQ/2.
    *  Values above the upper limit of quantification (ULOQ) will be set to ULOQ."*/
    %createCustomVars(adsDomain = ADLB, vars = aval ANRIND avalc parcat2)
    aval= lbstresn;
    avalc=lbstresc;
    IF index(lbstresc,'<')>0 THEN DO;
        aval= input(substr(lbstresc,2),best.)/2;
        avalc=strip(put(aval,best.));
    END;

    IF index(lbstresc,'>')>0 THEN DO;
        aval= input(substr(lbstresc,2),best.);
        avalc=strip(put(aval,best.));
    END;

    /* keep parcat2 blank for  CLOSE LIVER OBSERVATION to remove p21 warning as per Team decision*/
    IF NOT missing(lbscat) THEN parcat2=lbscat;
    IF parcat2 EQ "CLOSE LIVER OBSERVATION" THEN parcat2="";

    IF nmiss(ANRLO,ANRHI, AVAL) = 0 AND ANRLO<=AVAL<= ANRHI THEN ANRIND = "NORMAL";
    ELSE IF nmiss(ANRLO,ANRHI, AVAL) = 0 AND AVAL < ANRLO THEN ANRIND = "LOW";
    ELSE IF nmiss(ANRLO,ANRHI, AVAL) = 0 AND AVAL > ANRHI THEN ANRIND = "HIGH";
    ELSE IF missing(ANRIND) AND NOT missing(LBNRIND) THEN ANRIND=strip(LBNRIND);
    *Criterion Flag derivation;
    *CRIT1: >=20xULN;
    *CRIT2: >=10xULN;
    *CRIT3: >= 8xULN;
    *CRIT4: >= 5xULN;
    *CRIT5: >= 3xULN;
    *CRIT6: >= 2xULN;
    *CRIT7: >= 1.5xULN;
    *CRIT8: >= 1xULN;
    %createCustomVars(
        adsDomain = ADLB
      , vars      = CRIT1 CRIT1FL CRIT2 CRIT2FL CRIT3 CRIT3FL CRIT4 CRIT4FL CRIT5 CRIT5FL CRIT6 CRIT6FL  CRIT7 CRIT7FL CRIT8 CRIT8FL CRIT9 CRIT9FL CRIT10 CRIT10FL CRIT11 CRIT11FL CRIT12 CRIT12FL
    )
    ;
    IF paramcd IN ('SGOTSP' 'SGPTSP' 'BILITOSP' 'ALKPHOSP' 'PTINR') AND NOT missing(aval) AND NOT missing(anrhi) THEN DO;
        /*">=20xULN"*/
        IF  aval >=20*anrhi  THEN DO;
            CRIT1 =">=20 x ULN" ;
            CRIT1FL="Y";
        END;
        /*">=10xULN"*/
        IF  aval >=10*anrhi  THEN DO;
            CRIT2 =">=10 x ULN" ;
            CRIT2FL="Y";
        END;
        /*">=8xULN"*/
        IF  aval >=8*anrhi  THEN DO;
            CRIT3 =">=8 x ULN" ;
            CRIT3FL="Y";
        END;
        /*">=5xULN"*/
        IF  aval >=5*anrhi  THEN DO;
            CRIT4 =">=5 x ULN" ;
            CRIT4FL="Y";
        END;
        /*">=3xULN"*/
        IF  aval >=3*anrhi  THEN DO;
            CRIT5 =">=3 x ULN" ;
            CRIT5FL="Y";
        END;
        /*">=2xULN"*/
        IF aval >=2*anrhi  THEN DO;
            CRIT6 =">=2 x ULN" ;
            CRIT6FL="Y";
        END;
        /*">=1.5xULN"*/
        IF aval >=1.5*anrhi  THEN DO;
            CRIT7 =">=1.5 x ULN" ;
            CRIT7FL="Y";
        END;
        /*">=1xULN"*/
        IF  aval >=1*anrhi  THEN DO;
            CRIT8 =">=1 x ULN" ;
            CRIT8FL="Y";
        END;
        /*"<2xULN"*/
        IF aval <2*anrhi  THEN DO;
            CRIT9 ="<2 x ULN" ;
            CRIT9FL="Y";
        END;
        /*"<3xULN"*/
        IF aval <3*anrhi  THEN DO;
            CRIT10 ="<3 x ULN" ;
            CRIT10FL="Y";
        END;

        IF paramcd EQ "PTINR" THEN DO;
            IF aval >=2  THEN DO;
                CRIT12 =">=2" ;
                CRIT12FL="Y";
            END;

            IF aval >=1.5 THEN DO;
                CRIT11 =">=1.5" ;
                CRIT11FL="Y";
            END;
        END;

    END;

RUN;

