DATA adlb_crit5_axt;
    SET adlb_crit5_axt;
    BY studyid &subj_var paramcd;
    RETAIN _pre_adt _diff;
    IF FIRST.paramcd THEN CALL missing(_pre_adt, _diff);
    IF crit4fl='Y' THEN DO;
        IF missing(_diff) THEN DO;
            _pre_adt=adt;
            _diff=adt-_pre_adt;
        END;
        ELSE DO;
            _diff=adt-_pre_adt;
        END;
    END;
    ELSE CALL missing(_pre_adt,_diff);
RUN;

