  , post_base_list = Y
)
;

DATA ads.ADLB;
    SET ADLB_013;
    IF anl01fl='Y' AND avisitn=0 THEN CALL missing(anl01fl,anl02fl,anl03fl,chg);
    IF (avisitn=5 AND missing(ablfl)) or (avisitn=0 and ady>1) THEN DO;
        avisitn=900000;
        CALL missing(anl01fl,anl02fl,anl03fl);
    END;

    IF avisitn=500000 THEN CALL missing(anl01fl,anl02fl, anl03fl);

    *remove not needed 01/02/03 flag for those derived paramcds;
    if paramcd = :'CCRIT' then call missing(anl01fl,anl02fl,anl03fl);
RUN;

%LATE_ADS_PROCESSING(ADSDOMAIN = ADLB)
;

%endprog(cleanWork = Y)
;

