*<#pink For other data regarding post baseline expect PGI;

data &adsDomain._ncsp_fst(keep=studyid usubjid qscat qsscat avisitn adt atm);
    set &adsDomain._ncsp;
    by studyid usubjid qscat qsscat avisitn _v_priority adt atm;
    if first.avisitn;
    if avisitn ^=.;
