    * For ISI and MENQOL: select Baseline Visit, 4,8,12,16,26, Follow-up;
    if find(qscat, 'MENOPAUSE-SPECIFIC QUALITY-OF-LIFE QUESTIONNAIRE')>0 or find(qscat, 'ISI')>0 then do;
