    if nmiss(aval, base) = 0 then do;
        chg = aval - base;
        if base^=0 then pchg = ((aval - base)/base) * 100;
    END;
RUN;

*<*****************************************************************************;
*< Add ANL04FL for descriptive table display purpose
*< + remove tempfix dummy record
