/*******************************************************************************
 * Bayer AG
 * Study            :
 * Proj/Subst/GIAD  : 3427080 / BAY 3427080, ELINZANETANT BAY3427080 NK1-3 RA Vasomotor Symptoms
 *******************************************************************************
 *Name of program**************************************************************/
   %iniprog(name = d_adsl);
/*
 * Purpose          : Derivation of ADSL
 * Programming Spec :
 * Validation Level : 1
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Pre-conditions   :
 * Post-conditions  :
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqe (Endri Elnadav) / date: 30JAN2024
 * Reference prog   :
 ******************************************************************************/
/* Changed by       : evmqe (Endri Elnadav) / date: 18MAR2024
 * Reason           : Adapted o3 phase date
 ******************************************************************************/


%early_ads_processing(adsDomain = ADSL)

%*Select subjects;
%m_select_subject(
    indat          = ads.adsl
  , outdat         = adsl_001
  , removescrnfail = N
)

*================================================================================================================;
* Disposition ;
*================================================================================================================;
PROC SORT DATA=sp.ds OUT=_ds(KEEP=usubjid DSDECOD DSSCAT EPOCH DSSTDTC DSSUBDEC);
    BY usubjid DSSTDTC ;
    WHERE dsdecod NOT IN ("COMPLETED","SCREEN FAILURE")
          AND dscat NE  "PROTOCOL MILESTONE"
          AND EPOCH ^= "SCREENING"
          AND DSSCAT NE "INFORMED CONSENT"
          AND DSSUBDEC NOT IN ("CONTINUE WITH SCHEDULED VISITS/ PROCEDURES" "CONTINUE WITH PHONE CONTACTS REPLACING SITE VISITS")
          AND studyid NE '21686';
RUN;
DATA _ds;
  SET _ds;
  BY usubjid;
  IF FIRST.usubjid;
RUN;

PROC SORT DATA=sp.ds OUT=_ds21686(KEEP=usubjid DSDECOD DSSCAT EPOCH DSSTDTC DSSUBDEC);
    BY usubjid DSSTDTC ;
    WHERE dsdecod NOT IN ("COMPLETED","SCREEN FAILURE")
          AND dscat NE  "PROTOCOL MILESTONE"
          AND EPOCH ^= "SCREENING"
          AND DSSCAT NE "INFORMED CONSENT"
          AND DSSUBDEC NOT IN ("CONTINUE WITH SCHEDULED VISITS/ PROCEDURES" "CONTINUE WITH PHONE CONTACTS REPLACING SITE VISITS")
          AND studyid EQ '21686';
RUN;

DATA _ds21686;
  SET _ds21686;
  IF dsscat = 'END OF STUDY' THEN _prio = 1;
                             ELSE _prio = 2;
RUN;
PROC SORT; BY usubjid _prio DSSTDTC;
DATA _ds21686;
  SET _ds21686;
  BY usubjid;
  IF FIRST.usubjid;
RUN;

DATA _ds;
      SET _ds
          _ds21686;
RUN;
PROC SORT; BY usubjid; ruN;

*================================================================================================================;
* Smoking history ;
*================================================================================================================;
proc sort data=sp.su out=_su(KEEP=USUBJID SUNCF);
   where upcase(sucat) = 'TOBACCO' and not missing(SUNCF);
   by usubjid suncf;
RUN;

** alphabetical order will take care of priority CURRENT>FORMER>NEVER;;
proc sort data=_su nodupkey;
    by usubjid;
RUN;

*================================================================================================================;
* educational level;
*================================================================================================================;
proc sort data=sp.sc out=_edu(keep= usubjid scorres);
    by usubjid;
    where sctestcd="EDULEVEL";
RUN;

*******************************************************************************;
*< Custom derivation based on study needs;
*******************************************************************************;
DATA adsl_010_def;
  MERGE adsl_001   (IN = _data)
        _ds        (KEEP = usubjid DSDECOD)
        _su
        _edu;
  BY usubjid;

  IF _data THEN DO;
      %createCustomVars(adsDomain=adsl, vars=agegr1n);
           if age >  .z and age < 40 then agegr1n = 11; %** X_AGE2GP.11 [< 40 years];
      else if age >= 40 and age <=49 then agegr1n = 12; %** X_AGE2GP.12 [40 - 49 years];
      else if age >= 50 and age <=59 then agegr1n = 13; %** X_AGE2GP.13 [50 - 59 years];
      else if age >= 60 and age <=65 then agegr1n = 14; %** X_AGE2GP.14 [60 - 65 years];
      else if               age > 65 then agegr1n = 15; %** X_AGE2GP.15 [> 65 years];

      %createCustomVars(adsDomain=adsl, vars=BMIGR1N);
           if .z < bmibl <  18.5              then bmigr1n = 1; %** Z_BMIGRP.1 [< 18.5 kg/m2];
      else if bmibl >= 18.5 and bmibl < 25    then bmigr1n = 2; %** Z_BMIGRP.2 [>=18.5 to < 25 kg/m2];
      else if bmibl >= 25 and bmibl < 30      then bmigr1n = 3; %** Z_BMIGRP.3 [>=25 to < 30 kg/m2];
      else if bmibl >= 30                     then bmigr1n = 4; %** Z_BMIGRP.4 [>= 30 kg/m2];

      * Region;
      %createCustomVars(adsDomain=adsl, vars=region1n region1n);
      if country in ('USA' 'CAN') then region1n = 3; %** X_REGION.3 [North America];
                                  else region1n = 9; %** X_REGION.9 [Rest of the World];

      * Tobacco use;
      %createCustomVars(adsDomain=adsl, vars=SMOKHXN);
           if suncf='NEVER'    then SMOKHXN=1; %** NCF.1 [NEVER];
      else if suncf='FORMER'   then SMOKHXN=2; %** NCF.2 [FORMER];
      else if suncf='CURRENT'  then SMOKHXN=3; %** NCF.3 [CURRENT];


      * Education level;
      %createCustomVars(adsDomain=adsl, vars=EDULEVEL);
      EDULEVEL = propcase(scorres);

      * Discontinuation from study;
      %createCustomVars(adsDomain=adsl, vars=DCSREAS);
      DCSREAS = DSDECOD;

      OUTPUT;
  END;
RUN;

/*================================================================================================================
 * Treatment End Date
 * If the date for end of exposure is not available in eCRF, the last day of drug intake from eDiary will be used to determine the end of exposure.;
 *================================================================================================================*/
proc sort data=sp.ex out=ex_001_data;
    where not missing(exstdtc);
    by usubjid exstdtc;
RUN;

DATA ex_010_last;
    SET ex_001_data;
    BY usubjid;
    FORMAT exendt date9.;
    exendt = INPUT(SCAN(exendtc, 1, 'T'), ??yymmdd10.);
    IF LAST.usubjid;
RUN;



proc sort data=sp.ec out=ec_001_data;
    where     ecdose>0
/*          and eccat="STUDY INTERVENTION, DIARY"*/
          and ecoccur='Y'
          AND NOT MISSING(ecendtc);
    by usubjid ecendtc;
RUN;

DATA ec_001_data;
    SET ec_001_data;
    IF LENGTH(ecendtc) < 10 THEN DO;
/*        PUT 'ERR' 'OR: ECENDTC will be ignored and need to be checked ' usubjid = ecendtc = ;*/
        DELETE;
    END;
RUN;

data ec_010_last;
    set ec_001_data;
    BY usubjid;
    ** if actual date= planned date or if actual date=planned+1 and time up to 2am ;
    ** THEN dosing date=planned date, otherwise dosing date = actual date;
    FORMAT ecendt date9.;
    ecendt = input(scan(ECENDTC,1,'T'), yymmdd10.);
    if index(ECENDTC,'T')>0 then do;
        if     input(scan(ECENDTC,2,'T'),time5.)>=input('00:00',time5.)
           AND input(scan(ECENDTC,2,'T'),time5.)<=input('02:00',time5.)
        then ecendt = input(scan(ECENDTC,1,'T'),yymmdd10.)-1;
    END;

    IF LAST.usubjid;
RUN;

proc sort data=sp.ds out=non_ongoing (KEEP = usubjid) nodupkey;
    where epoch="TREATMENT" and missing(dsscat);
    by usubjid;
RUN;


data adsl_020_trtedt;
    merge adsl_010_def (in=a)
          ex_010_last  (keep=usubjid exendt)
          ec_010_last  (keep=usubjid ecendt)
          non_ongoing  (in=b);
    by usubjid;
    if a;

    %createCustomVars(adsDomain=adsl, vars=trtedt);
         if not missing(exendt)  then trtedt=exendt;
    else if not missing(ecendt)  then trtedt=ecendt;


    ** per team decision: for ongoing subjects, set TRTEDT to missing;
    if not b AND armcd NE 'SCRNFAIL' then DO;
/*        PUT 'WAR' 'NING: Subject still ONGOING?  Check again TRTEDT !!!' usubjid = ;*/
        call missing(trtedt);
    end;

    ** Check end treatment date;
    if b AND armcd NE 'SCRNFAIL' then DO;
       IF trtsdt > trtedt AND NOT MISSING (trtedt) THEN DO;
          PUT 'WAR' 'NING: Trt start > trt end. Max will be used!' usubjid= trtsdt= trtedt= ecendt=;
          trtedt = MAX(ecendt, rfxendt);
       END;
    END;

    %* Correction of TRTSDT;
    IF MISSING(trtsdt) AND NOT MISSING(RFXSTDTC) THEN DO;
        trtsdt = INPUT(SCAN(RFXSTDTC, 1, 'T'), yymmdd10.);
    END;


    IF NOT MISSING(trtedt) AND MISSING(trtsdt) AND MISSING(rfxstdtc) THEN DO;
        trtedt = .;
    END;

    IF MISSING(tr01edt) AND NOT MISSING(trtedt) THEN DO;
       tr01edt = trtedt;
    END;
RUN;

/*================================================================================================================
* Add PHASE1 and PHASE2 start and end date for OASIS1 and OASIS2
*
*   Phase1 starts: First Dose
*
*   Phase1 ends:
*       1) Participants who stayed in the study for at least 12 weeks and received the part two drug: First day of drug 2 intake (eCRF SP.EC) - 1 day.
*       2) Participants who discontinued from study drug before week 12 but agreed to complete the assessments until week 12 (post-treatment epoch):
*          Week 12 visit date or the post treatment phase end date, whichever is earlier.
*       3) Participants who discontinued from randomized drug and decided to go to the follow up period or withdraw from the study before week 12:
*          Study drug discontinuation date (DS) or EOT visit date - whichever is later.
*
*   Phase2 starts:
*       First day of part 2 drug intake (eCRF)
*
*   Phase2 ends:
*       1) Participants who completed the study: last study drug intake date from eCRF (EX)
*       2) Participants who discontinue from treatment/study prematurely during the second phase:
*          the study drug discontinuation date (DS) or  or EOT visit date - whichever is later.
*
* Add PHASE1 and PHASE2 start and end date for OASIS3
*
*   Phase1 starts: randomization (as the first dose will be taken on site, this should match the data in Rave)
*
*   Phase1 ends:
*        Week 12 assessment date
*        or for participants who discontinued early, study drug discontinuation date
*        or EOT assessment date, whichever is later
*
*   Phase2 starts: Week 12 assessment date + 1 (identified based on the eCRF entry).;
*
*   Phase2 ends (only applied in IA):
*       1) Participants who completed the study: End of treatment period date or treatment end date, whichever is later
*       2) Participants who discontinue from treatment/study prematurely after Day 84 (Week 12): Study drug discontinuation date or EOT assessment date or treatment end date, whichever is later
*================================================================================================================*/


%***** Get SV;
DATA ph_000_sv;
  SET sp.sv;
  ATTRIB astdt FORMAT = date9.
         aendt FORMAT = date9.;
  astdt= input(svstdtc, ?? e8601da.);
  aendt = input(svendtc, ?? e8601da.);
  IF visitnum IN (85 600000 700000);
  IF svoccur = 'Y';
  IF NOT MISSING(svstdtc);
RUN;

PROC SORT DATA = ph_000_sv ; BY usubjid astdt; RUN;
PROC TRANSPOSE DATA   = ph_000_sv
               OUT    = ph_010_svtransst (DROP = _name_)
               SUFFIX = _start;
  BY usubjid;
  ID visitnum;
  IDLABEL visit;
  VAR astdt;
  FORMAT visitnum best.;
RUN;

PROC SORT DATA = ph_000_sv ; BY usubjid aendt; RUN;
PROC TRANSPOSE DATA = ph_000_sv
               OUT  = ph_010_svtransen (DROP = _name_)
               SUFFIX = _end;
  BY usubjid;
  ID visitnum;
  IDLABEL visit;
  VAR aendt;
  FORMAT visitnum best.;
RUN;

PROC TRANSPOSE DATA = ph_000_sv            (WHERE = (EPOCH ne "POST-TREATMENT"))
               OUT  = ph_010_svtransen_trt (DROP = _name_)
               SUFFIX = _end_trt;
  BY usubjid;
  ID visitnum;
  IDLABEL visit;

