  DSSTDT_pt = input(dsstdtc, ?? e8601da.);
  IF LAST.usubjid;
RUN;


%**** Get DS - Completer / Non Completers;
data ph_020_dscomp (KEEP = usubjid DSSTDT_comp);
    set sp.ds;
    IF     epoch   =   'TREATMENT'
       and dscat   =   'DISPOSITION EVENT'
       and dsdecod EQ  'COMPLETED'
       and dsscat  NE  "INFORMED CONSENT" THEN DO;
