VAR aendt;
  FORMAT visitnum best.;
RUN;


%***** Get DS;
PROC SORT DATA = sp.ds
          OUT  = ph_020_dspost;
    BY usubjid dsstdtc;
    WHERE epoch='POST-TREATMENT';
RUN;
DATA ph_020_dspost (KEEP = usubjid DSSTDT_pt);
  SET ph_020_dspost;
  BY usubjid;
  format DSSTDT_pt date9.;
  DSSTDT_pt = input(dsstdtc, ?? e8601da.);
  IF LAST.usubjid;
RUN;


%**** Get DS - Completer / Non Completers;
data ph_020_dscomp (KEEP = usubjid DSSTDT_comp);
    set sp.ds;
    IF     epoch   =   'TREATMENT'
       and dscat   =   'DISPOSITION EVENT'
       and dsdecod EQ  'COMPLETED'
       and dsscat  NE  "INFORMED CONSENT" THEN DO;
       format DSSTDT_comp date9.;
       DSSTDT_comp = input(dsstdtc, ?? e8601da.);
       OUTPUT;
    END;
RUN;
PROC SORT DATA = ph_020_dscomp ; BY usubjid ; RUN;


data ph_020_dsnoncomp (KEEP = usubjid DSSTDT_noncomp);
    set sp.ds;
    IF     epoch   =  'TREATMENT'
       and dscat   =  'DISPOSITION EVENT'
       and dsdecod NE 'COMPLETED'
       and dsscat  NE "INFORMED CONSENT" THEN DO;
       format DSSTDT_noncomp date9.;
       DSSTDT_noncomp = input(dsstdtc, ?? e8601da.);
       OUTPUT;
    END;
RUN;
PROC SORT DATA = ph_020_dsnoncomp ; BY usubjid ; RUN;



%***** Get EC the second phase;
PROC SORT DATA = sp.ec  (WHERE = (eccat="STUDY INTERVENTION" and missing(ECDOSMOD) and missing(ECADJ) and ecoccur='Y' and cmiss(ecstdtc,ecendtc)<2 ))
          OUT  = ph_030_ec;
    BY usubjid ecstdtc;
RUN;
DATA ph_030_ecph2 (KEEP = usubjid p2_ecstdt);
    SET ph_030_ec;
    BY usubjid;
    p2_ecstdt = INPUT(ecstdtc, ??yymmdd10.);
    IF                      LAST.usubjid
       AND FIRST.usubjid NE LAST.USUBJID;
RUN;


%***** Derive Phase Dates;
data adsl_030_phdates;
  merge adsl_020_trtedt (in=a)
        ph_010_svtransst
        ph_010_svtransen
        ph_010_svtransen_trt
        ph_020_dspost
        ph_020_dscomp     (IN = _comp)
        ph_020_dsnoncomp  (IN = _noncomp)
        ph_030_ecph2
        ;
  by usubjid;
  if a;

  ATTRIB ph1sdt ph1edt FORMAT = date9.;

  *   Phase1 starts: First Dose;
  *   If subject is randomized but not treated, then use random date;
  ph1sdt = trtsdt;
  IF MISSING(trtsdt) AND NOT MISSING(randdt) THEN ph1sdt = randdt;

  *   Phase1 ends;
  *       1) Participants who stayed in the study for at least 12 weeks and received the part two drug: First day of drug 2 intake (eCRF) - 1 day.;
  *       2) Participants who discontinued from study drug before week 12 but agreed to complete the assessments until week 12 (post-treatment epoch);
  *          Week 12 visit date or the post treatment phase end date, whichever is earlier;
  *       3) Participants who discontinued from randomized drug and decided to go to the follow up period or withdraw from the study before week 12;
  *          Study drug discontinuation date (DS) or EOT visit date - whichever is later.;
  *   If randomized but not treated, set PH1EDT to random date also;
  if studyid in ("21651","21652") then do;
            if NOT MISSING(p2_ecstdt)                 then PH1EDT = p2_ecstdt-1;
       else if NOT MISSING(DSSTDT_pt)                 then PH1EDT = min(_85_end      , dsstdt_pt);
       else if nmiss(trtedt,_600000_end)<2            then PH1EDT = MAX(_600000_end  , trtedt   );
  end;
  else if studyid in ("21686") then do;
       IF NOT MISSING(trtedt) THEN PH1EDT = trtedt;
  end;
  else if studyid in ("21810") then do;
             if NOT MISSING(_85_end_trt)               then PH1EDT = _85_end_trt -1;
        else if nmiss(trtedt,_600000_end)<2            then PH1EDT = MAX(_600000_end  , trtedt, DSSTDT_noncomp   );
  END;

  *   If subject is randomized but not treated, then use random date;
  IF MISSING(trtsdt) AND NOT MISSING(randdt) THEN ph1edt = randdt;


  *   Phase2 starts: Day 85;
       if studyid in ("21651","21652") AND NOT MISSING(p2_ecstdt)   then PH2SDT = p2_ecstdt ;
  else if studyid in ("21810")         AND NOT MISSING(_85_end_trt) then PH2SDT = PH1EDT + 1;


  *   Phase2 ends;
  *       1) Participants who completed the study: End of treatment period date;
  *       2) Participants who discontinue from treatment/study prematurely after Day 84 (Week 12): Study drug discontinuation date or EOT assessment date, whichever is later;
  IF NOT MISSING(ph2sdt) THEN DO;
     IF _comp THEN PH2EDT = DSSTDT_comp;
              ELSE PH2EDT = MAX(trtedt, _600000_end);
  END;

  /* Oasis 3: Assign max to PH2EDT  !!
   * Study OASIS 3 dont have / use any PH2EDT definition at all */
  IF studyid in ("21810") AND NOT MISSING(ph2sdt) THEN DO;
     IF NOT(_noncomp) THEN ph2edt = MAX(DSSTDT_comp,    trtedt);
                      ELSE ph2edt = MAX(DSSTDT_noncomp, trtedt, _600000_end);
  END;
run;



