DATA adsl;  SET ads.adsl;   RUN;

**  Subgroup: Hepatic impairment in medical history (defined via SMQ hepatic disorders excl. sub-SMQs
*   - Liver related investigations, signs and symptoms
*   - Liver-related coagulation and bleeding disturbances);
DATA mh;    SET sp.mh;      RUN;

%smq_select(
    outdat    = hepatic
  , smqcode   = 20000005
  , smqtype   = _ALL_
  , smqsearch = _ALL_
)

DATA hepatic(KEEP=mhbodsys mhdecod);
    SET hepatic;
    IF pt_smq_name IN ('Liver related investigations, signs and symptoms (SMQ)'
                       'Liver-related coagulation and bleeding disturbances (SMQ)') THEN DELETE;
    mhbodsys = soc_name;
    mhdecod = pt_name;
RUN;

PROC SORT DATA=hepatic NODUPKEY; BY mhbodsys mhdecod; RUN;

%mergeDat(
    baseDat           = mh
  , keyDat            = hepatic
  , outDat            = hepatic_subjects(KEEP=&subj_var.)
  , by                = mhbodsys mhdecod
  , dropNonKeyDatRecs = Y
)

PROC SORT DATA=hepatic_subjects NODUPKEY;   BY &subj_var.; RUN;
PROC SORT DATA=adsl;                        BY &subj_var.; RUN;

DATA adsl;
    MERGE adsl              (IN=_adsl)
          hepatic_subjects  (IN=_hepatic);
    BY &subj_var.;
    %createCustomVars(adsDomain = adsl, vars = hepatic);
    IF _adsl;
    IF _hepatic THEN hepatic = 'Y';
    ELSE             hepatic = 'N';
RUN;

** Subgroup: Renal impairment (baseline eGFR (ml/min/1.73m2) category);
DATA b_egfrn(KEEP=&subj_var. b_egfrn);
    SET ads.adlb(WHERE=(paramcd EQ 'GFRE_C' AND ablfl='Y'));
    b_egfrn = aval;
RUN;

%mergeDat(baseDat = adsl, keyDat = b_egfrn, by = &subj_var.)

DATA adsl;
    SET adsl;
    %createCustomVars(adsDomain = adsl, vars = EGFRGR1N)
         IF .Z <  b_egfrn < 25  THEN egfrgr1n = 1;%** Z_EGFRGR.1 [< 25 mL/min/1.73 m2];
    ELSE IF 25 <= b_egfrn < 45  THEN egfrgr1n = 2;%** Z_EGFRGR.2 [25- < 45 mL/min/1.73 m2];
    ELSE IF 45 <= b_egfrn < 60  THEN egfrgr1n = 3;%** Z_EGFRGR.3 [45- < 60 mL/min/1.73 m2];
    ELSE IF 60 <= b_egfrn       THEN egfrgr1n = 4;%** Z_EGFRGR.4 [>= 60 mL/min/1.73 m2];
RUN;


** Pregnant women are identified based on information through the urine test in the laboratory data or pelvic ultrasound performed during the treatment phase.;

** Pregnant women based on urine test in the laboratory data;
DATA pregnant_urine(KEEP=&subj_var. pregnant);
    SET sp.lb(WHERE=(lbscat EQ 'PREGNANCY TEST' AND lbtestcd = 'HCG'));
    %createCustomVars(adsDomain = adsl, vars = PREGNANT)
         IF lbstresc = "NEGATIVE" THEN pregnant = 'N';
    ELSE IF lbstresc = "POSITIVE" THEN pregnant = 'Y';
    ELSE call missing(pregnant);
RUN;

** Pregnant women based on pelvic ultrasound performed during the treatment phase;
DATA pregnant_ultrasound(KEEP=&subj_var. pregnant);
    SET sp.fapr(WHERE=((fatestcd EQ 'PREG' AND epoch EQ 'TREATMENT')));
    %createCustomVars(adsDomain = adsl, vars = PREGNANT)
         IF fastresc = 'N' THEN pregnant = 'N';
    ELSE IF fastresc = 'Y' THEN pregnant = 'Y';
    ELSE call missing(pregnant);
RUN;

** Stack them together;
DATA pregnant;
    SET pregnant_urine
        pregnant_ultrasound;
RUN;

PROC SORT DATA = pregnant; BY &subj_var. pregnant; RUN;

** If multiple observations exist for the same subject, this data step will choose the latest one.;
** Due to sorting, 'Y' will appear last if it exists for a subject, thus making the subject 'Positive';
DATA pregnant;
    SET pregnant;
    BY &subj_var.;
    IF LAST.&subj_var.;
RUN;

%mergeDat(baseDat = adsl, keyDat = pregnant, by = &subj_var.)

DATA adsl;
    SET adsl;
    IF missing(pregnant) THEN pregnant = 'N';
RUN;

** This information is needed for Standard exposure Tables for the RMP;
** Since this information is not collected in any of these studies this variable is set to 'NOT APPLICABLE' for all subjects.;
DATA adsl;
    SET adsl;
    %createCustomVars(adsDomain = adsl, vars = breastn)
    breastn = 991;  %** NY.991 [NA];
RUN;

** Derive EXNYOVLN;
** Derived. Set to 1 if any EX.EXSTDTC is not missing and epoch is not 'RUN-IN';
DATA exnyovln(KEEP=&subj_var. exnyovln);
    SET sp.ex(WHERE=(not missing(exstdtc) AND epoch NE "RUN-IN"));
    %createCustomVars(adsDomain = adsl, vars = exnyovln)
    exnyovln = 1;
RUN;

PROC SORT DATA=exnyovln NODUPKEY; BY &subj_var.; RUN;

%mergeDat(baseDat = adsl, keyDat = exnyovln, by = &subj_var.)

DATA adsl;
    SET adsl;
    IF missing(exnyovln) THEN exnyovln = 0;
RUN;


DATA ads.adsl;
    SET adsl;
RUN;

%late_ads_processing(adsDat = ADS.ADSL)

