        SELECT DISTINCT usubjid INTO : mis_post_lst SEPARATED BY '","'
               FROM adlb_use(WHERE=(&base_cond.))
               WHERE usubjid NOT IN
                  (SELECT DISTINCT usubjid
                    FROM adlb_use
                    WHERE &post_base_cond. AND NOT missing(aval));

        SELECT DISTINCT usubjid INTO : mis_post_lst1 SEPARATED BY '","'
        FROM adsl
        WHERE usubjid NOT IN
          (SELECT DISTINCT usubjid
            FROM adlb_use
            WHERE NOT missing(aval));
    QUIT;
    %if not %symexist(mis_post_lst1) %then %let mis_post_lst1='';
    DATA adsl_use;
        SET adsl;
        IF usubjid IN ("&mis_post_Lst.") THEN mis_post=1;
        IF usubjid IN ("&mis_post_Lst1.") THEN mis_post=1;
    RUN;
