DATA ADS.adtte;
    SET out_adtte_ph1 out_adtte_ph2 out_adtte_ph3
        out_adtte_ds_ph1_1(IN=d1) /*out_adtte_ds_ph2(in=d2) out_adtte_ds_ph3(in=d3)*/
        out_adtte_cm_ph1_1(IN=c1) /*out_adtte_cm_ph2(in=c2) out_adtte_cm_ph3(in=c3)*/
        ;
    IF n(adt,startdt)=2 THEN aval=adt-startdt+1;
    %createCustomVars(
        adsDomain = adtte
      , vars      = paramtyp
    )
    ;

    paramtyp='DERIVED';
    IF d1 /*or d2 or d3*/ THEN DO;
        IF mod(aval,7)>5 THEN aval=ceil(aval/7)+1;
        ELSE IF mod(aval,7)=0 THEN aval=aval/7+1;
        ELSE aval=ceil(aval/7);
        IF adt=startdt THEN aval=0;
        IF NOT missing(icestwk) THEN DO;
            aval=icestwk;
            if aval=0 and adt-startdt>7 then adt=startdt;
            cnsr=0;
        END;

        IF d1 AND aval>12 THEN aval=12;
    END;

    IF c1 /*or c2 or c3*/ THEN DO;
        IF mod(aval,7)>5 THEN aval=ceil(aval/7);
        ELSE IF mod(aval,7)=0 THEN aval=aval/7;
        ELSE aval=floor(aval/7);
        IF cnsr=0 THEN aval=aval+1;
        IF adt=startdt THEN aval=0;
        IF NOT missing(icestwk) THEN DO;
            aval=icestwk;
            if aval=0 and adt-startdt>7 then adt=startdt;
            cnsr=0;
        END;
        IF c1 AND aval>12 THEN aval=12;
    END;
RUN;

