PROC SORT DATA=sp.ex(WHERE=(epoch NE 'RUN-IN')) OUT=ex;
    BY studyid usubjid /*exseq*/ exstdtc;
RUN;

DATA ex(KEEP=studyid usubjid trtsdt trtstm);
    SET ex;
    BY studyid usubjid /*exseq*/ exstdtc;
    FORMAT trtsdt date9. trtstm time5.;
    IF NOT missing(exstdtc) THEN DO;
        trtsdt=input(scan(exstdtc,1,'T'),yymmdd10.);
        IF index(exstdtc,'T') THEN trtstm=input(scan(exstdtc,2,'T'),time5.);
    END;
    ELSE DO;
     PUT 'ERR' 'OR: missing exposure date. Imputation needed ???' usubjid =;
     DELETE;
    END;
RUN;

