    SET ex;
    BY studyid usubjid;
    IF FIRST.usubjid THEN OUTPUT;
RUN;

PROC SQL;
    CREATE TABLE rand_ AS
           SELECT studyid,usubjid,dsstdtc
           FROM sp.ds
           WHERE dsdecod='RANDOMIZED'
           ORDER BY studyid,usubjid
           ;
QUIT;

DATA rand_(DROP=dsstdtc);
    SET rand_;
    FORMAT trtsdt_r date9. trtstm_r time5.;
    trtsdt_r=input(scan(dsstdtc,1,'T'),yymmdd10.);
    IF index(dsstdtc,'T') THEN trtstm_r=input(scan(dsstdtc,2,'T'),time5.);
RUN;


DATA ex;
    MERGE ex rand_;
    BY studyid usubjid;
    FORMAT trtsdt_tmp date9.;
    trtsdt_tmp=trtsdt;
    trtsdt=ifn(trtsdt>.,trtsdt,trtsdt_r);
    IF NOT missing(trtsdt) THEN trtstm=ifn(trtstm>.,trtstm,trtstm_r);
RUN;

%mergeDat(
    baseDat           = advs_002
  , keyDat            = ex
  , outDat            = advs_003
  , by                = studyid usubjid
  , dropNonKeyDatRecs = n
);

*Delete VSALL records to keep consist with the individual study;

DATA advs_003;
    SET advs_003;
    IF vstestcd='VSALL' THEN DELETE;
    _VISIT_ORG=VISITNUM;
    VISITNUM=AVISITN;
    %createCustomVars(
        adsDomain = advs
      , vars      = ady
    );

    if n(adt,trtsdt_r)=2 then ady=adt-trtsdt_r+(adt>=trtsdt_r);

RUN;

*Assign the analysis flag;

%M_ANLFN(
    INDAT               = advs_003
  , OUTDAT              = advs_004
  , SUBJIDN             = STUDYID USUBJID
  , BY                  = VSTESTCD
  , LAST_VISIT          = &last_v.
  , COMPLFN             =
  , OADDOMAIN           = VS
  , INCLFN              = missing(vsstat)
  , UNSCHEDULE_VISITNUM =900000
  , OADSEQ              = VSseq
);


*Check dupliacted records as needed;

%M_DUP(INDAT=advs_004,OUTDAT=advs_005,SUBJIDN=STUDYID USUBJID,BY=VSTESTCD,POSTFN=_POSTBASEFN,SEQ=VSseq,INCLFN=(_DUPFN));

*Create the baseline flag;


%m_base(
    indat   = advs_005
  , outdat  = advs_006
  , by      = VSTESTCD
  , seq     = VSseq
  , val     = avalc
  , postfn  = _POSTBASEFN
  , useuvfn = 0
  , inclfn  = not missing(_trtsdt)
);

DATA advs_006;
    SET advs_006;
    IF avisitn=5 AND missing(ablfn) THEN CALL missing(anl01fn,anl01fl);
    VISITNUM=_VISIT_ORG;
RUN;


PROC SQL nowarn nowarnrecurs;
    CREATE TABLE advs_007 AS
          SELECT a.*,b.aval AS base
          FROM advs_006 AS a
          LEFT JOIN
          (SELECT studyid, usubjid,vstestcd,aval
          FROM advs_006
          WHERE ablfl='Y') AS b
          ON a.studyid=b.studyid AND a.usubjid=b.usubjid AND a.vstestcd=b.vstestcd
          ;
QUIT;

* Store result from work to ADS;

DATA ads.ADVS;
   SET advs_007;

    IF avisitn NOT IN (&avisit_list.) THEN CALL missing(anl01fl,anl01fn);
    %createCustomVars(adsDomain=ADVS, vars=crit1 crit1fl chg);
    CALL missing(crit1,crit1fl);
    IF n(aval,base)=2 THEN chg=aval-base;
    if vstestcd='BMI' and visit ne 'Screening 2, day -14' then call missing(vsseq);

RUN;

%LATE_ADS_PROCESSING(ADSDOMAIN = ADVS);


%endprog(cleanWork = Y);

