/*******************************************************************************
 * Bayer AG
 * Study            :
 * Proj/Subst/GIAD  : 3427080 / BAY 3427080, ELINZANETANT BAY3427080 NK1-3 RA Vasomotor Symptoms
 *******************************************************************************
 *Name of program**************************************************************/
    %iniprog(name = f_adlb_box);
/*
 * Purpose          : Figure 3-4: Box plot of {LAB CATEGORY, parameter name, unit} by treatment group (safety analysis set)
 * Programming Spec :
 * Validation Level : 1 - Verification by Review
 * SAS Version      : Linux 9.4
 *******************************************************************************
 * Pre-conditions   :
 * Post-conditions  :
 * Comments         :
 *******************************************************************************
 * Author(s)        : evmqf (Rowland Hale) / date: 04APR2024
 * Reference prog   :
 ******************************************************************************/

%LET mosto_param_class = %scan(&extend_var_disp_12_ezn_52_a_nsa., 1, '@');
%let by_vars           = &mosto_param_class. usubjid parcat1 paramcd paramn /*anrlo anrhi*/; * Order from 21652: parcat1 paramcd paramn;

* Load and extend data;
%load_ads_dat(adlb_view, adsDomain = adlb, where = &lb_avisit_selection. and avisitn not in (20 900000) and paramcd in (%trim(%quoteWords(&lb_safety_param., quote = Y))), adslwhere = &saf_cond.); /* Planned visits starting from baseline */
%load_ads_dat(adsl_view, adsDomain = adsl, where = &saf_cond.);

%extend_data(
    indat       = adlb_view
  , outdat      = adlb_ext
  , subj_var    = USUBJID
  , var         = &extend_var_disp_12_ezn_52_a_nsa.
  , extend_rule = &extend_rule_disp_12_ezn_52_a_afl.
);

%extend_data(
    indat       = adsl_view
  , outdat      = adsl_ext
  , subj_var    = USUBJID
  , var         = &extend_var_disp_12_ezn_52_a_nsa.
  , extend_rule = &extend_rule_disp_12_ezn_52_a.
);

* Prepare data;
%m_switcher_avisit2(
    indat  = adlb_ext
  , trtvar = &mosto_param_class.
  , byvar  = paramcd
);

DATA adlb_ext;
    SET adlb_ext(keep = &by_vars. avisitn aval paramtyp anrlo anrhi);

    *%m_switcher_avisit();
    IF missing(paramtyp) AND NOT missing(aval) AND NOT missing(paramcd);
    * Remove liver related parameters;
    IF paramcd IN (%trim(%quoteWords(&lb_safety_param., quote = Y))) and paramcd not IN (&liver_param.);
RUN;

**get rounding factor from SLAT;
PROC SORT DATA = g_data.slat(KEEP = test roundf_c) OUT = rounding(RENAME=(test=paramcd)) NODUPKEY; BY test roundf_c; RUN;
PROC SORT DATA = adlb_ext;                                                                         BY paramcd;       RUN;

DATA adlb_ext;
    MERGE adlb_ext(IN = a)
          rounding;
    BY paramcd;
    IF a;

    IF missing(roundf_c) THEN roundf_c = 0.01;
    IF NOT missing(aval) THEN aval_r   = round(aval, roundf_c);
    label anrlo='Low limit'
          anrhi='High limit';

    /*< Removed because of incorrect high value in data */
    if paramcd in ('HDL' 'VITDHY') and anrhi > 10000 then call missing(anrhi);
RUN;


%let parameter = %sysfunc(tranwrd(&by_vars., %str(&mosto_param_class. usubjid), %str( )));

PROC SORT DATA = adlb_ext;                                        BY &parameter.; RUN;
PROC SORT DATA = adlb_ext out = tby(keep = &parameter.) nodupkey; by &parameter.; run;
data tby; set tby; order= _n_; run;


data outliers (drop=mvarlist);
    set tby end=eof;
    by paramcd notsorted;
    length mvarlist $2000;
    retain mvarlist;
    call missing(minAsOutlier, yinc);

    if last.paramcd;

    select (paramcd);
        when ('ALBUM')    do; minAsOutlier = 6;    yinc = 0.5; end;
        when ('CKSP')     do; minAsOutlier = 2000;             end;
        when ('SEXBH')    do; minAsOutlier = 350;  yinc = 50;  end;
        when ('BASO')     do; minAsOutlier = 4;    yinc = 1;   end;
        when ('ESTD3G')   do; minAsOutlier = 350;  yinc = 50;  end;
        when ('PROLAC')   do; minAsOutlier = 100;  yinc = 10;  end;
        when ('SPROGEST') do; minAsOutlier = 3;    yinc = 0.5; end;
        when ('TESTOSTT') do; minAsOutlier = 8;    yinc = 1;   end;
        when ('U_WBCH')   do; minAsOutlier = 30;               end;
        when ('PT')       do; minAsOutlier = 40;   yinc = 5;   end;
        when ('BILIDISP') do; minAsOutlier = 0.8;              end;
        when ('TRIGLY')   do; minAsOutlier = 1000; yinc = 100; end;
        when ('BASOABC' ) do; minAsOutlier = 0.3;              end;
        when ('LYMPHABC') do; minAsOutlier = 9;    yinc = 1;   end;
        when ('PLAT')     do; minAsOutlier = 700;  yinc = 100; end;
        when ('ESTDIOL')  do; minAsOutlier = 100;  yinc = 10;  end;
        when ('EOS')      do; minAsOutlier = 20;               end;
        when ('MONO')     do; minAsOutlier = 25;               end;
        when ('SGLUC')    do; minAsOutlier = 350;  yinc = 50;  end;
        otherwise;
    end;

    if not missing(minAsOutlier) then do;
        output;
        call symputx(cats(paramcd, '_yinc'), ifc(missing(yinc), 'AUTO', put(yinc, best.)));
        call symputx(cats(paramcd, '_minasoutlier'), minAsOutlier);
        mvarlist = trim(mvarlist) || ' ' || cats(paramcd, '_minasoutlier') || ' ' || cats(paramcd, '_yinc');
    end;
    if eof then call symputx('mvarlist', mvarlist);
RUN;

DATA adlb_ext;
    MERGE adlb_ext(IN=a)
          tby;
    BY &parameter.;
    *format &mosto_param_class. _trtgrp_nsa.;
run;


* Set together / axis label stuff;
data adlb_plot;
    set adlb_ext;
    length param unit baselabel ylabel ftn $200;
    baselabel = "Baseline value";
    param     = scan(vvalue(paramcd), 1, "(");
    unit      = prxchange('s/\)//', 1, scan(vvalue(paramcd), 2, "("));
    if lengthn(unit) > 0 then unit = cats('(', unit, ')');
    ylabel    = catx('$', param, unit);
    if index(vvalue(paramcd), '(Factor 2.8)') then do;
        ylabel = trim(ylabel) || ' (Factor 2.8)';
    end;
run;

* Prepare macro variables as needed;
%let legend_tit = %sysfunc(tranwrd(%scan(&extend_var_disp_12_ezn_52_a_nsa., 3, '='), %str(%"), %str())); %put &=legend_tit;
%let tby_vars   = %sysfunc(tranwrd(&parameter, %str(parcat1), %str(parcat1 order))) unit;           %put &=tby_vars;



* Select data as needed;
data ezn_pla_1_12; set adlb_plot(where = (&cond_actual_w12_nsa.));                         run; * EZN / PLA week 1-12;
data all_ezn_1_52; set adlb_plot(where = (&cond_actual_w26_52_nsa.  and &cond_excl_eot.)); run; * All EZN week 1-52;

* Create and apply visit format with tick split character for X axis ;
proc sort data=adlb_plot (keep=avisitn) out=plotfmt nodupkey;
    by avisitn;
run;
data plotfmt;
    set plotfmt;
    retain fmtname 'plotfmt';
    length label $100;
    start = avisitn;
    label = prxchange('s/(Week|End of)\s/$1|/', 1, vvalue(avisitn));
run;
proc format lib=work cntlin=plotfmt;
run;

proc sql noprint;
    select distinct paramcd format=$8. into : noswitchparam separated by ' '
    from ads.adlb
    where paramcd in (select distinct paramcd from ads.adlb where studyid in ('21651', '21652', '21810'))
      and paramcd not in (select distinct paramcd from ads.adlb where studyid in ('21686'))
      and paramcd in (%quoteWords(&lb_safety_param))
    ;
quit;

%sganno;
data annodat;
    %sgtext(label="n", textsize=7, anchor="left", x1=4, x1space="wallpixel", y1=2.5, y1space="wallpercent")
run;


* Create output;
%macro _plot(data =, week =, ftn =, suffix =) / minoperator mindelimiter=' ';

    %local curparam;

    proc sql noprint;
        select count(distinct &mosto_param_class) into :n_class from &data;
        select distinct roundf_c into :roundf_c from &data;
        select distinct paramcd format=$8. into :curparam from &data;
    quit;
    %let curparam = &curparam;

    proc sort data=&data (keep=&mosto_param_class paramcd avisitn aval_r) out=dat4outliers nodupkey;
        by &mosto_param_class paramcd avisitn descending aval_r;
    run;

    data annooutliers;
        set dat4outliers;
        by &mosto_param_class paramcd avisitn;
        format avisitn plotfmt.;
        if first.avisitn then samevisit = 0;
        if symexist(cats(paramcd, '_minasoutlier')) then do;
            if aval_r > symgetn(cats(paramcd, '_minasoutlier')) then do;
                %sgarrow(x1space='datavalue', x2space='datavalue', y1space='datapercent', y2space='datapercent', xc1=vvalue(avisitn), xc2=vvalue(avisitn), y1=97, y2=100, linethickness=1
                    %if &n_class = 2 %then %do;
                       , discreteoffset = ifn(&mosto_param_class = 1, -0.2, 0.2)
                    %end;
                );
                %sgtext(x1space='datavalue', y1space='datapercent', xc1=vvalue(avisitn), y1=95 - (3 * samevisit), label=cat('X=', aval_r), textsize=6, textweight='bold', width=100
                    %if &n_class = 2 %then %do;
                       , discreteoffset = ifn(&mosto_param_class = 1, -0.2, 0.2)
                    %end;
                );
                samevisit + 1;
            end;
        end;
    run;

    data annos;
        set annodat
        %if %dsattr(annooutliers, nlobsf) > 0 %then %do;
            annooutliers
        %end;
        ;
    run;

    %if %symexist(&curparam._yinc) = 0 %then %do;
        %let &curparam._yinc = AUTO;
    %end;

    %set_titles_footnotes(
        tit1 = "Figure: Box plot of $parcat1$, $paramcd$ by IA visit and by &week."
      , tit2 = "<cont>&saf_label."
    );

    footnote1 "IA = Integrated Analysis.  Arith. Mean = Arithmetic mean.";
    footnote2 &ftn;
    footnote3 "&foot_lb_limit_detection.";

    %if &curparam = BAP_UL %then %do;
        footnote4 "&foot_bap_ul_explanation";
        footnote5 'Only reference ranges with a single lower/upper limit of normal are displayed.';
        footnote7 "&idfoot";
    %end;
    %else %if &curparam = SEXBH %then %do;
        footnote4 "For Sex Hormone Binding Globulin, a value of 9999 is due to the result being unmeasurable.";
        footnote5 'Only reference ranges with a single lower/upper limit of normal are displayed.';
        footnote7 "&idfoot";
    %end;
    %else %do;
        footnote4 'Only reference ranges with a single lower/upper limit of normal are displayed.';
        footnote6 "&idfoot";
    %end;

    %BoxPlot(
        data          = &data.
      , xvar          = avisitn
      , yvar          = aval_r
      , by            = &tby_vars.
      , class         = &mosto_param_class.
      , datalabel     = big_n_box
      , annodata      = annos
      , title_ny      = No
      , legend        = yes
      , legendtitle   = &legend_tit.
      , data_n        = adlb_ext %if &curparam in &noswitchparam %then (where=(usubjid ne: '21686'));
      , data_n_ignore = unit
      , subject       = &subj_var
      , style         = presentation
      , outdat        = boxplot_out
      , show_stat     = MEAN
      , marker_legend = topleft
      , extremes      = No
      , desc_footnote = Yes
      , ticksplitchar = |
      , yincrement    = &&&curparam._yinc
      , yrefline      = anrlo anrhi
      , ylabel        = $ylabel$
