    *%m_switcher_avisit();
    *format &mosto_param_class. _trtgrp_nsa.;
    * Select continuous laboratory parameter;
    IF missing(paramtyp) AND NOT missing(aval) AND NOT missing(paramcd);

    * Select safety lab parameter incl. liver;
    IF paramcd in (&liver_param.);

RUN;
