* EZN / PLA week 1-12;
data ezn_pla_1_12;
    set adlb_round(where = (&cond_actual_w12_nsa.));
    if avisitn = 121 then analysis_visit = "yaxis";
    if not missing(analysis_visit);
run;

 * All EZN week 1-52;
data all_ezn_1_52;
    set adlb_round(where = (&cond_actual_w26_52_nsa.));
    * Please note that the definition of EoT in this plot is different from the IA visit "EoT". In this plot, EoT refers to
        "week 26/EoT" for OASIS 1 and 2, "week 52" and "EoT" for OASIS 3, and "week 12" for SWITCH-1. ;
    if (studyid in ('21651' '21652') and visitnum in (600000))
       or (studyid in ('21810') and avisitn in (520, 600000) )
       or (studyid = '21686' and avisitn = 121)
       then analysis_visit = "yaxis";
    if not missing(analysis_visit);
run;

proc sort data=all_ezn_1_52;
    by &by_vars. analysis_visit visitnum;
RUN;

