    by &by_vars. analysis_visit;
    if last.analysis_visit;
RUN;
%let tby_vars = %sysfunc(tranwrd(&by_vars., %str(parcat1), %str(parcat1 order))) unit; %put &=tby_vars;

* Create output;
%macro _plot(data =, week =, trt_tit =, ftn1 =, ftn2 =, suffix =, double =);

    PROC TRANSPOSE data = &data.
                   out  = adlb_axis_trans;
        BY &by_vars.;
        VAR aval_r;
        id analysis_visit;
    RUN;

    * Set together / axis label stuff;
    DATA adlb_plot;
        SET adlb_axis_trans;
        format baseline yaxis best. param $200.;
        param  = vvalue(paramcd);
    RUN;

    * Prepare macro variables as needed;
    %let legend_tit = %sysfunc(tranwrd( %scan(&extend_var_disp_12_ezn_52_a_nsa., 3, '='), %str(%"), %str())); %put &=legend_tit;
    %let tby_vars   = %sysfunc(tranwrd(&by_vars., %str(&mosto_param_class. usubjid), %str( )));          %put &=tby_vars;

    %set_titles_footnotes(
        tit1 = "Figure: Scatterplot of &week. against baseline of $parcat1$,"
      , tit2 = "<cont>$param$ by &trt_tit. &saf_label."
      %if &double = 1 %then %do;
      , tit3 = "<cont>(equal axes)"
      %end;
      %if &double = 2 %then %do;
      , tit3 = "<cont>(non-equal axes)"
      %end;
    );

    %if &data = plot1 %then %do;
        footnote1 "IA = Integrated Analysis.";
    %end;
    %else %do;
        footnote1 "IA = Integrated Analysis. EoT = End of Treatment.";
    %end;
    footnote2 "&ftn1";
    footnote3 "&foot_lb_limit_detection.";
    %if %length (&ftn2.) > 0 %then %do;
        footnote4 "&ftn2.";
        footnote6 "&idfoot";
    %end;
    %else %do;
        footnote5 "&idfoot";
    %end;

    proc sql noprint;
        select max(baseline), max(yaxis) into :_xmax, :_ymax from adlb_plot;
    quit;

    %ScatterPlot(
        data            = adlb_plot
      , xvar            = baseline
      , yvar            = yaxis
      , by              = &tby_vars.
      , quadratic       = %sysfunc(ifc(&double = or &double = 1, both, no))
      , class           = &mosto_param_class.
      , title_ny        = no
      , legend          = yes
      , identity_ny     = y
      , legendtitle     = &legend_tit.
      , data_n          = adsl_ext
      , data_n_ignore   = &tby_vars.
      , subject         = usubjid
      , style           = presentation
      , outdat          = tmp
      , regression      = y
      , regression_stat = FOOTNOTE
      , xlabel          = Baseline
      , ylabel          = &week.
      , filename        = &prog._&suffix._$paramcd$%sysfunc(ifc(&double ne , _&double, ))
      %if &double = or &double = 1 %then %do;
          , xend = %sysfunc(max(&_xmax, &_ymax))
          , yend = %sysfunc(max(&_xmax, &_ymax))
      %end;
    );

    /* Get number of decimal places required for Y axis format */
    data _null_;
        set tmpinp (where=(attribute in ('xticklist' 'yticklist'))) end=eof;
        retain maxdec 0;
        if findc(value, '.') then do i = 1 to countw(value, ' ');
            tick = scan(value, i, ' ');
            if findc(tick, '.') then do;
                maxdec = max(maxdec, lengthn(scan(tick, 2, '.')));
            end;
        end;
        if eof;
        call symputx(cats('xformat_', plot), cats('8.', maxdec));
        call symputx(cats('yformat_', plot), cats('8.', maxdec));
    run;

    data tmpinp;
        set tmpinp;
        %* Its needed because of a footnote handling bug in GraL (quotes in footnote in conjunction with regression footnote);
        %* So used # in footnotes as quotes and change them here to quotation marks.;
        if type = 'footnote' then value = '"' || prxchange("s/#/'/", -1, compress(value, "'")) || '"';
        if type = 'lineparm' and attribute = 'extend' then delete;
        if type = 'lineparm' and attribute = 'lineattrs' then value = '(thickness=1 color=lightgray)';

        if attribute = 'xformat' then do;
            value = symget(cats('xformat_', plot));
        end;
        if attribute = 'yformat' then do;
            value = symget(cats('yformat_', plot));
        end;
    run;

    %gral_from_dat(data=tmp)

%MEND _plot;

