      , ylabel        = $ylabel$
      , filename      = &prog._&suffix._$paramcd$
    )
    ;
%MEND _plot;

* Loop per PARAMCD;
%MACRO per_paramcd();
    PROC SQL;
        SELECT max(ORDER) INTO : MAX FROM tby;
    QUIT;

    %DO i = 1 %TO &max.;
        proc sql noprint;
            create table extrem_chg0 as
                   select roundf_c,avisitn,mean(chg) as _mean,stderr(chg) as _std
                   from adlb_ext(where=(order=&i.))
                   where chg is not null and avisitn ne 600
                   group by order,roundf_c,avisitn;

            create table extrem_chg as
                   select roundf_c, min(_mean-4*_std) as miny,max(_mean+4*_std) as maxy
                   from extrem_chg0
                   group by roundf_c
                   ;

        QUIT;
        data _null_;
            set extrem_chg;
            call symputx('_miny',cats(round(miny,roundf_c)));
            call symputx('_maxy',cats(round(maxy,roundf_c)));
        RUN;
        DATA plot1;
            SET adlb_ext(WHERE = (order = &i. AND &cond_actual_w12_nsa.
                and (avisitn<=121 or avisitn=600) ));
            IF avisitn=600 then avisitn=169;
            format avisitn _plotvis_iss.;
        RUN;* EZN / PLA week 1-12;

        DATA plot2;
            SET adlb_ext(WHERE = (order = &i. AND &cond_actual_w26_52_nsa. AND &cond_excl_eot.));
        RUN;* All EZN week 1-52;

        *< 1st plot: Line plot of mean change from baseline and 95% confidence interval of {parameter name, unit} by integrated analysis treatment group up to week 12 (safety analysis set);
        %_plot(
            data   = plot1
          , week   = %str(EZN 120 mg (week 1-12) and Placebo (week 1-12))
          , ftn    = "&foot_w1_12."
          , suffix = ezn_pla
          , miny   = &_miny.
          , maxy   = &_maxy.
        )
        ;

        *< 2nd plot: Line plot of mean change from baseline and 95% confidence interval of {parameter name, unit} by integrated analysis treatment group up to week 52 (safety analysis set);
        %_plot(
            data   = plot2
          , week   = %str(&lbl_ezn_w26_52.)
          , ftn    = "&foot_switcher_26_52."
          , suffix = all_ezn
          , miny   = &_miny.
          , maxy   = &_maxy.
        )
        ;
    %END;
%MEND per_paramcd;

