;

DATA advs_ext;
    SET advs_ext;

    * Round AVAL BASE and CHG;
    FORMAT aval 6./* &mosto_param_class. _trtgrp_nsa.*/;

    * y label should be the unit;
    LENGTH unit $20.;
    unit = strip(tranwrd(scan(vvalue(paramcd), 2, "("), ")", ""));

    * Vital signs parameter: systolic blood pressure and diastolic blood pressure;
    IF paramcd = 'SYSBP' THEN order = 2;
    ELSE IF paramcd = 'DIABP' THEN order = 3;
