/*    proc sql; select max(order) into : max from tby; quit;*/

    %DO i = 2 %TO 3 /*&max.*/;

        DATA plot1;
            SET ezn_pla_1_12(WHERE = (order = &i.));
            IF avisitn<=121 or avisitn=700000; RUN;* EZN / PLA week 1-12;
        DATA plot2;
            SET all_ezn_1_52(WHERE = (order = &i.));
