    * Vital signs parameter: heart rate, systolic blood pressure and diastolic blood pressure;
    IF paramcd = 'HR'    THEN order = 1;
    ELSE IF paramcd = 'SYSBP' THEN order = 2;
    ELSE IF paramcd = 'DIABP' THEN order = 3;
    ELSE DELETE;
RUN;

