      , data_n_ignore = &tby_vars.
      , subject       = USUBJID
      , style         = presentation
      , stat          = ARITH_CL95
      , ticksplitchar = |
      , xtype         = data
      , xoffset       = 0.05
      , ystart        = &miny.
      , yend          = &maxy.
      , ylabel        = $ylabel$(*ESC*){unicode '000A'x}(mean +/- 95% CI)
      , filename      = &prog._&suffix._$paramcd$
    )
    ;
%MEND _plot;

* Loop per PARAMCD;
%MACRO per_paramcd;
    PROC SQL;
        SELECT max(ORDER) INTO : MAX FROM tby;
    QUIT;

    %DO i = 1 %TO &max.;
        proc sql noprint;
            create table extrem_chg0 as
                   select avisitn,mean(chg) as _mean,stderr(chg) as _std
                   from advs_ext(where=(order=&i.))
                   where chg is not null and avisitn ne 600000
                   group by order,avisitn;

            create table extrem_chg as
                   select min(_mean-4*_std) as miny,max(_mean+4*_std) as maxy
                   from extrem_chg0
                   ;

        QUIT;
        data _null_;
            set extrem_chg;
            call symputx('_miny',put(miny,6.1));
            call symputx('_maxy',put(maxy,6.1));
        RUN;
        DATA plot1;
            SET ezn_pla_1_12(WHERE = (order = &i.));
            IF avisitn<=121 or avisitn=169; RUN;* EZN / PLA week 1-12;
        DATA plot2;
            SET all_ezn_1_52(WHERE = (order = &i.));
        RUN;* All EZN week 1-52;

        *< 1st plot: Line plot of mean change from baseline and 95% confidence interval of {parameter name, unit} by integrated analysis treatment group up to week 12 (safety analysis set);
