DATA advs_ext;
    SET advs_ext;

    * Round AVAL BASE and CHG;
    FORMAT aval base 6.;

    * y label should be the unit;
    LENGTH unit $20.;
    unit = strip(tranwrd(scan(vvalue(paramcd), 2, "("), ")", ""));

    * Vital signs parameter: systolic blood pressure and diastolic blood pressure;
    IF paramcd = 'SYSBP' THEN order = 2;
    ELSE IF paramcd = 'DIABP' THEN order = 3;
    ELSE DELETE;
RUN;

* Add TRT01AN=4: EZN week 1-26;
DATA advs_ext;
    SET advs_ext;
    OUTPUT;
    IF &mosto_param_class.=6 THEN DO;
        &mosto_param_class.=4;
        IF studyid NE '21810' THEN OUTPUT;
        ELSE DO;
            IF ady<=182 THEN OUTPUT;
        END;
    END;
RUN;

* Get maxiumum / minimum values;
%LET sql_vars = studyid, &mosto_param_class., usubjid, order, paramcd, unit, base;

PROC SQL;
    CREATE TABLE _min AS SELECT &sql_vars., min(aval) AS _aval FROM advs_ext WHERE avisitn > 5 GROUP BY &sql_vars.;* Minimum {parameter name, unit};
    CREATE TABLE _max AS SELECT &sql_vars., max(aval) AS _aval FROM advs_ext WHERE avisitn > 5 GROUP BY &sql_vars.;* Maximum {parameter name, unit};
QUIT;

* Set together / axis label stuff;
DATA advs_bp;
    SET _max(IN = inmax)
        _min(IN = inmin);
    FORMAT param yparam baselabel $200.;
    IF inmax THEN param = "maximum " || vvalue(paramcd);
    IF inmin THEN param = "minimum " || vvalue(paramcd);
    yparam = strip(upcase(substr(param, 1,1))) || strip(substr(param, 2));
    baselabel = strip(vvalue(paramcd)) || " at baseline";
RUN;

