%MEND _plot;

* Loop per PARAMCD;
%MACRO per_paramcd;
/*    proc sql; select max(order) into : max from tby; quit;*/

*< 1st plot: Scatterplot of baseline vs <maximum/minimum> {parameter name, unit} by integrated analysis treatment group up to week 12 (safety analysis set);
*< 2nd plot: Scatterplot of baseline vs <maximum/minimum> {parameter name, unit} by integrated analysis treatment group up to up to week 52 (safety analysis set);

    %DO i = 2 %TO 3 /*&max.*/;

        *? Maximum;
        DATA max_plot1;
            SET advs_bp(WHERE = (order = &i. AND find(upcase(param), "MAXIMUM") > 0 AND &mosto_param_class. IN (1 2)));
        RUN;* EZN / PLA week 1-12;
        DATA max_plot2;
            SET advs_bp(WHERE = (order = &i. AND find(upcase(param), "MAXIMUM") > 0 AND &mosto_param_class. EQ 4));
        RUN;* All EZN week 1-26;
        DATA max_plot3;
            SET advs_bp(WHERE = (order = &i. AND find(upcase(param), "MAXIMUM") > 0 AND &mosto_param_class. EQ 6));
        RUN;* All EZN week 1-52;

        %_plot(
            data   = max_plot1
          , week   = %str(EZN 120 mg (week 1-12) and Placebo (week 1-12))
          , suffix = ezn_pla_max
        )
        ;* EZN / PLA week 1-12;
        %_plot(
            data   = max_plot2
          , week   = %str(&lbl_ezn_w26.)
          , suffix = all_ezn_max1
          , ftn    = %str(For OASIS 3, the measurements include up to day 182 (inclusive) for EZN 120 mg (week 1-26).)
        )
        ;* All EZN week 1-26;
        %_plot(
            data   = max_plot3
          , week   = %str(&lbl_ezn_w52.)
          , suffix = all_ezn_max2
          , ftn    = %str(For OASIS 3, end of treatment includes measurements performed at Week 52 or at earlier performed end of treatment visit.)
        )
        ;* All EZN week 1-52;

        *? Minimum;

        DATA min_plot1;
            SET advs_bp(WHERE = (order = &i. AND find(upcase(param), "MINIMUM") > 0 AND &mosto_param_class.  IN (1 2)));
        RUN;* EZN / PLA week 1-12;
        DATA min_plot2;
            SET advs_bp(WHERE = (order = &i. AND find(upcase(param), "MINIMUM") > 0 AND &mosto_param_class. EQ 4));
        RUN;* All EZN week 1-52;
        DATA min_plot3;
            SET advs_bp(WHERE = (order = &i. AND find(upcase(param), "MINIMUM") > 0 AND &mosto_param_class. EQ 6));
        RUN;* All EZN week 1-52;

        %_plot(
            data   = min_plot1
          , week   = %str(EZN 120 mg (week 1-12) and Placebo (week 1-12))
          , suffix = ezn_pla_min
        )
        ;* EZN / PLA week 1-12;
        %_plot(
            data   = min_plot2
          , week   = %str(&lbl_ezn_w26.)
          , suffix = all_ezn_min1
          , ftn    = %str(For OASIS 3, the measurements include up to day 182 (inclusive) for EZN 120 mg (week 1-26).)
        )
        ;* All EZN week 1-26;
        %_plot(
            data   = min_plot3
          , week   = %str(&lbl_ezn_w52.)
          , suffix = all_ezn_min2
          , ftn    = %str(For OASIS 3, end of treatment includes measurements performed at Week 52 or at earlier performed end of treatment visit.)
        )
        ;* All EZN week 1-52;
    %END;
%MEND per_paramcd;
