DATA advs_switcher;
    SET advs_ext;

    * Round AVAL BASE and CHG;
    /*FORMAT aval chg best. &mosto_param_class _trtgrp_nsa.*/;

    LENGTH param unit ylabel $200 ;
    param  = 'Change in ' || scan(vvalue(paramcd), 1, "(");
    unit   = prxchange('s/\)//', 1, scan(vvalue(paramcd), 2, "("));
    IF lengthn(unit) > 0 THEN unit = cats('(', unit, ')');
    ylabel = catx(' ', param, unit);

    * Vital signs parameter: heart rate, systolic blood pressure and diastolic blood pressure;
    IF paramcd = 'WEIGHT'   THEN _paramn = 1;
    ELSE IF paramcd = 'HIPCIR'   THEN _paramn = 2;
    ELSE IF paramcd = 'WAISTHIP' THEN _paramn = 3;
    ELSE IF paramcd = 'WSTCIR'   THEN _paramn = 4;
    ELSE DELETE;
    IF NOT missing(chg) THEN DO;
       IF _paramn = 3 THEN chg=round(chg, 0.001);
       ELSE chg=round(chg,0.1);
    END;
    avisitn_old = avisitn;
    if avisitn_old =      5 then avisitn = 0 ;
    else if avisitn_old = 700000 then avisitn = 600 ;
    else avisitn = avisitn_old;
    format avisitn _plotvis_iss. avisitn_old z_avisit.;

RUN;

%LET legend_tit = %sysfunc(tranwrd( %scan(&extend_var_disp_12_ezn_52_a_nsa, 3, '='), %str(%"), %str()));
%PUT &=legend_tit;
%LET tby_vars  = _paramn paramcd unit;
%PUT &=tby_vars;

* Select data as needed;
DATA ezn_pla_1_12;
    SET advs_switcher(WHERE = (&cond_actual_w12_nsa.));
    if avisitn=600 then avisitn=169;
RUN;* EZN / PLA week 1-12;
DATA all_ezn_1_52;
    SET advs_switcher(WHERE = (&cond_actual_w26_52_nsa.  AND &cond_excl_eot.));
RUN;* All EZN week 1-26/1-52;

proc sql noprint;
    create table extrem_chg0 as
           select _paramn,avisitn,mean(chg) as _mean,stderr(chg) as _std
           from advs_switcher
           where chg is not null and avisitn ne 600000
           group by _paramn,avisitn;

    create table extrem_chg as
           select _paramn,min(_mean-4*_std) as miny,max(_mean+4*_std) as maxy
           from extrem_chg0
           group by _paramn
           ;

QUIT;
* Create and apply visit format with tick split character for X axis ;
PROC SORT DATA=all_ezn_1_52 (KEEP=avisitn) OUT=plotfmt NODUPKEY;
    BY avisitn;
RUN;
DATA plotfmt;
    SET plotfmt;
    RETAIN fmtname 'plotfmt';
    LENGTH label $100;
    start = avisitn;
    label = prxchange('s/(Week|End of)\s/$1|/', 1, vvalue(avisitn));
RUN;
PROC FORMAT LIB=work CNTLIN=plotfmt;
RUN;

PROC DATASETS LIB=work NOLIST;
    MODIFY all_ezn_1_52;
        FORMAT avisitn plotfmt.;
    RUN;
QUIT;

* Create output;
%MACRO _plot(
       data   =
     , week   =
     , ftn    =
     , suffix =
     , miny   =
     , maxy   =
);
