    FOOTNOTE;
    %set_titles_footnotes(
        tit1 = "Figure: Line plot of mean change from baseline and 95% confidence interval of $PARAMCD$ by"
      , tit2 = "<cont>&week. &saf_label."
/*      , ftn1 = "IA = Integrated Analysis. EoT = End of Treatment. CI = Confidence Interval."*/
/*      , ftn2 = "&ftn."*/
/*      , ftn3 = "&foot_ia_eot."*/
    )
    ;

    FOOTNOTE1 "IA = Integrated Analysis. CI = Confidence Interval.";
    FOOTNOTE2 "&ftn";
    *EoT = End of Treatment. ;
    *footnote3 "&foot_ia_eot.";
    FOOTNOTE4 "&idfoot";

    %MeanDeviationPlot(
        data          = &data.
      , xvar          = avisitn
      , yvar          = chg
      , by            = &tby_vars.
      , class         = &mosto_param_class.
      , title_ny      = no
      , legend        = yes
      , legendtitle   = &legend_tit.
      , data_n        = adsl_ext
      , data_n_ignore = &tby_vars.
      , subject       = USUBJID
      , style         = presentation
      , stat          = ARITH_CL95
      , ticksplitchar = |
      , xtype         = data
      , xoffset       = 0.05
      , ystart        = &miny
      , yend          = &maxy
      , ylabel        = $ylabel$(*ESC*){unicode '000A'x}(mean +/- 95% CI)
      , filename      = &prog._&suffix._$paramcd$
    )
    ;
%MEND _plot;

%macro _plot_out();

    data _null_;
        set extrem_chg end=last;
        call symputx('parm'||cats(_n_), cats(_paramn));
        call symputx('_miny'||cats(_n_),put(miny,6.3));
        call symputx('_maxy'||cats(_n_),put(maxy,6.3));
        if last then call symputx('nparam',cats(_n_));
    RUN;

    %do i=1 %to &nparam.;
    *< 1st plot: Line plot of mean change from baseline and 95% confidence interval of {parameter name, unit} by integrated analysis
                 treatment group up to week 12 (safety analysis set);
    %if &i.=3 %then %do;
        proc datasets lib=work mtype=data;
            modify ezn_pla_1_12;
                format chg 6.3;
            RUN;
            modify all_ezn_1_52;
                format chg 6.3;
            RUN;
        QUIT;
    %END;
    %else %do;
        proc datasets lib=work mtype=data;
            modify ezn_pla_1_12;
                format chg 6.1;
            RUN;
            modify all_ezn_1_52;
                format chg 6.1;
            RUN;
        QUIT;
    %END;
    %_plot(
        data   = ezn_pla_1_12(WHERE=((avisitn<=121 or avisitn=169) and _paramn=&&parm&i))
      , week   = %str(EZN 120 mg (week 1-12) and Placebo (week 1-12))
      , ftn    = &foot_w1_12.
      , suffix = ezn_pla_&&parm&i.
      , miny   = &&_miny&i.
      , maxy   = &&_maxy&i.
    )
    ;* EZN / PLA week 1-12;

    *< 2nd plot: Line plot of mean change from baseline and 95% confidence interval of {parameter name, unit} by integrated analysis
                 treatment group up to week 52 (safety analysis set);
    %_plot(
        data   = all_ezn_1_52(where=(_paramn=&&parm&i.))
      , week   = %str(&lbl_ezn_w26_52.)
      , ftn    = &foot_switcher_26_52.
      , suffix = all_ezn_&&parm&i.
      , miny   = &&_miny&i.
      , maxy   = &&_maxy&i.
    )
    ;* All EZN week 1-52;
    %end;
%MEND;

%_plot_out();
%SYMDEL mosto_param_class legend_tit tby_vars;

%endprog()
