%load_ads_dat(adqs_view, adsDomain = adqs, adslWhere = &fas_cond.) ;
%extend_data(indat = adqs_view, outdat = adqs  )  ;
%load_ads_dat(adsl_view, adsDomain = adsl, where = &fas_cond)  ;
