    merge final0(in=f) anal(keep=usubjid avisitn ANL01FL ICEDSRS ANL05FL ANL02FL ICEINTRS ANL03FL);
    by usubjid avisitn;
    if f; *** Patients with missing baseline and not enough post-baseline data will be excluded;
RUN;


