proc sort data=final; by _Imputation_ trt01pn studyid region1n avisitn usubjid; run;
/** main model **/
ods listing close;
PROC MIXED data=final;
    by _Imputation_;
    CLASS trt01pn studyid region1n avisitn usubjid ;
    MODEL chg = baseline_visit trt01pn studyid region1n avisitn trt01pn*avisitn baseline_visit*avisitn trt01pn*studyid/ddfm=KR outp=resid s;
