    proc npar1way data = t_step_3(where=(_imputation_ = &imp. ))
                         HL(REFCLASS="Placebo - Elinzanetant 120mg") NOPRINT;
                   class trt01pn;
                   var &cwk. ;
                   output out=m_HL_w&wk._&imp.;
    run;

    %mend;

    %macro imp (imp =  ) ;

/*        %cmhout (imp =  &imp.  ,  wk =  01  , cwk = chg_01 ) ;*/
