        %cmhout (imp =  &imp.  ,  wk =  12 , cwk = chg_12) ;

        Data M_residuals_all_&imp. ;
            merge /*M_residuals_w01_&imp.*/
/*                  M_residuals_w04_&imp. (keep=usubjid resid_w04)*/
