***************************************************************************************************************;
***************************************************************************************************************;
*** Consolidate all imputed data ;

data all_imputed_t1;
    merge allvtm
          p1_data_imputed(keep=_Imputation_ usubjid aval_p1_Week_4_imp aval_p1_Week_8_imp aval_p1_Week_12_imp)
          p2_data_imputed(keep=_Imputation_ usubjid aval_p2_Week_4_imp aval_p2_Week_8_imp aval_p2_Week_12_imp)
          p3_data_imputed(keep=_Imputation_ usubjid aval_p3_Week_4_imp aval_p3_Week_8_imp aval_p3_Week_12_imp)
          p4_data_imputed(keep=_Imputation_ usubjid aval_p4_Baseline_imp aval_p4_Week_4_imp aval_p4_Week_8_imp aval_p4_Week_12_imp)
          ;
    by _Imputation_ usubjid;
run;

data all_imputed_t2; set all_imputed_t1;
    array p1 {3} pattern1_Week_4  pattern1_Week_8  pattern1_Week_12;
    array p2 {3} pattern2_Week_4  pattern2_Week_8  pattern2_Week_12;
    array p3 {3} pattern3_Week_4  pattern3_Week_8  pattern3_Week_12;
    array p4 {3} pattern4_Week_4  pattern4_Week_8  pattern4_Week_12;

    array p_imp {3} p_imp_Week_4  p_imp_Week_8  p_imp_Week_12; * for data review later;

    array aval {3} aval_Week_4 aval_Week_8 aval_Week_12;

    array aval_p1_imp {3} aval_p1_Week_4_imp aval_p1_Week_8_imp aval_p1_Week_12_imp;
    array aval_p2_imp {3} aval_p2_Week_4_imp aval_p2_Week_8_imp aval_p2_Week_12_imp;
    array aval_p3_imp {3} aval_p3_Week_4_imp aval_p3_Week_8_imp aval_p3_Week_12_imp;
    array aval_p4_imp {3} aval_p4_Week_4_imp aval_p4_Week_8_imp aval_p4_Week_12_imp;

    * final consolidated observed and imputed values ;
    array aval_f_imp {3} aval_f_Week_4_imp aval_f_Week_8_imp aval_f_Week_12_imp;

    aval_f_Baseline = aval_Baseline;
    if aval_Baseline = . and aval_p4_Baseline_imp ne . then do;
        if aval_p4_Baseline_imp < 0 then aval_f_Baseline = 0;*** post-processing for values that got imputed with an unrealistic negative value;
        else aval_f_Baseline = aval_p4_Baseline_imp;
    end;

    do i=1 to 3;
        aval_f_imp[i] = aval[i];
        p_imp[i]=0;
        if p1[i] = "M" then do;
            if aval_p1_imp[i] < 0 then aval_f_imp[i] = 0; else aval_f_imp[i] = aval_p1_imp[i];
            p_imp[i] = 1; * indicates value imputed under pattern 1;
        end;
        else if p2[i] = "M" then do;
            if aval_p2_imp[i] < 0 then aval_f_imp[i] = 0; else aval_f_imp[i] = aval_p2_imp[i];
                p_imp[i] = 2; * indicates value imputed under pattern 2;
            end;
        else if p3[i] = "M" then do;
            if aval_p3_imp[i] < 0 then aval_f_imp[i] = 0; else aval_f_imp[i] = aval_p3_imp[i];
                p_imp[i] = 3; * indicates value imputed under pattern 3;
            end;
        else if p4[i] = "M" then do;
            if aval_p4_imp[i] < 0 then aval_f_imp[i] = 0; else aval_f_imp[i] = aval_p4_imp[i];
                p_imp[i] = 4; * indicates value imputed under pattern 4;
            end;
    END;

    drop i;
run;

*** Transpose final imputed data into vertical structure with one patient/visit per record ;
data final0(keep=_Imputation_ usubjid region1n trt01pn baseline_visit avisitn aval chg aval_orig p_imp);

    set all_imputed_t2;
    baseline_visit = aval_f_Baseline;

    avisitn=40;
    aval_orig = aval_Week_4;
    aval = aval_f_Week_4_imp;
    chg = aval_f_Week_4_imp - baseline_visit;
    p_imp = p_imp_Week_4;
    output;

    avisitn=80;
    aval_orig = aval_Week_8;
    aval = aval_f_Week_8_imp;
    chg = aval_f_Week_8_imp - baseline_visit;
    p_imp = p_imp_Week_8;
    output;

    avisitn=120;
    aval_orig = aval_Week_12;
    aval = aval_f_Week_12_imp;
    chg = aval_f_Week_12_imp - baseline_visit;
    p_imp = p_imp_Week_12;
    output;
run;

