/** main model **/
PROC MIXED data=final;
    by _Imputation_;
    CLASS trt01pn studyid region1n avisitn usubjid ;
    MODEL chg = baseline_visit trt01pn studyid region1n avisitn trt01pn*avisitn baseline_visit*avisitn trt01pn*studyid/ddfm=KR outp=resid s;
    REPEATED avisitn / subject=usubjid type=un;
    *RANDOM usubjid; /* only if AR(1) covariance structure is used */
    LSMEANS trt01pn*avisitn /cl pdiff=all;
    LSMEANS trt01pn*studyid /cl diff;
    lsmeans studyid / cl diff;
    ESTIMATE 'Elinzanetant - Placebo at Week 4' trt01pn 1 -1 trt01pn*avisitn 1 0 0 -1 0 0 /cl;
    ESTIMATE 'Elinzanetant - Placebo at Week 12' trt01pn 1 -1 trt01pn*avisitn 0 0 1 0 0 -1 /cl;
    ESTIMATE  'Study' studyid 1 -1 /cl ;
    ODS OUTPUT TESTS3=TYPE3_eff Diffs=diffs LSMeans=LSMEAN ESTIMATES=ESTIM SolutionF=mxparms;
RUN;
