                p_imp[i] = 3; * indicates value imputed under pattern 3;
            end;
        else if p4[i] = "M" then do;
            if aval_p4_imp[i] < 0 then aval_f_imp[i] = 0; else aval_f_imp[i] = aval_p4_imp[i];
                p_imp[i] = 4; * indicates value imputed under pattern 4;
            end;
    END;

