* Save final imputed dataset for validation;
Data tlfmeta.final&valsuf ;
    Set final;
Run;

**************************************************************************************************;

/*******************************************************************************************************/
*** Analyze imputed datasets ***;
/*******************************************************************************************************/
* Remove format from avisitn so that weeks are sorted in the same order as numerical levels ***;
data final; set final;
    format avisitn;
run;

%mergeDat(baseDat = final, keyDat = adsl(KEEP=usubjid studyid), by = usubjid)

proc sort data=final; by _Imputation_ trt01pn studyid region1n avisitn usubjid; run;
/** main model **/
ods listing close;
PROC MIXED data=final;
    by _Imputation_;
    CLASS trt01pn studyid region1n avisitn usubjid ;
    MODEL chg = baseline_visit trt01pn studyid region1n avisitn trt01pn*avisitn baseline_visit*avisitn trt01pn*studyid/ddfm=KR outp=resid s;
    REPEATED avisitn / subject=usubjid type=un;
    *RANDOM usubjid; /* only if AR(1) covariance structure is used */
    LSMEANS trt01pn*avisitn /cl pdiff=all;
    LSMEANS trt01pn*studyid /cl diff;
    lsmeans studyid / cl diff;
    ESTIMATE 'Elinzanetant - Placebo at Week 4' trt01pn 1 -1 trt01pn*avisitn 1 0 0 -1 0 0 /cl;
    ESTIMATE 'Elinzanetant - Placebo at Week 12' trt01pn 1 -1 trt01pn*avisitn 0 0 1 0 0 -1 /cl;
    ESTIMATE 'Study' studyid 1 -1 /cl ;
    ODS OUTPUT TESTS3=TYPE3_eff Diffs=diffs LSMeans=LSMEAN ESTIMATES=ESTIM SolutionF=mxparms;
RUN;
ods listing;

proc sort data=estim out=estim_s; by label; run;
ods output ParameterEstimates=pe_rubin ;
proc MIanalyze data=estim_s;
    by label;
    modeleffects estimate;
    stderr stderr;
run;


%LET timep = 10 40 80 120 ;
%m_anal_datastep(adqs, "MENB999",&timep,anal_1, where = &oasis1_cond.);
%m_anal_datastep(adqs, "MENB999",&timep,anal_2, where = &oasis2_cond.);

DATA anal;
    SET anal_1
        anal_2
        ;
RUN;

%m_mmrm_rubin  (estim, LSMEAN, mxparms, mq_sp2);

proc sort data = hfdd
     out = tby (keep = paramcd) nodupkey ;
    by paramcd ;
    where not missing(paramcd);
RUN;

Proc Sql noprint ;
    select count(usubjid) into : trtarm1 SEPARATED by "  "
           from adsl
           where trt01pn = 100
           group by trt01pn ;

    select count(usubjid) into : trtarm2 SEPARATED by "  "
           from adsl
           where trt01pn = 101
           group by trt01pn ;
    %put &trtarm1 &trtarm2 ;


    select paramcd into : paramcd SEPARATED by ""
           from tby
           where not missing(paramcd)
         ;

QUIT;

data final ;
    set t_0 t_l0 t_l2 t_study_interaction;
RUN;
proc sort data  = final ;
    by row row1 ;
RUN;

data final ;
    set final ;
    by row row1 ;
    if row1  = 0 then Col01  = Col0 ;
    if avisitn ^= 5 ;
