%let fti1 = %str(Figure: Line plot of LS-Means (MMRM) of change from baseline in &param. by treatment group &fas_label) ;
%let fti2 = %str() ;

%let fft1 = %str(Figure describes the time course of LS-Means +/- SE based on the estimates of the MMRM analysis.) ;
%let fft2 = %str(Study effect and study*treatment interaction are added for MMRM analysis.) ;
%let fft3 = %str(Placebo - Elinzanetant 120mg = Placebo for 12 weeks, followed by elinzanetant 120 mg for 14 weeks.) ;
%let fft4 = %str(LS-Means = Least Squares Means, SE = Standard Error, MMRM = Mixed Model Repeated Measures.) ;


/*****************************
 *Data step
 ****************************/
%load_ads_dat(adsl_view, adsDomain = adsl, where = &fas_cond.);
%extend_data(indat = adsl_view, outdat = adsl);

%LET timep = 10 40 80 120 ;
%m_anal_datastep(adqshfss, "HFDB998",&timep,anal_1, where = &oasis1_cond.);
%m_anal_datastep(adqshfss, "HFDB998",&timep,anal_2, where = &oasis2_cond.);

DATA anal;
    SET anal_1
        anal_2
        ;
RUN;

/*****************************
 *Multiple imputation
 ****************************/
%m_mi(anal_1,500,&seed_oasis1.,anal_imp_1);
%m_mi(anal_2,500,&seed_oasis2.,anal_imp_2);

DATA anal_imp;
    SET anal_imp_1
        anal_imp_2
        ;
RUN;

%mergeDat(baseDat = anal_imp, keyDat = adsl(KEEP=usubjid studyid), by = usubjid)

/*****************************
 *Analysis
 ****************************/
%LET byvar = _imputation_;
%LET classvar = usubjid trt01pn studyid region1n avisitn ;
%LET xvar = base trt01pn studyid region1n avisitn trt01pn*avisitn base*avisitn trt01pn*studyid;

OPTIONS MPRINT;
%m_mmrm(anal_imp,&byvar,&classvar,chg,&xvar,un,lsmean,estim,pred);
quit;

%let cov=&MMRMStrUsed;
data usedcov;
    print="Covariance structure used: &cov" ;
    label print='';
RUN;

OPTIONS NOMPRINT;


/*Outputting information to .lst*/
title1 "MI procedure - Model information" ;
proc print data = modelinfo0;
RUN;


title1 "Missing Data Patterns before non-monotone imputation " ;
proc print data = misspatt0;
RUN;

title1 "MI procedure - Model information" ;
proc print data = modelinfo1;
RUN;


title1 "Missing Data Patterns after non-monotone imputation " ;
proc print data = misspatt1;
RUN;

title1 "The Mixed Procedure " ;
proc print data = usedcov;
RUN;
title1 ' ';

/*****************************
 *Combining the results
 ****************************/

%m_mmrm_rubin (estim, lsmean, mxparms, hffreq_main);

proc sort data = hfdd
     out = tby (keep = paramcd) nodupkey ;
    by paramcd ;
    where not missing(paramcd);
RUN;

Proc Sql noprint ;
    select count(usubjid) into : trtarm1 SEPARATED by "  "
           from adsl
           where trt01pn = 100
           group by trt01pn ;

    select count(usubjid) into : trtarm2 SEPARATED by "  "
           from adsl
           where trt01pn = 101
           group by trt01pn ;
    %put &trtarm1 &trtarm2 ;


    select paramcd into : paramcd SEPARATED by ""
           from tby
           where not missing(paramcd)
         ;

QUIT;

