 ******************************************************************************/

/*Medical history: PTs reported for 1 of subjects in total group and their associated SOC- number (%) of subjects (SAF)*/

%let mhtable = %intext_find_metadata(title1 = %str(Table: Medical history: number of subjects with findings by primary system organ class and preferred term  (safety analysis set)));

%let numberPT = 1;

data out_01(drop=i);
    set &mhtable.;
    if _n_ =1 then do;
        retain re;
        re=prxparse('/(\d+)\s*\(\s*<*(\d+\.\d+)/');
    END;
    array _trt[*] _t_1 _t_2 _t_4 _t_5;
    array _n[4];
    array _pct[4];
    do i=1 to dim(_trt);
        _n[i]= input(strip(scan(_trt[i],1,'(')),best.);
        if prxmatch(re,_trt[i]) then _pct[i]=input(prxposn(re,2,_trt[i]),best.);
        else _pct[i]=0;
    END;
RUN;


data out_soc;
