%GLOBAL trt_ezn_12;  %LET trt_ezn_12 = 1;
%GLOBAL trt_pla_12;  %LET trt_pla_12 = 2;
%GLOBAL trt_tot_12;  %LET trt_tot_12 = 3;
%GLOBAL trt_ezn_26;  %LET trt_ezn_26 = 4;
%GLOBAL trt_pla_26;  %LET trt_pla_26 = 5;
%GLOBAL trt_ezn_52;  %LET trt_ezn_52 = 6;
%GLOBAL trt_pla_52;  %LET trt_pla_52 = 7;

** Postfix _a refers to Actual Treatment;
** Postfix _nt refers to No Total;

%GLOBAL extend_var_disp_12
        extend_rule_disp_12;
%LET extend_var_disp_12  = trt01pn @FORMAT=_trtgrp. LABEL = "Planned Treatment Group";
%LET extend_rule_disp_12 = trt01pn in (53)             # &trt_ezn_12.
                         @ trt01pn in (9901)           # &trt_pla_12.
                         @ trt01pn in (53 9901)        # &trt_tot_12.;


%GLOBAL extend_var_disp_12_nt
        extend_rule_disp_12_nt;
%LET extend_var_disp_12_nt  = trt01pn @FORMAT=_trtgrp. LABEL = "Planned Treatment Group";
%LET extend_rule_disp_12_nt = trt01pn in (53)             # &trt_ezn_12.
                            @ trt01pn in (9901)           # &trt_pla_12.;

*Demography and baseline characteristics;
%GLOBAL extend_var_disp_12_52
        extend_rule_disp_12_52;
%LET extend_var_disp_12_52  = trt01pn @FORMAT=_trtgrp_ns. LABEL = "Planned Treatment Group";
%LET extend_rule_disp_12_52 = trt01pn in (53)                           # &trt_ezn_12.
                            @ trt01pn in (9901)                         # &trt_pla_12.
                            @ trt01pn in (53 9901)                      # &trt_tot_12.
                            @ trt01pn in (53) OR trt02pn IN (53)        # &trt_ezn_52.
                            @ trt01pn in (9901)                         # &trt_pla_52.
                            ;

*Reproductive and menstrual history, Medical history;
%GLOBAL extend_var_disp_12_52_a
        extend_rule_disp_12_52_a;
%LET extend_var_disp_12_52_a  = trt01an @FORMAT=_trtgrp_ns. LABEL = "IA treatment group";
%LET extend_rule_disp_12_52_a = trt01an in (53)                             # &trt_ezn_12.
                                @ trt01an in (9901)                         # &trt_pla_12.
                                @ trt01an in (53 9901)                      # &trt_tot_12.
                                @ trt01an in (53) OR trt02an IN (53)        # &trt_ezn_52.
                                @ trt01an in (9901)                         # &trt_pla_52.
                                ;

*Disposition;
%GLOBAL extend_var_disp_12_ezn_52
