%LET extend_rule_disp_12_ezn_52 = trt01pn in (53)                             # &trt_ezn_12.
                                 @ trt01pn in (9901)                          # &trt_pla_12.
                                 @ trt01pn in (53) OR trt02pn IN (53)         # &trt_ezn_52.
                                 ;

*Prior treatment medication;
%GLOBAL extend_var_disp_12_a
        extend_rule_disp_12_a;
%LET extend_var_disp_12_a  = trt01an @FORMAT=_trtgrp_split. LABEL = "IA treatment group";
%LET extend_rule_disp_12_a = trt01an in (53)               # &trt_ezn_12.
                             @ trt01an in (9901)           # &trt_pla_12.
                             @ trt01an in (53 9901)        # &trt_tot_12.;

*Post-treatment medication, TEAEs up to week 12, pre-treatment and post-treatment AEs, Safety tables including only Baseline (BL)/Screening and EoT;
