%LET extend_rule_disp_12_nt_a = trt01an in (53)               # &trt_ezn_12.
                                @ trt01an in (9901)           # &trt_pla_12.;

*Post-treatment medication, TEAEs up to week 26, pre-treatment and post-treatment AEs, Safety tables including only Baseline (BL)/Screening and EoT;
%GLOBAL extend_var_disp_26_nt_a
        extend_rule_disp_26_nt_a;
%LET extend_var_disp_26_nt_a  = trt01an @FORMAT=_trtgrp_split. LABEL = "IA treatment group";
%LET extend_rule_disp_26_nt_a =  trt01an in (53) OR trt02an IN (53)        # &trt_ezn_26.
