%GLOBAL extend_var_disp_12_26_52_nt_a
        extend_rule_disp_12_26_52_nt_a;
%LET extend_var_disp_12_26_52_nt_a  = trt01an @FORMAT=_trtgrp_split. LABEL = "IA treatment group";
%LET extend_rule_disp_12_26_52_nt_a = trt01an in (53)                       # &trt_ezn_12.
