%GLOBAL extend_var_disp_12_52_nt_a
        extend_rule_disp_12_52_nt_a;
%LET extend_var_disp_12_52_nt_a  = trt01an @FORMAT=_trtgrp_ns_notsplitted. /*_trtgrp_ns.*/ LABEL = "IA treatment group";
%LET extend_rule_disp_12_52_nt_a = trt01an in (53)                          # &trt_ezn_12.
                                @ trt01an in (9901)                         # &trt_pla_12.
                                @ trt01an in (53) OR trt02an IN (53)        # &trt_ezn_52.
                                @ trt01an in (9901)                         # &trt_pla_52.
                                ;


*Safety tables except AEs, Cumulative incidence for time to AEs;
%GLOBAL extend_var_disp_12_ezn_52_a
        extend_var_disp_12_ezn_52_a_nsa
        extend_rule_disp_12_ezn_52_a
        extend_rule_disp_12_ezn_52_a1
        extend_rule_disp_12_ezn_52_a_afl
        extend_rule_disp_12_ezn_52_anofl
        extend_rule_disp_12_ezn_52_a_tte
        extend_rule_disp_12_52_lab
        extend_rule_disp_12_52_anofl
        ;

%LET extend_var_disp_12_ezn_52_a      = trt01an @FORMAT=_trtgrp.     LABEL = "IA treatment group";
%LET extend_var_disp_12_ezn_52_a_nsa  = trt01an @FORMAT=_trtgrp_nsa. LABEL = "IA treatment group"; * Needed in VS / LB;

%LET extend_rule_disp_12_ezn_52_a = trt01an in (53)                             # &trt_ezn_12.
                                    @ trt01an in (9901)                         # &trt_pla_12.
                                    @ trt01an in (53) OR trt02an IN (53)        # &trt_ezn_52.
                                    ; * Needed for ADSL;

%LET extend_rule_disp_12_ezn_52_a1 = trt01an in (53)                             # &trt_ezn_12.
                                    @ trt01an in (9901)                         # &trt_pla_12.
                                    @ trt01an in (53) OR trt02an IN (53)        # &trt_ezn_26.
                                    @ trt01an in (53) OR trt02an IN (53)        # &trt_ezn_52.
                                    ; * Needed for ADSL;

%let extend_rule_disp_12_ezn_52_a_afl = trt01an in (53)   and anl02fl='Y'    # &trt_ezn_12.
                                        @ trt01an in (9901) and anl02fl='Y'   # &trt_pla_12.
                                        @ (trt01an in (53)  and anl01fl='Y')
                                          OR (trt02an in (53) and anl03fl='Y')  # &trt_ezn_52.
                                        ; * Needed for ADVS, ADLB;

%LET extend_rule_disp_12_ezn_52_anofl =  (trt01an in (53)    and anl04fl='Y')
                                        OR (trt01an in (53)    and ablfl='Y')# &trt_ezn_12.
                                       @ (trt01an in (9901) and anl04fl ='Y' )
                                        OR (trt01an in (9901)   and ablfl='Y')# &trt_pla_12.
                                       @ (trt01an in (53) and anl06fl='Y')
                                         OR (trt01an in (53) and ablfl='Y')
                                         OR (trt02an in (53) and ablfl='Y')
                                         OR (trt02an in (53) and anl05fl='Y')  # &trt_ezn_26.
                                       @ (trt01an in (53) and anl07fl='Y')
                                         OR (trt01an in (53) and ablfl='Y')
                                         OR (trt02an in (53) and ablfl='Y')
                                         OR (trt02an in (53) and anl05fl='Y')  # &trt_ezn_52.
                                         ; * Needed high / low abnormal ADLB tables;



%let extend_rule_disp_12_ezn_52_a_tte = trt01an in (53)  and avisitn=121 # &trt_ezn_12.
      @   trt01an in (9901)  and avisitn=121 # &trt_pla_12.
      @  (trt01an in (53)   and avisitn=700000)
      OR (trt02an in (53)   and avisitn=600000) # &trt_ezn_52.;* Needed for ADTTE;


%LET extend_rule_disp_12_52_lab = trt01an in (53)                             # &trt_ezn_12.
                                @ trt01an in (9901)                         # &trt_pla_12.
                                @ trt01an in (53) OR trt02an IN (53)        # &trt_ezn_26.
                                @ trt01an in (53) OR trt02an IN (53)        # &trt_ezn_52.
                                @ trt01an in (9901)                         # &trt_pla_26.
                                @ trt01an in (9901)                         # &trt_pla_52.
                                ; * Needed for ADSL;


%LET extend_rule_disp_12_52_anofl =  (trt01an in (53)    and anl04fl='Y')
                                OR (trt01an in (53)    and ablfl='Y')# &trt_ezn_12.
                                @ (trt01an in (9901) and anl04fl ='Y' )
                                OR (trt01an in (9901)   and ablfl='Y')# &trt_pla_12.
                                @ (trt01an in (53) and anl06fl='Y')
                                OR (trt01an in (53) and ablfl='Y')
                                OR (trt02an in (53) and ablfl='Y')
                                OR (trt02an in (53) and anl05fl='Y')  # &trt_ezn_26.

                                @ (trt01an in (53) and anl07fl='Y')
