    data _used_adlb;
        set &indat.;
        if &mosto_param_class. in (&arms);
        IF paramn = &paramn.;
        format &mosto_param_class. _trtgrp.;
        astdt=adt;
    RUN;

    data _used_adsl;
        set adsl_ext;
        if &mosto_param_class. in (&arms);
        format &mosto_param_class. _trtgrp.;
    RUN;

    %* EVMQE Filter ADSL which has only measurement;
