    PROC SORT NODUPKEY DATA = _used_adlb
                       OUT  = _temp_subject;
      BY &subj_var.;
    RUN;
    DATA _used_adsl_1;
      MERGE _used_adsl
            _temp_subject (IN = _keep KEEP = &subj_var.);
      BY &subj_var.;
      IF _keep;
    RUN;


    %m_inc_100_patyears(
        indat       = _used_adlb    (WHERE=(&triggercond.))
      , indat_adsl  = _used_adsl_1
      , class       = &mosto_param_class.
      , censordt    = enddt
      , startdt     = startdt
      , var         = paramn
      , triggercond = &triggercond.
      , evlabel     = AA
      , anytxt      = TO_DELETE
