      , ftn8 = "*IRs are study size adjusted incidence rates according to Crowe et al (2016)."
    );


    %MACRO _loop(paramn = );

    data _used_adlb;
        set &indat.;
        if &mosto_param_class. in (&arms);
        IF paramn = &paramn.;
        format &mosto_param_class. _trtgrp.;
        astdt=adt;
    RUN;

